-- Poems batch 198
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('ae3c48b3-675d-4127-a32c-70c4feb446c4','用王司理韵送別  其二','洪咨夔','宋','宋诗','song-poetry','','[]','蘆花秋摵摵，征思旆悠悠。',48,'全唐诗/poet.song.188000.json','["蘆花秋摵摵，征思旆悠悠。", "歌吹莫愁國，鼓鐃熊繹州。", "胸奇空盾鼻，膽雋落旄頭。", "儻有西風鴈，頻書老故侯。"]'),
('5a9e5a1b-6a83-4a0f-aedb-65b687ec1960','挽鍾孺人','洪咨夔','宋','宋诗','song-poetry','','[]','夫沒姑嫜老，年芳鑑珥新。',48,'全唐诗/poet.song.188000.json','["夫沒姑嫜老，年芳鑑珥新。", "孤峰晴後雪，碩果剝中春。", "命義生無媿，言容死未陳。", "西風吹拱木，雙劍合龍津。"]'),
('3e6234a2-29e7-4c55-b377-51f4879735d7','挽阮宣義','洪咨夔','宋','宋诗','song-poetry','','[]','夜氣精神飽，春風笑語酣。',48,'全唐诗/poet.song.188000.json','["夜氣精神飽，春風笑語酣。", "脩篁森道北，叢桂郁城南。", "雨露榮三釜，煙雲老一龕。", "瀧岡阡上路，秋思薄晴嵐。"]'),
('49b97b6f-b0d6-423b-8601-766d1b81edea','奬菊  其一','洪咨夔','宋','宋诗','song-poetry','','[]','木犀滿送第三香，交割秋光與後行。',32,'全唐诗/poet.song.189000.json','["木犀滿送第三香，交割秋光與後行。", "細雨斜風籬下菊，安排青蘂做重陽。"]'),
('8e3fb268-4543-4d49-8147-9f925f9d825b','奬菊  其二','洪咨夔','宋','宋诗','song-poetry','','[]','菰葉離披藕葉欹，精神得似未秋時。',32,'全唐诗/poet.song.189000.json','["菰葉離披藕葉欹，精神得似未秋時。", "西風坐斷群芳路，不屬黄花更屬誰。"]'),
('02d294d3-908e-40ec-b143-8b5ecf2692cb','章升伯妻孺人挽詩','洪咨夔','宋','宋诗','song-poetry','','[]','婉孌從君子，青雲遠大謀。',48,'全唐诗/poet.song.189000.json','["婉孌從君子，青雲遠大謀。", "樂羊燈火夜，李侃鼓鼙秋。", "露舄鳬迎喜，星機鵲送愁。", "誥花紛五色，光動九原頭。"]'),
('b84fd4f6-f7a0-44e5-8d1c-bb5cde57786b','東山懷謝傅用禮滅翁韵','洪咨夔','宋','宋诗','song-poetry','','[]','金堂石室舊徜徉，被髮依然下大荒。',64,'全唐诗/poet.song.189000.json','["金堂石室舊徜徉，被髮依然下大荒。", "月送嬋娟華落蘂，雲移縹緲濕疎篁。", "桓伊箏外深情酒，幼度棋邊定力香。", "往古來今開闔眼，樓頭吹面朔風凉。"]'),
('2cc167c5-b936-440b-a602-e0fef3c69cef','山中菰生米父老謂豐年之祥用子有韵','洪咨夔','宋','宋诗','song-poetry','','[]','秋風菰黍黑，山崦罕聞之。',48,'全唐诗/poet.song.189000.json','["秋風菰黍黑，山崦罕聞之。", "産瑞摇銀海，占豐灧玉池。", "芃芃秔合穗，裊裊穄分枝。", "却憶官張望，嘗新薦一匙。"]'),
('3f7642c9-5af5-45c6-989a-c54574aec3eb','初霜','洪咨夔','宋','宋诗','song-poetry','','[]','庭下曉來霜，菰頓芭蕉折。',24,'全唐诗/poet.song.189000.json','["庭下曉來霜，菰頓芭蕉折。", "絡石瘦菖蒲，獨抱青青節。"]'),
('11f91284-c26e-4700-8650-29c650d8d06d','九州山僧房','洪咨夔','宋','宋诗','song-poetry','','[]','路突亭依石，林凹渚見沙。',48,'全唐诗/poet.song.189000.json','["路突亭依石，林凹渚見沙。", "嶔危幾岣嶁，深蔚似琅琊。", "客倦驚寒思，僧閑忘歲華。", "兩窗風露影，一樹枇杷花。"]'),
('e3746027-9a20-48b2-92a6-8b7f44e1199b','挽俞致政','洪咨夔','宋','宋诗','song-poetry','','[]','涉世萬緣薄，愛書雙眼明。',48,'全唐诗/poet.song.189000.json','["涉世萬緣薄，愛書雙眼明。", "身從平處立，道向拙中生。", "啖蔗何妨晚，栽槐恰待榮。", "偈成投筆去，天闊暮雲橫。"]'),
('25ffe918-5f94-4e90-bdfa-95b60acd9f73','挽銅里葉提點','洪咨夔','宋','宋诗','song-poetry','','[]','養性居士白，用心承事黄。',48,'全唐诗/poet.song.189000.json','["養性居士白，用心承事黄。", "春風花竹墅，秋雨鱠蓴鄉。", "簡淡趨真諦，廉平絜義方。", "誌幽無長語，手墨粲琳琅。"]'),
('f867fd7f-4a31-4816-bf8d-bd8fe69316eb','徽州葉司理送冬笋','洪咨夔','宋','宋诗','song-poetry','','[]','凍雪晴邊白柄鑱，浴泥扶出錦綳衫。',32,'全唐诗/poet.song.189000.json','["凍雪晴邊白柄鑱，浴泥扶出錦綳衫。", "定知王謝家苗裔，風味生來便不凡。"]'),
('d09cab48-eca9-44cb-b1c6-73cd7c3a4a7c','挽俞景梁','洪咨夔','宋','宋诗','song-poetry','','[]','億計橋門士，輸君第一籌。',48,'全唐诗/poet.song.189000.json','["億計橋門士，輸君第一籌。", "文爲天下樣，行與古人謀。", "磨鐵素心在，注金蒼鬢休。", "梅邊清絕夢，誰更酒扶頭。"]'),
('282e6c97-f182-49e2-a125-eb0dbb765e8a','用韵答厲輔卿  其一','洪咨夔','宋','宋诗','song-poetry','','[]','坐窮無過客，失喜得吾儕。',48,'全唐诗/poet.song.189000.json','["坐窮無過客，失喜得吾儕。", "材逸類淮海，詩清如簡齋。", "山明知玉氣，水涸見霜涯。", "期子進此道，爲親生好懷。"]'),
('2329de98-e29f-4119-93dd-20a64d2dd015','用韵答厲輔卿  其二','洪咨夔','宋','宋诗','song-poetry','','[]','南北錦一住，東西巖屢登。',48,'全唐诗/poet.song.189000.json','["南北錦一住，東西巖屢登。", "報春梅有信，送酒鵲無憑。", "之子能相過，詩名不浪稱。", "漉冰烹小鳳，爽思爲渠增。"]'),
('fecffd2a-8e44-469a-a8d0-d30031cdc050','敬用老人功臣浄土院韵','洪咨夔','宋','宋诗','song-poetry','','[]','髓腦供祠寺，膏脂倒井閭。',48,'全唐诗/poet.song.189000.json','["髓腦供祠寺，膏脂倒井閭。", "岸隤猶畧彴，塔禿只夫須。", "窈窕釵先燕，夷猶带不魚。", "醉歸天欲雪，好箇探梅圖。"]'),
('4851dd9d-d971-4732-b4f6-dc7ac0ec05a2','石斛','洪咨夔','宋','宋诗','song-poetry','','[]','蚱蜢髀多節，蜜蜂脾有香。',48,'全唐诗/poet.song.189000.json','["蚱蜢髀多節，蜜蜂脾有香。", "蘚痕分磥砢，蘭穎聚琳琅。", "藥譜知曾有，詩題得未嘗。", "瓦盆風弄晚，披拂一襟凉。"]'),
('929034bb-6bbd-4d8b-9ee8-d98cb3f1ad13','庚寅元日甲子晴','洪咨夔','宋','宋诗','song-poetry','','[]','聖君元命是元正，三素雲開甲子晴。',32,'全唐诗/poet.song.189000.json','["聖君元命是元正，三素雲開甲子晴。", "不識姓名農圃老，相逢便與賀升平。"]'),
('73d95e02-ccb2-4303-a5a6-c73353229873','元夕','洪咨夔','宋','宋诗','song-poetry','','[]','輕陰不隔團團月，遺俗猶傳緩緩歌。',32,'全唐诗/poet.song.189000.json','["輕陰不隔團團月，遺俗猶傳緩緩歌。", "踏雪看燈知不惡，宜春釀酒恨無多。"]'),
('df4fc06f-b425-4cf0-bedf-c40fbad587d8','水仙蘭','洪咨夔','宋','宋诗','song-poetry','','[]','水仙瀟洒伴梅寒，鴻鴈行中合數蘭。',32,'全唐诗/poet.song.189000.json','["水仙瀟洒伴梅寒，鴻鴈行中合數蘭。", "七里香花陪隸耳，涪翁醉眼被粗瞞。"]'),
('46824f45-6ed0-4fcc-80b7-ef743717c32f','燈歎','洪咨夔','宋','宋诗','song-poetry','','[]','坐久燈欲乾，倒檠丐餘瀝。',96,'全唐诗/poet.song.189000.json','["坐久燈欲乾，倒檠丐餘瀝。", "點滴能幾多，燼滅在漏刻。", "可以觀養生，精涸神氣蝕。", "豈伊半圭茸，能續踵後息。", "可以觀爲政，歛苦生理迫。", "豈伊數匙糜，能起溝中瘠。", "嗟哉秋晨禾，葉葉含露液。", "毋使暵就槁，而望一溉益。"]'),
('fccb437e-631b-4425-94df-1fd92785606c','對門  其一','洪咨夔','宋','宋诗','song-poetry','','[]','對門三日罷晨炊，無處傭身老畫師。',32,'全唐诗/poet.song.189000.json','["對門三日罷晨炊，無處傭身老畫師。", "安得化山爲飯顆，大家鼓腹太平時。"]'),
('b288c2cd-dc95-403f-aa4e-b24b987012f3','對門  其二','洪咨夔','宋','宋诗','song-poetry','','[]','一簾霏雨暗花朝，焙藥爐邊擁破貂。',32,'全唐诗/poet.song.189000.json','["一簾霏雨暗花朝，焙藥爐邊擁破貂。", "深坐不知畦麥信，喜看黄液上瓶焦。"]'),
('c6c204a9-29b3-4ddd-afe4-3997d797a0a7','禽語','洪咨夔','宋','宋诗','song-poetry','','[]','脫却布袴博米歸，崗泥滑滑行苦遲。',64,'全唐诗/poet.song.189000.json','["脫却布袴博米歸，崗泥滑滑行苦遲。", "打麥作飯知何時，阿婆餠焦涎滿頤。", "更願春蠶一百箔，賣新得價絲貴樂。", "葫蘆沽酒和家酌，免教竈婦嘲姑惡。"]'),
('8e3c22f0-8927-4924-8db6-42c8951de0cc','讀元公輔傳有感','洪咨夔','宋','宋诗','song-poetry','','[]','公輔溪壑慾，胡椒八百斛。',80,'全唐诗/poet.song.189000.json','["公輔溪壑慾，胡椒八百斛。", "若比梁冀大是廉，幾舡珠璣幾車玉，三十萬萬無厭足。", "我宋從來相用儒，國肥民飽却家臞。", "田園圖史論貧富，鼎鼐樓臺辨有無。", "嗚呼哉鄙夫，嗚呼哉貪夫。"]'),
('d4e98dec-694c-4a6f-a56f-5b672e5ac401','示諸兒','洪咨夔','宋','宋诗','song-poetry','','[]','道大兩儀小，身寡萬物衆。',240,'全唐诗/poet.song.189000.json','["道大兩儀小，身寡萬物衆。", "此心能砥柱，斯文即隆棟。", "書從羲孔來，字字濟世用。", "愈窮理愈邃，如探無底洞。", "有書不勤讀，惰農失春種。", "如何望秋成，箕杵日簸弄。", "一經勝籯金，萬帙供洛誦。", "所願器業進，增益門戶重。", "兒童悟易玄，奴婢曉詩頌。", "而况以士名，經史懶條綜。", "古來天目下，誰識三歲貢。", "吾翁破天荒，教子期命中。", "顧我肋已雞，望汝毛猶鳳。", "詩書氣脈續，聲價天壤鬨。", "毋學韓家符，燈火照睡夢。", "毋學陶家雍，文術付遊縱。", "光明發勤苦，奇雋出餓凍。", "四壁瓢腹空，一檠鐺脚共。", "人情易喘筒，世事難算甕。", "努力須青春，三陳與二宋。"]'),
('f4d24b27-13e0-45c6-84f9-3325007398cb','春行','洪咨夔','宋','宋诗','song-poetry','','[]','花信雨擔閣，睡魔茶破除。',48,'全唐诗/poet.song.189000.json','["花信雨擔閣，睡魔茶破除。", "朗吟摇矮屋，徐步逸輕車。", "鳥語向人密，交情隨事疎。", "紛紛何足問，天地一蘧廬。"]'),
('55847afa-313e-43aa-8daa-57f6f6766cdb','次趙保之清明即事  其一','洪咨夔','宋','宋诗','song-poetry','','[]','餠喫紅綾空復憶，錢分白打底曾知。',32,'全唐诗/poet.song.189000.json','["餠喫紅綾空復憶，錢分白打底曾知。", "推排風雨清明過，只有梨花三兩枝。"]'),
('9a7730d5-97a1-4e74-8947-4832ecefd66a','次趙保之清明即事  其二','洪咨夔','宋','宋诗','song-poetry','','[]','草草携家去踏青，舊阡新冢紙錢輕。',32,'全唐诗/poet.song.189000.json','["草草携家去踏青，舊阡新冢紙錢輕。", "觸懷易作中年惡，羨殺兒童笑語聲。"]'),
('cbdd682b-221d-4906-b588-e128be24d856','次趙保之清明即事  其三','洪咨夔','宋','宋诗','song-poetry','','[]','花信東風第幾回，蕭條門巷老蒼苔。',32,'全唐诗/poet.song.189000.json','["花信東風第幾回，蕭條門巷老蒼苔。", "漢宮儘有新鑽火，無分傳將一點來。"]'),
('5cb87060-b12d-4d3b-bbea-7c76ee803f60','次趙保之清明即事  其四','洪咨夔','宋','宋诗','song-poetry','','[]','看花何必只長安，到處韶華總一般。',32,'全唐诗/poet.song.189000.json','["看花何必只長安，到處韶華總一般。", "可是家貧風物晚，郎當萵筍鬭春盤。"]'),
('bfa285c1-5249-43b2-87b1-e7b463fc890a','次趙保之清明即事  其五','洪咨夔','宋','宋诗','song-poetry','','[]','擅春正是海棠時，賸爲新晴準備詩。',32,'全唐诗/poet.song.189000.json','["擅春正是海棠時，賸爲新晴準備詩。", "潑火雨來還有信，崗南崗北竹雞啼。"]'),
('f9b61194-8e5f-479d-8d81-1793a58543fa','九華葉子真賦汴吳兩都極陳治亂之原仍有詩用杜遣懷韵見寄因和酬之','洪咨夔','宋','宋诗','song-poetry','','[]','於皇永昌陵，食龜大梁都。',252,'全唐诗/poet.song.189000.json','["於皇永昌陵，食龜大梁都。", "坐控天下樞，卜世周鼎俱。", "聖賢六七作，夷夏同康衢。", "懷鴆玩積安，厝火忘細娛。", "黼京相與樂，興亡視如無。", "元氣付一錮，膏血供百須。", "但知豢富貴，金珠潤黄壚。", "豈料醉夢中，蠱瘵生華腴。", "凄風暗離黍，斜陽渺煙蕪。", "空令老忠簡，渡河死猶呼。", "南來吳會雄，北望汴水枯。", "迓續赤帝脈，覊縻黄頭胡。", "楚蜀壯襟带，江淮豐灌輸。", "以此圖中原，所嗟欠謀夫。", "平園舊賓客，清燈耿寒爐。", "搔首宿感集，拊髀流光徂。", "理亂有成鑒，天高不容呼。", "擬古賦二京，舉一通三隅。", "謂墮狗監舌，寧老瓜芋區。", "誰能齒臯朔，俳優雜星巫。", "芙蓉歸去來，月落長庚孤。"]'),
('516583a1-919c-40fe-ae7b-2f73802134e0','暮春即事','洪咨夔','宋','宋诗','song-poetry','','[]','溫明好天氣，猛憶湖山遨。',168,'全唐诗/poet.song.189000.json','["溫明好天氣，猛憶湖山遨。", "平堤到處柳，流水誰家桃。", "樽斚選勝檻，笙歌喚輕舠。", "百需不移具，一醉何庸逃。", "膜鼓着日緊，紙鳶得風高。", "買歸不論價，矜詡相爲豪。", "迅晷畧兩眼，柔颸摇三毛。", "閙裏夢已破，閑邊趣方牢。", "摘桑暮西崦，浸穀朝東臯。", "病來飯即藥，客至茶當醪。", "雲煙面目稔，筍蕨氣勢鏖。", "腰頑渠稱鶴，脚硬難爲鰲。", "吾非東山謝，亦非華陽陶。", "泊乎潜溪潜，萬事隨所遭。"]'),
('61585f80-ce72-4a38-8593-913413e99843','次韵閔饑  其一','洪咨夔','宋','宋诗','song-poetry','','[]','貴人生長不知田，絲竹聲中醉飽眠。',32,'全唐诗/poet.song.189000.json','["貴人生長不知田，絲竹聲中醉飽眠。", "渠信春山青草盡，排門三日未炊煙。"]'),
('0dbf2958-d9e7-407c-99f4-ec80a1f20ae5','次韵閔饑  其二','洪咨夔','宋','宋诗','song-poetry','','[]','巷頭巷尾幾夷齊，日爲饑腸不肯西。',32,'全唐诗/poet.song.189000.json','["巷頭巷尾幾夷齊，日爲饑腸不肯西。", "只願天公多雨粟，便教米價賤如泥。"]'),
('35217c37-5b76-4fdd-8d9a-e69258b1cf35','茶笋病','洪咨夔','宋','宋诗','song-poetry','','[]','蕾金初出焙，板玉又登厨。',60,'全唐诗/poet.song.189000.json','["蕾金初出焙，板玉又登厨。", "爲愛頰車雋，做成風骨臞。", "黄婆幾倒盡，姹女得安無。", "快意宜知悔，清標不忍孤。", "五兵生厚味，寧作病浮屠。"]'),
('18d36d45-c786-4e9f-8f4f-52064269213c','口占酬俞端叔牡丹','洪咨夔','宋','宋诗','song-poetry','','[]','沉香亭北夢魂賒，驚見祥雲七寶車。',32,'全唐诗/poet.song.189000.json','["沉香亭北夢魂賒，驚見祥雲七寶車。", "窮孟嘗君空好客，病維摩老不禁花。"]'),
('39bf46a3-f9b2-4928-b6fa-47b0b9caeea1','次韵何伯溫  其一','洪咨夔','宋','宋诗','song-poetry','','[]','庭前木蘭花，皦皦扶春陽。',48,'全唐诗/poet.song.189000.json','["庭前木蘭花，皦皦扶春陽。", "鶴鳴夜漏午，步花獨歌商。", "低迷露濕衣，浩蕩月滿梁。", "深省渺誰語，中心空自藏。"]'),
('30ac1c92-dc3e-4c6e-8f04-bafff3337066','次韵何伯溫  其二','洪咨夔','宋','宋诗','song-poetry','','[]','出門夾徑松，春盡花滿林。',48,'全唐诗/poet.song.189000.json','["出門夾徑松，春盡花滿林。", "毿毿麈尾黄，裊裊雲氣深。", "仙人左元放，騎龍夜相尋。", "飯我花杪露，實腹虛其心。"]'),
('d0730a29-a5ca-4cfc-a0b7-9755e5b150e0','次韵何伯溫  其三','洪咨夔','宋','宋诗','song-poetry','','[]','銅瓶一穟蕙，芳潔以自旌。',48,'全唐诗/poet.song.189000.json','["銅瓶一穟蕙，芳潔以自旌。", "相看色轉睟，未言意先傾。", "翛如鄭子真，聲名豈其卿。", "明窗細披挹，心空氣和平。"]'),
('0f01fde0-c913-4c41-8659-c927ac92c934','山鄉','洪咨夔','宋','宋诗','song-poetry','','[]','石田磽确萬山隈，逢着荒年更可哀。',64,'全唐诗/poet.song.189000.json','["石田磽确萬山隈，逢着荒年更可哀。", "盡日幾人擔米上，長年何處得錢來。", "扣門强貸刑難逭，閉戶清饑死又催。", "不是乾坤芻狗汝，要令箇箇學顔回。"]'),
('27772340-c1d7-498d-aaa6-4f5366232fb1','錢德成山水窟','洪咨夔','宋','宋诗','song-poetry','','[]','亦有黄金埒，非無瑞錦窠。',48,'全唐诗/poet.song.189000.json','["亦有黄金埒，非無瑞錦窠。", "養蒙知趣早，觀復用功多。", "嘉客賁場谷，碩人槃澗阿。", "時平風日好，花竹幾行窩。"]'),
('3fb2b8fa-f59a-4075-b48e-ffa92c243bd8','壽程宰  其一','洪咨夔','宋','宋诗','song-poetry','','[]','作縣如弄潮，莫吸半呷水。',36,'全唐诗/poet.song.189000.json','["作縣如弄潮，莫吸半呷水。", "紅旗上岸來，喝采沙河市。", "拈取第一籌，細柳天風裏。"]'),
('b03af157-47f1-4cac-b1be-ec46fd71957b','壽程宰  其二','洪咨夔','宋','宋诗','song-poetry','','[]','愛民如緣竿，百尺頭進步。',36,'全唐诗/poet.song.189000.json','["愛民如緣竿，百尺頭進步。", "未到百尺頭，努力莫回顧。", "當場萬人看，亭亭碧霄住。"]'),
('16fe00b3-43de-4e03-bd34-fa9d3bc2ac1a','壽程宰  其三','洪咨夔','宋','宋诗','song-poetry','','[]','回翁十日前，先脫老鶴胎。',36,'全唐诗/poet.song.189000.json','["回翁十日前，先脫老鶴胎。", "拍手浮玉頂，君騎鳳凰來。", "相逢說長生，一笑榴花開。"]'),
('8a2cfe51-270f-4f75-b84e-034695c7f556','曉出','洪咨夔','宋','宋诗','song-poetry','','[]','一雙杜宇青天月，兩點烏犍白水陂。',32,'全唐诗/poet.song.189000.json','["一雙杜宇青天月，兩點烏犍白水陂。", "不爲好山勾引出，那知已是插秧時。"]'),
('f1b63102-c97f-4eac-993b-fd7d52182e47','行臨安縣圃','洪咨夔','宋','宋诗','song-poetry','','[]','縣勢坡陀樹老蒼，山光明潤客荒唐。',64,'全唐诗/poet.song.189000.json','["縣勢坡陀樹老蒼，山光明潤客荒唐。", "木蘭多露不能濕，薝蔔匪風還自香。", "萬事婦姑鳴好醜，百年翁仲領興亡。", "九龍堂裏隨宜酒，盧橘來禽日正長。"]'),
('28aa0f87-465d-4250-9204-cbbf3d338f6d','寄題永嘉林氏真意堂','洪咨夔','宋','宋诗','song-poetry','','[]','萱草逕庭寂，橘花窗戶明。',48,'全唐诗/poet.song.189000.json','["萱草逕庭寂，橘花窗戶明。", "我惟天地性，物自古今情。", "玄酒無窮味，朱弦不盡聲。", "道從涵泳得，寬作讀書程。"]'),
('dcd84498-f9d0-4d88-b585-ebb1023f4610','答隆慶李守','洪咨夔','宋','宋诗','song-poetry','','[]','萬里一天碧，百懷雙鬢秋。',48,'全唐诗/poet.song.189000.json','["萬里一天碧，百懷雙鬢秋。", "凄其占後會，展也企前脩。", "風露昂藏鶴，煙波浩蕩鷗。", "書來如覿面，香滿藕花洲。"]'),
('a91054c9-c732-4958-bcfd-46144f926245','東山次俞紫微止止堂韵','洪咨夔','宋','宋诗','song-poetry','','[]','佛法元無法，人謀盡過謀。',48,'全唐诗/poet.song.189000.json','["佛法元無法，人謀盡過謀。", "說空猶是着，領妙更何求。", "徑滑松杉古，窗虛水石幽。", "琤琤鳴鐵裏，安處一時休。"]'),
('0f85a93b-ff03-453f-840d-9a97e681fa35','繡觀音酬郢州王知錄丹青美人之贈兩絕  其一','洪咨夔','宋','宋诗','song-poetry','','[]','楚人不識女須面，只畫昭君并莫愁。',32,'全唐诗/poet.song.189000.json','["楚人不識女須面，只畫昭君并莫愁。", "贏得江南窮相眼，自嗟空白一生頭。"]'),
('65edeb83-a465-4cdc-af51-6f638ddd3c20','繡觀音酬郢州王知錄丹青美人之贈兩絕  其二','洪咨夔','宋','宋诗','song-poetry','','[]','十相端嚴具足身，一團楊柳浄瓶春。',32,'全唐诗/poet.song.189000.json','["十相端嚴具足身，一團楊柳浄瓶春。", "石城莫與蛾眉看，羞不如人却妬人。"]'),
('1d10c4ef-111e-46ee-a721-153db5025972','乍凉','洪咨夔','宋','宋诗','song-poetry','','[]','一雨添一凉，秋近暑已遠。',84,'全唐诗/poet.song.189000.json','["一雨添一凉，秋近暑已遠。", "菰荷響騷颯，忽其歲年晚。", "悁悁我所思，室而偏其反。", "燕乳巢未空，蛩吟枕先滿。", "涉非忘淺深，飲自知冷暖。", "黄姑與織女，隔河送悽惋。", "南金英瓊瑶，不換霜鬢短。"]'),
('104c1ba9-85b3-4730-8dae-575d6d7adb7b','七夕','洪咨夔','宋','宋诗','song-poetry','','[]','好箇牽牛織女天，凄其獨夜不成眠。',64,'全唐诗/poet.song.189000.json','["好箇牽牛織女天，凄其獨夜不成眠。", "柳家細婢何能問，太尉粗人祗自憐。", "比翼難磨終古恨，嫵眉未了宿生緣。", "新凉如水誰消得，平等天公也解偏。"]'),
('afddea00-276e-4a58-8624-5c7ac3874dee','秋思','洪咨夔','宋','宋诗','song-poetry','','[]','一曲玉連瑣，十分金屈巵。',24,'全唐诗/poet.song.189000.json','["一曲玉連瑣，十分金屈巵。", "故新相代謝，底用爲秋悲。"]'),
('3ce136f4-90ce-4341-9532-7b314e9fd7ab','寓興','洪咨夔','宋','宋诗','song-poetry','','[]','巨口松江鱸，縮頸槎頭鯿。',60,'全唐诗/poet.song.189000.json','["巨口松江鱸，縮頸槎頭鯿。", "一釂聊復爾，百懷故依然。", "林靜橫沆瀣，庭空澹嬋娟。", "鳴螿識人意，切切悲流年。", "最憐重開桂，抱寒爲人妍。"]'),
('db5ddc73-9fd9-479d-a756-966c98622edb','阮亨甫壽樂堂澹庵各一首 壽樂','洪咨夔','宋','宋诗','song-poetry','','[]','孤塔明橫巘，短橋華枉渚。',108,'全唐诗/poet.song.189000.json','["孤塔明橫巘，短橋華枉渚。", "結堂水石邃，奉此清節母。", "菊能駐頹景，松下蔚可數。", "萱能忘百憂，竹間粲欲語。", "日淡迎春風，雲薄謝秋暑。", "板輿穿蔭來，綵袂踏花舞。", "點頭每一笑，彈指忽千古。", "盡將柏舟淚，灑作蓼莪雨。", "僾然其若存，青山照庭戶。"]'),
('b021eaa2-a31d-43bc-af20-6e3c4f0bd710','阮亨甫壽樂堂澹庵各一首 澹庵','洪咨夔','宋','宋诗','song-poetry','','[]','江西老澹庵，高節湛秋水。',96,'全唐诗/poet.song.189000.json','["江西老澹庵，高節湛秋水。", "君庵亦澹名，聞其風興起。", "一徑窈柏竹，八窗秀荃芷。", "意行襲幽芳，燕坐鑑碧泚。", "銅爐古鍾磬，瓦研素屏几。", "玄根息芸芸，泰宇安止止。", "大羹及玄酒，不入世人齒。", "床頭周易在，更與參妙理。"]'),
('b7de7ef5-0c0a-4ff6-90e8-7a7d69437112','秋懷  其一','洪咨夔','宋','宋诗','song-poetry','','[]','素節垂垂杪，衰懷拍拍叢。',48,'全唐诗/poet.song.189000.json','["素節垂垂杪，衰懷拍拍叢。", "風乾梧葉白，霜老菊花紅。", "理曲多添瘦，停詩不減窮。", "出尋空闊處，揩眼送飛鴻。"]'),
('dbdf8de2-6632-4c03-b904-307f62e134b6','秋懷  其二','洪咨夔','宋','宋诗','song-poetry','','[]','鸚鵡琵琶恨，融歸十四弦。',48,'全唐诗/poet.song.189000.json','["鸚鵡琵琶恨，融歸十四弦。", "撥寒紅玉笋，拍暖繡金蓮。", "梅影春風裏，茶聲雪水邊。", "自憐還自笑，星髮照嬋娟。"]'),
('7a856e52-c3da-435a-9440-dad3cd17778b','記夢','洪咨夔','宋','宋诗','song-poetry','','[]','青天一朵雲起東，斗黑怒雨驤玉龍。',64,'全唐诗/poet.song.189000.json','["青天一朵雲起東，斗黑怒雨驤玉龍。", "江頭女子十七八，喚出八十老龍翁。", "龍翁擲珠引龍舞，女子笑滿雙頰紅。", "天風吹動翡翠佩，騎龍直入蓬萊宮。"]'),
('dcbd254d-982e-4331-b6fe-885139bf37bb','山行紀事','洪咨夔','宋','宋诗','song-poetry','','[]','扉開日華早，路轉霜花鮮。',288,'全唐诗/poet.song.189000.json','["扉開日華早，路轉霜花鮮。", "遊鴻得嘉客，健鶴隨老僊。", "舴艋野渡淺，畧彴孤村連。", "紆餘盤龍外，杳靄烏猿邊。", "麥畦破凍剗，稻架烘晴懸。", "萬鴉暗澒洞，隻鷺明㛹娟。", "寺古繚虛嶂，房深貯澄漣。", "珍鱗紫金睟，秀石蒼玉攣。", "住僧自縛律，愛客能逃禪。", "老帖不容搨，枯琴尚堪弦。", "出訪文舉碣，還息維摩氈。", "窗暉梅枝月，帳鬰柏子煙。", "吸清飽蟬腹，擁薄攢龜肩。", "忍寒如忍艾，望曉猶望年。", "報明翠鯨壯，送暖紅鱗妍。", "讀易坐方穩，搜詩去俄翩。", "行行晉縣壘，歷歷吳墓田。", "森峭徑絕壁，嵌空派危泉。", "飛墮雪珂境，撼動冰輪天。", "憇寂小養雋，挾酣急凌巔。", "閣摧失傑詠，巖在餘奇鎸。", "夕氣生遠嶼，倦懷寄平川。", "路旁柳如此，陌上花依然。", "數年束强項，一日舒聯拳。"]'),
('7f832b65-c38e-484a-be73-7c93267f347f','和何伯溫見寄  其一','洪咨夔','宋','宋诗','song-poetry','','[]','問字無人過草堂，昨非今是兩俱忘。',64,'全唐诗/poet.song.189000.json','["問字無人過草堂，昨非今是兩俱忘。", "鶴何骯髒寒方警，梅許凄凉靜更香。", "萬古江山窮太白，一簾風月老張蒼。", "多君不作炎凉語，識我平生鐵石腸。"]'),
('2e1ab6d8-1bc9-470b-a591-884acd00fd09','和何伯溫見寄  其二','洪咨夔','宋','宋诗','song-poetry','','[]','青山流水曉葱朧，讀遍黄庭萬境空。',64,'全唐诗/poet.song.189000.json','["青山流水曉葱朧，讀遍黄庭萬境空。", "羔甕無緣澆舌本，貘屏有分護頭風。", "人謀歷歷既未濟，民力班班大小東。", "陶寫此懷須好句，殷勤時與寄來鴻。"]'),
('0b6547dc-7d93-4ea0-bd3b-ac105d0b0328','和子有感時','洪咨夔','宋','宋诗','song-poetry','','[]','八州都督新推轂，兩紀中書舊覆甌。',32,'全唐诗/poet.song.189000.json','["八州都督新推轂，兩紀中書舊覆甌。", "郿塢然臍如有策，聊城飛笴便無憂。"]'),
('f1eecdf3-6bce-4d85-bdb2-61640d8f4835','歲杪用韵  其一','洪咨夔','宋','宋诗','song-poetry','','[]','日月磨心緒，風霜染鬢華。',48,'全唐诗/poet.song.189000.json','["日月磨心緒，風霜染鬢華。", "曆看新歲草，梅憶舊年花。", "濁酒供僛舞，清歌應摻撾。", "阿咸多事在，猶問老生涯。"]'),
('b13a0bde-ce66-4a70-b24c-5c408a2f6691','歲杪用韵  其二','洪咨夔','宋','宋诗','song-poetry','','[]','黄麾春簇仗，夢不到東華。',48,'全唐诗/poet.song.189000.json','["黄麾春簇仗，夢不到東華。", "瓦研磨冰葉，磚爐煮雪花。", "窮甘猿帳卧，老倦犢轅撾。", "凍解光風轉，晴波拍兩涯。"]'),
('fb5b7dfd-74bb-4943-a949-483ef5db2eb8','元宵前三日侍老人遊雙林','洪咨夔','宋','宋诗','song-poetry','','[]','大徑山高寺山巔，小徑山深寺山趾。',144,'全唐诗/poet.song.189000.json','["大徑山高寺山巔，小徑山深寺山趾。", "辛夷花開數點雨，艾納香空半泓水。", "新新故故自樓閣，下下高高各窗几。", "二三名公詩一束，八十老衲畫幾紙。", "雲岑滅沒野屋浮，草樹離列渡舟檥。", "露橫斷浦月已高，日落平沙風欲起。", "直疑着我江湖間，安得伴君巖壑裏。", "魚肥尚恨絲蓴晚，酒酣苦愛葅筍美。", "參寥有句墮杳靄，更上迎暉亭徙倚。"]'),
('9ffb5102-9762-4d06-b089-66d90683e0d9','謹和老人明朝中春  其一','洪咨夔','宋','宋诗','song-poetry','','[]','田夫野老布長衫，郊外相逢與共譚。',64,'全唐诗/poet.song.189000.json','["田夫野老布長衫，郊外相逢與共譚。", "一把年華將望六，九分春色又過三。", "竹雞絕叫茶生笋，梅子微酸酒熟藍。", "流轉風光無間斷，此身元與化功參。"]'),
('24708501-7da0-4021-b61e-0a05edc0a6d6','謹和老人明朝中春  其二','洪咨夔','宋','宋诗','song-poetry','','[]','淡黄深碧上春衫，無限春懷豈易譚。',64,'全唐诗/poet.song.189000.json','["淡黄深碧上春衫，無限春懷豈易譚。", "隨手去來拈放一，到頭得失暮朝三。", "日烘花氣通玄牝，雨洗山光漲蔚藍。", "熟聽五更晴哢好，不須多恨罷朝參。"]'),
('e8a77e80-776c-4ae4-a274-b97c8c35cc70','春行次韵','洪咨夔','宋','宋诗','song-poetry','','[]','拂開芳草碧，坐斷落花紅。',48,'全唐诗/poet.song.189000.json','["拂開芳草碧，坐斷落花紅。", "世味觥籌外，年華带眼中。", "六州空鑄鐵，萬物任爲銅。", "有鷕桑疇雉，逢時會長雄。"]'),
('c7de458d-310e-4379-86c9-99ebb80cdd2c','病齒','洪咨夔','宋','宋诗','song-poetry','','[]','吾母苦蚤衰，髮霜齒存幾。',276,'全唐诗/poet.song.189000.json','["吾母苦蚤衰，髮霜齒存幾。", "小兒得其髮，大兒得其齒。", "予方四十時，上齶右車毀。", "從茲白石源，歲歲費經理。", "軟疑梅着酸，疎類榴罅子。", "根浮觸易兀，力弱遇輒靡。", "懷核忌堅栗，設胔便脆美。", "爛炰故自佳，急嚥聊復爾。", "刺肥劇鉏姦，剔纖難拔壘。", "屢搜風屢入，一快勢一圯。", "撼摇腫貫顴，焦蠹痛徹髓。", "外雖編貝然，中實空齦似。", "赤龍攪沆瀣，玉池漲清泚。", "天鼓弗能扣，金鼎亦徒舐。", "乳媼老不羞，機女少自喜。", "風流久已絕，血氣安足恃。", "磨治朝辛鹽，漱溉夕莎芷。", "庶幾尚扶危，不至遽乏使。", "太官羊何腴，五侯鯖更旨。", "雖無轑釜嗔，未免媚竈耻。", "菽腐柔趁梜，粟糜滑流匕。", "不愁餒在中，却笑飽欲死。", "舌以柔故存，此語未敢唯。"]'),
('8c4ddadd-9c9e-45b6-91d9-16f43fc242da','春思  其一','洪咨夔','宋','宋诗','song-poetry','','[]','柳汁何能染鬢根，柳絲只解絆愁魂。',32,'全唐诗/poet.song.189000.json','["柳汁何能染鬢根，柳絲只解絆愁魂。", "年光有底催人急，水牡丹花又上盆。"]'),
('9e24f018-da85-4ea7-ac92-bf42f9ba7b1a','春思  其二','洪咨夔','宋','宋诗','song-poetry','','[]','細草荒煙古墓田，知經寒食幾年天。',32,'全唐诗/poet.song.189000.json','["細草荒煙古墓田，知經寒食幾年天。", "雪條花下翩翩紙，疑是曾分白打錢。"]'),
('2b493af1-4643-46b7-94ff-eed4f076e3a1','春思  其三','洪咨夔','宋','宋诗','song-poetry','','[]','蝴蝶深深淺淺黄，被春惱得一般狂。',32,'全唐诗/poet.song.189000.json','["蝴蝶深深淺淺黄，被春惱得一般狂。", "打團飛入菜花去，自信世間無別香。"]'),
('d4558218-a3c2-4c63-850c-5277438e6615','偶成','洪咨夔','宋','宋诗','song-poetry','','[]','沂水春風弄夕暉，舞雩意得詠而歸。',32,'全唐诗/poet.song.189000.json','["沂水春風弄夕暉，舞雩意得詠而歸。", "爲何與點狂曾晢，箇裏須參最上機。"]'),
('8fed55ff-5682-4e39-85af-8e6f544e46aa','三月晦東山','洪咨夔','宋','宋诗','song-poetry','','[]','太皞明朝禪祝融，杖藜能送幾東風。',64,'全唐诗/poet.song.189000.json','["太皞明朝禪祝融，杖藜能送幾東風。", "兩崖蘿蔓因依綠，一樹桐華自在紅。", "聒聒竊脂農即事，喈喈摶黍女趨功。", "細思舉世誰閑得，一笑浮圖倒景中。"]'),
('a60a3125-d064-4f1f-aeaa-c79a044a5a69','續夢','洪咨夔','宋','宋诗','song-poetry','','[]','琉璃庭釦水晶欄，寶樹婆娑玉斧閑。',32,'全唐诗/poet.song.189000.json','["琉璃庭釦水晶欄，寶樹婆娑玉斧閑。", "只恐姮娥嫌冷落，却隨飛月下人間。"]'),
('89e40594-e135-4932-9436-9d77776815ee','作茶行','洪咨夔','宋','宋诗','song-poetry','','[]','磨斲女媧補天不盡石，磅礴輪囷凝紺碧臼刳。',200,'全唐诗/poet.song.189000.json','["磨斲女媧補天不盡石，磅礴輪囷凝紺碧臼刳。", "扶桑掛日最上枝，媻跚勃窣生紋漪。", "吳罡小君贈我杵，阿香藁砧授我斧。", "斧開蒼璧粲磊磊，杵碎玄璣紛楚楚。", "出臼入磨光吐吞，危坐隻手旋乾坤。", "碧瑶宮殿几塵墮，蕊珠樓閣粧鉛翻。", "慢流乳泉活火鼎，淅瑟微波開溟涬。", "花風迸入毛骨香，雪月浸澈須眉影。", "太一真人走上蓮花航，維摩居士驚起獅子床。", "不交半談共細啜，山河日月俱清凉。", "桑苧翁，玉川子，款門未暇相倒屣。", "予方抱易坐虛明，參到洗心玄妙旨。"]'),
('3652584e-8b5e-4675-86d3-ccf680d651e2','送程於潜  其一','洪咨夔','宋','宋诗','song-poetry','','[]','溪山民物古，政理器能寬。',48,'全唐诗/poet.song.189000.json','["溪山民物古，政理器能寬。", "平易見眉睫，明清生肺肝。", "春風簾影暖，霜月研聲寒。", "野老自相語，元豐崔長官。"]'),
('7744c671-14f5-43be-9bab-3b59547dc73e','送程於潜  其二','洪咨夔','宋','宋诗','song-poetry','','[]','遡紫催飛舄，攢紅簇去鞍。',48,'全唐诗/poet.song.189000.json','["遡紫催飛舄，攢紅簇去鞍。", "吾邦傾市送，旁邑塞塗看。", "清廟登犧象，明庭峙孔鸞。", "野翁麋鹿友，時與訊平安。"]'),
('23708841-c5cf-45ea-88e5-6595c075655a','新月','洪咨夔','宋','宋诗','song-poetry','','[]','天面如人面，昏昏鎮是愁。',24,'全唐诗/poet.song.189000.json','["天面如人面，昏昏鎮是愁。", "晚來雲色解，新月放眉頭。"]'),
('565bacf1-b73a-4836-b0f6-7ebaaab9f7d5','百合花','洪咨夔','宋','宋诗','song-poetry','','[]','日月飛雙轂，如何駐黑頭。',48,'全唐诗/poet.song.189000.json','["日月飛雙轂，如何駐黑頭。", "纔看敷密友，又見拆彊仇。", "葉聚稜稜峭，花垂娜娜稠。", "晚凉芬烈甚，欲睡更遲留。"]'),
('e7ef32d4-793b-43af-8a17-ea58a6848135','雨中次韵  其一','洪咨夔','宋','宋诗','song-poetry','','[]','積多雲鶴巖前雨，種遍長松墓上田。',32,'全唐诗/poet.song.189000.json','["積多雲鶴巖前雨，種遍長松墓上田。", "豐歉相乘天有數，今年管取斗三錢。"]'),
('5f31fe9f-a25c-46e0-95f8-266a3889a79f','雨中次韵  其二','洪咨夔','宋','宋诗','song-poetry','','[]','提壺勸飲元無秫，促織催機未有絲。',32,'全唐诗/poet.song.189000.json','["提壺勸飲元無秫，促織催機未有絲。", "葉底蟬蟟尤更苦，吸風飲露伴人饑。"]'),
('e5f35957-fcf5-47af-8711-c6a28d4a6a99','送徐顯道尉無錫','洪咨夔','宋','宋诗','song-poetry','','[]','握手不禁別，庭梧聲欲秋。',48,'全唐诗/poet.song.189000.json','["握手不禁別，庭梧聲欲秋。", "雲霄生脚底，田里付眉頭。", "敬是禔身柱，和爲應物舟。", "卷旗蒲柳市，茶鼎雨颼颼。"]'),
('0f352617-dffa-42b1-8c5e-966d71e61f8e','二花','洪咨夔','宋','宋诗','song-poetry','','[]','粲粲金錢映玉簪，榮華能得幾光陰。',32,'全唐诗/poet.song.189000.json','["粲粲金錢映玉簪，榮華能得幾光陰。", "季倫歌妓春申客，零落秋風沒處尋。"]'),
('9eed15d9-e69c-4c7d-aa33-76fdb3425eb4','理菖蒲','洪咨夔','宋','宋诗','song-poetry','','[]','朝刪石上青之黄，暮摘鏡裏黑之蒼。',77,'全唐诗/poet.song.189000.json','["朝刪石上青之黄，暮摘鏡裏黑之蒼。", "胸中多少冗荆棘，不翦不芸空過日。", "君不見顔子一克己，曾參三省身。", "每日低頭矻矻自點檢，何曾浪把外物勞精神。", "嗟乎我猶未免爲鄉人。"]'),
('b81ff239-623c-4242-8dd7-da8e7f71b4f9','閑居  其一','洪咨夔','宋','宋诗','song-poetry','','[]','一覺湯餠睡，幾轉庭花陰。',60,'全唐诗/poet.song.189000.json','["一覺湯餠睡，幾轉庭花陰。", "不作八翼夢，以無富貴心。", "東家朝鳴玉，西家暮橫金。", "芭蕉大蔽牛，不柰霜風侵。", "何如老忘得，曲肱滋味深。"]'),
('c5045e7d-c185-49fe-8f64-71e327dfa103','閑居  其二','洪咨夔','宋','宋诗','song-poetry','','[]','出門聞鳩語，秋思生春妍。',60,'全唐诗/poet.song.189000.json','["出門聞鳩語，秋思生春妍。", "豆苗深沒腰，稻花高出肩。", "路旁兩三叟，合爪感謝天。", "老身幸不死，得見穰穰田。", "眼中多少人，不能待豐年。"]'),
('01a88bc0-ff0c-4338-bd7f-92994f98d09a','雙林志廉得玄暉筆法作此七十三矣爲賦六言兩首  其一','洪咨夔','宋','宋诗','song-poetry','','[]','近浦霏開略彴，遠山雲沒招提。',28,'全唐诗/poet.song.189000.json','["近浦霏開略彴，遠山雲沒招提。", "樹底人家欲曉，隔籬彷彿雞啼。"]'),
('5dcd1ec3-b66e-4dbb-bc28-196bfa2f1342','雙林志廉得玄暉筆法作此七十三矣爲賦六言兩首  其二','洪咨夔','宋','宋诗','song-poetry','','[]','潮退寒洲聚沫，雨收春嶂蒸雲。',28,'全唐诗/poet.song.189000.json','["潮退寒洲聚沫，雨收春嶂蒸雲。", "歷歷舊經行處，江村曙色初分。"]'),
('8702c81d-dcc9-4835-b3ac-dcbee183d7e9','送阮深甫尉桂東  其一','洪咨夔','宋','宋诗','song-poetry','','[]','秋陰疎梧桐，暮寒老蒹葭。',48,'全唐诗/poet.song.189000.json','["秋陰疎梧桐，暮寒老蒹葭。", "病鶴卧空谷，遊鴻起平沙。", "飄摇征衣單，寂歷津堠賒。", "中年不禁別，湘江渺天涯。"]'),
('7a17739f-1d0e-41dc-b7e4-3c4df2b09394','送阮深甫尉桂東  其二','洪咨夔','宋','宋诗','song-poetry','','[]','一靜鎮百紛，一恕生百順。',48,'全唐诗/poet.song.189000.json','["一靜鎮百紛，一恕生百順。", "所居欲官大，此道貴坐進。", "塗平鞭影疾，風壯帆力迅。", "臯蘭拾秋芳，好寄南來信。"]'),
('7fb0b785-471d-4ae8-9bbb-28c297945020','九月一日侍老人遊洞霄宿超然館聞鐘','洪咨夔','宋','宋诗','song-poetry','','[]','太一相過燭未銷，朝元鐘動鬰羅蕭。',32,'全唐诗/poet.song.189000.json','["太一相過燭未銷，朝元鐘動鬰羅蕭。", "身輕不怕瓊臺滑，蹴踏青霞上斗杓。"]'),
('aadee59a-b9d5-4eb7-ba1a-ec6532c49016','翠蛟亭  其一','洪咨夔','宋','宋诗','song-poetry','','[]','壯杉耄檜護嵌空，飛墮蜿蜒白玉虹。',32,'全唐诗/poet.song.189000.json','["壯杉耄檜護嵌空，飛墮蜿蜒白玉虹。", "莫道隔凡元有柱，胡麻流出石矼東。"]'),
('e2c796bd-688d-401c-9e21-ae8749ae7220','翠蛟亭  其二','洪咨夔','宋','宋诗','song-poetry','','[]','晴雷碾破白雲窩，無數林華衮下坡。',32,'全唐诗/poet.song.189000.json','["晴雷碾破白雲窩，無數林華衮下坡。", "好把轆轤翻轉着，崑崙頂上卷黄河。"]'),
('1282c9f4-6354-42cc-876a-57e2f3e478a7','贈石室朱修行  其一','洪咨夔','宋','宋诗','song-poetry','','[]','響泉一派落天風，人在浮雲柳絮中。',32,'全唐诗/poet.song.189000.json','["響泉一派落天風，人在浮雲柳絮中。", "亭午柴關猶未啟，碧玲瓏底拒霜紅。"]'),
('1f7663e8-f961-463d-9337-1bd271fe1a5b','贈石室朱修行  其二','洪咨夔','宋','宋诗','song-poetry','','[]','落葉堆中折脚鐺，白雲煮盡又還生。',32,'全唐诗/poet.song.189000.json','["落葉堆中折脚鐺，白雲煮盡又還生。", "洞門黄鶴婆娑舞，留得松風待月明。"]'),
('74d6d6b7-e00e-47ea-aed3-333d52f41452','送趙處士遊方','洪咨夔','宋','宋诗','song-poetry','','[]','道家何荒唐，釋氏更汗漫。',108,'全唐诗/poet.song.189000.json','["道家何荒唐，釋氏更汗漫。", "君胡欲逃儒，結入楊墨案。", "時文窘枘鑿，俗好厭冰炭。", "起尋出頭路，去覓行脚飯。", "左携仙君茅，右挾佛祖粲。", "隨身絕長物，到處得奇觀。", "江山枯桐寫，風月老筆判。", "識透心轉空，養足骨自換。", "長生不可獨，分寄石髓半。"]'),
('a30ec59a-daf1-4ecc-8b13-e00f808cb116','何正言母安人挽詩','洪咨夔','宋','宋诗','song-poetry','','[]','鳳采生丹穴，螢光聚絳幃。',48,'全唐诗/poet.song.189000.json','["鳳采生丹穴，螢光聚絳幃。", "兩登黄甲去，一佩皂囊歸。", "萱老悲方切，蘭枯夢又非。", "青山秋寂歷，客淚不勝揮。"]'),
('69a03d0b-5199-4e6e-943c-6ef2e3985653','初釀','洪咨夔','宋','宋诗','song-poetry','','[]','手臼登新秫，頭缸試嫩醪。',48,'全唐诗/poet.song.189000.json','["手臼登新秫，頭缸試嫩醪。", "蒲城寒信早，栗里曠懷高。", "重熟魚沾麵，微生蟹带糟。", "老儂元不飲，隨喜亦陶陶。"]'),
('7c6e22b1-51be-4dab-b6bb-5249eaf4f6cc','贈前京東王制屬','洪咨夔','宋','宋诗','song-poetry','','[]','赤葉風欲盡，黄花霜未乾。',48,'全唐诗/poet.song.189000.json','["赤葉風欲盡，黄花霜未乾。", "病添予許老，窮迫子能寒。", "劍蝕蛟還吼，袍塵鶻尚盤。", "山東河北事，欲語淚汍瀾。"]'),
('c74e2a70-d38e-4a3d-bb83-702ea51c375e','翁媼行','洪咨夔','宋','宋诗','song-poetry','','[]','翁頭白如銀，媼頭黄如金。',60,'全唐诗/poet.song.189000.json','["翁頭白如銀，媼頭黄如金。", "抵足搔瘡昏到明，羞殺敗布多年衾。", "晴窗蟢子懸瀰瀰，翁媼相看顔色啟。", "門前人送撰碑錢，半贖冬衣半糴米。"]'),
('05be6635-fbb9-4b1c-bc03-a77d6cad8382','哭都城火','洪咨夔','宋','宋诗','song-poetry','','[]','九月丙戌夜未中，祝融漲焰通天紅。',128,'全唐诗/poet.song.189000.json','["九月丙戌夜未中，祝融漲焰通天紅。", "曾樓傑觀舞燧象，綺峰繡陌奔燭龍。", "始從李博士橋起，三面分風十五里。", "崩摧洶洶海潮翻，填咽紛紛釜魚死。", "開禧回祿前未聞，今更五分多二分。", "大塗小撤噤不講，拱手坐視連宵焚。", "殿前將軍猛如虎，救得汾陽令公府。", "祖宗神靈飛上天，痛哉九廟成焦土。"]'),
('74435162-dd45-4872-aab9-dc52e7c70534','仲冬二日還自谷川道中  其一','洪咨夔','宋','宋诗','song-poetry','','[]','晴烟杳靄似春山，疎柳啼鴉意度閑。',32,'全唐诗/poet.song.189000.json','["晴烟杳靄似春山，疎柳啼鴉意度閑。", "溪上麥田翻未遍，故遲牛带夕陽還。"]'),
('1aaacbfb-fb3a-4d19-b858-e34f2ecdebd1','仲冬二日還自谷川道中  其二','洪咨夔','宋','宋诗','song-poetry','','[]','滿天返照醉紅殷，未到生明月已彎。',32,'全唐诗/poet.song.189000.json','["滿天返照醉紅殷，未到生明月已彎。", "好是蛾眉無點恨，盈盈淡掃有無間。"]'),
('add886a8-a650-451d-ae82-41d13ec0eaf4','至節前十日遊勝因寺','洪咨夔','宋','宋诗','song-poetry','','[]','霜霽午曦暖，潦收沙路晞。',48,'全唐诗/poet.song.189000.json','["霜霽午曦暖，潦收沙路晞。", "束山知寺古，避客怪僧稀。", "籜滑涉危屐，藤鈎穿密衣。", "月黄風不動，燈火虹橋歸。"]'),
('c8da5e78-82d6-4a46-a6dc-d5f204b70791','謹次老人至節韵','洪咨夔','宋','宋诗','song-poetry','','[]','但見陰陽遞斡流，誰知陽本未嘗休。',64,'全唐诗/poet.song.189000.json','["但見陰陽遞斡流，誰知陽本未嘗休。", "善端繼繼無窮脈，元化生生不盡頭。", "杜牧浪將箱勸讀，少陵空爲線添愁。", "何如靜坐觀其復，一點靈臺造物遊。"]'),
('487efb57-dbd9-4c0d-9703-4efab05a7b6a','至節出謁回  其一','洪咨夔','宋','宋诗','song-poetry','','[]','一脈陽從地底回，人情物意便春臺。',32,'全唐诗/poet.song.189000.json','["一脈陽從地底回，人情物意便春臺。", "鮮衣稚子面紅醉，知向外家參節來。"]'),
('b29ea7bb-8ac9-4311-833f-99d1330bb7af','至節出謁回  其二','洪咨夔','宋','宋诗','song-poetry','','[]','巧笑聲摇六博盆，纖纖人在綠窗根。',32,'全唐诗/poet.song.189000.json','["巧笑聲摇六博盆，纖纖人在綠窗根。", "隔紗想見春風面，雲滑金釵欲溜痕。"]'),
('75d9f05a-86f9-4f60-854c-e1e4ccfff85b','病目','洪咨夔','宋','宋诗','song-poetry','','[]','日過學不力，年催名未芳。',48,'全唐诗/poet.song.189000.json','["日過學不力，年催名未芳。", "心期雖皦皦，目視已茫茫。", "燈疊青紅暈，書紛黑白行。", "蒲團深瞑坐，禪味覺偏長。"]'),
('d6037709-88f3-4b6e-8c98-879035610373','椒菊枕','洪咨夔','宋','宋诗','song-poetry','','[]','矮檠矻初年，細字窘晚節。',192,'全唐诗/poet.song.189000.json','["矮檠矻初年，細字窘晚節。", "天憐蠹書障，神授鴻寶訣。", "金葩凉而嚴，丹寶溫以烈。", "兩囊貯風露，半簪藉霜雪。", "芬透頂𩕳爽，清祛腦脂熱。", "夢魂寥廓遠，宇觀沆瀣澈。", "雲開月更朗，電掣巖欲裂。", "術妙刮膜金，功過刳蟆鐵。", "聱牙讀楚詛，瑣尾窺越絕。", "不憂幻景侵，且喜翳根滅。", "頌花醉春溫，餐英飽秋潔。", "塗屋兆蕃碩，飲潭進耆耋。", "况茲芳澤聚，盡洗空華結。", "夜氣存虛明，天光發昭晰。", "須彌能微塵，渤澥或丘垤。", "不直一笑粲，已判雙眥决。"]'),
('919ba468-3856-4c1f-b57e-aa04e44b56f4','俞提舉挽詩  其一','洪咨夔','宋','宋诗','song-poetry','','[]','展也萬夫特，翛然山澤臞。',48,'全唐诗/poet.song.189000.json','["展也萬夫特，翛然山澤臞。", "朔風空汴泗，春水渺淮湖。", "籌驛尹師魯，詩壇梅聖俞。", "繡衣歸老去，有韞不輕沽。"]'),
('3727e2a3-ec09-4946-b214-875ff8732055','俞提舉挽詩  其二','洪咨夔','宋','宋诗','song-poetry','','[]','蒼鶴孤山曉，黄花栗里秋。',48,'全唐诗/poet.song.189000.json','["蒼鶴孤山曉，黄花栗里秋。", "一身雖物外，萬國尚眉頭。", "遺老幾何在，耆英只麽休。", "問天天不語，江闊莫雲愁。"]'),
('643a8369-be18-4162-ba7f-05fd8f6438f7','奚知縣挽詩','洪咨夔','宋','宋诗','song-poetry','','[]','敏銳霹靂手，寬平雲夢胸。',48,'全唐诗/poet.song.189000.json','["敏銳霹靂手，寬平雲夢胸。", "雄臺高幕畫，劇邑富民庸。", "帆掛風方駃，戈揮日又舂。", "炊粱剪春韭，無復奉從容。"]'),
('4f975758-713a-4c93-8272-d66f066c5a08','臈中步月  其一','洪咨夔','宋','宋诗','song-poetry','','[]','平山堂下解圍去，天水堡前經戰來。',32,'全唐诗/poet.song.189000.json','["平山堂下解圍去，天水堡前經戰來。", "天地無情一般月，照人霜骨白皚皚。"]'),
('5a9ad59c-6fd8-445b-9573-5d194ac72a9e','臈中步月  其二','洪咨夔','宋','宋诗','song-poetry','','[]','賣妻鬻子年饑後，索母求爺賊亂餘。',32,'全唐诗/poet.song.189000.json','["賣妻鬻子年饑後，索母求爺賊亂餘。", "對月椎胸幾家哭，更堪蕭索歲將除。"]'),
('9f81303b-f1b4-40d2-9e69-dcad615f3273','何正言挽詩','洪咨夔','宋','宋诗','song-poetry','','[]','雋手芥拾紫，忠肝蒲伏青。',48,'全唐诗/poet.song.189000.json','["雋手芥拾紫，忠肝蒲伏青。", "嬰龍雲氣直，縛虎雪毛腥。", "炊枕夢何短，書棺名更馨。", "眇然人物幾，墓草涕交零。"]'),
('c0ac7071-3e7f-46d2-bf52-97791c415cec','謹和老人惠山泉  其一','洪咨夔','宋','宋诗','song-poetry','','[]','取水驛符到，喊山旗信通。',48,'全唐诗/poet.song.189000.json','["取水驛符到，喊山旗信通。", "碾分花底月，爐受竹間風。", "金谷正覓醉，玉川誰道窮。", "頂門甘露入，喚醒主人公。"]'),
('67cb5b72-cb0d-4c7a-b05c-a6fa79e58a37','謹和老人惠山泉  其二','洪咨夔','宋','宋诗','song-poetry','','[]','第二水泉動，斜三封印通。',48,'全唐诗/poet.song.189000.json','["第二水泉動，斜三封印通。", "愛奇親煮雪，得雋細生風。", "酒肺蘇將渴，詩情洗盡窮。", "娉婷須好買，供奉讀書公。"]'),
('ea9e4559-2513-49a3-9574-26b02e809161','歲暮山中紀事  其一','洪咨夔','宋','宋诗','song-poetry','','[]','南山大小空，橫行無常時。',48,'全唐诗/poet.song.189000.json','["南山大小空，橫行無常時。", "蓄狗豢豕盡，澤吻樵牧兒。", "翁嫗起譟逐，妥尾行愈遲。", "力窮哭且駡，天網不汝遺。"]'),
('c8437bad-e59c-41c9-994f-d41961f7d599','歲暮山中紀事  其二','洪咨夔','宋','宋诗','song-poetry','','[]','里巷負暄翁，隤然支離疏。',48,'全唐诗/poet.song.189000.json','["里巷負暄翁，隤然支離疏。", "饕虱緣縕袍，點綴頷下須。", "旁人勸翁捫，摇手一任渠。", "虱多轉不癢，何庸事驅除。"]'),
('ad58d455-90b7-4ddd-80f1-d3facff3d049','歲暮山中紀事  其三','洪咨夔','宋','宋诗','song-poetry','','[]','鄉風臘廿五，比戶然爆竹。',48,'全唐诗/poet.song.189000.json','["鄉風臘廿五，比戶然爆竹。", "窮陰挾黄昏，霹靂起空屋。", "梁間鬼拍手，笑人未免俗。", "罔兩白晝行，渠爾一爆逐。"]'),
('2f4ec4a9-f1cc-4d57-bfec-94c31189f382','除夜','洪咨夔','宋','宋诗','song-poetry','','[]','市兒數十百，挾炬相追奔。',72,'全唐诗/poet.song.189000.json','["市兒數十百，挾炬相追奔。", "爭唱賣獃歌，祈以昭易惛。", "我獃大如屋，幾臘擁敗垣。", "群雛勸我賣，急售價莫論。", "弄巧或成拙，太清不如渾。", "老鐵無孔鎚，甘守鈍性根。"]'),
('2f6f33d9-4249-4ba2-8ba9-b09120644517','新年','洪咨夔','宋','宋诗','song-poetry','','[]','欲識新年課，都非舊日圖。',48,'全唐诗/poet.song.189000.json','["欲識新年課，都非舊日圖。", "詞分詩料帳，酒奪飯工夫。", "鍛息柳邊手，鑷閑花裏鬚。", "寒消芳草綠，打急辦行厨。"]'),
('9645e7aa-fadd-4edc-9ec8-31417edbd7a7','謹和老人欲還故廬','洪咨夔','宋','宋诗','song-poetry','','[]','颼颼破屋小青裯，客枕頻年寄道周。',64,'全唐诗/poet.song.189000.json','["颼颼破屋小青裯，客枕頻年寄道周。", "行止非人真可笑，窮通有命尚何愁。", "春風舊壘雙飛燕，宿雨新巢百拙鳩。", "信是還家貧亦好，德人何處不天遊。"]'),
('ec2ad1ec-2e15-4202-ab25-47fcb9c19646','謹和老人春行','洪咨夔','宋','宋诗','song-poetry','','[]','抗疏明時效伏伽，一歸七度試春紗。',64,'全唐诗/poet.song.189000.json','["抗疏明時效伏伽，一歸七度試春紗。", "柔風綠遍庭前草，細雨紅催陌上花。", "惠遠買來猶濁酒，趙州喫去只粗茶。", "回頭恰恰鶑啼處，黄四娘今尚有家。"]'),
('f1980054-6d79-4f6d-b8e9-326c018ea381','又塔院','洪咨夔','宋','宋诗','song-poetry','','[]','僧伽傳法處，阿育放光時。',48,'全唐诗/poet.song.189000.json','["僧伽傳法處，阿育放光時。", "到頂直無縫，透心橫有枝。", "梅間詩鳳咮，竹裏酒鴟夷。", "醉上危層去，空明渺所思。"]'),
('5a7f6125-e7d1-4c92-b767-1da83b597c92','燈夕獨酌  其一','洪咨夔','宋','宋诗','song-poetry','','[]','鈿車羅帕禁街夜，珂傘炬城沙路春。',32,'全唐诗/poet.song.189000.json','["鈿車羅帕禁街夜，珂傘炬城沙路春。", "少不自强今老矣，落梅風暖酒生鱗。"]'),
('26d5efd4-27a2-4a36-8192-dbd51606d534','燈夕獨酌  其二','洪咨夔','宋','宋诗','song-poetry','','[]','海濤風定柳枝曲，江檝波明桃葉歌。',32,'全唐诗/poet.song.189000.json','["海濤風定柳枝曲，江檝波明桃葉歌。", "剪燭停盃聽宛轉，不妨白雪映青蛾。"]'),
('67abe9c1-3c24-4199-beba-e6ec18c1ce08','送游考功將漕夔門  其一','洪咨夔','宋','宋诗','song-poetry','','[]','溫公一傳諫議劉，菊坡一傳吏部游。',32,'全唐诗/poet.song.189000.json','["溫公一傳諫議劉，菊坡一傳吏部游。", "長庚伴月天欲曉，西照太白南羅浮。"]'),
('74abe650-3d3e-4522-8c95-b13be0f2413b','送游考功將漕夔門  其二','洪咨夔','宋','宋诗','song-poetry','','[]','神鼎一鑄魑魅怖，法鼓四震波旬悲。',32,'全唐诗/poet.song.189000.json','["神鼎一鑄魑魅怖，法鼓四震波旬悲。", "祖宗涵養天下氣，留得此脈扶顛危。"]'),
('a3fafa9f-e624-4775-8773-173835f8f98c','送游考功將漕夔門  其三','洪咨夔','宋','宋诗','song-poetry','','[]','欲鳴不鳴銜口馬，欲去不去羸角羝。',32,'全唐诗/poet.song.189000.json','["欲鳴不鳴銜口馬，欲去不去羸角羝。", "排天絕叫河漢裂，隻舸飛上岷江西。"]'),
('38f33db0-fd15-49fb-9058-437ad4be6c26','送游考功將漕夔門  其四','洪咨夔','宋','宋诗','song-poetry','','[]','古來刀鋸鼎鑊具，用待誹謗妖言人。',32,'全唐诗/poet.song.189000.json','["古來刀鋸鼎鑊具，用待誹謗妖言人。", "掁觸不怒予節去，惟天爲大知堯仁。"]'),
('9fb6c8ab-ac30-45bd-962f-dc29b3c1f588','送游考功將漕夔門  其五','洪咨夔','宋','宋诗','song-poetry','','[]','金湯棄去七百里，珠玉走盡六十州。',32,'全唐诗/poet.song.189000.json','["金湯棄去七百里，珠玉走盡六十州。", "誰生厲階不可問，桔柏江上風颼飀。"]'),
('b5863209-6799-47b9-a6c9-b83a1be4b57d','送游考功將漕夔門  其六','洪咨夔','宋','宋诗','song-poetry','','[]','燒畬瀼外竹枝瘦，踏磧灘上桃花肥。',32,'全唐诗/poet.song.189000.json','["燒畬瀼外竹枝瘦，踏磧灘上桃花肥。", "繡衣故鄉豈不好，爲天下計毋庸歸。"]'),
('f6ae9e2c-ede5-4c0c-8368-10a9113aa9aa','送游考功將漕夔門  其七','洪咨夔','宋','宋诗','song-poetry','','[]','四肢誰謂可無骨，五臟自信難留寒。',32,'全唐诗/poet.song.189000.json','["四肢誰謂可無骨，五臟自信難留寒。", "跂予望之不得語，但願萬里書平安。"]'),
('b0ada143-e73e-405f-96b1-cbe90f11a2bc','正月二十四日早夢乞聰明於東坡','洪咨夔','宋','宋诗','song-poetry','','[]','東來一舸橫天上，御風而行無點浪。',64,'全唐诗/poet.song.189000.json','["東來一舸橫天上，御風而行無點浪。", "有人野服帽高簷，宛如赤壁圖中樣。", "舉手疾聲呼先生，爲我心孔開聰明。", "輾然一笑若相語，乞得聰明不如魯。"]'),
('e945fe3b-d249-41cd-9054-5322a93fe131','老人晚得女真真又曾孫女金華皆再周而殤葬塔院後今春焚化用前韵賦詩謹和','洪咨夔','宋','宋诗','song-poetry','','[]','窣波影裏誦陀伽，古佛燈籠護絳紗。',64,'全唐诗/poet.song.189000.json','["窣波影裏誦陀伽，古佛燈籠護絳紗。", "智慧竭羅雖正果，慈悲妙善亦空花。", "怕寒婉孌初拳蕨，望雨醒鬆細舌茶。", "節物感人還自解，有兒何用女當家。"]'),
('712a4493-41c6-4744-a6dd-ca702a67c4d8','送澄維那訪舊湖山','洪咨夔','宋','宋诗','song-poetry','','[]','梅子酸猶淺，桃花豔已饒。',48,'全唐诗/poet.song.189000.json','["梅子酸猶淺，桃花豔已饒。", "春風開口吸，明月換肩挑。", "鶴向平湖放，猿從古洞招。", "出門天地闊，何處不逍遥。"]'),
('1bb12454-4216-43b0-a329-526ce971f7b8','葉主簿挽詩','洪咨夔','宋','宋诗','song-poetry','','[]','生理鴟夷子，心期桑苧翁。',48,'全唐诗/poet.song.189000.json','["生理鴟夷子，心期桑苧翁。", "行厨脩竹月，坐艦落花風。", "雛好纔孤鳳，行疎忽斷鴻。", "吳松明遠目，一點夕陽紅。"]'),
('d71bdad1-d51d-4b72-acf0-0b5bdc22e7ca','謹和老人古硯韵','洪咨夔','宋','宋诗','song-poetry','','[]','破壞憨僧衲，凹欹漫叟漥。',48,'全唐诗/poet.song.189000.json','["破壞憨僧衲，凹欹漫叟漥。", "吐雲頭縮蜃，啖月口呿蟆。", "宮㜮愁難捧，堂胥怒可撾。", "莫貪濡筆利，浪草侍中麻。"]'),
('29df1cef-825a-4d85-99c5-2570b68b6466','路逢徽州送牡丹入都','洪咨夔','宋','宋诗','song-poetry','','[]','飛絮遊絲弄霽華，出門芳草渺天涯。',32,'全唐诗/poet.song.189000.json','["飛絮遊絲弄霽華，出門芳草渺天涯。", "太平莫道全無象，脫繡鳴鈴傳送花。"]'),
('58494a4a-c226-4180-bd09-528cc8ba757b','首夏一絕示徐錦囊','洪咨夔','宋','宋诗','song-poetry','','[]','金丸未熟櫻桃過，錦幄俱空芍藥來。',32,'全唐诗/poet.song.189000.json','["金丸未熟櫻桃過，錦幄俱空芍藥來。", "共坐晚凉觀物化，床頭有酒爲君開。"]'),
('4ce7a108-f4aa-400c-8541-48aa8f74cfe4','答王仲鈞  其一','洪咨夔','宋','宋诗','song-poetry','','[]','無言安止止，不動妙如如。',48,'全唐诗/poet.song.189000.json','["無言安止止，不動妙如如。", "暴虎未聞道，汗牛空讀書。", "赤窮遑恤後，白坐且求初。", "寂歷野花晚，嫣然風雨餘。"]'),
('838e78f4-2eac-4f1a-ab47-1c86e6ec9541','答王仲鈞  其二','洪咨夔','宋','宋诗','song-poetry','','[]','老鏡風霜飽，離觴歲月悠。',48,'全唐诗/poet.song.189000.json','["老鏡風霜飽，離觴歲月悠。", "曲多傳郢水，詩亦到蘇州。", "拽轉撩天鼻，抽將閙市頭。", "投林毋用急，時至會封侯。"]'),
('410ad59b-cc2f-4e3a-8948-c81a979880bd','次子有下第韵','洪咨夔','宋','宋诗','song-poetry','','[]','東風換骨立成僊，五色終迷自古然。',64,'全唐诗/poet.song.189000.json','["東風換骨立成僊，五色終迷自古然。", "龍變未符今舉讖，鶴來當驗後科緣。", "情如中酒宜親酒，命合腰錢會有錢。", "許買娉婷供老伴，不妨遲得兩三年。"]'),
('c92f3ae3-f80c-4257-9a43-c1066f534b75','答駱肖秦','洪咨夔','宋','宋诗','song-poetry','','[]','過我葵榴巷，留君筍薤厨。',48,'全唐诗/poet.song.189000.json','["過我葵榴巷，留君筍薤厨。", "襟懷新雨快，面目故山癯。", "自笑孤飛鶴，誰憐返哺烏。", "未應埋沒得，囊有萬驪珠。"]'),
('a0d9a750-62d5-48dd-b72c-12177748a33c','初夏即事一首謝俞德遠惠茶','洪咨夔','宋','宋诗','song-poetry','','[]','病眼昏花懶讀書，閉門恬養冉溪愚。',64,'全唐诗/poet.song.189000.json','["病眼昏花懶讀書，閉門恬養冉溪愚。", "一簾草色蛤呼伴，四壁樹陰雞護雛。", "已是歸來何用引，本無太極不須圖。", "小團自汲新泉試，凉滿松風石銚爐。"]'),
('266e7da1-9eb3-4a17-af4a-c9a43da7ccc8','重午山蹊獨步','洪咨夔','宋','宋诗','song-poetry','','[]','扶病索清蔭，循林步幽霏。',96,'全唐诗/poet.song.189000.json','["扶病索清蔭，循林步幽霏。", "花拈勃姑飯，草拾蝦蟆衣。", "良藥觸手是，壯容轉頭非。", "易補天上漏，難駐人間暉。", "寒暑遞流斡，悲樂相因依。", "功名少終吉，富貴多危機。", "李泌語欲咽，屈平志空違。", "不如滿引酒，舉世知我希。"]'),
('eba3b6f3-1f53-4394-954f-deeb6fdc0666','觀物  其一','洪咨夔','宋','宋诗','song-poetry','','[]','飽飯茶甌罷，閑觀萬物情。',48,'全唐诗/poet.song.189000.json','["飽飯茶甌罷，閑觀萬物情。", "狗加獅立號，貓冒虎爲名。", "故沼慈姑王，新畦腐婢榮。", "蟬從何許變，忽送出林聲。"]'),
('37293604-d547-4625-94ec-e304fd79bf82','觀物  其二','洪咨夔','宋','宋诗','song-poetry','','[]','薄命天元定，深居日轉長。',48,'全唐诗/poet.song.189000.json','["薄命天元定，深居日轉長。", "塔鈴空洛度，車鐸慣琅璫。", "筍長竹還老，蓮遲荷自香。", "羨他雛又乳，雙燕勝春忙。"]'),
('a3c60b15-e42a-4be9-8128-03b790ec0818','抹利','洪咨夔','宋','宋诗','song-poetry','','[]','翡翠簾帷雪透肌，纖風不動閙香吹。',32,'全唐诗/poet.song.189000.json','["翡翠簾帷雪透肌，纖風不動閙香吹。", "裴回顧影精神發，省得京華識面時。"]'),
('a4e9d063-cb03-42ce-9995-6678859ef90f','晚蓮','洪咨夔','宋','宋诗','song-poetry','','[]','颯然秋入井梧嘶，窗下紅蕖始脫泥。',64,'全唐诗/poet.song.189000.json','["颯然秋入井梧嘶，窗下紅蕖始脫泥。", "但有意開何論晚，縱無力上不嫌低。", "魚貪芳影機還熟，蝶怕深香路自迷。", "更把閑情堅耐着，明年花與屋簷齊。"]'),
('f5fd52a3-b99b-4122-a652-a25d5a1aba56','凉月  其一','洪咨夔','宋','宋诗','song-poetry','','[]','蓮房折盡只留荷，露蓋班班一丈過。',32,'全唐诗/poet.song.189000.json','["蓮房折盡只留荷，露蓋班班一丈過。", "高下橫斜無定影，聚凉着得月明多。"]'),
('c3e7d201-4268-4d08-8306-02482f7c83c7','凉月  其二','洪咨夔','宋','宋诗','song-poetry','','[]','金粟安排雨後黄，定知花亦愛新凉。',32,'全唐诗/poet.song.189000.json','["金粟安排雨後黄，定知花亦愛新凉。", "夜深月透玲瓏影，花自光明月自香。"]'),
('3619472d-58be-4201-af7e-6ed419118be7','挽阮倅','洪咨夔','宋','宋诗','song-poetry','','[]','膠庠推博洽，州縣著廉平。',48,'全唐诗/poet.song.189000.json','["膠庠推博洽，州縣著廉平。", "人物萬夫特，山川千古英。", "虬髯橫意氣，猿臂鬰功名。", "一掬同年淚，西風浩蕩情。"]'),
('b74e65fc-9bf2-4973-bc22-910983a506fe','挽李丞','洪咨夔','宋','宋诗','song-poetry','','[]','篤敬古君子，公平賢大夫。',48,'全唐诗/poet.song.189000.json','["篤敬古君子，公平賢大夫。", "筆端知已有，券外得心無。", "落日摇牆竹，淒風墮井梧。", "蓄深施不盡，留與讀書符。"]'),
('077b6e62-f7f9-4da5-a641-d3c3efce94f1','和子有催歸','洪咨夔','宋','宋诗','song-poetry','','[]','卜廬必擇地，買鄰不論金。',120,'全唐诗/poet.song.189000.json','["卜廬必擇地，買鄰不論金。", "出機與入機，去心即來心。", "拗性臨川翁，罷相老境侵。", "霜竹鍾山寺，雅寄金玉音。", "强項峨眉僊，渡海憂患深。", "𥝧稏陽羨田，歡言飽甘霖。", "故山月在眼，客屋風滿襟。", "欲歸欠生業，隨寓如家林。", "覓榿適閑趣，借竹供清吟。", "俛仰一逆旅，乾坤古猶今。"]'),
('6cd94168-7043-414e-8910-48eb3c7bb3f5','謹和老人蓮桂  其一','洪咨夔','宋','宋诗','song-poetry','','[]','點破秋光數葉荷，水清時見小魚過。',32,'全唐诗/poet.song.189000.json','["點破秋光數葉荷，水清時見小魚過。", "渟涵風露三更足，收拾江湖萬頃多。"]'),
('e0a536af-3e33-418d-a038-7c80d61e4379','謹和老人蓮桂  其二','洪咨夔','宋','宋诗','song-poetry','','[]','搗成一百八丸黄，入手能令熱惱凉。',32,'全唐诗/poet.song.189000.json','["搗成一百八丸黄，入手能令熱惱凉。", "金粟如來身已化，蕊珠僊子骨猶香。"]'),
('c6493153-edad-4079-bfc1-78f6afc7c625','移居西郭重樓','洪咨夔','宋','宋诗','song-poetry','','[]','欲歸未辦買山資，東寄西存漫一枝。',64,'全唐诗/poet.song.189000.json','["欲歸未辦買山資，東寄西存漫一枝。", "樓上起樓渠自巧，客中作客我何癡。", "崎嶇溪步通虛市，鬰屈山蹊護短籬。", "不用子猷親種竹，屋頭元有綠猗猗。"]'),
('b0d87828-cba7-4547-98b3-70e25bf32ce5','自和','洪咨夔','宋','宋诗','song-poetry','','[]','得寮便住似西資，誰暇安巢更擇枝。',64,'全唐诗/poet.song.189000.json','["得寮便住似西資，誰暇安巢更擇枝。", "閤密不妨中酒聖，樓明大好養書癡。", "誌公分料存刀尺，龐老家風欠笊籬。", "大厦千間宵八尺，傍人莫笑太窮猗。"]'),
('0278cdcd-1b8c-4181-b433-facd06ab225c','小雪前三日鍾冠之約余侍老人行山舟發後洪入杜塢自鄭蓋庵過閬山趨翔鳳山菁山徧覽楊墳秀園遂至何山道場山乘興薄吳興訪玉湖書院水晶境界而歸自戊子至庚子陰晴相半勝處輒徘徊賦詩飲酒偉哉觀也數詩見後 長橋渡','洪咨夔','宋','宋诗','song-poetry','','[]','溪流轉處兩三家，落落疎林淺淺沙。',32,'全唐诗/poet.song.189000.json','["溪流轉處兩三家，落落疎林淺淺沙。", "可是小春風物早，檐頭一束杜鵑花。"]'),
('a1bfa278-5798-4ed4-876e-229b6df66222','小雪前三日鍾冠之約余侍老人行山舟發後洪入杜塢自鄭蓋庵過閬山趨翔鳳山菁山徧覽楊墳秀園遂至何山道場山乘興薄吳興訪玉湖書院水晶境界而歸自戊子至庚子陰晴相半勝處輒徘徊賦詩飲酒偉哉觀也數詩見後 閬山妙嚴院松月堂讀張汪二公詩有感用無垢韵','洪咨夔','宋','宋诗','song-poetry','','[]','止水攪不動，好山邀輒來。',24,'全唐诗/poet.song.189000.json','["止水攪不動，好山邀輒來。", "松間寒月晚，似欠兩翁催。"]'),
('8c4d3511-c8a4-46ea-b85f-c9cc67f0a316','小雪前三日鍾冠之約余侍老人行山舟發後洪入杜塢自鄭蓋庵過閬山趨翔鳳山菁山徧覽楊墳秀園遂至何山道場山乘興薄吳興訪玉湖書院水晶境界而歸自戊子至庚子陰晴相半勝處輒徘徊賦詩飲酒偉哉觀也數詩見後 宿妙勝閣 其一','洪咨夔','宋','宋诗','song-poetry','','[]','鈎輈格磔鳥呼晚，勃窣媻姍人試寒。',32,'全唐诗/poet.song.189000.json','["鈎輈格磔鳥呼晚，勃窣媻姍人試寒。", "野水不流山四合，寶華雲裏着欄干。"]'),
('ef25197b-cd06-4c2e-974b-349189662c62','小雪前三日鍾冠之約余侍老人行山舟發後洪入杜塢自鄭蓋庵過閬山趨翔鳳山菁山徧覽楊墳秀園遂至何山道場山乘興薄吳興訪玉湖書院水晶境界而歸自戊子至庚子陰晴相半勝處輒徘徊賦詩飲酒偉哉觀也數詩見後 宿妙勝閣 其二','洪咨夔','宋','宋诗','song-poetry','','[]','一徑白雲明似雪，滿山紅葉豔於花。',32,'全唐诗/poet.song.189000.json','["一徑白雲明似雪，滿山紅葉豔於花。", "過溪買酒等閑事，只恐客來非當家。"]'),
('d0da4f86-c1c1-4e3c-a41b-ca1ccc036ef0','小雪前三日鍾冠之約余侍老人行山舟發後洪入杜塢自鄭蓋庵過閬山趨翔鳳山菁山徧覽楊墳秀園遂至何山道場山乘興薄吳興訪玉湖書院水晶境界而歸自戊子至庚子陰晴相半勝處輒徘徊賦詩飲酒偉哉觀也數詩見後 出閬山','洪咨夔','宋','宋诗','song-poetry','','[]','無雨又無日，此行天相之。',48,'全唐诗/poet.song.189000.json','["無雨又無日，此行天相之。", "荒園遺木老，古隧得峰奇。", "霜晚蔬猶劍，風溫茗已旗。", "行厨何用許，勝處可忘饑。"]'),
('ccaefa9f-8a9f-46a7-a19a-ff121edab2d7','小雪前三日鍾冠之約余侍老人行山舟發後洪入杜塢自鄭蓋庵過閬山趨翔鳳山菁山徧覽楊墳秀園遂至何山道場山乘興薄吳興訪玉湖書院水晶境界而歸自戊子至庚子陰晴相半勝處輒徘徊賦詩飲酒偉哉觀也數詩見後 謹和老人鳳口遇雨','洪咨夔','宋','宋诗','song-poetry','','[]','狂暖釀成雨，逆風摇斷橈。',48,'全唐诗/poet.song.189000.json','["狂暖釀成雨，逆風摇斷橈。", "寂談王舍衛，悶想鬰臺蕭。", "遊興孤芒屩，歸期數翠翹。", "推篷占霽色，木末散聲招。"]'),
('d110f4a7-47c6-4a50-a081-6f518cce1876','小雪前三日鍾冠之約余侍老人行山舟發後洪入杜塢自鄭蓋庵過閬山趨翔鳳山菁山徧覽楊墳秀園遂至何山道場山乘興薄吳興訪玉湖書院水晶境界而歸自戊子至庚子陰晴相半勝處輒徘徊賦詩飲酒偉哉觀也數詩見後 翔鳳山資福寺','洪咨夔','宋','宋诗','song-poetry','','[]','聽雨客無寐，放晴山有靈。',48,'全唐诗/poet.song.189000.json','["聽雨客無寐，放晴山有靈。", "禪關深紫翠，勳廟肅丹青。", "鼇負摩雲碣，龍扶拱日屏。", "真如無盡意，石澗水泠泠。"]'),
('5a23c52d-7569-4958-8c32-4ca2538b55fc','小雪前三日鍾冠之約余侍老人行山舟發後洪入杜塢自鄭蓋庵過閬山趨翔鳳山菁山徧覽楊墳秀園遂至何山道場山乘興薄吳興訪玉湖書院水晶境界而歸自戊子至庚子陰晴相半勝處輒徘徊賦詩飲酒偉哉觀也數詩見後 宿資福小閣次梁間韵 其一','洪咨夔','宋','宋诗','song-poetry','','[]','古木陰陰兀老蒼，月於疎處弄昏黄。',32,'全唐诗/poet.song.189000.json','["古木陰陰兀老蒼，月於疎處弄昏黄。", "巡簷不見梅花面，認得東風句子香。"]'),
('985b254d-4185-4a00-9b0d-8e13e5b6fe04','小雪前三日鍾冠之約余侍老人行山舟發後洪入杜塢自鄭蓋庵過閬山趨翔鳳山菁山徧覽楊墳秀園遂至何山道場山乘興薄吳興訪玉湖書院水晶境界而歸自戊子至庚子陰晴相半勝處輒徘徊賦詩飲酒偉哉觀也數詩見後 宿資福小閣次梁間韵 其二','洪咨夔','宋','宋诗','song-poetry','','[]','小窗無欠亦無餘，一榻翛然雪透膚。',32,'全唐诗/poet.song.189000.json','["小窗無欠亦無餘，一榻翛然雪透膚。", "收拾故書藏恰好，怕人寫入鳳山圖。"]'),
('93ec5e93-2316-4605-aafa-29b92d0dc874','小雪前三日鍾冠之約余侍老人行山舟發後洪入杜塢自鄭蓋庵過閬山趨翔鳳山菁山徧覽楊墳秀園遂至何山道場山乘興薄吳興訪玉湖書院水晶境界而歸自戊子至庚子陰晴相半勝處輒徘徊賦詩飲酒偉哉觀也數詩見後 楊墳','洪咨夔','宋','宋诗','song-poetry','','[]','生前圖形燿凌煙，死後起冢高祁連。',64,'全唐诗/poet.song.189000.json','["生前圖形燿凌煙，死後起冢高祁連。", "垛樓陰合蒼官立，輦路苔生石翁泣。", "吳人最重十月朝，紙錢掛冢風飄飄。", "積金至斗命可買，玉带貂冠鎮長在。"]'),
('b9ae193e-f197-4b42-ab8f-189c2971e970','小雪前三日鍾冠之約余侍老人行山舟發後洪入杜塢自鄭蓋庵過閬山趨翔鳳山菁山徧覽楊墳秀園遂至何山道場山乘興薄吳興訪玉湖書院水晶境界而歸自戊子至庚子陰晴相半勝處輒徘徊賦詩飲酒偉哉觀也數詩見後 何山書堂','洪咨夔','宋','宋诗','song-poetry','','[]','日高裹飯看何山，山缺東南水遶關。',32,'全唐诗/poet.song.189000.json','["日高裹飯看何山，山缺東南水遶關。", "松檜不摇風自度，讀書聲在白雲間。"]'),
('3dd3449b-eda6-44a4-8b99-ffdcb8506762','小雪前三日鍾冠之約余侍老人行山舟發後洪入杜塢自鄭蓋庵過閬山趨翔鳳山菁山徧覽楊墳秀園遂至何山道場山乘興薄吳興訪玉湖書院水晶境界而歸自戊子至庚子陰晴相半勝處輒徘徊賦詩飲酒偉哉觀也數詩見後 道場山','洪咨夔','宋','宋诗','song-poetry','','[]','何山如幽人，道場如大家。',264,'全唐诗/poet.song.189000.json','["何山如幽人，道場如大家。", "穰穰衲子脚，剌剌騷翁牙。", "挾雋控寒飈，搜光躡晨霞。", "危顛矯窣堵，平疇畧汙邪。", "巖泉跑虎湧，徑松髯龍拏。", "鍾梵破深寂，金碧開紛葩。", "脩廊步屐峻，傑閣望眼賒。", "山勢珮玦矗，湖光鏡奩谺。", "清苕杳靄入，古弁空濛遮。", "列翠不可唾，群籟無敢譁。", "坐我旃檀林，酌之槍旗茶。", "宇定岫出雲，語妙天雨華。", "吾生久墮甑，昔遊慣乘槎。", "夷猶廬阜陽，宿留岷江涯。", "高曾凌嶠棧，卑或搜崖漥。", "昨夢難歷省，此行足雄誇。", "老親八十健，閑儔二三嘉。", "拍浮一葉眇，收攬萬景奢。", "富貴上蔡犬，貧賤東陵瓜。", "未須笑落鐸，誰能苦觰沙。", "候門占噪鵲，旋橈趁歸鴉。", "奇事恐沒沒，舉詩屬僧伽。"]'),
('cd8d12a6-32b3-493c-8681-07e88f132cbb','小雪前三日鍾冠之約余侍老人行山舟發後洪入杜塢自鄭蓋庵過閬山趨翔鳳山菁山徧覽楊墳秀園遂至何山道場山乘興薄吳興訪玉湖書院水晶境界而歸自戊子至庚子陰晴相半勝處輒徘徊賦詩飲酒偉哉觀也數詩見後 玉湖書院懷二倪','洪咨夔','宋','宋诗','song-poetry','','["\u592a\u6e56"]','苕霅趍太湖，地少天宇寬。',72,'全唐诗/poet.song.189000.json','["苕霅趍太湖，地少天宇寬。", "高低寶樓閣，盛之水晶盤。", "中有讀書廬，八窗頫晴瀾。", "衡弁儼相望，不受湖光吞。", "彼美金玉人，伊吾斗闌干。", "騎鯨渺何許，衰柳風露寒。"]'),
('3b15e604-372a-44b0-857c-67cfbbe696f4','小雪前三日鍾冠之約余侍老人行山舟發後洪入杜塢自鄭蓋庵過閬山趨翔鳳山菁山徧覽楊墳秀園遂至何山道場山乘興薄吳興訪玉湖書院水晶境界而歸自戊子至庚子陰晴相半勝處輒徘徊賦詩飲酒偉哉觀也數詩見後 葉推官無盡景','洪咨夔','宋','宋诗','song-poetry','','[]','繫舡官柳根，闤闠得深密。',48,'全唐诗/poet.song.189000.json','["繫舡官柳根，闤闠得深密。", "日落遠水明，雲收好山出。", "天開有聲畫，人立無價璧。", "酒行不須多，鷺下菰蒲夕。"]'),
('1f7a7125-05df-4c7c-a8f8-f13411544cb6','梅  其一','洪咨夔','宋','宋诗','song-poetry','','[]','風霜摇落都盧盡，一點春回造化家。',32,'全唐诗/poet.song.189000.json','["風霜摇落都盧盡，一點春回造化家。", "萬物成終又成始，須將艮體看梅花。"]'),
('80e9aa08-481f-4989-8e1a-7ff779d88c5e','梅  其二','洪咨夔','宋','宋诗','song-poetry','','[]','寒根不與物俱陳，髁髁梢頭寂寂春。',32,'全唐诗/poet.song.189000.json','["寒根不與物俱陳，髁髁梢頭寂寂春。", "却月凌風誰會得，不沾一葉是真身。"]'),
('a7e89ec8-b8e0-41a2-b0be-5468ede62624','和樓前梅  其一','洪咨夔','宋','宋诗','song-poetry','','[]','飛香漲艷拍簷牙，暖熱樓居鄂陸家。',32,'全唐诗/poet.song.189000.json','["飛香漲艷拍簷牙，暖熱樓居鄂陸家。", "寶髻盤鴉冰柱曉，倚闌平折北梢花。"]'),
('1f0209e4-b124-476e-8d59-c3f25b9483e0','和樓前梅  其二','洪咨夔','宋','宋诗','song-poetry','','[]','樓高夜靜月華陳，冷浸含章一段春。',32,'全唐诗/poet.song.189000.json','["樓高夜靜月華陳，冷浸含章一段春。", "人影花光相上下，定知梅亦解分身。"]'),
('e71149f2-8bb4-48a4-bb99-fa248aac5c8c','送李致遠安遠簿  其一','洪咨夔','宋','宋诗','song-poetry','','[]','四海幾青眼，五車今白頭。',48,'全唐诗/poet.song.189000.json','["四海幾青眼，五車今白頭。", "信天投矮屋，覓地起岑樓。", "山迥風煙合，江平潦霧收。", "誰歟人物計，留取備枚鄒。"]'),
('75e82c19-b834-49b5-a6f5-e0e12021e68c','送李致遠安遠簿  其二','洪咨夔','宋','宋诗','song-poetry','','[]','與我迭知己，喜君初得官。',48,'全唐诗/poet.song.189000.json','["與我迭知己，喜君初得官。", "時來寧論晚，身健莫辭難。", "訪雪牽魂夢，停雲寄肺肝。", "斯文元氣在，努力好加餐。"]'),
('529eee65-4aef-4976-b764-d09105fb6a2b','夜坐','洪咨夔','宋','宋诗','song-poetry','','[]','夜永難爲睡，群兒坐伴翁。',48,'全唐诗/poet.song.189000.json','["夜永難爲睡，群兒坐伴翁。", "漉虀冰甕碧，撚豆雪爐紅。", "清誦聽還雋，閑談笑又烘。", "安排明蚤供，薺長後園叢。"]'),
('bfd7d07c-cb09-4da9-8ddd-1ea8c5f03d87','大人和云樓底雪千峰樓頭着寓翁梅方開萼綠桃已亞枝紅斟淺偏勞勸眠遲不受烘錦城春在眼何暇問蠶叢時四川李制置以榮州見辟辭之也某因用前韵','洪咨夔','宋','宋诗','song-poetry','','[]','寄榻高寒地，收心懶散翁。',48,'全唐诗/poet.song.189000.json','["寄榻高寒地，收心懶散翁。", "雞鳴虛室白，鴉起小窗紅。", "古操塵絃拂，新詩凍研烘。", "桃梅芳意覺，不是去年叢。"]'),
('7e0c78ba-b748-4abb-b7bd-bb8e18ec0b3d','洪崖圖行','洪咨夔','宋','宋诗','song-poetry','','[]','脩髯危肩老僊人，布袍革带烏靴巾。',176,'全唐诗/poet.song.189000.json','["脩髯危肩老僊人，布袍革带烏靴巾。", "胸中不着半點塵，天地萬象肧腪春。", "扇者橘，書者栗，瓢者朮，韁而掣者葛，笠而鞭者拙。", "中間厖然大者雪，從我兩髯三髧一蹩躠。", "馿何鈍，奴何癡，前掣後鞭趣使馳。", "麾鞭愈急行愈遲，掣韁欲斷人馿疲。", "但見尻禿禿，蹄局局，欲墜不墜止鳴木。", "本無伎倆能噴玉，正可吞聲春草綠。", "先生御氣存其神，下馿步行意更真。", "從渠蹇材拗莫馴，超然目送八極轡鳳驂麒麟。"]'),
('1cc47c5f-d356-43d4-a32a-529588cd672f','歲晏  其一','洪咨夔','宋','宋诗','song-poetry','','[]','得路隻輪車易上，失時獨幅被難眠。',32,'全唐诗/poet.song.189000.json','["得路隻輪車易上，失時獨幅被難眠。", "淡黄虀飯茅柴酒，東掩西遮也過年。"]'),
('19fe5fcf-81af-4a72-8ac1-01d28b2fa659','歲晏  其二','洪咨夔','宋','宋诗','song-poetry','','[]','百想卧輪翻伎倆，三生圓澤弄精魂。',32,'全唐诗/poet.song.189000.json','["百想卧輪翻伎倆，三生圓澤弄精魂。", "何如靜對梅花坐，春滿江南雪後村。"]'),
('14f8dd7d-0320-4526-ac2b-4373600ada64','謹和老人賦梅','洪咨夔','宋','宋诗','song-poetry','','[]','寄得江南驛信來，窺林映水幾枝開。',64,'全唐诗/poet.song.189000.json','["寄得江南驛信來，窺林映水幾枝開。", "形容綺語空能絮，酬答芳心總已灰。", "厭舊趨新和粉染，奪真弄假點酥裁。", "紛紛兒女春風惱，却笑詩翁醉打隈。"]'),
('254048e0-580d-4dea-886b-c762abe95738','和趙保之青田即事','洪咨夔','宋','宋诗','song-poetry','','[]','寶犀壓帳春風入，渴烏傳箭寒澌滴。',160,'全唐诗/poet.song.189000.json','["寶犀壓帳春風入，渴烏傳箭寒澌滴。", "砉然推枕起放衙，霜月滿庭鳧鴈集。", "簿書顛倒六作五，文移縱橫一取十。", "精神坐照吏姦破，政事流從儒術出。", "墨池霹靂送飛雨，積案如山笑譚畢。", "逢迎合爪遞相賀，戒石亭前見天日。", "公餘琴疊舞胎僊，客退爐熏齋繡佛。", "芳蹊桃李不自言，舊燕新鶑沸消息。", "詩筒入手如見面，金井新泉生玉色。", "汗青不朽須早計，過眼年華征羽急。"]'),
('0f830c68-7b05-4da8-bd44-0264115a6c50','臈月二十五夜','洪咨夔','宋','宋诗','song-poetry','','[]','炙玉懷雪貍，膾銀憶冰鱭。',192,'全唐诗/poet.song.189000.json','["炙玉懷雪貍，膾銀憶冰鱭。", "異哉山澤荒，坐我窮鬼祟。", "兒頭似耶白，相對玩殘歲。", "爐寒灰熒熒，檠涸燈翳翳。", "擘柑老赤脚，煖酒小青髻。", "一酌佳入蔗，再酌甘勝薺。", "陶然會道妙，嗒然司德契。", "吾身與乾坤，共此小關捩。", "三百六十節，一節一節繫。", "四萬八千息，一息一息繼。", "日月有往來，陰陽有開閉。", "太和行其間，周流無邊際。", "臈盡梅紛披，春回柳摇曳。", "非時難强揠，有命莫過計。", "顔回簞瓢空，季路縕袍弊。", "只恐非大賢，公不待後世。"]'),
('fdce8a0a-821a-47c6-85a7-b109ab6abe21','送程宗武遊岝崿','洪咨夔','宋','宋诗','song-poetry','','[]','驟暖揠芳意，薄遊烘軟塵。',48,'全唐诗/poet.song.189000.json','["驟暖揠芳意，薄遊烘軟塵。", "亂山雲氣曉，啼鳥杏花春。", "人物少催老，物華新換陳。", "一聲鏗爾瑟，沂水綠鱗鱗。"]'),
('248f39e1-25f1-44ca-82ce-107c23411673','謹和老人雪晴','洪咨夔','宋','宋诗','song-poetry','','[]','雲屏九折跨三休，公欲行春雪不愁。',64,'全唐诗/poet.song.189000.json','["雲屏九折跨三休，公欲行春雪不愁。", "逗暖流澌鳴暗谷，送晴倒景漾層樓。", "似無似有草痕動，半落半開花氣浮。", "婆餠焦聲林外起，便從野渡喚橫舟。"]'),
('f9bf49ac-7cef-4f81-9cf4-46cdfc0eb830','元寂宮生祠行','洪咨夔','宋','宋诗','song-poetry','','[]','間臺珍館嚴鶴林，老桂鉅竹籠春陰。',221,'全唐诗/poet.song.189000.json','["間臺珍館嚴鶴林，老桂鉅竹籠春陰。", "騎鶴僊翁杳莫尋，適從何來貂插金。", "裳珮丹青雜璆琳，旗旛繡綵薰甲沉。", "蕊函三洞羅森森，雲璈九奏鏘愔愔。", "擁爐步虛摇箕參，稽首寥陽祈博臨。", "庭下朝謁紛冠簪，願言福壽高於岑。", "問子爲誰對輒瘖，以目代口手拊襟。", "伊民豺虎國蠹蟫，細大敲剝無遺針。", "凜虞膏血供几砧，巧諛曲媚求回心。", "天乎少戢湯火燖，庶幾沸魚逃釜鬵。", "上帝福善禍必淫，高目下耳一監歆。", "察此頌禱皆呻吟，革彼飛鴞懷好音。", "嗚呼愛而祠者古，畏而祠者今。", "安得皞皞相忘，武城弦歌單父琴。"]'),
('9f8caab8-661c-468a-9685-862e2011b24e','婆餠焦','洪咨夔','宋','宋诗','song-poetry','','[]','萬斛精神一握身，清吭宛轉欲飛塵。',64,'全唐诗/poet.song.189000.json','["萬斛精神一握身，清吭宛轉欲飛塵。", "雞纔唱後便知曉，燕未來前先得春。", "驚覺海棠休苦睡，提醒楊柳莫空顰。", "最憐吉語能相報，麥熟同爲鼓腹人。"]'),
('5f04a7d3-7e0d-47cf-8ff8-14e5cd5efc5c','孫教授挽詩','洪咨夔','宋','宋诗','song-poetry','','[]','手織天孫錦，胸吞海若洋。',48,'全唐诗/poet.song.189000.json','["手織天孫錦，胸吞海若洋。", "官卑材不盡，年往慮空長。", "啼鳥呼春夢，飛花餞夕陽。", "唯餘君子澤，插架簡編香。"]'),
('421d62eb-a1df-49d9-b395-807f480150f0','笋蕨','洪咨夔','宋','宋诗','song-poetry','','[]','小兒握固骨何弱，稚子着綳肌尚寒。',32,'全唐诗/poet.song.189000.json','["小兒握固骨何弱，稚子着綳肌尚寒。", "豈不愛渠風味好，只應催我鬢毛殘。"]'),
('3db4cb89-f536-4959-afff-075e786a7cae','浴罷氣體和','洪咨夔','宋','宋诗','song-poetry','','[]','浴罷氣體和，坐睡便胡床。',72,'全唐诗/poet.song.189000.json','["浴罷氣體和，坐睡便胡床。", "首欹如汲瓶，數俯輒一昂。", "瞢騰復瞢騰，慾泯想亦忘。", "乾坤孰高下，今古誰興亡。", "矍然瞠兩眼，疎窗半斜陽。", "窗下櫻桃花，無風自吹香。"]'),
('1d393b55-8299-42d4-8966-813b4b4ad624','金不換歌','洪咨夔','宋','宋诗','song-poetry','','[]','東家鼎貴萬戶侯，西家暴富十谷牛。',72,'全唐诗/poet.song.189000.json','["東家鼎貴萬戶侯，西家暴富十谷牛。", "喚絲呼竹進玉舟，把酒已作明朝愁。", "中間人家賤貧慣，既得未得兩無患。", "晏眠起喫盫菜飯，飯罷亂拈書冊看。", "此樂名爲金不換。"]'),
('dcae4d8c-8f81-4d11-b87c-7f1b300c592d','酬東風引','洪咨夔','宋','宋诗','song-poetry','','[]','魏鄭公，田舍翁。',48,'全唐诗/poet.song.189000.json','["魏鄭公，田舍翁。", "陸敬輿，老獠奴。", "斯人斯人尚如許，薄命蛾眉何足數。", "野桃溪杏次第紅，脫袴博酒酬東風。"]'),
('f495af1a-e725-4fdb-b891-a535a37b1d87','溪行','洪咨夔','宋','宋诗','song-poetry','','[]','却掃晝陰永，意行溪上汀。',48,'全唐诗/poet.song.189000.json','["却掃晝陰永，意行溪上汀。", "鬢華年減黑，草暈日添青。", "魚舞新磨鏡，鷗飛小畫屏。", "梨花寒食近，誰與管飄零。"]'),
('ca52629d-3938-4f37-923c-94a1c1aa2af8','用吳祕書正月晦韵','洪咨夔','宋','宋诗','song-poetry','','[]','攬春群玉寫芳懷，次第安排到藥苔。',64,'全唐诗/poet.song.189000.json','["攬春群玉寫芳懷，次第安排到藥苔。", "但得斯文留脈在，須教我輩放眉開。", "疎風細雨桃花過，竹屋柴門燕子來。", "老去湖山無復夢，荷鉏西崦覓榿栽。"]'),
('c40b7510-2ce2-470f-ae38-f72322a93fcb','禮滅翁退天台能仁院歸梁渚一絕寄之','洪咨夔','宋','宋诗','song-poetry','','[]','倒劄枯藤立晚風，山光不與水俱東。',32,'全唐诗/poet.song.189000.json','["倒劄枯藤立晚風，山光不與水俱東。", "蘋花落盡蘆花老，地闊天高一箇鴻。"]'),
('a9844bea-081d-40d5-868a-9e9fd557de4c','椶櫚','洪咨夔','宋','宋诗','song-poetry','','[]','舊脫敗蓑亂，新添華節高。',48,'全唐诗/poet.song.189000.json','["舊脫敗蓑亂，新添華節高。", "肅容春尚靜，俠氣夏方豪。", "黄孕子魚腹，青披孔雀尻。", "豐撞知可製，雷動景鍾號。"]'),
('9c7df524-3d09-44f5-a300-14b74e16c873','碧桃曲','洪咨夔','宋','宋诗','song-poetry','','[]','草平不斷瑶池路，樓礙東風花滿樹。',64,'全唐诗/poet.song.189000.json','["草平不斷瑶池路，樓礙東風花滿樹。", "綠眉素頰澹裙裳，月華暖透三更露。", "雙成飛瓊妬高妍，引梢摇月分嬋娟。", "雲璈一曲迸空碧，青鸞驚起花翩翩。"]'),
('ba7a86df-6ff4-4e2f-9acd-77f1a0b76ce9','燭下次海棠','洪咨夔','宋','宋诗','song-poetry','','[]','紅深翠淺浣花春，投老相逢過所欣。',64,'全唐诗/poet.song.189000.json','["紅深翠淺浣花春，投老相逢過所欣。", "有許精神宜半睡，無多醖藉莫全醺。", "涵渟芳露須饒月，籠護晴暉不礙雲。", "成就化工真富貴，天香更與牡丹分。"]'),
('2a014679-2741-4c94-a7d0-702c8e974106','送李微之倅成都','洪咨夔','宋','宋诗','song-poetry','','[]','鳳生丹山西，來爲太平符。',96,'全唐诗/poet.song.189000.json','["鳳生丹山西，來爲太平符。", "矯立青琅玕，祥雲蔚相扶。", "一鳴合簫韶，再鳴應騶虞。", "散爲清明風，萬象皆敷與。", "色舉抑何决，矢脫金僕姑。", "戛摩參旗高，可望不可呼。", "穿花迷嬌雉，唼藻戲乳鳬。", "搔首重太息，春陰渺江湖。"]'),
('495fd9e9-1626-4aa0-a998-58751ffdf47e','次叔厚韵','洪咨夔','宋','宋诗','song-poetry','','[]','夢斷紅塵踏九衢，雲山佳處借樓居。',64,'全唐诗/poet.song.189000.json','["夢斷紅塵踏九衢，雲山佳處借樓居。", "採將瓠葉隨宜煮，拾得榴皮信意書。", "未問我今忘我世，須知吾本愛吾廬。", "黄公壚在花陰裏，磊砢從君一破除。"]'),
('09eb6276-d953-4d18-bbe1-6cc128f541d5','二佳','洪咨夔','宋','宋诗','song-poetry','','[]','佳笋如佳人，柔晢飽風致。',60,'全唐诗/poet.song.189000.json','["佳笋如佳人，柔晢飽風致。", "佳醑如佳士，醇明負骨氣。", "此笋配此醑，可愛不可醉。", "得醉豈不好，醉恐不知味。", "蔚如王謝家，文雅將富貴。"]'),
('5af16ae8-ba7e-4238-b09c-e404a21e2984','二月二十七遊仙洞次壁間韵','洪咨夔','宋','宋诗','song-poetry','','[]','點脚地維絕，舉頭天語聞。',48,'全唐诗/poet.song.189000.json','["點脚地維絕，舉頭天語聞。", "瀑泉飛響雪，洞石湧崩雲。", "縹緲追元放，低回揖郭文。", "神清知好在，煙鎖綠苔紋。"]'),
('ad8f1a10-1d7a-40bc-a3f9-6dc6daf99b34','用韵答趙主簿','洪咨夔','宋','宋诗','song-poetry','','[]','逸氣蓋三謝，英詞參二班。',48,'全唐诗/poet.song.189000.json','["逸氣蓋三謝，英詞參二班。", "飛緌宜北闕，枉駕忽東山。", "花妥晝陰寂，絮吹春思閑。", "光風知幾轉，盡付酒杯間。"]'),
('7e5818db-66a2-48ff-b81b-c0a64c82d7b4','謹和老人羅山','洪咨夔','宋','宋诗','song-poetry','','[]','自鑄鐵成錯，誰吹灰使然。',48,'全唐诗/poet.song.189000.json','["自鑄鐵成錯，誰吹灰使然。", "俗情床上下，野趣蜜中邊。", "花豔明光錦，苔痕白打錢。", "醉翁詩板在，山莫放童顛。"]'),
('fb3516b5-1898-4a78-a5f5-7187615bd6f0','寄題辛氏塵外樓','洪咨夔','宋','宋诗','song-poetry','','[]','羅浮三十里，樓對玉崔嵬。',48,'全唐诗/poet.song.189000.json','["羅浮三十里，樓對玉崔嵬。", "風卷軟紅去，雲扶飛翠來。", "會心須盡帙，適性莫多杯。", "除得翳根盡，靈光生鏡臺。"]'),
('c362095d-a3e0-4cd5-8368-fd639aa7ff03','初夏','洪咨夔','宋','宋诗','song-poetry','','[]','鶴帳華纓絕，牛蹊老屐穿。',48,'全唐诗/poet.song.189000.json','["鶴帳華纓絕，牛蹊老屐穿。", "薄晴生晚哢，深綠護餘妍。", "萬卷不堪煮，百懷空自煎。", "朱櫻黄苦笋，小酌便陶然。"]'),
('8766d272-a45e-4399-9166-059fa477d8af','里人送芍藥用韵','洪咨夔','宋','宋诗','song-poetry','','[]','詩墨淋漓似小王，殷勤包贈暖紅香。',32,'全唐诗/poet.song.189000.json','["詩墨淋漓似小王，殷勤包贈暖紅香。", "楊州金繫腰何在，隨分留春共一觴。"]'),
('043d5fa2-71b9-4dfd-9a3b-80b83b9e09ad','寄高子厚','洪咨夔','宋','宋诗','song-poetry','','[]','盤隠門下客，流落餘兩箇。',144,'全唐诗/poet.song.189000.json','["盤隠門下客，流落餘兩箇。", "我故稔子窮，子亦諒我懦。", "穉松高未尺，早望屋脊過。", "小蓮出纔寸，便譽車輪大。", "急灘倒撐舡，狹路錯推磨。", "不誚材無堪，祗嘆命未作。", "沽酒勞閴寂，裹飯問寒餓。", "爲分猢猻愁，相對橐駝坐。", "有無共甘苦，休戚先吊賀。", "綢繆平生期，荏苒歲月蹉。", "人情少耐久，世事難預課。", "欲尋買山盟，恐踏算甕破。"]'),
('0e1f0aab-f593-43a3-b70c-c3e313578a34','憫農','洪咨夔','宋','宋诗','song-poetry','','[]','麥黄蠶登簇，秧青雨催耕。',60,'全唐诗/poet.song.189000.json','["麥黄蠶登簇，秧青雨催耕。", "農家竭作時，無工搏蚊蝱。", "短杠鴈鶩進，脩繂螻蟻行。", "謨蓋溪壑滿，名言輿梁成。", "吞聲不敢怨，但願天長晴。"]'),
('07bf3906-bd17-445d-9db0-90dd799d07b2','和禮滅翁感錢氏舊事','洪咨夔','宋','宋诗','song-poetry','','[]','民不知兵物自華，表忠消得老碑誇。',64,'全唐诗/poet.song.189000.json','["民不知兵物自華，表忠消得老碑誇。", "虎符龍節故王國，鳳舞鸞飛今帝家。", "遺廟斷垣低槲葉，荒村舊井濕桐花。", "馮夷尚怕潮頭弩，一望西興渡口沙。"]'),
('95fdbc63-ae10-46f5-ae53-466bfef899b3','滅翁爲日者求詩','洪咨夔','宋','宋诗','song-poetry','','[]','大橈甲子一串穿，東州西州走諸禪。',64,'全唐诗/poet.song.189000.json','["大橈甲子一串穿，東州西州走諸禪。", "芭蕉虛實果何物，橄欖苦甜猶問天。", "華光佛壽十二劫，瞿曇像法一千年。", "兩翁見子肯倒屣，好爲推到無生前。"]'),
('7a55e937-0769-4e58-aa71-741776ce54a2','用鍾侍郎韵贈懶谷','洪咨夔','宋','宋诗','song-poetry','','[]','蒲團竹几妙高臺，瞑坐何能放眼開。',32,'全唐诗/poet.song.189000.json','["蒲團竹几妙高臺，瞑坐何能放眼開。", "門外白雲多事在，又將飛雨出山來。"]'),
('def12f8d-9f72-4965-9f18-6fe38a1ea944','暑夕','洪咨夔','宋','宋诗','song-poetry','','[]','樓高收晚照，野迥送宵陰。',48,'全唐诗/poet.song.189000.json','["樓高收晚照，野迥送宵陰。", "鷺下汀沙靜，螢行岸竹深。", "攖寧和順氣，緣督正平心。", "轉物天機妙，昭文不在琴。"]'),
('96a60581-e230-407d-91f7-c0b5ea021e17','王章','洪咨夔','宋','宋诗','song-poetry','','[]','皂囊盥手自封題，忘却牛衣忍凍啼。',32,'全唐诗/poet.song.189000.json','["皂囊盥手自封題，忘却牛衣忍凍啼。", "一點丹心通碧落，歲寒寧負白頭妻。"]'),
('9d72a8a6-d526-4d68-aeb4-1a205db99cd3','暑坐','洪咨夔','宋','宋诗','song-poetry','','[]','隔簾草樹隔溪山，密密深深洞啟關。',32,'全唐诗/poet.song.189000.json','["隔簾草樹隔溪山，密密深深洞啟關。", "水色山光無障礙，南風送入亂書間。"]'),
('c3978c9c-e77a-4374-b9ab-4878c1eab5f3','謹和老人夏日東山即事  其一','洪咨夔','宋','宋诗','song-poetry','','[]','剗草根須盡，傳花葉未多。',48,'全唐诗/poet.song.189000.json','["剗草根須盡，傳花葉未多。", "明波撐窣堵，老石卧盤陀。", "煨美甘分芋，蒸肥欠裹荷。", "醒然下山去，明月滿林阿。"]'),
('88ec8967-6027-4c94-918c-59804deedc59','謹和老人夏日東山即事  其二','洪咨夔','宋','宋诗','song-poetry','','[]','菜把野園送，花枝隣巷賒。',48,'全唐诗/poet.song.189000.json','["菜把野園送，花枝隣巷賒。", "搗蟾和絳雪，騎斗弄青霞。", "古帖臨禽李，新詩續稻瓜。", "晚凉隨杖履，携酒訪魚槎。"]'),
('b8c0ca52-2980-48e5-bbc5-f6c4c4539f4b','田家建除體','洪咨夔','宋','宋诗','song-poetry','','[]','建鼓勸竭作，除田綠紛披。',72,'全唐诗/poet.song.189000.json','["建鼓勸竭作，除田綠紛披。", "滿築沮澤岸，平流綺堘陂。", "定約欲水均，執熱願雨隨。", "破柱雷電合，危簷溜紳垂。", "成功一天瓢，收穫萬京坻。", "開元貞觀盛，閉關更休師。"]'),
('f1a74954-e9b5-45d9-8a65-205aa36de42f','和趙青田燕坐','洪咨夔','宋','宋诗','song-poetry','','[]','青田鶴翁杜德機，天根月窟手探之。',96,'全唐诗/poet.song.189000.json','["青田鶴翁杜德機，天根月窟手探之。", "嬰兒姹女熟摶弄，妙處不許旁人知。", "渠家庭院紛花藥，啄木黄鸝幾推却。", "流蘇百子卧春風，萬慾難供無底壑。", "生門死戶一線間，內丹走盡求外丹。", "明朝赤黄裂大山，護鼎龍虎方閑閑。"]'),
('28049897-dc6c-4c3e-9a5f-3fba9f56963b','新秋藥名  其一','洪咨夔','宋','宋诗','song-poetry','','[]','老色蒼蒼耳向聾，秋聲欺得白頭翁。',64,'全唐诗/poet.song.189000.json','["老色蒼蒼耳向聾，秋聲欺得白頭翁。", "已甘草詔元無分，只苦耽詩久欠功。", "引興從容風月足，放懷浪宕水雲空。", "雨餘凉意生庭戶，夜半天河鵲信通。"]'),
('21e9f76f-f47b-4cff-aaf8-19b2098d3781','新秋藥名  其二','洪咨夔','宋','宋诗','song-poetry','','[]','兩眼旋花雪點鬚，鑽頭故紙枉工夫。',64,'全唐诗/poet.song.189000.json','["兩眼旋花雪點鬚，鑽頭故紙枉工夫。", "倦懷懶附子公櫝，閑性熟諳摩詰圖。", "枝拂雲香行到桂，葉隨風舞又催梧。", "乘槎欲到空青問，織女牽牛事有無。"]'),
('5b2ae57e-e303-447a-9337-3379b1639a4a','謹和老人官山看高子厚修墓','洪咨夔','宋','宋诗','song-poetry','','[]','秋風問訊老芙蕖，靖節前行後阿舒。',64,'全唐诗/poet.song.189000.json','["秋風問訊老芙蕖，靖節前行後阿舒。", "緩策穩過金絡馬，小烹佳勝蔗漿厨。", "何榮何辱人千古，誰是誰非冢一區。", "遇着好花隨處醉，莫論他屋與吾廬。"]'),
('eb218e37-a187-47f4-8438-511c90d80c62','用子有述懷韵爲壽','洪咨夔','宋','宋诗','song-poetry','','[]','筆力强於二石弓，文場早合擅元戎。',64,'全唐诗/poet.song.189000.json','["筆力强於二石弓，文場早合擅元戎。", "東西塗抹未爲老，左右圖書那得窮。", "三日窺牛酬壯志，十年到鳳策奇功。", "更須傳取長生訣，蜜炬高燒不受風。"]'),
('4e13f464-b1e8-44c6-b883-ad3db20e6b0c','俞成大送新芋','洪咨夔','宋','宋诗','song-poetry','','[]','謝三郎女敗蓑衣，繿縷中藏玉雪肌。',32,'全唐诗/poet.song.189000.json','["謝三郎女敗蓑衣，繿縷中藏玉雪肌。", "柱下莫愁無乳媼，秋風得此可忘饑。"]'),
('a437ae7e-f07a-4b3f-9e92-d7542dac4087','范待制挽詩  其一','洪咨夔','宋','宋诗','song-poetry','','[]','太白曉燄燄，飛鴻秋冥冥。',48,'全唐诗/poet.song.189000.json','["太白曉燄燄，飛鴻秋冥冥。", "氣節蚤已勁，勳名晚逾馨。", "冰霜蜀棧蹇，風雨秦關腥。", "一范不可作，岷峨千古青。"]'),
('eb25504b-d64c-4d91-a5ea-67dbc7173239','范待制挽詩  其二','洪咨夔','宋','宋诗','song-poetry','','[]','生不餌柏寺，死纔跨松階。',48,'全唐诗/poet.song.189000.json','["生不餌柏寺，死纔跨松階。", "浮雲忽易滅，明月終難埋。", "宇宙卓有立，江山渺無涯。", "掩卷獨搔首，西風知此懷。"]'),
('377a3b16-6f49-4e67-8c09-8aae28bf36e1','和俞成大八月梅花','洪咨夔','宋','宋诗','song-poetry','','[]','秋光深處送春來，青葉扶疎數點梅。',32,'全唐诗/poet.song.189000.json','["秋光深處送春來，青葉扶疎數點梅。", "料是知君新釀熟，攙先九月菊花開。"]'),
('80890964-66ca-4e2c-bc96-743a704f610d','謹和老人秋日遣懷','洪咨夔','宋','宋诗','song-poetry','','[]','鬰鬰年來亦欲東，窮魔揮斥欠天蓬。',64,'全唐诗/poet.song.189000.json','["鬰鬰年來亦欲東，窮魔揮斥欠天蓬。", "得甜自喜皆花蜜，與苦相忘獨蓼蟲。", "張望紅秔新作業，柴桑青菊舊家風。", "隣翁强解人間事，數問朱轓甚日熊。"]'),
('9b2f458b-bd88-4149-aadb-51be63d2f4d2','月下用鄭大參和沾維那圓覺韵','洪咨夔','宋','宋诗','song-poetry','','[]','無縫冰輪萬古同，御風飛到碧天中。',32,'全唐诗/poet.song.189000.json','["無縫冰輪萬古同，御風飛到碧天中。", "四方上下無遮礙，一點清光處處通。"]'),
('d9b542cf-4965-4632-8a84-fc9bceb83345','東山即事','洪咨夔','宋','宋诗','song-poetry','','[]','西風卷宿祲，天高近重陽。',84,'全唐诗/poet.song.189000.json','["西風卷宿祲，天高近重陽。", "閣虛自沆瀣，塔靜能琅璫。", "幽花多素英，穠香奪春芳。", "老木未黄落，繁陰生夏凉。", "棋雋决楚漢，杯壯迷彭殤。", "醉帽信孟嘉，歸鞭忘葛强。", "萬事貴適意，誰能扣蒼蒼。"]'),
('26a7b23a-7da4-4d54-bcee-f19805183866','九月四日過增口道中','洪咨夔','宋','宋诗','song-poetry','','[]','秋光拍塞小村墟，高下人家意自如。',64,'全唐诗/poet.song.189000.json','["秋光拍塞小村墟，高下人家意自如。", "屋底四蠶抽蛹細，牆頭三桂着花疎。", "握兒早秫酒無限，杓子晚菘虀有餘。", "大似元豐年界好，天應容我老樵漁。"]'),
('93ee69b5-fea4-4dd8-89c7-aaae6af2e1b3','謹和老人九日','洪咨夔','宋','宋诗','song-poetry','','[]','樓頭獨立夕陽西，摇落高風萬木嘶。',64,'全唐诗/poet.song.189000.json','["樓頭獨立夕陽西，摇落高風萬木嘶。", "人自官芻銜馬口，我方社酒薦豚蹄。", "一塵不著青銅鏡，萬法皆空黑漆篦。", "節後龍山應更好，秋光拍滿錦障泥。"]'),
('27318b3e-a3ce-4411-80dd-b2e21058842e','謹和老人賦牛尾貍  其一','洪咨夔','宋','宋诗','song-poetry','','[]','踏白霜明夜，牽黄木葉秋。',48,'全唐诗/poet.song.189000.json','["踏白霜明夜，牽黄木葉秋。", "斕斑文未豹，觳𧥆炙先牛。", "壓玉開三面，蒸酥讓一頭。", "酒邊纖手削，醉倒老浮丘。"]'),
('1a8e8a0a-2e7f-43fe-98df-7a0eb2006345','謹和老人賦牛尾貍  其二','洪咨夔','宋','宋诗','song-poetry','','[]','北雪佛貍種，西風金狗秋。',48,'全唐诗/poet.song.189000.json','["北雪佛貍種，西風金狗秋。", "謀生貪過鼠，逃死喘如牛。", "糟熟涎奴舌，虀芳點客頭。", "何時明獵火，吞盡楚青丘。"]'),
('d7e66c54-9a8e-4262-8324-9355de99b8c1','趙忠簡孫璧見過有詩用韵','洪咨夔','宋','宋诗','song-poetry','','[]','薄命窘震凌，餘生颯糞朽。',240,'全唐诗/poet.song.189000.json','["薄命窘震凌，餘生颯糞朽。", "閑閑飽款竹，寂寂老鍛柳。", "溪空漁爭隈，野熟飲被肘。", "有隣晨致薤，無客夜剪韭。", "忽來闖戶屨，自挈問字酒。", "初見了眉睫，徐語應心口。", "顧予果誰與，恐子不我友。", "維昔燕夾攻，坐使汴失守。", "應奉固亂階，新法實禍首。", "療危非庸醫，救敗須國手。", "豐魏兩翁奮，關洛孤憤久。", "人謀密相濟，天意斷非偶。", "攻守豈必同，勝負亦常有。", "誰推姦人出，竟墮黠虜誘。", "包將復讎戈，付與掃愁帚。", "風雲激矢脫，日月峻輪走。", "殘羶污北雪，遺憾掛南斗。", "功名本同舟，學術廼各牖。", "一時策得失，千古史妍醜。", "忠簡社稷臣，尚起九京否。"]'),
('ef77f5de-eb86-4aa7-bbfc-9dd04f24ac7a','謹和老人初冬即事','洪咨夔','宋','宋诗','song-poetry','','[]','莫怒狙公賦芧慳，萬緣一定不容干。',64,'全唐诗/poet.song.189000.json','["莫怒狙公賦芧慳，萬緣一定不容干。", "老便窗下迷離暖，醉愛尊前郭索寒。", "屑玉晨光明沆瀣，流珠夜氣鬰蘭玕。", "但能飽喫長年飯，射虎南山有分看。"]'),
('e27ac8ed-fe8a-4fba-90b1-2debcbc54b8c','謹和老人初冬寓筆十絕  其一','洪咨夔','宋','宋诗','song-poetry','','[]','平泉草木須臾夢，金谷鶑花一撮塵。',32,'全唐诗/poet.song.189000.json','["平泉草木須臾夢，金谷鶑花一撮塵。", "富貴若生根到底，兩家占斷別無人。"]'),
('2f714c23-13e3-4a74-95ed-126c2d317e28','謹和老人初冬寓筆十絕  其二','洪咨夔','宋','宋诗','song-poetry','','[]','是非不驗道應壞，禍福無憑天也荒。',32,'全唐诗/poet.song.189000.json','["是非不驗道應壞，禍福無憑天也荒。", "便使曹瞞生賣履，已賒王衍死排牆。"]'),
('3e564e1f-b3a4-47be-9dd2-e4745c81c4c3','謹和老人初冬寓筆十絕  其三','洪咨夔','宋','宋诗','song-poetry','','[]','何人地下管天條，不是臯陶即是蕭。',32,'全唐诗/poet.song.189000.json','["何人地下管天條，不是臯陶即是蕭。", "金埒謾誇錢過斗，鐵圍寧問玉垂腰。"]'),
('8503e9a2-b714-47be-b4cf-f76304a76f03','謹和老人初冬寓筆十絕  其四','洪咨夔','宋','宋诗','song-poetry','','[]','當場弄出百般奇，傀儡棚中老偃師。',32,'全唐诗/poet.song.189000.json','["當場弄出百般奇，傀儡棚中老偃師。", "滿眼機關無着處，到頭線索有收時。"]'),
('b0a20c64-8b47-4a84-a324-57bbd490f346','謹和老人初冬寓筆十絕  其五','洪咨夔','宋','宋诗','song-poetry','','[]','兩儀亦有盈虧數，萬物難逃出入機。',32,'全唐诗/poet.song.189000.json','["兩儀亦有盈虧數，萬物難逃出入機。", "一把牙籌空自苦，蓋棺着得幾通衣。"]'),
('70abacdf-a07f-4300-87bf-67b6acaa988e','謹和老人初冬寓筆十絕  其六','洪咨夔','宋','宋诗','song-poetry','','[]','避風臺上深情寵，偃月堂中盡意謀。',32,'全唐诗/poet.song.189000.json','["避風臺上深情寵，偃月堂中盡意謀。", "爭柰天公無面目，滿林黄葉一番秋。"]'),
('676eeeff-14de-434b-8d2a-2ca982052665','謹和老人初冬寓筆十絕  其七','洪咨夔','宋','宋诗','song-poetry','','[]','煮茗燒香雙赤脚，撿書洗研一蒼頭。',32,'全唐诗/poet.song.189000.json','["煮茗燒香雙赤脚，撿書洗研一蒼頭。", "斯文興喪由天在，未用安排地起樓。"]'),
('e6f32802-0739-42d0-ba48-939279936f3a','謹和老人初冬寓筆十絕  其八','洪咨夔','宋','宋诗','song-poetry','','[]','元子掃空桓氏業，窟郎蕩盡李家風。',32,'全唐诗/poet.song.189000.json','["元子掃空桓氏業，窟郎蕩盡李家風。", "前人留得兒孫立，何患鸞枝不長桐。"]'),
('1db3b1a8-8849-4251-b8f8-2da4cfe23ef2','謹和老人初冬寓筆十絕  其九','洪咨夔','宋','宋诗','song-poetry','','[]','方窮蔡澤問唐舉，未遇鄴侯逢懶殘。',32,'全唐诗/poet.song.189000.json','["方窮蔡澤問唐舉，未遇鄴侯逢懶殘。", "觸石起雲能沛雨，不應長作旱雷看。"]'),
('116b3e90-2b76-4bc8-823b-360a276175d0','謹和老人初冬寓筆十絕  其一○','洪咨夔','宋','宋诗','song-poetry','','[]','命有窮通分虎鼠，事無得失盡雞蟲。',32,'全唐诗/poet.song.189000.json','["命有窮通分虎鼠，事無得失盡雞蟲。", "東籬獨有黄花在，挹取寒香壽阿翁。"]'),
('c2f3aa8a-3964-4ca3-9157-a2403f78a934','又和  其一','洪咨夔','宋','宋诗','song-poetry','','[]','青女籠晴試小春，門前沙路浄無塵。',32,'全唐诗/poet.song.189000.json','["青女籠晴試小春，門前沙路浄無塵。", "平洲水竹因依好，白鷺飛來不避人。"]'),
('3ae42f69-4a47-45bb-8d2c-04c03673fe66','又和  其二','洪咨夔','宋','宋诗','song-poetry','','[]','往來魚虎澗流淺，出沒鼠狼庭草荒。',32,'全唐诗/poet.song.189000.json','["往來魚虎澗流淺，出沒鼠狼庭草荒。", "宅近市傍人不到，獨迎西日上東牆。"]'),
('61b0bb22-3030-430c-b2be-e936fc2cb9b9','又和  其三','洪咨夔','宋','宋诗','song-poetry','','[]','柳亞溪橋幾換條，鬢根添得雪飄蕭。',32,'全唐诗/poet.song.189000.json','["柳亞溪橋幾換條，鬢根添得雪飄蕭。", "清臞自信堪騎鶴，最喜無錢絆住腰。"]'),
('7129b9d2-4147-41b2-8f5e-92f86a1e62f7','又和  其四','洪咨夔','宋','宋诗','song-poetry','','[]','爾雅蟲魚已熟知，更將埤雅訪農師。',32,'全唐诗/poet.song.189000.json','["爾雅蟲魚已熟知，更將埤雅訪農師。", "投糟赤蟹真無價，薦餠黄雞正及時。"]'),
('b706ba81-47a6-471e-a995-da838cc7fd3d','又和  其五','洪咨夔','宋','宋诗','song-poetry','','[]','終朝聒得耳神飛，東舍西隣盡販機。',32,'全唐诗/poet.song.189000.json','["終朝聒得耳神飛，東舍西隣盡販機。", "百樣攀花無我分，慣將簾作後堂衣。"]'),
('835bc692-517e-4677-ad74-8a8d48eb242c','又和  其六','洪咨夔','宋','宋诗','song-poetry','','[]','架上亂書兒自整，床頭濁酒婦能謀。',32,'全唐诗/poet.song.189000.json','["架上亂書兒自整，床頭濁酒婦能謀。", "只將翹足垂蓮勢，靜對書窗課弈秋。"]'),
('1d104536-c2c9-448e-b9e6-3e291a2c843b','又和  其七','洪咨夔','宋','宋诗','song-poetry','','[]','風裏行雲不自由，低眉重整玉搔頭。',32,'全唐诗/poet.song.189000.json','["風裏行雲不自由，低眉重整玉搔頭。", "桃根縱有飛花渡，燕子寧無接翅樓。"]'),
('06d552c1-09f0-448b-9696-b97b699b4d17','又和  其八','洪咨夔','宋','宋诗','song-poetry','','[]','寒燈芳燼發春紅，讀到豳詩繼匪風。',32,'全唐诗/poet.song.189000.json','["寒燈芳燼發春紅，讀到豳詩繼匪風。", "吾道有消還有長，欲將此意寫絲桐。"]'),
('64be7518-0619-40d4-a77e-0c82060ed7c4','又和  其九','洪咨夔','宋','宋诗','song-poetry','','[]','蟹正肥時秋色老，鴉爭噪處夕陽殘。',32,'全唐诗/poet.song.189000.json','["蟹正肥時秋色老，鴉爭噪處夕陽殘。", "未須多進玻瓈椀，滿樹霜紅正好看。"]'),
('7aa84639-dfb0-4fb0-bf70-6f80ad246aa6','又和  其一○','洪咨夔','宋','宋诗','song-poetry','','[]','天時人事共流通，何用將冰語夏蟲。',32,'全唐诗/poet.song.189000.json','["天時人事共流通，何用將冰語夏蟲。", "判爲梅花多釀酒，春風裏着蜜翁翁。"]'),
