('cfd523b0-f50e-48d5-9f70-73b1189809ff','臺中聽雪','洪咨夔','宋','宋诗','song-poetry','','[]','淅瀝松廳夜，空山一樣聲。',48,'全唐诗/poet.song.189000.json','["淅瀝松廳夜，空山一樣聲。", "冰霜元自勁，水月更添清。", "衾薄難留夢，窗虛易得明。", "庭烏催奏墨，未曉已先鳴。"]'),
('dbb1e13a-13e8-4caf-aa98-ca41e134ec8a','太一宮齋祭呈司封吳舍人','洪咨夔','宋','宋诗','song-poetry','','[]','寶鑰轟霄啟玉晨，風恬雪霽浄無塵。',64,'全唐诗/poet.song.189000.json','["寶鑰轟霄啟玉晨，風恬雪霽浄無塵。", "東皇太一紫壇曉，世界大千青陸春。", "藜杖流光環珮集，鏠旗歛影豆籩陳。", "樂歌須仗甘泉筆，斧藻天家泰道新。"]'),
('62fd2dd7-a95d-48fe-adb3-eefef68d9a2c','謹和老人除日','洪咨夔','宋','宋诗','song-poetry','','[]','吾道何通塞，人情自寂喧。',48,'全唐诗/poet.song.189000.json','["吾道何通塞，人情自寂喧。", "無羔還可茗，有鶴不須錢。", "議論追嘉祐，聲名續貞元。", "壽親惟此爾，一笑柏椒邊。"]'),
('516ddb50-3050-4a25-a992-0dfadea0e79c','清凉院僧房致齋','洪咨夔','宋','宋诗','song-poetry','','[]','花片牆陰晚，禽聲屋角晴。',24,'全唐诗/poet.song.189000.json','["花片牆陰晚，禽聲屋角晴。", "東風猶峭在，煨芋坐深明。"]'),
('896368fc-6ad8-4441-b73a-9f5fb379a3ba','銓闈董試上巳二絕  其一','洪咨夔','宋','宋诗','song-poetry','','["\u897f\u6e56"]','天氣年年只麽新，官忙不似舊閑身。',32,'全唐诗/poet.song.189000.json','["天氣年年只麽新，官忙不似舊閑身。", "油車畫舫西湖閙，可惜埋頭典却春。"]'),
('552908d2-95d2-42f6-9444-cba00b615d45','銓闈董試上巳二絕  其二','洪咨夔','宋','宋诗','song-poetry','','[]','柳暗鴉嬌日正長，筆頭風雨響脩廊。',32,'全唐诗/poet.song.189000.json','["柳暗鴉嬌日正長，筆頭風雨響脩廊。", "一簾芳碧雙蝴蝶，也解尋人姓字香。"]'),
('96deac5c-fc95-46db-8546-df87f571aab9','除夜哭內','洪咨夔','宋','宋诗','song-poetry','','[]','密雪疎風客屋穿，幾回除夕伴憂煎。',64,'全唐诗/poet.song.189000.json','["密雪疎風客屋穿，幾回除夕伴憂煎。", "團欒方索日邊飯，契闊已成松底眠。", "畫火何堪思舊事，理衣誰與管新年。", "平時戒汝無多酌，爭得屠蘇到汝前。"]'),
('3bd0937b-59f0-4596-a311-8b64c4d8a6b9','省闈試士','洪咨夔','宋','宋诗','song-poetry','','[]','東風蓆帽快行催，渾爲天家造士來。',64,'全唐诗/poet.song.189000.json','["東風蓆帽快行催，渾爲天家造士來。", "捧詔九霄雲氣濕，分題五色日華開。", "揀金沙裏須精鑒，脫穎囊中盡異材。", "容受直言天子聖，好聽臚唱響春雷。"]'),
('aa2dffb9-ce4e-4872-afa8-a3106e28a25a','六月五日集英殿策士從官待宣于內軍器庫廊','洪咨夔','宋','宋诗','song-poetry','','[]','漢廷與目策英豪，投釣知誰首掣鰲。',64,'全唐诗/poet.song.189000.json','["漢廷與目策英豪，投釣知誰首掣鰲。", "百日紅連綸閣迥，萬年枝拂禁城高。", "內廊坐永風生席，輦路歸遲月映袍。", "西抹東塗渾忘却，一絇短雪不堪搔。"]'),
('2d80f33e-f853-44f8-9354-465943f097e5','六月十六日宣鎖','洪咨夔','宋','宋诗','song-poetry','','[]','禁門深鑰寂無譁，濃墨淋漓兩相麻。',32,'全唐诗/poet.song.189000.json','["禁門深鑰寂無譁，濃墨淋漓兩相麻。", "唱徹五更天未曉，一池月浸紫薇花。"]'),
('e603b1e6-e091-4ec3-8b48-894e74b1b349','恭和御製賜吳叔告已下聞喜宴詩','洪咨夔','宋','宋诗','song-poetry','','[]','致主唐虞澤兆民，賢才端是國精神。',64,'全唐诗/poet.song.189000.json','["致主唐虞澤兆民，賢才端是國精神。", "作人欲返皇風古，拔士先隨聖化新。", "收歛文章歸獻替，安排事業到彌綸。", "宸章屬望丁寧甚，上答天恩莫愛身。"]'),
('181dad89-1dda-43b9-ad11-2e4df7620673','謹和老人瘳字韵','洪咨夔','宋','宋诗','song-poetry','','[]','本期洗眼看伊周，到此華胥只夢遊。',64,'全唐诗/poet.song.189000.json','["本期洗眼看伊周，到此華胥只夢遊。", "爛熳蒼苔心事晚，婆娑紅槿鬢華秋。", "藏頭欲效鑽沙鼈，捫舌空成噍草牛。", "飯豆芋魁渾好在，得歸不藥病還瘳。"]'),
('bea245c7-a16d-4882-9302-821be27f9100','謹和大人喜晴','洪咨夔','宋','宋诗','song-poetry','','[]','雨脚如麻日日然，垂成生恐壞豐年。',64,'全唐诗/poet.song.189000.json','["雨脚如麻日日然，垂成生恐壞豐年。", "九重肸蠁通方寸，一點光明徧大千。", "喜動朝行花底散，愁銷野次葦間緣。", "奄觀銍艾霜風晚，重壓牛車倍費鞭。"]'),
('9f959e05-d6b6-49f3-bb96-0981ee7855e9','閏月廿六日奉御香祈天竺觀音於昭慶寺是日得霽','洪咨夔','宋','宋诗','song-poetry','','[]','大士慈悲出補陀，掃除陰翳作人和。',32,'全唐诗/poet.song.189000.json','["大士慈悲出補陀，掃除陰翳作人和。", "武康芋子鹽官棗，遇着豐年也倍多。"]'),
('2124feec-2588-45f4-9a22-4dc5c2b52a15','謹和老人賦退朝','洪咨夔','宋','宋诗','song-poetry','','[]','世事鵬斥鷃，人情燕伯勞。',48,'全唐诗/poet.song.189000.json','["世事鵬斥鷃，人情燕伯勞。", "心須腔放闊，眼要孔提高。", "陳力惟求健，承恩敢恃牢。", "熟思歸計是，春酒薦蔞蒿。"]'),
('511185d6-0c81-4d21-869e-bf6a2d24acf0','下元節後省試進奏院吏','洪咨夔','宋','宋诗','song-poetry','','[]','推雲不動雨聲苦，醖雪未成風力乾。',32,'全唐诗/poet.song.189000.json','["推雲不動雨聲苦，醖雪未成風力乾。", "瘖鶩一庭淘墨汁，也煩老子坐深寒。"]'),
