('f73b110e-b033-4307-978f-346578d912d9','端平三年春帖子詞 皇帝閤 其一','洪咨夔','宋','宋诗','song-poetry','','[]','龢鳳東風轉，携龍北斗回。',24,'全唐诗/poet.song.189000.json','["龢鳳東風轉，携龍北斗回。", "人間遒鐸振，天上獸樽開。"]'),
('c89f245b-836e-4674-9ba2-6d2653bd9b4c','端平三年春帖子詞 皇帝閤 其二','洪咨夔','宋','宋诗','song-poetry','','[]','冰天寒色餞，暘谷霽華賓。',24,'全唐诗/poet.song.189000.json','["冰天寒色餞，暘谷霽華賓。", "生意乾坤滿，宸襟一點春。"]'),
('a2e3ae97-19e7-4faf-b451-c9fac6da7b13','端平三年春帖子詞 皇帝閤 其三','洪咨夔','宋','宋诗','song-poetry','','[]','寬大朝廷詔，中和郡國詩。',24,'全唐诗/poet.song.189000.json','["寬大朝廷詔，中和郡國詩。", "欲求躋慶曆，先使見淳熙。"]'),
('48c8a9c3-03d9-4d4f-8b5c-7610604b6af7','端平三年春帖子詞 皇帝閤 其四','洪咨夔','宋','宋诗','song-poetry','','[]','喚仗紫宸披曉靄，退朝清燕坐晴霏。',32,'全唐诗/poet.song.189000.json','["喚仗紫宸披曉靄，退朝清燕坐晴霏。", "簡編有味爐熏永，鈴索無聲漏箭稀。"]'),
('d688976f-d6f6-48d7-ac99-ead31484a7ec','端平三年春帖子詞 皇帝閤 其五','洪咨夔','宋','宋诗','song-poetry','','[]','東風送喜上天顔，吉語飛來井軫間。',32,'全唐诗/poet.song.189000.json','["東風送喜上天顔，吉語飛來井軫間。", "榆塞雪消鳴鏑靜，柳營月暖擊刁閑。"]'),
('b5b48e58-e032-45a5-abbe-757cf3adf29b','端平三年春帖子詞 皇帝閤 其六','洪咨夔','宋','宋诗','song-poetry','','[]','麥苗培秀臘前雪，稻種浸芽春後晴。',32,'全唐诗/poet.song.189000.json','["麥苗培秀臘前雪，稻種浸芽春後晴。", "野老田夫觀治象，便從新歲賀升平。"]'),
('88473d8a-b5fb-4046-8c71-68ea88a6219e','端平三年春帖子詞 皇后閤 其一','洪咨夔','宋','宋诗','song-poetry','','[]','太液輕澌泮，溫明霽日融。',24,'全唐诗/poet.song.189000.json','["太液輕澌泮，溫明霽日融。", "菜流芳荇碧，花頌瑞椒紅。"]'),
('b8843242-19ea-466e-b58c-8d6af0b0cb8c','端平三年春帖子詞 皇后閤 其二','洪咨夔','宋','宋诗','song-poetry','','[]','甲觀韶光集，禖壇好語傳。',24,'全唐诗/poet.song.189000.json','["甲觀韶光集，禖壇好語傳。", "思齊男慶百，假樂子宜千。"]'),
('e9fb33b6-6733-4c8e-a165-cd9523c556d4','端平三年春帖子詞 皇后閤 其三','洪咨夔','宋','宋诗','song-poetry','','[]','塗山陰贊夏王化，媯汭密裨虞帝仁。',32,'全唐诗/poet.song.189000.json','["塗山陰贊夏王化，媯汭密裨虞帝仁。", "保合大和無間斷，際天蟠地一般春。"]'),
('aff7c160-41b6-4c83-859c-11eab19f2909','端平三年春帖子詞 皇后閤 其四','洪咨夔','宋','宋诗','song-poetry','','[]','關雎風化冠周南，次第桃夭及葛覃。',32,'全唐诗/poet.song.189000.json','["關雎風化冠周南，次第桃夭及葛覃。", "農事未興先獻種，女紅方起又親蠶。"]'),
('30405752-9dc2-44dd-9339-1d1c3590aba3','端平三年春帖子詞 皇后閤 其五','洪咨夔','宋','宋诗','song-poetry','','[]','殷雷金鑰千門邃，斜月璇題六寢深。',32,'全唐诗/poet.song.189000.json','["殷雷金鑰千門邃，斜月璇題六寢深。", "禁柳護寒鴉未起，求衣已獻晚朝箴。"]'),
('ca4c5155-e727-457f-90e1-3e241ec0ccf2','端平三年春帖子詞 貴妃閤 其一','洪咨夔','宋','宋诗','song-poetry','','[]','梅試催粧粉，蘭披入夢香。',24,'全唐诗/poet.song.189000.json','["梅試催粧粉，蘭披入夢香。", "迎春占北斗，受福拜東皇。"]'),
('e7c79855-4885-4dc4-ae72-2b9bb17048b5','端平三年春帖子詞 貴妃閤 其二','洪咨夔','宋','宋诗','song-poetry','','[]','象應軒龍次，恩承帝座光。',24,'全唐诗/poet.song.189000.json','["象應軒龍次，恩承帝座光。", "燕壇風澹蕩，蠶館日舒長。"]'),
('557813f1-7a22-48ea-8d6a-2b53c3d27efd','端平三年春帖子詞 貴妃閤 其三','洪咨夔','宋','宋诗','song-poetry','','[]','春透蓬萊碧玉壺，晴窗恭侍寶奎敷。',32,'全唐诗/poet.song.189000.json','["春透蓬萊碧玉壺，晴窗恭侍寶奎敷。", "從容玩畫家人卦，取次題箴列女圖。"]'),
('b537837f-b4c6-4ece-a3b7-e88e7005e061','端平三年春帖子詞 貴妃閤 其四','洪咨夔','宋','宋诗','song-poetry','','[]','鳷鵲雪殘籠霽景，鵁鶄波暖颺紋漪。',32,'全唐诗/poet.song.189000.json','["鳷鵲雪殘籠霽景，鵁鶄波暖颺紋漪。", "宮中不用催行樂，草木群生各自熙。"]'),
('1cffbd83-6242-41d5-b151-b8ef795a9401','端平三年春帖子詞 貴妃閤 其五','洪咨夔','宋','宋诗','song-poetry','','[]','萬年枝上綵裁綠，千葉花頭酥點紅。',32,'全唐诗/poet.song.189000.json','["萬年枝上綵裁綠，千葉花頭酥點紅。", "鏡綬囊絲相映燭，探先半月慶流虹。"]'),
('8edcb310-a549-4f4c-ac4d-b54da38bc02b','壽劉宰','洪咨夔','宋','宋诗','song-poetry','','[]','製錦新城衣錦歸，種桃遺愛蒲桃蹊。',64,'全唐诗/poet.song.189000.json','["製錦新城衣錦歸，種桃遺愛蒲桃蹊。", "恩波淮水流不盡，福力螺山高與齊。", "天上已催班玉筍，日邊行見月璇題。", "歡聲都是長生曲，薰作香雲覆寶猊。"]'),
('33f4bc63-975e-44d8-bb33-e7a2eb42d97f','壽劉丞','洪咨夔','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','秋橫岱嶽氣象豪，仰瞻萬仞青且高。',224,'全唐诗/poet.song.189000.json','["秋橫岱嶽氣象豪，仰瞻萬仞青且高。", "上凌層漢直咫尺，下視列岫真兒曹。", "此山萬古儲勝跡，年年人慶東平日。", "誰知此嶽復降神，鍾作南州人第一。", "我公之生超凡塵，申甫當年應此身。", "嶽之大兮公器宇，嶽之秀兮公精神。", "平生節義磨天地，冰雪丰姿了無翳。", "詞鋒凜凜人膽寒，少年斫却月中桂。", "人指杭川水遶東，于今清澈亦如公。", "太平官府能重創，等閑清興獨哦松。", "他年三鳳成名了，笑道雙親猶未老。", "料應坐席煖方生，又赴九天紫泥詔。", "金鴨香濃慶誕神，好看戲綵滿堂新。", "不須把酒殷勤祝，嶽算從來無盡春。"]'),
('370bfaf2-79d7-4d98-8a9b-a3ed522ae083','太后挽詩  其一','洪咨夔','宋','宋诗','song-poetry','','[]','德名三后並，母道兩朝尊。',48,'全唐诗/poet.song.189000.json','["德名三后並，母道兩朝尊。", "勇决高千古，危疑定一言。", "先期還政事，隆禮改山園。", "哀挽西郊道，雲愁晝亦昏。"]'),
('fd3854dc-cc3d-4ab2-89b5-213922fd9fd7','太后挽詩  其二','洪咨夔','宋','宋诗','song-poetry','','[]','扶日行黄道，乘雲上紫微。',48,'全唐诗/poet.song.189000.json','["扶日行黄道，乘雲上紫微。", "憂勞形末命，恭儉見陳衣。", "布德開刑網，和戎戢武威。", "要知懷重處，行路涕交揮。"]'),
('a1e28614-5940-459f-b4d6-d994e4b71659','挽謝疊山','洪咨夔','宋','宋诗','song-poetry','','[]','千古精忠日月光，恨無麟筆寫堂堂。',64,'全唐诗/poet.song.189000.json','["千古精忠日月光，恨無麟筆寫堂堂。", "還家耻作梁江總，辟穀誰如韓子房。", "後死十年應有待，輕生萬里故非狂。", "有兒可拾江邊骨，須信人亡道不亡。"]'),
('19b32b81-4bda-419f-b902-ca55bedd9cb2','送石士志推官赴調','洪咨夔','宋','宋诗','song-poetry','','[]','石友抱奇璞，朅來掾吾邦。',168,'全唐诗/poet.song.189000.json','["石友抱奇璞，朅來掾吾邦。", "昂然凌霄姿，莒鼎獨力扛。", "入幕有此士，諸人亮難雙。", "決事風赴谷，哦詩雨翻江。", "青衫裹妍骨，黑髮今眉龐。", "世無九方皋，誰識驪與駹。", "一朝解綬去，船鼓催逢逢。", "闔府少顔色，我心若爲降。", "倦游方閉門，寄傲但一窗。", "惜別不得餞，况能綴羊腔。", "明廷急才俊，召驛南逾瀧。", "森森鄧林枝，剪拔窮株樁。", "豈其飯牛戚，未作展驥龐。", "早晚對北闕，葉鐘發鯨撞。"]'),
('7aa88fa9-9b44-4203-86ef-fb5d253b18bc','奉使燕山回早行書事','洪咨夔','宋','宋诗','song-poetry','','[]','露滿中庭月滿天，秋來懷抱轉悽然。',64,'全唐诗/poet.song.189000.json','["露滿中庭月滿天，秋來懷抱轉悽然。", "客程恨不日千里，歸思亂如雲一川。", "故國傷心那忍說，遺民望眼幾回穿。", "當家舊事堪垂淚，海上看牛十五年。"]'),
('62d11a72-49d2-4d25-9b77-f9f1363e5e44','姪壽叔祖','洪咨夔','宋','宋诗','song-poetry','','[]','鵲噪梅梢喜報晴，催開幾葉砌邊蓂。',64,'全唐诗/poet.song.189000.json','["鵲噪梅梢喜報晴，催開幾葉砌邊蓂。", "和薰愛日如春日，光動文星映壽星。", "賓客稱觴應滿座，兒孫戲綵自盈庭。", "萱堂幸繼芝蘭末，仰祝百千龜鶴齡。"]'),
('c8b2f9df-7240-454d-8a7e-923083f83fd2','句  其一','洪咨夔','宋','宋诗','song-poetry','','[]','拓罷淮南金戟牙，時平來坐野僧家。',32,'全唐诗/poet.song.189000.json','["拓罷淮南金戟牙，時平來坐野僧家。", "槍旗謾摘社前雨，旌節旋移春後花。"]'),
('5f2eadfd-d654-45b5-a76a-51ca9d60cc34','句  其二','洪咨夔','宋','宋诗','song-poetry','','[]','生憐一架明於雪，終殿群芳嫁却春。',16,'全唐诗/poet.song.189000.json','["生憐一架明於雪，終殿群芳嫁却春。"]'),
('a8a08f90-a5f6-4226-bdb7-a0f5b9cad0c0','句  其三','洪咨夔','宋','宋诗','song-poetry','','[]','風雨寂歷蘆荻秋，梧葉落盡斜陽洲。',16,'全唐诗/poet.song.189000.json','["風雨寂歷蘆荻秋，梧葉落盡斜陽洲。"]'),
('c9e06d2d-4497-4c39-8de2-c985bb99dfbb','默坐偶成  其一','鄭清之','宋','宋诗','song-poetry','','[]','洹河見水老如新，此見云何別妄真。',64,'全唐诗/poet.song.189000.json','["洹河見水老如新，此見云何別妄真。", "心本佛心須作佛，境皆塵境莫隨塵。", "空中花果浮生眼，夢裏悲歡現在身。", "萬事盧胡喫茶去，不知誰主更誰賓。"]'),
('e8c60f70-2072-4ce4-9268-6904ed3c7e14','默坐偶成  其二','鄭清之','宋','宋诗','song-poetry','','[]','底須莫莫更休休，老去浮湛一敝舟。',64,'全唐诗/poet.song.189000.json','["底須莫莫更休休，老去浮湛一敝舟。", "病惱幻軀天惡劇，醉尋熟睡我先籌。", "眼前勤惰書開闔，窗下陰晴雨散收。", "假使莊生夢爲蝶，也應貸粟監河侯。"]'),
('1dbe0e32-b38a-4e31-94d5-a302aab0fe10','默坐偶成  其三','鄭清之','宋','宋诗','song-poetry','','[]','睡魔勾引鶴投林，書債中拋筆似瘖。',64,'全唐诗/poet.song.189000.json','["睡魔勾引鶴投林，書債中拋筆似瘖。", "尚有烏髭贏白髮，擬尋朱汞養黄金。", "寸機解起千疆畝，一息能藏萬古今。", "塵世何人是知己，推窗明月正當心。"]'),
('8b4a3d44-ffef-440f-9ed6-beaa767b8888','追記覺際偶成','鄭清之','宋','宋诗','song-poetry','','[]','我到家山雪尚飛，看看寒食展歸期。',64,'全唐诗/poet.song.189000.json','["我到家山雪尚飛，看看寒食展歸期。", "花開無酒蝶貽笑，春盡不吟鶑有辭。", "窗下竹君陪晤對，手中杖子共追隨。", "閑來自唱無生曲，井底泥蛇舞柘枝。"]'),
('0bf2e47a-d7a6-4a54-9f00-b90aa25f8df6','靜極','鄭清之','宋','宋诗','song-poetry','','[]','磨磚豈解成明鏡，打坐如何作佛身。',32,'全唐诗/poet.song.189000.json','["磨磚豈解成明鏡，打坐如何作佛身。", "靜閙頭頭須認着，暑中冰凍雪中春。"]'),
('a7d60a0f-b6c7-4589-906a-0db00aba0914','燈薪','鄭清之','宋','宋诗','song-poetry','','[]','小草虛心不染塵，傳燈會上屢焚身。',32,'全唐诗/poet.song.189000.json','["小草虛心不染塵，傳燈會上屢焚身。", "光明一點元無盡，謾結空花作好春。"]'),
('98042fde-70bc-4009-9412-21313cb69efd','臂疼醫令灼艾戲成','鄭清之','宋','宋诗','song-poetry','','[]','幻體當如泡影觀，法身清浄本堅完。',32,'全唐诗/poet.song.189000.json','["幻體當如泡影觀，法身清浄本堅完。", "四千八萬陀羅臂，艾炷教君何處安。"]'),
('44b6c80d-75ee-4f80-ab10-44733c79fa79','食豆莢','鄭清之','宋','宋诗','song-poetry','','[]','西風摵摵草蟲鳴，萬莢叢中詫瑞蓂。',32,'全唐诗/poet.song.189000.json','["西風摵摵草蟲鳴，萬莢叢中詫瑞蓂。", "煮啖快輸兒女吻，燃萁不忍尚堆青。"]'),
('7baba3c2-980c-49d8-9f19-2941d7bbfc00','臂疼自砭','鄭清之','宋','宋诗','song-poetry','','[]','雲長鑿骨未爲奇，斷臂亭亭對祖師。',32,'全唐诗/poet.song.189000.json','["雲長鑿骨未爲奇，斷臂亭亭對祖師。", "萬法從心當自省，箇中冷暖有魚知。"]'),
('c9b518dc-e4eb-4e92-838a-6a6c2cd1d777','有感','鄭清之','宋','宋诗','song-poetry','','[]','子思問學惟誠意，孟氏工夫只反身。',32,'全唐诗/poet.song.189000.json','["子思問學惟誠意，孟氏工夫只反身。", "定慧妙明何處覓，要知儒釋共天真。"]'),
('0abc3f9e-8f38-47e9-a61a-2f725c06fe57','秋色佳甚未能一到覺際像景謾賦二絕  其一','鄭清之','宋','宋诗','song-poetry','','[]','秋光澹薄有無間，掠水斜風雨脚斑。',32,'全唐诗/poet.song.189000.json','["秋光澹薄有無間，掠水斜風雨脚斑。", "試向菰蒲深處望，嫩黄一點荇花閑。"]'),
('96252c5d-55bc-4cc7-be82-cf486bdb12e3','秋色佳甚未能一到覺際像景謾賦二絕  其二','鄭清之','宋','宋诗','song-poetry','','[]','藕花萬柄歛春妝，賸駐霜荷葺芰裳。',32,'全唐诗/poet.song.189000.json','["藕花萬柄歛春妝，賸駐霜荷葺芰裳。", "水路想通漁艇入，我來月下要鳴榔。"]'),
('86178fde-cb0c-4de6-bb3d-baecc4d8a326','感風悶坐戲成六言一首示雲岑','鄭清之','宋','宋诗','song-poetry','','[]','夢覺無兩莊子，是非只一東坡。',84,'全唐诗/poet.song.189000.json','["夢覺無兩莊子，是非只一東坡。", "顔淵簞食爲樂，啟期带索行歌。", "魯侯不遇天也，伯寮其如命何。", "世事如棋新局，人生落葉辭柯。", "誰人見張平叔，何處覓藍采和。", "且服單方妙藥，般若波羅蜜多。"]'),
('af2969d6-482d-471c-b8eb-032b848bbcdd','秋成風雨','鄭清之','宋','宋诗','song-poetry','','[]','垂垂金穎賀秋成，去逐狂風一羽輕。',32,'全唐诗/poet.song.189000.json','["垂垂金穎賀秋成，去逐狂風一羽輕。", "何事天工惡戲劇，眼前翻覆見虧盈。"]'),
('e64f1618-d191-4a8e-8641-9e56e9b69c4d','雨後閑坐偶成','鄭清之','宋','宋诗','song-poetry','','[]','秋霖得晚晴，景色似郊坰。',48,'全唐诗/poet.song.189000.json','["秋霖得晚晴，景色似郊坰。", "山向閑中碧，雲從闕處青。", "簷牙抽宿溜，木杪掛疎星。", "一枕便高卧，清風入暑欞。"]'),
('d95c430e-4bb7-4c30-a94c-f673d2212b20','兀坐','鄭清之','宋','宋诗','song-poetry','','[]','夜聽寒蛩曉聽蟬，梧桐疎雨晚秋天。',32,'全唐诗/poet.song.189000.json','["夜聽寒蛩曉聽蟬，梧桐疎雨晚秋天。", "空齋抱膝元無事，半是癡憨半是禪。"]'),
('3a49a3ae-c442-4944-9fbd-6cff6cfc2730','香山老惠兩貓','鄭清之','宋','宋诗','song-poetry','','[]','殺活禪機本自由，順行逆用總先籌。',32,'全唐诗/poet.song.189000.json','["殺活禪機本自由，順行逆用總先籌。", "伽梨親抱貍奴送，管是南泉是趙州。"]'),
('be794fd1-fb97-45db-b515-4f738a7d096b','香山貓食粥','鄭清之','宋','宋诗','song-poetry','','[]','梵宮新遣兩貍奴，晨粥饑餐食肉如。',32,'全唐诗/poet.song.189000.json','["梵宮新遣兩貍奴，晨粥饑餐食肉如。", "料是伊蒲三昧熟，未知繞膝訴無魚。"]'),
('4d30fb73-0e25-4d48-beaf-7b57e293f5c0','冬瓜','鄭清之','宋','宋诗','song-poetry','','[]','剪剪黄花秋後春，霜皮露葉護長身。',32,'全唐诗/poet.song.189000.json','["剪剪黄花秋後春，霜皮露葉護長身。", "生來籠統君休笑，腹裏能容數百人。"]'),
('20b811a1-ede1-4889-9b45-2852459f6e90','茄子','鄭清之','宋','宋诗','song-poetry','','[]','青紫皮膚類宰官，光圓頭腦作僧看。',32,'全唐诗/poet.song.189000.json','["青紫皮膚類宰官，光圓頭腦作僧看。", "如何緇俗偏同嗜，入口元來總一般。"]'),
('296d5f4a-6a14-4087-bbf8-474688975bc8','贈李相士','鄭清之','宋','宋诗','song-poetry','','[]','未遇公卿儘好看，會將碧眼照人寒。',32,'全唐诗/poet.song.189000.json','["未遇公卿儘好看，會將碧眼照人寒。", "邯鄲夢覺君休問，試卜何時可掛冠。"]'),
('126338bc-9b9b-4ff8-b671-ed34b0f58c8c','七月初五日城中大風雨','鄭清之','宋','宋诗','song-poetry','','[]','颶風超海撼官城，吹斷銀河徹曉傾。',64,'全唐诗/poet.song.189000.json','["颶風超海撼官城，吹斷銀河徹曉傾。", "瓦陣飛翻千鵠起，屐聲旁午萬蛙鳴。", "駢肩重足人如醉，湧溜奔雲氣未平。", "誰與箋天如帝律，毒龍斥去鎖東瀛。"]'),
('ce3e040f-762c-49c4-ab1b-de862c8ed30e','聞覺際被風寄頔老','鄭清之','宋','宋诗','song-poetry','','[]','古德把茅惟蓋頭，颶風飄屋等虛舟。',32,'全唐诗/poet.song.189000.json','["古德把茅惟蓋頭，颶風飄屋等虛舟。", "矮窗猶有蒲團滑，也勝床前衮雪毬。"]'),
('8de5a18d-23e2-4f60-afda-94fff7fe5ea8','督覺際蒔菜','鄭清之','宋','宋诗','song-poetry','','[]','秋後從來數晚菘，自鋤稀甲幾多叢。',32,'全唐诗/poet.song.189000.json','["秋後從來數晚菘，自鋤稀甲幾多叢。", "莫辭榾榾頻携甕，準擬清饞玉糝翁。"]'),
('d8aeb341-ab24-4df6-bbdf-03efd1856da6','偶記賦王昭君謾錄之','鄭清之','宋','宋诗','song-poetry','','[]','伐國曾聞用女戎，忍留妖麗漢宮中。',64,'全唐诗/poet.song.189000.json','["伐國曾聞用女戎，忍留妖麗漢宮中。", "如知褒姒貽周患，須信巫臣爲楚忠。", "青冢不遺芳草恨，白溝那得戰塵空。", "解移尤物柔强虜，延壽當年合議功。"]'),
('82c90d74-be86-412c-bcb8-e0d150668588','八月初五夢桃杏枝上皆小蕊頃刻間一花先開既而次第皆拆色殊紅鮮可愛夢中爲賦一詩覺但記其第二句戲足成之','鄭清之','宋','宋诗','song-poetry','','[]','天孫紅錦淺深裁，爲惜芳苞未肯開。',32,'全唐诗/poet.song.189000.json','["天孫紅錦淺深裁，爲惜芳苞未肯開。", "爭奈東風披拂甚，枝頭次第吐香腮。"]'),
('e913fd7b-9088-4b21-a439-595719072755','贈談命陳總屬','鄭清之','宋','宋诗','song-poetry','','[]','彈鋏朱門歲月過，生涯安樂遍行窩。',64,'全唐诗/poet.song.189000.json','["彈鋏朱門歲月過，生涯安樂遍行窩。", "談天有口機關別，處世無心笑語多。", "自是君平忠孝在，其如曼倩滑稽何。", "一帆又作鴟夷去，遥想江湖聽踏歌。"]'),
('79eb5994-5a71-4ff0-8913-ac64d20b352e','八月上弦夕','鄭清之','宋','宋诗','song-poetry','','[]','輕風熨貼晚雲開，爲放中秋半月來。',32,'全唐诗/poet.song.189000.json','["輕風熨貼晚雲開，爲放中秋半月來。", "待得月圓多值雨，不如今夕共罇罍。"]'),
('212b9ba5-e9d7-4a1b-9661-9806b882d529','覺際閑坐紀所見','鄭清之','宋','宋诗','song-poetry','','[]','蛛網雨中時恤緯，蜂屯衙後自嬰城。',32,'全唐诗/poet.song.189000.json','["蛛網雨中時恤緯，蜂屯衙後自嬰城。", "竹根得土筍爭長，紙隙受風窗善鳴。"]'),
('0bbd7d89-5391-4943-bece-c615bcff8832','食蛤戲成','鄭清之','宋','宋诗','song-poetry','','[]','滿殻濡潮汐，因沙産海滣。',48,'全唐诗/poet.song.189000.json','["滿殻濡潮汐，因沙産海滣。", "文身吳太伯，緘口魯銅人。", "雀化宜分雋，蛙烹肯擬倫。", "試呈饕賦手，半熟酒含津。"]'),
('ed1e912b-84ac-4d1a-8298-ed27ddfc7630','督覺際植花  其一','鄭清之','宋','宋诗','song-poetry','','[]','桂後秋蘭解出奇，幽香元不許春知。',32,'全唐诗/poet.song.189000.json','["桂後秋蘭解出奇，幽香元不許春知。", "移根好向它山覓，承受風光到菊籬。"]'),
('c85cfaec-3796-4a6a-9867-0ec01ecdb3f6','督覺際植花  其二','鄭清之','宋','宋诗','song-poetry','','[]','兄弟梅礬是水仙，曝根向暖種宜先。',32,'全唐诗/poet.song.189000.json','["兄弟梅礬是水仙，曝根向暖種宜先。", "銀臺金盞惟須酒，不可無渠對雪天。"]'),
('821863de-acc8-46be-85e6-44f40a323c4f','催覺際殖芥','鄭清之','宋','宋诗','song-poetry','','[]','淡交耐久最宜蔬，風味清嚴莫芥如。',32,'全唐诗/poet.song.189000.json','["淡交耐久最宜蔬，風味清嚴莫芥如。", "沃壤深畦須蚤計，雪中滿擬飫冰葅。"]'),
('b42f2377-a860-4c0c-8997-b1f0e19d1ede','觀書','鄭清之','宋','宋诗','song-poetry','','[]','肝脾何藥解清虛，不用參苓不㕮咀。',32,'全唐诗/poet.song.189000.json','["肝脾何藥解清虛，不用參苓不㕮咀。", "一種單方無授受，明窗端坐只觀書。"]'),
('657544ba-b492-40a5-91eb-921d0a49c9ef','夜雨','鄭清之','宋','宋诗','song-poetry','','[]','依風急雨墊秋清，疎數無時總有聲。',32,'全唐诗/poet.song.189000.json','["依風急雨墊秋清，疎數無時總有聲。", "最是可憐雲裏月，幾番陰翳幾番明。"]'),
('a1f498c7-ce60-4d3b-b80a-ac3efd58bb6c','睡起戲筆','鄭清之','宋','宋诗','song-poetry','','[]','范蠡功成便五湖，鴟夷未了復陶朱。',32,'全唐诗/poet.song.189000.json','["范蠡功成便五湖，鴟夷未了復陶朱。", "爭如終老嚴陵釣，千古清名一事無。"]'),
('26045eea-edda-48ef-8c17-66f62c76eb31','謝天童老秋蘭  其一','鄭清之','宋','宋诗','song-poetry','','[]','楚畹春曾汎曉光，直留雅艷到虹藏。',32,'全唐诗/poet.song.189000.json','["楚畹春曾汎曉光，直留雅艷到虹藏。", "山中不把一枝到，世外那聞千佛香。"]'),
('fae5d316-e9f8-43b8-b810-f7432e8ee1b7','謝天童老秋蘭  其二','鄭清之','宋','宋诗','song-poetry','','[]','秋色追隨入慧光，肯携幽卉問行藏。',32,'全唐诗/poet.song.189000.json','["秋色追隨入慧光，肯携幽卉問行藏。", "深林未省炎凉態，來爲閑人特地香。"]'),
('4762cf94-9f0c-4076-adaf-0bcdc8675d7b','謝天童老秋蘭  其三','鄭清之','宋','宋诗','song-poetry','','[]','綠葉青青带紫光，拈來笑處沒遮藏。',32,'全唐诗/poet.song.189000.json','["綠葉青青带紫光，拈來笑處沒遮藏。", "密圓應具楞嚴偈，非木非空出妙香。"]'),
('1e2bb637-5aab-4ab6-9e06-3f6f689f6285','夜雨不睡  其一','鄭清之','宋','宋诗','song-poetry','','[]','浮湛世事付洪喬，欹枕迢迢度永宵。',64,'全唐诗/poet.song.189000.json','["浮湛世事付洪喬，欹枕迢迢度永宵。", "雨細無聲簷溜滴，香殘有燼篆煙銷。", "翻盆碩鼠全欺暗，繞鬢飛蚊始作嬌。", "老去易驚寒暑變，幾多今夕又明朝。"]'),
('755bcb34-714b-46c2-8960-c4146a466e0e','夜雨不睡  其二','鄭清之','宋','宋诗','song-poetry','','[]','少日無歡老易愁，鶑花過眼一春休。',64,'全唐诗/poet.song.189000.json','["少日無歡老易愁，鶑花過眼一春休。", "清虛未解窮聃釋，情思誰能更孔周。", "白醉蹔煩簷送暖，蒼顔惟恐鏡包羞。", "爭知一點天然物，不共浮生作去留。"]'),
('5d89cbe5-7a43-483e-9123-94efbf7ad434','育王老禪屢惠佳茗比又携日鑄爲餉因言久則味失師授以焙藏之法必有以專之笑謂非力所及謾成拙語解嘲錄以爲謝','鄭清之','宋','宋诗','song-poetry','','[]','曾讀茶經如讀律，一物不備茶不出。',224,'全唐诗/poet.song.189000.json','["曾讀茶經如讀律，一物不備茶不出。", "未論煮瀹應節度，第一收藏在堅密。", "摘鮮封裹須焙芳，濕蒸爲寇防侵疆。", "朝屯暮蒙要微火，九轉溫養如丹房。", "育王老慧老茶事，新授秘訣乃如此。", "幾番惠我先春芽，朅來細問茶何似。", "我初謂師茶絕奇，十日之後如飲糜。", "頗疑緇俗果異撰，良苦輒爲居所移。", "吾言未終師絕叫，爲茶傳法恨不早。", "綺疏應合有司存，料理如前毋草草。", "對師大笑面欲靴，三年宰相食無鮭。", "長鬚赤脚供井臼，荒寒政類山人家。", "扊扅炊盡瓶笙吼，何曾敲雪春雲走。", "不如時扣趙州門，侍者可人長摸首。"]'),
('cdca88aa-fa13-476f-8da3-7b5eaff25d0a','竹下見蘭','鄭清之','宋','宋诗','song-poetry','','[]','竹下幽香祗自知，孤高終近歲寒姿。',32,'全唐诗/poet.song.189000.json','["竹下幽香祗自知，孤高終近歲寒姿。", "垂楊曼舞多嬌態，倚頼東風得幾時。"]'),
('618225b5-5c55-4d2f-ae24-7c87f22e82ce','小軒偶成','鄭清之','宋','宋诗','song-poetry','','[]','齋餘宴坐息深深，萬法皆閑境會心。',64,'全唐诗/poet.song.189000.json','["齋餘宴坐息深深，萬法皆閑境會心。", "輕浪颭荷珠溜玉，晴曦穿竹翠籠金。", "岸頭舟楫人歸語，檻外菰蒲鳥去音。", "謾說陶車并謝屐，如如不動勝登臨。"]'),
('ba4aa24a-3376-4d9b-b98b-2c6a97c8f026','舊冬得蔞蒿數十根植之舍傍今春遂可採擷輒持羾黄堂拙語先之聊發一笑','鄭清之','宋','宋诗','song-poetry','','[]','蔞蒿見錄爾雅篇，族譜系出荆楚壖。',288,'全唐诗/poet.song.189000.json','["蔞蒿見錄爾雅篇，族譜系出荆楚壖。", "居人采擷不論錢，橫道𨈆轢如車前。", "物有貴賤所遇然，雞壅豕苓以帝言。", "世間何有正味焉，耆芰昌歜性所便。", "冰壺先生虀甕傳，敢驕玉食輕膏羶。", "天隨酷謂杞菊賢，一賦金石聲相宣。", "玉糝羹芋稱蘇仙，天上酥酡能比肩。", "憶昔客授湘湖偏，乍逢此蒿口流涎。", "嚼寒冰玉香滿咽，紺滑琉璃鳴貝編。", "糅以豚膏軟如綿，脆甘豐膩潔且鮮。", "天花石耳羞爭妍，木雞退飛山之巔。", "笑渠芽蕨成兒拳，岸視橰圃眉宇軒。", "七葅五菜誰敢先，獨能兄事玉版禪。", "一別楚産知幾年，孤根朅來植鄞川。", "春苗出土含曉煙，援條小摘喜欲癲。", "故人千里方言還，調芼酌之雙觥船。", "枯腸慰滿藜莧緣，食芹而美不敢專。", "遣送兵厨羞俎籩，噴飯一笑篔簹邊。"]'),
('9394624a-110a-4894-b7fc-c761d8a44d36','太史報彗星沒','鄭清之','宋','宋诗','song-poetry','','[]','老彗妖芒欲爇天，王良見迫爲收鞭。',32,'全唐诗/poet.song.189000.json','["老彗妖芒欲爇天，王良見迫爲收鞭。", "紫微一夜璣衡轉，甘雨祥風到野田。"]'),
('a9dcaae8-e90b-4e42-b600-f9bde4234be4','謝虛齋和詩','鄭清之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','關心穡事恐春遲，蹔許花風入繡旗。',64,'全唐诗/poet.song.189000.json','["關心穡事恐春遲，蹔許花風入繡旗。", "翠浪半天岐麥詠，玉簪數筯刈蔞詩。", "野亭寄韵追唐什，秋菊餐芳敵楚辭。", "早晚催歸漢廷右，西湖深處樂天碑。"]'),
('31263e39-3c3f-4a4e-8195-81c63c74851f','和虛齋勸農十詩  其一','鄭清之','宋','宋诗','song-poetry','','[]','迢遞層陰曉自開，仙舟花底問瀛萊。',32,'全唐诗/poet.song.189000.json','["迢遞層陰曉自開，仙舟花底問瀛萊。", "文章太守非遊衍，爲省春耕特地來。"]'),
('3329ada0-0e85-4393-ad7c-9dc40808eb8f','和虛齋勸農十詩  其二','鄭清之','宋','宋诗','song-poetry','','[]','爇天妖焰彗初沉，朝汲仁賢簡帝心。',32,'全唐诗/poet.song.189000.json','["爇天妖焰彗初沉，朝汲仁賢簡帝心。", "未用鋒車便脂牽，小須千里遍春霖。"]'),
('b61bfe42-e8d9-4f2c-be64-474a3ae7a00d','和虛齋勸農十詩  其三','鄭清之','宋','宋诗','song-poetry','','[]','蔽日寒雲悄欲秋，仁風載路曉光浮。',32,'全唐诗/poet.song.189000.json','["蔽日寒雲悄欲秋，仁風載路曉光浮。", "田翁攬抱兒孫笑，竹馬橫陳未肯休。"]'),
('ef875062-f307-4881-85a5-b898d3d7c3f7','和虛齋勸農十詩  其四','鄭清之','宋','宋诗','song-poetry','','[]','問訊桑麻真郡政，按行松菊似家山。',32,'全唐诗/poet.song.189000.json','["問訊桑麻真郡政，按行松菊似家山。", "挽回和氣歸田里，只費齋鈴半日閑。"]'),
('700ebdfb-9b94-4e55-9609-0788b7aedcc3','和虛齋勸農十詩  其五','鄭清之','宋','宋诗','song-poetry','','[]','暇日棋書六一翁，錦檣絲轡與春逢。',32,'全唐诗/poet.song.189000.json','["暇日棋書六一翁，錦檣絲轡與春逢。", "年時豹尾車中望，山色有無知幾重。"]'),
('3079a8f5-bdda-41b9-808e-cd984fcbd81d','和虛齋勸農十詩  其六','鄭清之','宋','宋诗','song-poetry','','[]','曉夢吟成望帝歸，征鞍未許柳絲知。',32,'全唐诗/poet.song.189000.json','["曉夢吟成望帝歸，征鞍未許柳絲知。", "笑聽鄮嶺春禽哢，去博延英午漏遲。"]'),
('73b02885-82fa-47e0-9997-436795eee3c6','和虛齋勸農十詩  其七','鄭清之','宋','宋诗','song-poetry','','[]','酡顔醉客玉西東，半濕塵衫上翠空。',32,'全唐诗/poet.song.189000.json','["酡顔醉客玉西東，半濕塵衫上翠空。", "鄒谷雖寒應解黍，朱車面面是春風。"]'),
('6fd83382-e79c-4ef1-935d-5003cde41fc9','和虛齋勸農十詩  其八','鄭清之','宋','宋诗','song-poetry','','[]','小隊旌旗半道歸，松陰緩策攬清暉。',32,'全唐诗/poet.song.189000.json','["小隊旌旗半道歸，松陰緩策攬清暉。", "女郎未覺褰帷過，笑語相教着嫁衣。"]'),
('8748ded6-d01a-441d-970e-ea122894acde','和虛齋勸農十詩  其九','鄭清之','宋','宋诗','song-poetry','','[]','老黠山靈具六通，解將蒼狗護奇峰。',32,'全唐诗/poet.song.189000.json','["老黠山靈具六通，解將蒼狗護奇峰。", "虛齋自有青囊眼，却笑景純書未工。"]'),
('d90493ab-7ad0-438b-acdb-86b932c1e2d1','和虛齋勸農十詩  其一○','鄭清之','宋','宋诗','song-poetry','','[]','恰好農時踏翠煙，睡龍驚起雨公田。',32,'全唐诗/poet.song.189000.json','["恰好農時踏翠煙，睡龍驚起雨公田。", "官程便作乘閑看，不用扁舟學計然。"]'),
('4b13a59c-9f51-4233-9af8-31502d9867f6','宿翠山  其一','鄭清之','宋','宋诗','song-poetry','','[]','箯輿十里見青嶄，行盡松陰得翠巖。',64,'全唐诗/poet.song.189000.json','["箯輿十里見青嶄，行盡松陰得翠巖。", "萬壑聲中清磬出，一峰高處白雲緘。", "茶新煮鼎作魚沫，僧有可人能麈談。", "自覺靈山緣境熟，佛禪重問後三三。"]'),
('e79f8a58-1670-43b7-ba5c-60f96b87ffaf','宿翠山  其二','鄭清之','宋','宋诗','song-poetry','','[]','暖風依日佐山行，幾許春隨屐齒生。',64,'全唐诗/poet.song.189000.json','["暖風依日佐山行，幾許春隨屐齒生。", "溪舞綠雲苔出沒，田翻翠浪麥斜橫。", "閑中適意榮三事，歲晚無年式耦耕。", "一靜可能銷幻藥，剩開胸次着崢嶸。"]'),
('6e5ec509-60cd-4a03-8e84-11e3857655ad','和葺芷應直院送秋蘭韵','鄭清之','宋','宋诗','song-poetry','','[]','大椿凌千秋，靈芝競三秀。',84,'全唐诗/poet.song.189000.json','["大椿凌千秋，靈芝競三秀。", "書傳遞誇詡，垂芳古今宙。", "貴耳但奇奇，相馬失之瘦。", "誰知楚醒花，遠避漢金酎。", "擇交得素節，彼哉懷春誘。", "夫君全德馨，內美本吾有。", "姑置芝與椿，秋蘭歲相壽。"]'),
('0795ae36-6483-47aa-85a1-f18979a279a1','南坡口號十八首  其一','鄭清之','宋','宋诗','song-poetry','','[]','十日南坡兩日晴，晴時不放日華明。',32,'全唐诗/poet.song.189000.json','["十日南坡兩日晴，晴時不放日華明。", "春光似妬閑人佔，端的春風飽世情。"]'),
('7aa5dc9b-a102-447d-9bba-fb6a6cfc9fa2','南坡口號十八首  其二','鄭清之','宋','宋诗','song-poetry','','[]','天工忽忽度年光，料理人間富貴忙。',32,'全唐诗/poet.song.189000.json','["天工忽忽度年光，料理人間富貴忙。", "閑裏何曾關造物，一分風景亦收藏。"]'),
('5e35bd23-9c28-49f8-a559-5091b44fff3c','南坡口號十八首  其三','鄭清之','宋','宋诗','song-poetry','','[]','誰將春晚作冬看，添着綿衣減却難。',32,'全唐诗/poet.song.189000.json','["誰將春晚作冬看，添着綿衣減却難。", "道是麥寒猶未在，願渠麥熟且禁寒。"]'),
('677ff73f-39b4-4fea-92f4-24f81820e366','南坡口號十八首  其四','鄭清之','宋','宋诗','song-poetry','','[]','休言無地起樓臺，十箇花窠沒處栽。',32,'全唐诗/poet.song.189000.json','["休言無地起樓臺，十箇花窠沒處栽。", "東近比鄰西近水，且教紅白面牆開。"]'),
('8923a575-064c-4726-8f8a-18aadd6a185c','南坡口號十八首  其五','鄭清之','宋','宋诗','song-poetry','','[]','欲識魚梁試作看，輕拋野淥罩清寒。',32,'全唐诗/poet.song.189000.json','["欲識魚梁試作看，輕拋野淥罩清寒。", "幾回漉起空無物，輸殺羣兒下釣竿。"]'),
('af6aa558-67b8-4dfc-aab0-e472cc76808f','南坡口號十八首  其六','鄭清之','宋','宋诗','song-poetry','','[]','吾孫宗子喜相過，一笑檀欒似樂窩。',32,'全唐诗/poet.song.189000.json','["吾孫宗子喜相過，一笑檀欒似樂窩。", "且向尊中陪北海，直須閑裏識南坡。"]'),
('223ea74e-43f1-42a7-bd81-1f69fdb93a43','南坡口號十八首  其七','鄭清之','宋','宋诗','song-poetry','','[]','酷愛鳥鳴山更幽，牆陰風雨但颼颼。',32,'全唐诗/poet.song.189000.json','["酷愛鳥鳴山更幽，牆陰風雨但颼颼。", "筠籠買得春禽語，不會憂時也白頭。"]'),
('99e9d60b-6804-4d80-95f4-ccf6497fe213','南坡口號十八首  其八','鄭清之','宋','宋诗','song-poetry','','[]','管絃不礙登山屐，粱肉何妨滿腹書。',32,'全唐诗/poet.song.189000.json','["管絃不礙登山屐，粱肉何妨滿腹書。", "豈是清談愧夷甫，爲無阿堵繞吾廬。"]'),
('7713a5d8-0ffa-4bd7-abee-74b5901beac8','南坡口號十八首  其九','鄭清之','宋','宋诗','song-poetry','','[]','試向清池放小鮮，洋洋圉圉忽攸然。',32,'全唐诗/poet.song.189000.json','["試向清池放小鮮，洋洋圉圉忽攸然。", "校人真箇知魚樂，殺活機鋒總是禪。"]'),
('6be3d319-747f-490a-a1b7-6ff8ae1ffa18','南坡口號十八首  其一○','鄭清之','宋','宋诗','song-poetry','','[]','分席春畦僅一弓，靈根移自石窗東。',32,'全唐诗/poet.song.189000.json','["分席春畦僅一弓，靈根移自石窗東。", "饒渠五味誇仙藥，爭似鹽梅正策功。"]'),
('80cb1b39-091a-440a-902f-edd5540e2c8a','南坡口號十八首  其一一','鄭清之','宋','宋诗','song-poetry','','[]','紛綸兒造信多才，果解分風作去來。',32,'全唐诗/poet.song.189000.json','["紛綸兒造信多才，果解分風作去來。", "我向南坡一旬雨，春陰今曉爲誰開。"]'),
('fe8c649d-b6f7-4457-bcc5-cedf8b8a89f5','南坡口號十八首  其一二','鄭清之','宋','宋诗','song-poetry','','[]','小窗白醉篆香遲，只有書君伴燕頤。',32,'全唐诗/poet.song.189000.json','["小窗白醉篆香遲，只有書君伴燕頤。", "料得人間無此樂，殷勤獻與定牢辭。"]'),
('91a3715a-b447-4a6e-99ac-a18ea87d6226','南坡口號十八首  其一三','鄭清之','宋','宋诗','song-poetry','','[]','枝筇掛起一旬彊，剪剪春寒到柳塘。',32,'全唐诗/poet.song.189000.json','["枝筇掛起一旬彊，剪剪春寒到柳塘。", "白髮不公欺老我，偏於閑處引風霜。"]'),
('2b8b6de9-e4f9-4c86-a103-608e1518680d','南坡口號十八首  其一四','鄭清之','宋','宋诗','song-poetry','','[]','記得兒時誦古詩，其甘如薺謂吾欺。',32,'全唐诗/poet.song.189000.json','["記得兒時誦古詩，其甘如薺謂吾欺。", "淡交休恨相知晚，携向晶盤笑殺伊。"]'),
('66eec841-2e5f-4d22-b1dc-535d7663a1a3','南坡口號十八首  其一五','鄭清之','宋','宋诗','song-poetry','','[]','曉來兩鵲屋山鳴，報喜多應只報晴。',32,'全唐诗/poet.song.189000.json','["曉來兩鵲屋山鳴，報喜多應只報晴。", "似爲東皇傳好語，故留勝賞到清明。"]'),
('a7de7056-93f5-470e-9630-c8c31c40e71c','南坡口號十八首  其一六','鄭清之','宋','宋诗','song-poetry','','[]','舊日都城飫子魚，一鱗今不到茅廬。',32,'全唐诗/poet.song.189000.json','["舊日都城飫子魚，一鱗今不到茅廬。", "果然額上通三印，盡去侯門代鯉書。"]'),
('873df1d9-c95b-4495-8a6e-22df0a25e2d5','南坡口號十八首  其一七','鄭清之','宋','宋诗','song-poetry','','[]','安晚生涯冷似灰，別墅經營半月迴。',32,'全唐诗/poet.song.189000.json','["安晚生涯冷似灰，別墅經營半月迴。", "誇與兒郎翁驟富，詩囊盈握送陳雷。"]'),
('f89a2ed2-115a-4a5c-a5a9-7634b7e77aa4','南坡口號十八首  其一八','鄭清之','宋','宋诗','song-poetry','','[]','紅紅白白共枝榮，怪底山茶有寧馨。',32,'全唐诗/poet.song.189000.json','["紅紅白白共枝榮，怪底山茶有寧馨。", "倩得司花來判斷，不妨一姓養螟蛉。"]'),
('0122ae49-52aa-4c41-a292-c2117442a441','辛丑仲春同黄制屬自延壽雨過禪寂','鄭清之','宋','宋诗','song-poetry','','[]','箯輿掠雨到僧門，带得清閑一二分。',64,'全唐诗/poet.song.189000.json','["箯輿掠雨到僧門，带得清閑一二分。", "素喜堂中無偃月，朅來寺裏作穿雲。", "赤心莫逆唯松友，青眼相看有竹君。", "燒葉更聯東野句，紙窗鑽隙候晴曛。"]'),
('276a7907-102e-4b41-a5f3-61ff02edf401','病後和黄玉泉韵  其一','鄭清之','宋','宋诗','song-poetry','','[]','山扉連月款言巵，擬共還家浣客衣。',64,'全唐诗/poet.song.189000.json','["山扉連月款言巵，擬共還家浣客衣。", "愧失養生收一溉，笑擒夢豎竄三危。", "大槐安國休重省，兜率陀天尚緩歸。", "一病一衰秋後雨，孰言之武老能爲。"]'),
('270d6ec7-2804-4382-9409-c672210dcad0','病後和黄玉泉韵  其二','鄭清之','宋','宋诗','song-poetry','','[]','赤明瀹篆正恢台，戲挹雄風滌悶懷。',64,'全唐诗/poet.song.189000.json','["赤明瀹篆正恢台，戲挹雄風滌悶懷。", "病骨喜隨新籜換，好詩忽餽寶珠來。", "巨魚未縱王褒壑，陋室聊淹禹錫階。", "且共理身如理國，小須握手詠康哉。"]'),
('8cb1793c-4d3e-4e27-894a-e69c8faf8eaa','再和前韵  其一','鄭清之','宋','宋诗','song-poetry','','[]','爲乏刀圭飲卯巵，黄庭空想衣朱衣。',64,'全唐诗/poet.song.189000.json','["爲乏刀圭飲卯巵，黄庭空想衣朱衣。", "三田未遣三彭去，九軌幾成九折危。", "瘦骨可能支夜永，醉鄉那復挽春歸。", "亦知有客真佳甚，握手還須笑樂爲。"]'),
('a63645a5-e08f-41c3-a372-2949c38b7290','再和前韵  其二','鄭清之','宋','宋诗','song-poetry','','[]','若時風雨候三台，憂國豐年幾入懷。',64,'全唐诗/poet.song.189000.json','["若時風雨候三台，憂國豐年幾入懷。", "執戟未愁方朔死，閉門唯喜子桑來。", "人間宰相真如夢，天上羣仙詎可階。", "事業鏤冰何所有，之乎者也矣焉哉。"]'),
('472fa3a6-6351-4d3d-9912-a6a6f0a990ad','再和前韵  其三','鄭清之','宋','宋诗','song-poetry','','[]','轅門怒髮彘肩巵，計相當年笑解衣。',64,'全唐诗/poet.song.189000.json','["轅門怒髮彘肩巵，計相當年笑解衣。", "誰識英雄千古意，肯論性命一絲危。", "伏波卧看飛鳶墮，杜曲生憐獨鶴歸。", "自愧此身成濩落，空搔種種欲何爲。"]'),
('3c19cc37-a948-41d6-9ace-fdc9bdb4ea6c','再和前韵  其四','鄭清之','宋','宋诗','song-poetry','','[]','遂初雅喜賦天台，牆月東邊謾古懷。',64,'全唐诗/poet.song.189000.json','["遂初雅喜賦天台，牆月東邊謾古懷。", "雖乏平泉供宴樂，幸尋荒徑愜歸來。", "蹣跚愧我無金汞，蹀躞看君上玉階。", "傍舍數弓畦藥本，聊支晚歲亦優哉。"]'),
('9a6ea705-20d0-4b3c-9cff-501ba1b5572c','再和前韵  其五','鄭清之','宋','宋诗','song-poetry','','[]','難追八駿舉瑶巵，肯向羅浮醉綠衣。',64,'全唐诗/poet.song.189000.json','["難追八駿舉瑶巵，肯向羅浮醉綠衣。", "敝服真成原憲病，枯枝幾賦仲堪危。", "忘憂擬問酒中聖，覓句懶從天外歸。", "笑傲桑榆知有幾，春秋敢以大椿爲。"]'),
('bda928bc-7e82-40d1-829b-ceeb927d1c5c','再和前韵  其六','鄭清之','宋','宋诗','song-poetry','','[]','茂先博物懵星台，世味沉酣酷鴆懷。',64,'全唐诗/poet.song.189000.json','["茂先博物懵星台，世味沉酣酷鴆懷。", "風月自爲無盡藏，湖山誰肯愛閑來。", "競知疾下多車乘，豈悟機危蹈廩階。", "幸與樂天相伴住，休論達者謂何哉。"]'),
('4ed7b371-4215-4858-ac30-b25b217d0931','送姚提幹行','鄭清之','宋','宋诗','song-poetry','','[]','虛齋填東鄞，從之南容君。',180,'全唐诗/poet.song.189000.json','["虛齋填東鄞，從之南容君。", "我初未之識，邕翰傾殷勤。", "修潔以博習，秀美而有文。", "玉犀映秋水，英辭湧春雲。", "雞距角魯蜀，昂然鶴非羣。", "晤言到聖處，商也樂所聞。", "最喜直而義，壯音駴鼓鼖。", "告子少於孟，先策養氣勛。", "牛山木信美，謹勿容斧斤。", "助苗固得槁，可使稗不耘。", "觀子所植立，真能張吾軍。", "仁義可效治，淵源在河汾。", "詩書自師友，芝蘭足膏薰。", "剛風接逕翮，去去翔霄旻。", "清時有聞者，必也吾子云。"]'),
('79345d54-52c4-4661-af0d-779be9069e74','和德夫治中林宗諭雪詩簡黄制卿','鄭清之','宋','宋诗','song-poetry','','[]','齋壇將禱肅熊貔，一縷忱恂六出奇。',64,'全唐诗/poet.song.189000.json','["齋壇將禱肅熊貔，一縷忱恂六出奇。", "雲欲商量驚先路，雨方收卷避催詩。", "冰花肯斅梅妝額，風絮嫌隨柳獻眉。", "鹽虎玉龍莊語在，願光遠業瑞昌時。"]'),
('3ee3e93a-77d4-4ae6-bcae-2f9a219f4a7e','古風一篇簡徐德夫提刑','鄭清之','宋','宋诗','song-poetry','','[]','昌黎有名言，受恩異知己。',288,'全唐诗/poet.song.189000.json','["昌黎有名言，受恩異知己。", "而况不識面，知心詎能幾。", "浮雲日多變，交道冷如水。", "握手遽下石，利害毫髮比。", "人情易燥濕，灧澦發九軌。", "終然風雨晦，雞鳴獨無已。", "世變方下趨，特立繄君子。", "山谷未見坡，氣味已相似。", "希文非素交，永叔甘遠徙。", "敢謂世無人，前修可專美。", "我昔聞君名，恍如讀青史。", "已乃知同時，深心愛敬起。", "端平濫持衡，薦賢職當爾。", "亟以聞九重，夜半下一紙。", "雅志樂弦歌，公車猶尼止。", "賢者固難進，奪情辭詔旨。", "知賢未及用，上印返田里。", "閑居事幽屏，黜陟不到耳。", "賓朋有公言，聲徽振商祉。", "入則禆國論，挺挺中流砥。", "出持皇華節，光風汎桃李。", "從容五六載，平進付常理。", "又聞交游間，榮落保終始。", "不負楊臨賀，真見其人矣。"]'),
('10027eb5-7dff-4338-b995-aeeb74f221ff','簷前蜘蛛','鄭清之','宋','宋诗','song-poetry','','[]','如蠶吐緯自縈纏，出沒無蹤屋陋邊。',32,'全唐诗/poet.song.189000.json','["如蠶吐緯自縈纏，出沒無蹤屋陋邊。", "懷毒滿身如蝎大，謾張羅網欲謾天。"]'),
('51ed0fde-aa9e-46c8-92d4-5ad1c1cb482e','安晚軒竹','鄭清之','宋','宋诗','song-poetry','','[]','松號大夫交可絕，梅爲清客志相同。',64,'全唐诗/poet.song.189000.json','["松號大夫交可絕，梅爲清客志相同。", "英英鳳實卑餘子，楚楚龍孫過乃翁。", "晚際一弓櫜素月，暑中千斛糶清風。", "小軒政欲供晨坐，付女遮闌曉日東。"]'),
('4d7242d1-9c01-48da-a82e-cb7e02db2f00','冬節忤寒約客默坐爇品字柴作五禽戲體中差小佳園丁以矮梅至如見東郭順子使人之意也消欣然呵皸手凍筆占數語呈劉菊坡博一笑  其一','鄭清之','宋','宋诗','song-poetry','','[]','少日愛花螽趯趯，老去凍蠶已休織。',112,'全唐诗/poet.song.189000.json','["少日愛花螽趯趯，老去凍蠶已休織。", "水村山郭一枝曉，忽到窗前三嘆息。", "年年雪裏自作春，摇手東皇不相識。", "衣冠古岸綺季至，介胄嶙峋亞夫色。", "從來魏徵真嫵媚，要是廣平終鐵石。", "月香水影兒女語，千古詩腸描不得。", "笑馮與可幻竹君，相對無言面深墨。"]'),
('78f7742d-9cb1-4e9b-8932-926f9260d602','冬節忤寒約客默坐爇品字柴作五禽戲體中差小佳園丁以矮梅至如見東郭順子使人之意也消欣然呵皸手凍筆占數語呈劉菊坡博一笑  其二','鄭清之','宋','宋诗','song-poetry','','[]','雪毛舞風學喓趯，凍落天孫碎雲織。',112,'全唐诗/poet.song.189000.json','["雪毛舞風學喓趯，凍落天孫碎雲織。", "玉肌不粟彭祖方，戲挾奇芬笑安息。", "生憎萬花肯同調，嗤點壽陽聊半識。", "結根不向青桂宮，絕交月姊無難色。", "誰能柔此老强項，朝暮隆隆轉媧石。", "春風爲媒懶結子，來訪苔痕娛夢得。", "人間要覓爾許清，語渠肉食乃無墨。"]'),
('db9cd84a-1035-4b2d-838c-30db09b42f0b','冬節忤寒約客默坐爇品字柴作五禽戲體中差小佳園丁以矮梅至如見東郭順子使人之意也消欣然呵皸手凍筆占數語呈劉菊坡博一笑  其三','鄭清之','宋','宋诗','song-poetry','','[]','滕六附暄墮寒力，六花未辦天機織。',112,'全唐诗/poet.song.189000.json','["滕六附暄墮寒力，六花未辦天機織。", "籬菊老盡蘭始芽，凌波仙子方踵息。", "水邊亭亭逢玉人，照眼縞衣如舊識。", "冰霜相與厲貞操，蜂蝶那能犯莊色。", "聽渠吹笛作商聲，正音滿地出金石。", "菊坡爲索孤山詩，好句新從座中得。", "二君聯璧如長城，笑整雲梯再攻墨。"]'),
('7139cba4-4d5f-4d92-9f50-a1785bc15210','冬節忤寒約客默坐爇品字柴作五禽戲體中差小佳園丁以矮梅至如見東郭順子使人之意也消欣然呵皸手凍筆占數語呈劉菊坡博一笑  其四','鄭清之','宋','宋诗','song-poetry','','[]','牡丹驕春醉無力，艷紫妖紅錦新織。',112,'全唐诗/poet.song.189000.json','["牡丹驕春醉無力，艷紫妖紅錦新織。", "鹿解銜花空誤唐，楚以姬歸竟亡息。", "何如野外挺孤操，照水淵然有深識。", "昂昂雪鬢顔真卿，何物女子稱國色。", "主張繁華勿復言，如對雁門二千石。", "語君欲識梅花面，好向雲巖訪拾得。", "語君欲作梅花詩，磨盡蓮經大千墨。"]'),
('5d538928-b802-459b-bed5-11cf47f29c74','冬節忤寒約客默坐爇品字柴作五禽戲體中差小佳園丁以矮梅至如見東郭順子使人之意也消欣然呵皸手凍筆占數語呈劉菊坡博一笑  其五','鄭清之','宋','宋诗','song-poetry','','[]','菊坡筆挽千鈞力，剪就冰綃出鮫織。',112,'全唐诗/poet.song.189000.json','["菊坡筆挽千鈞力，剪就冰綃出鮫織。", "謫仙笑作揚州詩，鵬賦消摇六月息。", "市門聊學子真隠，下坐還從季野識。", "清標自是孤山姿，㜮眡唐家六宮色。", "芒端琢句貌疎影，竹邊着渠牛礪石。", "枝橫带雪最佳處，近水清寒月先得。", "語梅政可兄涪翁，凍雨浯溪打碑墨。"]'),
('148fc7d7-6cc2-4b20-b4c1-b09e5ccee23f','謝鄭廣文和韵','鄭清之','宋','宋诗','song-poetry','','[]','春工漚絲呈巧力，紅日如梭萬花織。',112,'全唐诗/poet.song.189000.json','["春工漚絲呈巧力，紅日如梭萬花織。", "愛花蕩子不愛命，效死驪姬似荀息。", "草木摇落天地閉，賢哉梅也衆不識。", "靈根九轉到仙品，千古離騷作書色。", "漲晴癡暖動山意，攀翻健倒蒼苔石。", "高標底須雪後見，清芬每向閑中得。", "花前失喜廣文詩，柿葉書成點新墨。"]'),
('6268fccb-ac5e-489e-88a4-fb1c7352d7e2','廣文出新意得梅之全花實根葉譜入秀句輒效反騷一章','鄭清之','宋','宋诗','song-poetry','','[]','東風不借半分力，老樹絲窠罥寒織。',112,'全唐诗/poet.song.189000.json','["東風不借半分力，老樹絲窠罥寒織。", "虛枝生白獨也正，夜氣歸根吹以息。", "箇中灑灑無一塵，無眼界至無意識。", "居然暗發定慧香，不取諸相了空色。", "若於此花論相好，是人如以木鑽石。", "吾嘗聞之老瞿曇，無有少法爲可得。", "我詩當以無耳聽，索梅一笑付蠅墨。"]'),
('5c046b5b-31a9-4969-b6c6-c594670a1fae','再和  其一','鄭清之','宋','宋诗','song-poetry','','[]','青藜不解支脚力，機杼微聞隔林織。',112,'全唐诗/poet.song.189000.json','["青藜不解支脚力，機杼微聞隔林織。", "暗香來處窮幽棲，蹇馿崎嶇牛喘息。", "山中欲訪隠君子，等閑未許李邕識。", "同盟頗笑五大夫，晚節污秦有慚色。", "摩挱寒玉古苔蘚，從渠喚作荆山石。", "雪中素隠非行怪，自是花間着不得。", "直須謫仙蘇二來，溪藤快掃如鴻墨。"]'),
('1b807a2b-9ae5-49c8-8cfb-72ea63579336','再和  其二','鄭清之','宋','宋诗','song-poetry','','[]','雪意賈寒欺酒力，思婦懶學迴文織。',112,'全唐诗/poet.song.189000.json','["雪意賈寒欺酒力，思婦懶學迴文織。", "屏山未合篆痕銷，笑倩南枝陪燕息。", "冰紈絳蠟入纖手，素臉殷跗未真識。", "兒癡認作春風面，剛道杏花欠顔色。", "香浮紙帳夢欲醒，影到窗紗月移石。", "爲梅着語將無同，左袒孤山未爲得。", "吳都誇麗逸此士，十年浪費老傖墨。"]'),
('cddf522f-24b3-4f34-99d7-390d28da06f0','和趙靜樂梅韵  其一','鄭清之','宋','宋诗','song-poetry','','[]','伊祁作春私帝力，司花女課千機織。',112,'全唐诗/poet.song.189000.json','["伊祁作春私帝力，司花女課千機織。", "月四十五以爲功，化工何嘗停半息。", "老梅偃蹇傲衆芳，一錢輕視程不識。", "和羹肯爲媚竈計，望林祗笑欲炙色。", "莓苔被服當文繡，冰雪定交過金石。", "靜樂先生大雅韵，始信清名不虛得。", "政須草聖傳新篇，安得張顛首濡墨。"]'),
('9f2ea4f8-a868-4311-b121-a8c6fc5b8040','和趙靜樂梅韵  其二','鄭清之','宋','宋诗','song-poetry','','[]','司寒駕天騁軌力，凍合冰蠶不成織。',112,'全唐诗/poet.song.189000.json','["司寒駕天騁軌力，凍合冰蠶不成織。", "皮膚皸瘃雪滿衣，真人恬漠與道息。", "一花挺出萬木僵，其友松筠乃能識。", "清香遠到惟德馨，素質自持無異色。", "春工着意嬪衆卉，用物精多老蒼石。", "耄紅飛盡蜜房深，佳處暗爲蜂翅得。", "誰知竹外一枝好，千載垂芳在詩墨。"]'),
('b9632182-1ed4-46ea-8004-b826414a370d','菊坡疊遣梅什忽惠蘭芽此變風也敢借前韵效楚詞一章以謝來辱','鄭清之','宋','宋诗','song-poetry','','[]','霜雰雰兮風乍力，草變衰兮蛩罷織。',102,'全唐诗/poet.song.189000.json','["霜雰雰兮風乍力，草變衰兮蛩罷織。", "思秋蘭兮委蕭艾，望椒丘兮聊止息。", "悵佳人兮既遠，紛吾美兮誰識。", "忽有人兮好修，遺予佩兮春色。", "茁瓊芽兮九畹，带杜衡兮被石。", "凜增冰兮峩峩，杳光風兮驟得。", "卜蘭居兮南坡，拂余龜兮食墨。"]'),
('bcc6fc9c-1228-49b3-a307-3808d494b1eb','和趙大監知宗韵','鄭清之','宋','宋诗','song-poetry','','[]','萬里修程占學力，色絲黄絹新組織。',112,'全唐诗/poet.song.189000.json','["萬里修程占學力，色絲黄絹新組織。", "只今下筆追二雅，端如養氣閉千息。", "公子何自知寒梅，須知三長具精識。", "亭亭玉雪瑞煙曉，愛日香浮綵衣色。", "自然雅韵出天姿，芝蘭那肯羨玄石。", "我慚姱節對俚語，炊沙鏤冰竟何得。", "願君寫入遂錦堂，冷蘂疎枝陪淡墨。"]'),
('9227933b-6497-4856-ac36-7ff5ce47134e','再韵簡菊坡','鄭清之','宋','宋诗','song-poetry','','[]','訪梅長與寒角力，兩鬢絲絲尚堪織。',112,'全唐诗/poet.song.189000.json','["訪梅長與寒角力，兩鬢絲絲尚堪織。", "吊湘賦鵩强解事，長沙少年空太息。", "酷愛孤芳支歲寒，草木雖多嬾求識。", "肥遁不爲蒼帝臣，白賁丘園義形色。", "風饕雪虐真養素，笑枕溪流漱寒石。", "請翻橘頌作梅賦，倍覺風騷楚人得。", "詩翁試爲决然疑，謂余非是甘飲墨。"]'),
('de3be50f-27a3-49ba-82a1-ddb17c1fa862','昨雖移韵於蘭然石鼎聯章不可以不成也再賦一則語以殿衆作亦騷之亂詞云  其一','鄭清之','宋','宋诗','song-poetry','','[]','好惡移人信有力，宮姬尚取崑崙織。',112,'全唐诗/poet.song.189000.json','["好惡移人信有力，宮姬尚取崑崙織。", "剛姿未必廣平愛，皓首誰憐趙岐息。", "夷車衡茝蓀芷荃，富矣離騷誇博識。", "靈均頌橘不及梅，內白孰爲有精色。", "夫何卞玉楚見棄，素榮無乃碔砆石。", "梅古賢人又何怨，伯夷正自求仁得。", "氏以墨胎端自污，請效公輸爲削墨。"]'),
('4b8e709e-1310-469e-aa05-d4ce3cb68726','昨雖移韵於蘭然石鼎聯章不可以不成也再賦一則語以殿衆作亦騷之亂詞云  其二','鄭清之','宋','宋诗','song-poetry','','[]','續詩愧無修綆力，意緒中斷軻母織。',112,'全唐诗/poet.song.189000.json','["續詩愧無修綆力，意緒中斷軻母織。", "掉頭吟坐欲成寐，出吻悲鳴方願息。", "君詩愛梅筆不停，四疊陽關人未識。", "冰壺交映雪同調，秋水爲神月爭色。", "翛然未肯弟山礬，介如何必化松石。", "詩壇置韵百夷姓，敵壘收功劇孟得。", "須君爲梅作佳傳，問事玄冥煩史墨。"]'),
('fb019a8c-a2bf-4d79-aa25-b4cfd9ac8a72','再和靜樂','鄭清之','宋','宋诗','song-poetry','','[]','夫君論事回天力，斯文如貢厥篚織。',112,'全唐诗/poet.song.189000.json','["夫君論事回天力，斯文如貢厥篚織。", "天葩瑞時來帝傍，天香染衣未渠息。", "因携天上白琅玕，散作天花天女識。", "冰清誰似乃翁譽，玉麈孩視寧馨色。", "月中疎影射銀漢，雪裏樛枝護磐石。", "望林笑策蓋世勛，萬戶侯封爲公得。", "吹徹樓頭畫角春，十行朝拜睿思墨。"]'),
('596b2496-a6de-41c1-bac1-86594791c7a9','靜樂用元韵爲勸學之什再和','鄭清之','宋','宋诗','song-poetry','','[]','士惟食志非食力，於陵奚事親屨織。',112,'全唐诗/poet.song.189000.json','["士惟食志非食力，於陵奚事親屨織。", "靜樂一門自師友，簣進不爲子貢息。", "元仲季方從太丘，海內人士俱願識。", "案上惟作羽籥聲，室中定無鉏箒色。", "申旦督課如園蔬，子夜程書過衡石。", "舉似翁嫗笞其兒，教育英才笑安得。", "文獻超羣王謝家，韋布當磨鐵硯墨。"]'),
('8bb74c16-19f0-4f27-975c-44fd4cb43715','再和梅韵','鄭清之','宋','宋诗','song-poetry','','[]','北窗夢覺呼一力，曙鳥微聞絡緯織。',112,'全唐诗/poet.song.189000.json','["北窗夢覺呼一力，曙鳥微聞絡緯織。", "推窗宛見野梅面，带雨猶如看花息。", "堅白雅佔南枝先，淺紅留待北人識。", "宮中自是憐玉奴，天上何爲愛藍色。", "肯隨蘭芷媚屈宋，獨主芙蓉笑丁石。", "愧我聯篇蟻空旋，羨君六博梟已得。", "梅嬾作尉竟仙去，拜官無用斜封墨。"]'),
('8b5c294f-cba2-46ea-861f-2afc4f785328','再和勸學韵','鄭清之','宋','宋诗','song-poetry','','[]','仕學優於服田力，公儀之家廢葵織。',112,'全唐诗/poet.song.189000.json','["仕學優於服田力，公儀之家廢葵織。", "詩書爲府道德林，樂在藏修洎游息。", "濃薰班馬有餘香，暗摸曹劉豈難識。", "插架牙籤映隙曛，近竹芸編侵晚色。", "諸生競詫邊腹笥，正音如聞孔堂石。", "從知車馬自稽古，須信熊魚可兼得。", "四科褒進惟尚賢，欽想昌黎方讀墨。"]'),
('b4d1f49a-e9fe-4184-8137-88336c92f3cc','和葺芷雪韵  其一','鄭清之','宋','宋诗','song-poetry','','[]','冰山鑿碎五丁力，散作席花誰捆織。',112,'全唐诗/poet.song.189000.json','["冰山鑿碎五丁力，散作席花誰捆織。", "射鵰人去飛燕寒，擁衾內視方閉息。", "能令赤鳳冒白羽，夜半翾翻天際識。", "白雲鄉中助劇戲，從以萬妃紛玉色。", "鸞沼乍驚舞明鏡，虎鹽未見蓋危石。", "乍離還合紛總總，已定復飄如得得。", "姑置是事先年豐，有突不黔應笑墨。"]'),
('8d774302-5170-436e-b862-8ec3de3c7d76','和葺芷雪韵  其二','鄭清之','宋','宋诗','song-poetry','','[]','夸父逐日有餘力，驅萬白蜺飛練織。',112,'全唐诗/poet.song.189000.json','["夸父逐日有餘力，驅萬白蜺飛練織。", "連天照耀作夜明，湧池培堆驚壤息。", "竹高已學槍頭勢，梅近猶能半面識。", "坡翁笑效六一體，八章聯翩韵聲色。", "麻衣忽見蜉蝣陣，硯池觀魚來紫石。", "鄭谷祗解瘦寒句，江上漁蓑正披得。", "何如囊錦生縠紋，兔園老筆陽春墨。"]'),
('788b6d32-bafa-4a97-afb3-ee9950e69305','再和雪韵','鄭清之','宋','宋诗','song-poetry','','[]','司冬已窮造父力，寒機墮指曉猶織。',112,'全唐诗/poet.song.189000.json','["司冬已窮造父力，寒機墮指曉猶織。", "長安貴人金屋嬌，琉璃屏下方偃息。", "穿窗入幕兒女笑，喚作楊花元不識。", "明珠照乘月午夜，秋水連雲天一色。", "翻縞新詩出退之，撒鹽戲語欺安石。", "一寒最憐東郭士，履穿踵决行不得。", "自喜猶爲孔子徒，且學顔淵食炊墨。"]'),
('2154c063-09fc-42d8-8716-250081cbe6ce','適得滷蛤頗佳遣餉菊坡因記曾作蛤子詩有文身吳太伯緘口魯銅人之句戲綴前語代簡','鄭清之','宋','宋诗','song-poetry','','[]','文身太伯甘斥鹵，緘口銅人舌微吐。',181,'全唐诗/poet.song.189000.json','["文身太伯甘斥鹵，緘口銅人舌微吐。", "借資墨客富濡沫，骨醉唇香登燕俎。", "半熟含酒老饕賦，此翁僅可闖堂戶。", "班班雋永带神液，入室真味翁未睹。", "菊坡風裁黄豫章，如食蝤蛑江{搖扌=虫}柱。", "盤餐盡廢太瘦生，格遠調高自清苦。", "子蛤遣汝到眉案，努力去爲酒中虎。", "末下鹹豉有何好，猶侶蓴羹傲傖父。", "海之介夫此小兒，雞肋見笑楊德祖。", "前身曾作水解仙，飛入珠宮飲甘露。", "能令齒吻策餘烈，一鼎松風漱寒乳。"]'),
('2e92772c-825b-4655-a984-a85bbdf7ac63','閑中口占數絕 觀書困甚','鄭清之','宋','宋诗','song-poetry','','[]','眼欲觀書身欲眠，斜拖黄卷曲肱邊。',32,'全唐诗/poet.song.189000.json','["眼欲觀書身欲眠，斜拖黄卷曲肱邊。", "不須身眼爭然否，試待醒來問孝先。"]'),
('8035f5a2-ca4b-44ce-8f93-06d967efac00','閑中口占數絕 聯雨解悶','鄭清之','宋','宋诗','song-poetry','','[]','雨多愁麥又憂苗，不雨還憂旱火驕。',32,'全唐诗/poet.song.189000.json','["雨多愁麥又憂苗，不雨還憂旱火驕。", "憂國浪愁端自苦，老天那肯病湯堯。"]'),
('2f5f6789-4969-4897-b4ea-6f1b124666d5','閑中口占數絕 濃綠中見芍藥一朵','鄭清之','宋','宋诗','song-poetry','','[]','杏桃結子已成翁，稚綠中間着耄紅。',32,'全唐诗/poet.song.189000.json','["杏桃結子已成翁，稚綠中間着耄紅。", "階藥元來如許壽，麥秋天氣露春工。"]'),
('a462c6ba-7f9a-47c0-b8f2-d41dd718218f','閑中口占數絕 園丁去烏蜂','鄭清之','宋','宋诗','song-poetry','','[]','見說烏蜂不採花，羣飛啄蜜喙如鴉。',32,'全唐诗/poet.song.189000.json','["見說烏蜂不採花，羣飛啄蜜喙如鴉。", "雖然冗食真堪汰，笑語園丁且放衙。"]'),
('9ba6d634-c6b4-4fa3-88f5-aa2c53dc0883','閑中口占數絕 海魚絕少','鄭清之','宋','宋诗','song-poetry','','[]','春魚潮罷捉洋山，數水艚船索手還。',32,'全唐诗/poet.song.189000.json','["春魚潮罷捉洋山，數水艚船索手還。", "海若想應饕更甚，飽鮮無復到人間。"]'),
('c9c2ba9b-0f5f-439d-b2d7-a93be24c96ec','林治中鄭廣文以詩來遣魯酒報聘拙語輔行','鄭清之','宋','宋诗','song-poetry','','[]','長公本喜飲，半入野人腹。',264,'全唐诗/poet.song.189000.json','["長公本喜飲，半入野人腹。", "南洲春夢婆，亦復開醉目。", "尚想晉流麗，鼈飲更升木。", "興來索老兵，誰謂酌可獨。", "我亦愛客至，陶巾時一漉。", "雖有彭澤田，種秫苦不足。", "頗因病入務，瓢棄尚餘綠。", "豈無大雅朋，來伴離騷讀。", "廣文粲簷花，和靖峙修竹。", "交情如酎醇，秀句喜心沃。", "觴政嘗卜夜，談闈屢更僕。", "胡爲闊宇芝，但憶頹山玉。", "聊爾遣書瓻，安得洗愁斛。", "昔誇聖人中，今愧平原督。", "杯手助持螯，車涎笑逢麴。", "青州豈烏有，白衣問黄菊。", "如臯應解顔，對飲頗勝俗。", "何時赤壁游，匏樽笑相屬。", "欲歌鹿鳴三，正苦龜藏六。", "飲肯遺公榮，雨煩過御叔。", "忻聞麥兩岐，况有魚百族。", "小却揖二豪，觥船倒醽醁。"]'),
('7b8f911b-c1cf-4467-87de-197ed9463730','謝玉泉君黄伯厚和韵','鄭清之','宋','宋诗','song-poetry','','[]','卯飲貪引巵，夕食不厭腹。',264,'全唐诗/poet.song.189000.json','["卯飲貪引巵，夕食不厭腹。", "松醪灧玉池，鬰尊傲黄目。", "歸閑喜携幼，欣榮對夏木。", "頗笑屈原醒，寧甘馬周獨。", "詩筒發豪思，江月欲戲漉。", "每賡北海詠，未羨西鄰足。", "槽規長吉紅，蟻玩杜陵綠。", "醉鄉擬續記，書眼瞭可讀。", "時康萬戶春，興到七賢竹。", "筵虛艷姬舞，面想宮嬪沃。", "別腸驅藥使，健筆命騷僕。", "居然得良朋，清辭瀉壺玉。", "習池可聯乘，步兵有餘斛。", "誰能酒限拘，强效八州督。", "今年小麥好，豈屑官廩麴。", "嘉節迫蒲艾，早計數萸菊。", "客中真有佳，眼前喜無俗。", "賦殷金石聲，光粲牛斗屬。", "句到後三三，人誰賽六六。", "試編諸賢詩，第以伯仲叔。", "共成杜康傳，更聚山中族。", "萬事付亡何，乾坤一杯醁。"]'),
('0af918ca-98d4-4222-a73c-3bc6ef072e0f','諸君和篇摩壘致師不容閉壁再繹前韵  其一','鄭清之','宋','宋诗','song-poetry','','[]','平生周伯仁，耿耿空洞腹。',264,'全唐诗/poet.song.189000.json','["平生周伯仁，耿耿空洞腹。", "翛然猿鶴姿，豈辨鳩鷹目。", "僕射不解事，居士偶題木。", "種柳僅成五，樂園祗可獨。", "皓首愧商隠，湛恩霑漢漉。", "城府百無有，丘壑一已足。", "詎省醉裙紅，安識墜樓綠。", "生經未渠諳，酒頌聊喜讀。", "耳熱聞秦聲，浪謂肉勝竹。", "高陽有勍者，盛氣如曲沃。", "直須殿上飲，撫床徑呼僕。", "競看椀揮金，幾欲斗撞玉。", "方丈食萬錢，娉婷珠一斛。", "豈復堪束带，靡徙揖郡督。", "耆壽祝老饕，嘉名艷春麴。", "乃知梁州萄，大勝伯始菊。", "相逢作青眼，洗去爾許俗。", "泠然曲寡和，尚有騎能屬。", "元和一漁翁，喜共學士六。", "吳歈間雅奏，楚優效孫叔。", "石鼎夜未央，春空雲已族。", "何當一會期，清驩溢寒醁。"]'),
('712f6b10-fe33-4c45-b598-5deed99dc2bc','諸君和篇摩壘致師不容閉壁再繹前韵  其二','鄭清之','宋','宋诗','song-poetry','','[]','邴原解劇飲，雅名稱龍腹。',264,'全唐诗/poet.song.189000.json','["邴原解劇飲，雅名稱龍腹。", "季倫殺爲嬉，席妓敢嗔目。", "有酒何庸辭，恐射蔣濟木。", "但當携酒去，名花賞幽獨。", "年秫未足了，聖米猶可漉。", "愛屐憐猩魂，奪巵笑蛇足。", "桂漿有餘芳，桑落見重綠。", "諫遠衢尊投，法置酺飲讀。", "籌觥進蔌肴，流觴屏絲竹。", "未憂瓶罌罄，但費𠤷盥沃。", "勝事在園林，家務付兒僕。", "釀羔截肪乳，炰鳳泣脂玉。", "鍊句丹九轉，擒文泉萬斛。", "競詆酒中賢，祗堪帳下督。", "穿幘俯前案，障面厭方麴。", "吹不落眼花，歸去來籬菊。", "華胥國遨遊，無懷氏風俗。", "登詩壇爭長，破愁城相屬。", "二簋用坎四，三客敬需六。", "共樂時方清，誰言世之叔。", "相從孟公座，寧別輔氏族。", "一笑祝諸賢，行釂天家醁。"]'),
('872568d0-60b8-4983-8250-05cb3f77c93c','再和戲黄玉泉','鄭清之','宋','宋诗','song-poetry','','[]','黄公辭酒壚，經笥捧便腹。',264,'全唐诗/poet.song.189000.json','["黄公辭酒壚，經笥捧便腹。", "讀書饑鳶聲，了了崇文目。", "陂澄萬頃波，巢寄一枝木。", "戲題百姓眼，自笑孤舘獨。", "轍涸聊相濡，神液未容漉。", "嘯歌匪彈劍，悁隘殊躄足。", "文織犧尊黄，句弦綺琴綠。", "不見蠏杯持，徒費爾雅讀。", "坐對罌卧牆，空有葉映竹。", "枯腸但茶搜，燥吻遲膏沃。", "主人如馬瘦，酒使欠猩僕。", "思折酤媼券，欲訪義漿玉。", "喟茲鯨吸量，眇矣龍驤斛。", "靈根日灌溉，詩課自程督。", "試當閲醫經，薄釀借神麴。", "共醉靈均絲，未問長房菊。", "飲興非有期，衣曬寧免俗。", "杯勺雖不勝，嘔泄聽隨屬。", "嬾疊陽關三，肯競梟博六。", "不飲但麥豆，頗勝劉文叔。", "醉騎黄犢孫，歸玩墨君族。", "子爲評酒名，擬號安晚醁。"]'),
('4a05b291-5fe0-45c3-865c-83ff6e141b62','謝葺芷和韵','鄭清之','宋','宋诗','song-poetry','','[]','無詩不言酒，作賦真誑腹。',264,'全唐诗/poet.song.189000.json','["無詩不言酒，作賦真誑腹。", "未破公子慳，况與佳人目。", "壯心思擊壺，聖杯賡啄木。", "袖想胡旋雙，妝記摇手獨。", "賓筵乏酬獻，醴齊催泲漉。", "禰衡辦撾鼓，元崇方病足。", "曾無列屋粉，空韵梳鬟綠。", "百篇摘仙詠，十軸蒙溪讀。", "有美建安璩，競爽淇園竹。", "芒端寒燠轉，胸次古今沃。", "卧甕嗤舍郎，祭酒可令僕。", "時陳南北洗，頗醉東西玉。", "雖微醖五斗，端有才一斛。", "詩壇長齊盟，筆陣嚴總督。", "方將喝銀雲，未肯平封麴。", "宮宴看傳柑，帝歌須和菊。", "牛心固異撰，犢鼻且同俗。", "尊酒日相逢，我歌君爲屬。", "歡期踐三五，釀頃虧十六。", "酣暢嗟阮修，飲狂謝裴叔。", "漥尊留古製，長勺分魯族。", "居然同老襟，淺斟醽水醁。"]'),
('9fd74938-7482-4689-bd8a-84fa2ee8cb8c','謝鄭廣文和韵','鄭清之','宋','宋诗','song-poetry','','[]','鱣堂心醉經，精神應滿腹。',264,'全唐诗/poet.song.189000.json','["鱣堂心醉經，精神應滿腹。", "溫飽非所志，飲食不以目。", "說詩稱解頤，善問待攻木。", "頗愁百斛量，孔庭惟立獨。", "俎豆答衛問，筐瓷欠鄒漉。", "曾子非養口，漆園且尊足。", "時於清夜分，酌以翠勺綠。", "聊澆磊磈胸，不廢吾伊讀。", "每篇亦作句，如對紀書竹。", "相逢蓋初傾，一別桑重沃。", "融尊慚坐滿，魯餽疎拜僕。", "衛生不自寶，抑首親患玉。", "囊無諛墓金，米乏佳傳斛。", "厨煙爨人凊，蔬課園夫督。", "粟缾收秫田，黍釀用陰麴。", "解同杜陵襟，期醉昌黎菊。", "赤手當縛菟，白眼謾嗔俗。", "莊虛左氏宴，觴肯西子屬。", "酒債負尋常，會期遭百六。", "要須中聖賢，庶以展伯叔。", "醉入無功鄉，醒豈屈原族。", "岸幘一笑粲，共賦醽酒醁。"]'),
('b40c487a-2ff0-496a-9c93-57d9e98283fb','雨中即事簡二友  其一','鄭清之','宋','宋诗','song-poetry','','[]','怒蛙頻作灌夫駡，老鸛唯聞莊舄吟。',32,'全唐诗/poet.song.189000.json','["怒蛙頻作灌夫駡，老鸛唯聞莊舄吟。", "麥熟只應呼快活，林間欠此一聲禽。"]'),
('e40f2162-3f27-4afb-914a-d14f253a949b','雨中即事簡二友  其二','鄭清之','宋','宋诗','song-poetry','','[]','舉頭但覺雲頭闇，移脚何曾雨脚乾。',32,'全唐诗/poet.song.189000.json','["舉頭但覺雲頭闇，移脚何曾雨脚乾。", "衣裌未便時衣褐，薄寒渾作晚秋看。"]'),
('04916fea-e90f-481e-8684-d1064f3afd16','雨中即事簡二友  其三','鄭清之','宋','宋诗','song-poetry','','[]','鳩能喚雨復呼晴，日日長從屋角鳴。',32,'全唐诗/poet.song.189000.json','["鳩能喚雨復呼晴，日日長從屋角鳴。", "晴雨不應關汝事，强饒唇舌效君卿。"]'),
('d443245c-f18a-4b14-a949-b3b661757e91','雨中即事簡二友  其四','鄭清之','宋','宋诗','song-poetry','','[]','五月炎天正及時，輕絲扇子未曾持。',32,'全唐诗/poet.song.189000.json','["五月炎天正及時，輕絲扇子未曾持。", "殷勤寄語班姬道，只恐秋深却要伊。"]'),
('f3d11a91-4eec-4b0c-a9a4-c3e5d7fe9b50','雨中即事簡二友  其五','鄭清之','宋','宋诗','song-poetry','','[]','籜龍厭俗託孫兒，隔砌相過人不知。',32,'全唐诗/poet.song.189000.json','["籜龍厭俗託孫兒，隔砌相過人不知。", "借宅敲門太多事，胡床竟日對漪漪。"]'),
('95ca74b5-b3be-4a8e-a8cb-74faf40e110d','雨中即事簡二友  其六','鄭清之','宋','宋诗','song-poetry','','[]','鶑聲求友亂繅車，兀坐翻思二客佳。',32,'全唐诗/poet.song.189000.json','["鶑聲求友亂繅車，兀坐翻思二客佳。", "乞得晚晴紅照水，南坡東畔月侵階。"]'),
('2b9c3d77-53d7-4001-af6e-8890ff18b45d','客有誦袁蒙齋得雨酬倡之什輒賡元韵志喜也呈虛齋使君  其一','鄭清之','宋','宋诗','song-poetry','','[]','雷伯四月瘖無聲，鳴鳩呼婦鳬浴晴。',240,'全唐诗/poet.song.189000.json','["雷伯四月瘖無聲，鳴鳩呼婦鳬浴晴。", "星如榝沙燈吐紅，羲和駕鞭乘赤明。", "稚秧針水未入種，秀麥浪畦猶督耕。", "香車不動百龍蟄，轉轆如織千蛇橫。", "愛民太守心語口，瘨我以旱寧無生。", "川靈有知龜亦許，異物蜿蜒歸掌撫。", "一雨果從方寸來，此念端誠本天與。", "但看父老歌豐年，不用兒童學皇舞。", "弭災肯效欒巴噀，哺民無異紫芝乳。", "一年事在阿堵中，四封笑溢迎門語。", "我州潴野同淮徐，公方有意六輔渠。", "上天下澤鍾惠施，千里波及皆君餘。", "蒙齋詩成虛齋和，我樂賦之如遂初。", "坐對聯珠飽官粟，但有歡喜無欷歔。", "祗今快續二賢詠，不須乞米移顔書。"]'),
('756c3705-4cf8-41a8-a08b-bd3796a9f454','客有誦袁蒙齋得雨酬倡之什輒賡元韵志喜也呈虛齋使君  其二','鄭清之','宋','宋诗','song-poetry','','[]','媧石補天玻璃聲，遇坎爲雨離爲晴。',240,'全唐诗/poet.song.189000.json','["媧石補天玻璃聲，遇坎爲雨離爲晴。", "金烏玉兔旁午出，百二十官稱常明。", "下土臣敢再拜問，誰主風雨催民耕。", "天江津河尾北見，玉井水漿參左橫。", "胡爲湯旱龜土坼，胡爲堯水魚頭生。", "孰令赤地星丈許，吭扼雷公仍背撫。", "孰令河鼓塞銀潢，勺水線流不輕與。", "孰令卷舌自張翕，孰令天雞自飛舞。", "雲師族聚曷遽散，電母兒號奚不乳。", "黑豬渡河去無迹，蒼龍銜珠噤弗語。", "朱鳥崛强王偃徐，烏龜縮頸老沮渠。", "夫君牋天帝馮怒，旱魃磔死不問餘。", "天街清潤聯璧珠，不爲乾封爲太初。", "一雨三日誰力歟，更唱迭和忘欷歔。", "歸之太守不肯有，欵乃聊代志喜書。"]'),
('a5426be8-ca4f-4ec9-b899-137d12fce23f','客有誦袁蒙齋得雨酬倡之什輒賡元韵志喜也呈虛齋使君  其三','鄭清之','宋','宋诗','song-poetry','','[]','豢龍作醢龍吞聲，天公憒憒迷雨晴。',240,'全唐诗/poet.song.189000.json','["豢龍作醢龍吞聲，天公憒憒迷雨晴。", "玉脂泣烹足媚嫵，苦酒五色生光明。", "龍雖神物畏饞吻，携朋去作天田耕。", "稚禾婉婉魚薧立，高原庚庚龜兆橫。", "漢家燮調豈無術，陰陽縱閉歸董生。", "□□□□□□□，□□□□□□□。", "我貧自笑一瓢許，瓶粟屢空慚釜與。", "彭澤曾無種秫資，沂水聊助詠雩舞。", "頗怪吹雲讀風訟，浪愁淅米繙危語。", "清時何事弘羊烹，善政端無甯虎乳。", "仁人拯溺非姑徐，亟挽天漢如决渠。", "我知造物識君意，十日一雨焉取餘。", "願君展此作霖手，蘇民旱徙扶黄初。", "在在京坻賦高廩，坐令歌頌銷欷歔。", "病坡作計羹玉糝，辟穀寧羨黄石書。"]'),
('c955d9b5-c503-4a4c-b8ce-420dc567809c','湖上口占','鄭清之','宋','宋诗','song-poetry','','[]','賣葑千艘底處藏，媧天濯熱卧湖光。',64,'全唐诗/poet.song.189000.json','["賣葑千艘底處藏，媧天濯熱卧湖光。", "山雲既雨猶相逐，水草無花亦自香。", "野徑遍穿人借問，僧茶旋點客先嘗。", "翻思舉世趨炎者，誰識蘋風五月涼。"]'),
('cb8fa569-f0d7-43c7-b97d-9f6d089e51d5','戲續前韵簡幕掾林治中','鄭清之','宋','宋诗','song-poetry','','[]','梅霖妬日强遮藏，西雨東邊漏隙光。',64,'全唐诗/poet.song.189000.json','["梅霖妬日强遮藏，西雨東邊漏隙光。", "黄口禽鳴應乳臭，白花梔坼似衙香。", "排根荷出憐嵇紹，遁迹蓴肥哂孟嘗。", "閑處便成清境界，底須沂水羨雩涼。"]'),
('86842c50-e619-4368-aa3e-2d3559c93934','煮白酒送林治中','鄭清之','宋','宋诗','song-poetry','','[]','長門思渴薦寒泉，浪讀松醪桂酒篇。',64,'全唐诗/poet.song.189000.json','["長門思渴薦寒泉，浪讀松醪桂酒篇。", "數米釀來成玉液，傳家方秘出金川。", "白飛瓊斚應歸重，紅滴珠槽敢忌前。", "聊遣朋壺供一笑，平分風月晚凉天。"]'),
('5ced6367-4be9-4c50-a86a-9e7c660337b5','偶成呈林鄭二友兩絕  其一','鄭清之','宋','宋诗','song-poetry','','[]','人才百年能幾見，俗子一揖已累人。',32,'全唐诗/poet.song.189000.json','["人才百年能幾見，俗子一揖已累人。", "元溫亦知有此客，德操未省誰爲賓。"]'),
('58c470c0-f440-4e1c-8974-7f398dc37bb9','偶成呈林鄭二友兩絕  其二','鄭清之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','聲名谷口吾宗秀，風調西湖我輩人。',32,'全唐诗/poet.song.189000.json','["聲名谷口吾宗秀，風調西湖我輩人。", "自是山巖着不得，天教蹔此伴閑身。"]'),
('76237a5f-b1e7-41ff-8f4a-13b8fabb0d33','紹定閩寇平上功省府黄伯厚與焉余時在政事堂趙用甫掾西曹力言此文墨士請官以左選既而賞戾法迄授武階去歲戊戌用甫帥鄞乃來爲閫屬余浪跡湖山歲餘始一見稍稔接觴詠亹亹迫人間及前事有見晚恨余與之酒曰一文資直慁子然以人廢法雖相知如今日亦弗敢則笑而不怨赴調行在所贈以君莫愁之歌','鄭清之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','君莫愁，君莫愁，不龜澼絖能封侯。',224,'全唐诗/poet.song.189000.json','["君莫愁，君莫愁，不龜澼絖能封侯。", "君莫愁，君莫愁，腰六相印一敝裘。", "看渠涎顙與躄足，千金信矣壺中流。", "荻花江月正佳耳，青衫浪泣琵琶舟。", "短衣楚製乃翁喜，未必挽弓右丁字。", "貂蟬本是侍臣冠，有時出自兜鍪裏。", "雖然萬戶將軍臂，夜逢醉尉頭搶地。", "賣薪愚婦輕買臣，不信讀書有奇事。", "世間衆萬無定容，桃笙木棋唯所逢。", "秋來桂菊黄金叢，千機錦繡開芙蓉。", "西風也解作富貴，豈必桃李專春風。", "得時失據自甘苦，姑置是事天夢夢。", "君莫愁，君莫愁，雙手試捫舌在不。", "勸君勤買西湖船，打篷疎雨旗亭酒。"]'),
('3d173ddf-e2d4-403e-86e0-685b8823d12d','家園即事十三首  其一','鄭清之','宋','宋诗','song-poetry','','[]','水滿橫塘占曉涼，蓮腮霞舉葉雲生。',32,'全唐诗/poet.song.189000.json','["水滿橫塘占曉涼，蓮腮霞舉葉雲生。", "魚兒富貴真難比，翠蓋紅妝擁隊行。"]'),
('82676055-8ae9-449a-a322-3defbf769bc9','家園即事十三首  其二','鄭清之','宋','宋诗','song-poetry','','[]','新竹地肥方怒長，幽花晚發自欣榮。',32,'全唐诗/poet.song.189000.json','["新竹地肥方怒長，幽花晚發自欣榮。", "飛來野蝶多情思，不逐蜻蜓點水輕。"]'),
('157e7e2a-b123-4114-accb-b00c64360503','家園即事十三首  其三','鄭清之','宋','宋诗','song-poetry','','[]','池荷岸竹閟寒清，肱枕欹眠夢欲成。',32,'全唐诗/poet.song.189000.json','["池荷岸竹閟寒清，肱枕欹眠夢欲成。", "珍重西鄰知好事，隔河送過讀書聲。"]'),
('e7a284a1-ff79-407b-9129-415552e5cb63','家園即事十三首  其四','鄭清之','宋','宋诗','song-poetry','','[]','千巖萬壑自秋春，靜處觀山能幾人。',32,'全唐诗/poet.song.189000.json','["千巖萬壑自秋春，靜處觀山能幾人。", "疊得假山人競看，世間宜假不宜真。"]'),
('51d0cc11-3a8a-4c58-af1f-bc6cc17540ce','家園即事十三首  其五','鄭清之','宋','宋诗','song-poetry','','[]','綠陰樂靜未號蟬，藕葉扶嬌汎水眠。',32,'全唐诗/poet.song.189000.json','["綠陰樂靜未號蟬，藕葉扶嬌汎水眠。", "輸殺蜂屯深閉壁，峙糧宿飽蜜中邊。"]'),
('b429e45e-8456-42cc-ae35-9eac1c1898db','家園即事十三首  其六','鄭清之','宋','宋诗','song-poetry','','[]','侏儒飽愧東方朔，嫗母呼回郭舍人。',32,'全唐诗/poet.song.189000.json','["侏儒飽愧東方朔，嫗母呼回郭舍人。", "博局由來更勝負，雉盧那復較疎親。"]'),
('6ccd3f14-5b35-4f47-bfe8-d7f6316e4450','家園即事十三首  其七','鄭清之','宋','宋诗','song-poetry','','[]','早作南風午北風，暄涼翻手雨無蹤。',32,'全唐诗/poet.song.189000.json','["早作南風午北風，暄涼翻手雨無蹤。", "田翁舉似霖霪日，脚踏鳴車笑殺儂。"]'),
('0556d9b4-9b15-4a43-986e-dd397558e4ec','家園即事十三首  其八','鄭清之','宋','宋诗','song-poetry','','[]','書带環生繚岸青，葉間蟲篆學陽冰。',32,'全唐诗/poet.song.189000.json','["書带環生繚岸青，葉間蟲篆學陽冰。", "墨池文冢非難化，芝菌從教子厚蒸。"]'),
('b85a096d-a785-4782-a5ff-20718dd75279','家園即事十三首  其九','鄭清之','宋','宋诗','song-poetry','','[]','樹底鳴鳩相唯諾，花間飛蝶自綢繆。',32,'全唐诗/poet.song.189000.json','["樹底鳴鳩相唯諾，花間飛蝶自綢繆。", "二蟲得失聊堪笑，鴻鵠誰能問弈秋。"]'),
('d2ea8d52-de20-4f6f-9961-78690d4f338c','家園即事十三首  其一○','鄭清之','宋','宋诗','song-poetry','','[]','游魚繞石日千里，反舌鳴聲已百能。',32,'全唐诗/poet.song.189000.json','["游魚繞石日千里，反舌鳴聲已百能。", "老鶴易饑增廩稍，乳鷄勤哺領孫曾。"]'),
('d37d12d7-ebba-43b6-aa2d-d2df3acbd543','家園即事十三首  其一一','鄭清之','宋','宋诗','song-poetry','','[]','客有可人君子竹，書無同至大王風。',32,'全唐诗/poet.song.189000.json','["客有可人君子竹，書無同至大王風。", "此風此竹堪誰共，着得茶經桑苧翁。"]'),
('c4651d9b-ce69-496c-98b7-e7dec3b5cdea','家園即事十三首  其一二','鄭清之','宋','宋诗','song-poetry','','[]','人心似鐵爐猶在，世事如棋路不移。',32,'全唐诗/poet.song.189000.json','["人心似鐵爐猶在，世事如棋路不移。", "閑著目光牛背上，英雄千古竟兒嬉。"]'),
('bdcfa87b-85a1-4c4f-abae-4b0b25f7b7dc','家園即事十三首  其一三','鄭清之','宋','宋诗','song-poetry','','[]','老紅擬佔春光住，嫩綠枝頭更嬌妬。',32,'全唐诗/poet.song.189000.json','["老紅擬佔春光住，嫩綠枝頭更嬌妬。", "隨風宛轉未肯落，猶作霓裳羽衣舞。"]'),
('2aea7923-de67-48a8-94d6-4424e924f8f1','家園即事','鄭清之','宋','宋诗','song-poetry','','[]','樂天故不憂，作德心逸休。',48,'全唐诗/poet.song.189000.json','["樂天故不憂，作德心逸休。", "鷄蟲笑杜甫，蝴蝶夢莊周。", "苛政猛於虎，蹊田奪之牛。", "書傳亂人意，周易在床頭。"]'),
('5ccb0cff-d3b3-4313-8636-a392fba9bc72','詩別可齋陳制置移鎮吳門','鄭清之','宋','宋诗','song-poetry','','[]','恭惟上明聖，宵旰親政初。',288,'全唐诗/poet.song.189000.json','["恭惟上明聖，宵旰親政初。", "朝有快活貫，野無薄笨車。", "我獨何因緣，濫持鈞與樞。", "妄意在人物，搜羅到巖墟。", "穆之百函至，酬答疲卷舒。", "雖云得梗概，詎必相賢愚。", "君時藹廉譽，一再登除書。", "公牘耻私謝，直語非貢諛。", "尚無赫蹏牋，而况雙鯉魚。", "元龍一世豪，名下定不虛。", "我歸海之濱，偃息田園居。", "生平舊交游，相忘付江湖。", "軍將忽打門，君書來自吳。", "瓿藁富鴻筆，硯銘出龜趺。", "興懷向㵳泬，論文逮荒疎。", "自言久愛敬，今始通勤渠。", "不爲熱翕翕，不爲暖姝姝。", "云何好尚真，夐與世俗殊。", "意者元城賢，待以涑水迂。", "獸旗畫星壤，龍藩開玉符。", "老我嘆蒲柳，投閑託枌榆。", "味言喜啖蔗，秀句嫌催租。", "的知我輩人，調度非轅駒。", "子長固多愛，舍菀乃集枯。"]'),
('a9cb39e8-c16a-468b-ab26-a918a6eaaee9','懷可齋簡林鄭二從事','鄭清之','宋','宋诗','song-poetry','','[]','可齋嚴冷如古書，莊語敢下鉛與朱。',96,'全唐诗/poet.song.189000.json','["可齋嚴冷如古書，莊語敢下鉛與朱。", "讀之不厭味有餘，簫韶聞奏愁爰居。", "文墨政事同機樞，照人炯炯懸冰壺。", "昆弟親我同二蘇，對床風雨夜夢俱。", "別來半歲意鬰紆，頼有二客能從余。", "或寄可齋雙鯉魚，道甫問訊今何如。"]'),
('9f40663b-b698-4d83-98f2-4bf9397ed8e6','乍晴觀蜂房戲占','鄭清之','宋','宋诗','song-poetry','','[]','蜜蜂家計千頭奴，日併花課供蜜租。',144,'全唐诗/poet.song.189000.json','["蜜蜂家計千頭奴，日併花課供蜜租。", "粉紅黄白各本色，擁腫雙脚尻爲車。", "採花歸來不知數，一一到門如合繻。", "方春乳房湧金屋，子弟分王遣之國。", "廣輪處處成甘州，饞口嚌嚅不遺力。", "蜜脾割盡刲蠟膚，畢歲辛勤用謀食。", "秋深冬早未見春，嗅芳咀華來藻蘋。", "釀成餱糧香滿室，日日飽衙知愛君。", "問誰食蜜還主臣，阜財富國今何人。"]'),
('44e18306-2690-4418-bcf8-2235d338ead3','糟蟚蚏送葺芷','鄭清之','宋','宋诗','song-poetry','','[]','月腹一寸能郭索，黄流在中自濡殻。',213,'全唐诗/poet.song.189000.json','["月腹一寸能郭索，黄流在中自濡殻。", "蝤蛑可是丈人行，螃蠏眡之師長伯。", "二眸挺出勝怒蛙，八跪前驅非屈蠖。", "笑令樊噲自橫行，何用呂布須急縛。", "餔糟啜醨乃吾味，嚼齒穿齦未渠惡。", "屬厭祗覺一解勝，效美不辭雙距落。", "蔡謨但記尊足存，孫卿不悟鐵成錯。", "謾誇右手亦持螯，水中之怒無乃虐。", "梁王葅醢猶至今，千古吁嗟漢恩薄。", "玉柱江{搖扌=虫}酒半酣，銀絲鯽魚膾新斫。", "此非不足君所邪，斶顧居貧未能學。", "蟲魚瑣碎熟爾雅，麯生逢之三距躍。", "太真小物自足佳，葺芷一笑爲飛白。"]'),
('19a33161-f130-4592-b396-b0070e087dac','再和且答索飲語','鄭清之','宋','宋诗','song-poetry','','[]','海塗之人暗摸索，如龜自遮聊以殻。',208,'全唐诗/poet.song.189000.json','["海塗之人暗摸索，如龜自遮聊以殻。", "沈湘雖避屈三閭，斷髮奈逢吳太伯。", "周官自詭蠯蠃蚔，羲經敢並龍蛇蠖。", "嫗妃投甕甘骨醉，舌味無心寧法縛。", "黄詩未足助盤飧，吳稻詎能爲歲惡。", "尊前介士尚錚錚，海底漫郎終落落。", "帛聲試聽響犀瓠，玉指爲渠代金錯。", "掩羣而取僅遺小，誰念坑降秦政虐。", "二螯六跪冒族姓，穴居頗笑鄰之薄。", "縱令臏足亦可喜，中有妙解木應斫。", "賸擬新篘問揚字，先賦南烹仰韓學。", "蠔山馬甲不易致，岸下紫鱗方牣躍。", "主人鸛鶴真耐痛，笑許子彭如水白。"]'),
('8445d7a9-efac-4577-9a21-83bc2fd7557f','鄭德言暫館于別墅','鄭清之','宋','宋诗','song-poetry','','[]','我如杜甫逢王翰，君似梁鴻領孟光。',64,'全唐诗/poet.song.189000.json','["我如杜甫逢王翰，君似梁鴻領孟光。", "花竹自慚非獨樂，杼機聊喜聽鄰牆。", "賦成寧笑老傖父，甕熟定容同舍郎。", "他日楊花飛燕子，可能長記陸宣莊。"]'),
('81cb0feb-215c-40e1-bd33-94a26ce32fe6','安晚偶成','鄭清之','宋','宋诗','song-poetry','','[]','五物中間着一翁，園廛隨分可支筇。',64,'全唐诗/poet.song.189000.json','["五物中間着一翁，園廛隨分可支筇。", "章施采服花妝露，戛擊鳴球竹嘯風。", "疎種密栽觀木漸，淺流深浚養泉蒙。", "眼前丘壑無佳句，自哂詩腸苦未窮。"]'),
('a4b68cee-d803-4c2d-ad74-efa57e957d51','和鄭制幹遷居','鄭清之','宋','宋诗','song-poetry','','[]','帝遣夫君侍玉除，籋雲飛上駕龍駒。',64,'全唐诗/poet.song.189000.json','["帝遣夫君侍玉除，籋雲飛上駕龍駒。", "兵談蹔此棲油幕，荷隰居然見子都。", "風牖喜便鴻案舉，月臺長對兔輪孤。", "孟嘗幸舍非吾事，徒愧荀林爲送孥。"]'),
('9726d6e3-5208-4c50-bd0e-c75c2e1914a9','和鄭制幹謝借居且惠朋樽醉螯詩','鄭清之','宋','宋诗','song-poetry','','[]','平生愛山林，里居想王屋。',228,'全唐诗/poet.song.189000.json','["平生愛山林，里居想王屋。", "孤月自無朋，斷雲曾不族。", "詎知莊遵市，儵有賈誼卜。", "西河就索居，漆園問尊足。", "翟門羅可去，軻宅仁已熟。", "似聞結駟多，每見後騎屬。", "魯臺時遣餽，監侯已發粟。", "競歡王儉蓮，肯問顔公粥。", "家貧願鄰富，蒹葭欣倚玉。", "頗容滑稽叟，來簉堂上燭。", "猶能辨絲簧，漸近不如竹。", "濁醪慁兵醖，庸行參聖讀。", "願爲善頌禱，既醉備五福。", "謀婦擬提壺，敲門驚啄木。", "持螯兩從事，來就桑下宿。", "美味均適口，雙明喜增目。", "命駕匪千里，星言媿不夙。", "聯句乏追韓，補詩聊繼束。", "終當效樂天，駱馬爲酒鬻。"]'),
('573c1104-e220-420a-8f84-4ebb063ee7f0','題雪竇千丈巖','鄭清之','宋','宋诗','song-poetry','','[]','並海危峰駕六鼇，招提深處綠周遭。',64,'全唐诗/poet.song.189000.json','["並海危峰駕六鼇，招提深處綠周遭。", "樛松直上睡龍起，怒瀑飛來風虎嘷。", "坐向亭空雲作伴，待看身與月爭高。", "山靈意我酬清賞，爲酌冰泉讀楚騷。"]'),
('ee164d4f-be00-464b-a583-92af1273cecd','林治中近有捕虎之役調以拙詩','鄭清之','宋','宋诗','song-poetry','','[]','豺狼當道實堪嗔，就乳於菟笑楚臣。',64,'全唐诗/poet.song.189000.json','["豺狼當道實堪嗔，就乳於菟笑楚臣。", "馮婦下車宜衆說，將軍射石見心真。", "渡河應避馮河勇，搏獸終歸舞獸仁。", "他日朕虞須命益，九官濟濟定相親。"]'),
('003a6c28-1e62-44e8-8132-51906f35d4cd','比以拙詩戲調張籍不知作者已盈軸矣輒和兩韵  其一','鄭清之','宋','宋诗','song-poetry','','[]','展也虞朝庶績熙，合修厥貢暨熊貍。',64,'全唐诗/poet.song.189000.json','["展也虞朝庶績熙，合修厥貢暨熊貍。", "兕容于野雖非地，豹澤其文似識時。", "毛革正須供有用，血牙安事殺爲嬉。", "國僑惠政人誰犯，虎聽多應謝子皮。"]'),
('83fb4883-aba4-4942-9af8-0a05be5eed6f','比以拙詩戲調張籍不知作者已盈軸矣輒和兩韵  其二','鄭清之','宋','宋诗','song-poetry','','[]','虓虎寧如龜有知，陸行端自觸危機。',64,'全唐诗/poet.song.189000.json','["虓虎寧如龜有知，陸行端自觸危機。", "縛渠呂布還須急，驅以王尋謾失威。", "肯使黔馿呈短技，直教獵騎合邊圍。", "惡盈詎必分人獸，猛獲終擒自衛歸。"]'),
('f99e51b3-6fab-4fdd-b86c-e0073b006896','圃中問訊梅友老榦疎花有足喜者','鄭清之','宋','宋诗','song-poetry','','[]','洗出金灘鎖骨沙，種成老樹競槎牙。',64,'全唐诗/poet.song.189000.json','["洗出金灘鎖骨沙，種成老樹競槎牙。", "冰霜歷盡肌生玉，窗牖寒深影到紗。", "舊歲枝頭新歲景，十分好處一分花。", "誰言冷圃惟秋菊，春意撩人乃爾耶。"]'),
('94ca393a-dd06-461a-9dcd-648591e4723a','謝徐德夫右司和御製賜詩  其一','鄭清之','宋','宋诗','song-poetry','','[]','直道何曾較尺尋，昔賢垂範到斯今。',64,'全唐诗/poet.song.189000.json','["直道何曾較尺尋，昔賢垂範到斯今。", "臯謨勉勉歌元首，說誨言言沃朕心。", "幸遇千齡開聖治，頃塵三事愧宵箴。", "奎文衣被真難報，盥誦新詩愛助深。"]'),
('13117a12-1be1-4af7-95bd-b6dadb9bfbff','謝徐德夫右司和御製賜詩  其二','鄭清之','宋','宋诗','song-poetry','','[]','朅來林下破天慳，要使明詩見一閑。',64,'全唐诗/poet.song.189000.json','["朅來林下破天慳，要使明詩見一閑。", "齒屐印苔春縱步，頸壺蒸粟晚加餐。", "夢魂飛到味書閣，世路牢封函谷關。", "翻笑醉翁猶未醉，黄金白鬢詫腰環。"]'),
('048d5683-bb1d-4fb2-92c4-c27639ac8f88','和林治中雪詩五首  其一','鄭清之','宋','宋诗','song-poetry','','[]','擘天滕六勇如貔，移下瓊臺撲凸奇。',64,'全唐诗/poet.song.189000.json','["擘天滕六勇如貔，移下瓊臺撲凸奇。", "老盡青山真是幻，從渠白戰更無詩。", "馮闌且喜明雙目，嘶騎寧愁到十眉。", "羔酒不妨敲竹韵，園林正好樂清時。"]'),
('ed05263f-e3f6-45f7-ac51-20d81acd8078','和林治中雪詩五首  其二','鄭清之','宋','宋诗','song-poetry','','[]','兒嬉犯凍搦文貔，怒眥張唇狀崛奇。',64,'全唐诗/poet.song.189000.json','["兒嬉犯凍搦文貔，怒眥張唇狀崛奇。", "圖得形模規婦笑，絕憐冷落賦翁詩。", "幕談多暇堪娛目，喜色排寒爲上眉。", "頗念袁安正高卧，柮柴煨芋了年時。"]'),
('d03d77ef-3331-449c-a59f-d9462b0d346c','和林治中雪詩五首  其三','鄭清之','宋','宋诗','song-poetry','','[]','鹽虎模糊懵豹貔，玉峰高並自多奇。',64,'全唐诗/poet.song.189000.json','["鹽虎模糊懵豹貔，玉峰高並自多奇。", "春先北苑供花事，夜入西淮奏雅詩。", "銀闕勢增開雉尾，賀班香近列蛾眉。", "看君來歲賡酬筆，移在儀曹進表時。"]'),
('795f49e0-a099-4a60-9994-d42a8792b09e','和林治中雪詩五首  其四','鄭清之','宋','宋诗','song-poetry','','[]','白旄麾遍牧郊貔，羽扇分飛更出奇。',64,'全唐诗/poet.song.189000.json','["白旄麾遍牧郊貔，羽扇分飛更出奇。", "凍裂弓鍪元濟縛，嚙殘氈毳子卿詩。", "蘆花夜月凝湓口，梅玉春風侈蜀眉。", "一幅溪藤知幾返，鏤冰冷語不驚時。"]'),
('fc7f4431-4fea-43f4-9325-608d39a1343c','和林治中雪詩五首  其五','鄭清之','宋','宋诗','song-poetry','','[]','貙貗甝狒貊貛貔，獵騎漫山伏正奇。',64,'全唐诗/poet.song.189000.json','["貙貗甝狒貊貛貔，獵騎漫山伏正奇。", "瘃手草成熊舘賦，掩羣驅入兔罝詩。", "獸奔駭類淮淝口，狐媚讙摧虢國眉。", "滕六倚渠真誤事，大寒不出是知時。"]'),
('3085cd10-43b4-4cc7-85d8-c4b3c31159ab','因會來詩再賡元韵','鄭清之','宋','宋诗','song-poetry','','[]','組練橫陳壯士貔，想因舞羽去窮奇。',64,'全唐诗/poet.song.189000.json','["組練橫陳壯士貔，想因舞羽去窮奇。", "千山白髮存公道，十日清吟費老詩。", "待伴易銷春有脚，交光最勝月如眉。", "只愁無著梅花處，東絹平章付伯時。"]'),
('504657bd-751d-4cbb-9fe7-1167f9b552d9','續詩之寵依韵以謝','鄭清之','宋','宋诗','song-poetry','','[]','莫搜險韵續貒貔，雪景須知雪後奇。',64,'全唐诗/poet.song.189000.json','["莫搜險韵續貒貔，雪景須知雪後奇。", "日絢寒光莊浄界，梅將真色薦新詩。", "試敲折竹煎茶舌，旋覓遥岑出黛眉。", "油幕輸君談笑樂，聖杯正是一中時。"]'),
('ffa0f959-2de2-4e8d-b7fd-2a7cedde770a','村邊以湯婆樣惠示與詩俱來依元韵','鄭清之','宋','宋诗','song-poetry','','[]','惠中秀外更清便，婭姹嬌羞二八年。',64,'全唐诗/poet.song.189000.json','["惠中秀外更清便，婭姹嬌羞二八年。", "無奈畏塗生衽席，寧教寒夜折冰綿。", "遣來勣嫗知君狀，擬伴涪翁到曉天。", "只恐磚花陶學士，風流未了續膠緣。"]'),
('ae1b8f4a-f309-428c-ba44-ef9e62cf14c4','再和村邊解嘲  其一','鄭清之','宋','宋诗','song-poetry','','[]','閑身惟向靜中便，莫景侵尋絳縣年。',64,'全唐诗/poet.song.189000.json','["閑身惟向靜中便，莫景侵尋絳縣年。", "失解真精昏默默，且觀玄牝息綿綿。", "溫柔鄉裏誰能老，冷澹生涯別有天。", "笑撫脚婆爲法喜，漆園何必問經緣。"]'),
('2e887707-0493-45e9-b4eb-82031990ad9d','再和村邊解嘲  其二','鄭清之','宋','宋诗','song-poetry','','[]','暖足番君老更便，摩挱笑問阿婆年。',64,'全唐诗/poet.song.189000.json','["暖足番君老更便，摩挱笑問阿婆年。", "聊吟夜月移花影，肯向春風逐柳綿。", "自有散花居丈室，何妨姹女共壺天。", "鉛華列屋諸君事，乞與寒梅了世緣。"]'),
('3e033a2e-963f-45e8-9ae2-042362e06ada','再和村邊解嘲  其三','鄭清之','宋','宋诗','song-poetry','','[]','造化真機動靜便，誰云巧智可同年。',64,'全唐诗/poet.song.189000.json','["造化真機動靜便，誰云巧智可同年。", "藍田日暖煙生玉，閩嶠霜濃木有綿。", "萬象爲春皆是物，一花不實豈其天。", "吾身太極元同運，陽長陰消在所緣。"]'),
('ea55c96f-398e-4a55-90c3-400277de2ddb','和葺芷筍詩','鄭清之','宋','宋诗','song-poetry','','[]','我貧每笑齊之斶，晚食雖甘未忘肉。',144,'全唐诗/poet.song.189000.json','["我貧每笑齊之斶，晚食雖甘未忘肉。", "梅肥尚餘風折綠，溟涬餐英命騷僕。", "藩籬剟彼羝角觸，送似玉堂如楚束。", "惡詩聊賦徐凝瀑，妙句飛來漱鳴玉。", "曾無導吏隨賈餗，坐遣跛奚委葵菽。", "茁芽勤視緣坡竹，期飫伯仁空洞腹。", "書腸膏腥士之辱，得魚不敢餉羊續。", "要知菜味勝山谷，步趨强顔髮曲局。", "盤有美茹無不足，陋矣王芻箋衛奧。"]'),
('b3f1b3b1-5291-4d24-971b-50df6b582ef0','贈許石田爲僧','鄭清之','宋','宋诗','song-poetry','','[]','平明對鏡良獨難，子能脫屣彈指間。',112,'全唐诗/poet.song.189000.json','["平明對鏡良獨難，子能脫屣彈指間。", "戲視此身如髦蠻，冠巾擺落逃繻關。", "千鈞强弩一笑彎，萬錢買盡江南山。", "厭渠世路車輪殷，赤脚健倒苔痕斑。", "參寥佛印若是班，江湖風月不汝慳。", "汝狂方醒衆所讙，我獨見之爲三嘆。", "辨詰孔釋語可刪，白雲深處輸君閑。"]'),
('1ea094ba-b973-4002-ae75-250a2ca8fc20','和敬禪師茶偈  其一','鄭清之','宋','宋诗','song-poetry','','[]','飯罷茶來手接時，箇中日日是真機。',32,'全唐诗/poet.song.189000.json','["飯罷茶來手接時，箇中日日是真機。", "建溪顧渚君休問，冷暖如魚只自知。"]'),
('68e035f1-46cb-4729-93e0-9a85d3f96bc8','和敬禪師茶偈  其二','鄭清之','宋','宋诗','song-poetry','','[]','睡蛇纏繞黑甜時，棒喝全提落鈍機。',32,'全唐诗/poet.song.189000.json','["睡蛇纏繞黑甜時，棒喝全提落鈍機。", "管取一甌先着到，三更日出有誰知。"]'),
('f0ffab5a-9e56-4fe2-84cb-f67fe3037be2','和敬禪師茶偈  其三','鄭清之','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','魚鼓纔休客至時，摸頭元是最先機。',32,'全唐诗/poet.song.189000.json','["魚鼓纔休客至時，摸頭元是最先機。", "不須吸盡西江水，一滴曹溪味便知。"]'),
('43ff4cc1-9aca-4322-bbab-efa444635c6e','贈育王堪笑翁','鄭清之','宋','宋诗','song-poetry','','[]','問訊瞿曇老比丘，靈山何似雪山頭。',32,'全唐诗/poet.song.189000.json','["問訊瞿曇老比丘，靈山何似雪山頭。", "笑翁底事真堪笑，面似靴皮笑未休。"]'),
('70782aeb-3057-447e-aef7-edf18dcf08d2','蔬圃','鄭清之','宋','宋诗','song-poetry','','[]','活計園蔬日日新，杜陵差慰婦長貧。',64,'全唐诗/poet.song.189000.json','["活計園蔬日日新，杜陵差慰婦長貧。", "旱薑水芋年時熟，春薤秋菘意味真。", "畦甕賸分三伏雨，露根常占百花晨。", "荷鋤未省勤耕稼，猶愧師門學圃人。"]'),
('1879f2c1-a924-42f3-a588-4d6108e8d3de','和林倅賦郡守隨車雨','鄭清之','宋','宋诗','song-poetry','','[]','旌車勤雨拂參旗，大士圓通現白衣。',64,'全唐诗/poet.song.189000.json','["旌車勤雨拂參旗，大士圓通現白衣。", "爐穟輕煙方先路，雷門急令已宣威。", "爲霖賸作西成計，書歲誰云大有稀。", "賢守劬躬民國念，食言應笑魯臣肥。"]'),
('99dc8499-1c41-4081-8047-6881e8a9c6c0','和白雪老禪二偈  其一','鄭清之','宋','宋诗','song-poetry','','[]','閲盡恒河水上波，聲塵何似泡漚多。',32,'全唐诗/poet.song.189000.json','["閲盡恒河水上波，聲塵何似泡漚多。", "還師拍板鉗鎚後，更唱誰家別調歌。"]'),
('53e52d01-db9c-410b-8200-0a48146f44ff','和白雪老禪二偈  其二','鄭清之','宋','宋诗','song-poetry','','[]','簷鐸吟風月半凹，黄金布地欠誅茅。',32,'全唐诗/poet.song.189000.json','["簷鐸吟風月半凹，黄金布地欠誅茅。", "三更出日真光景，大好欽身正笠包。"]'),
('e59c7ade-c55d-471d-bcaf-07cbd8856cc2','靈隠慧上人惠詩爲古風以贈','鄭清之','宋','宋诗','song-poetry','','[]','貫休齊己唐詩人，當時逸氣凌簪紳。',147,'全唐诗/poet.song.189000.json','["貫休齊己唐詩人，當時逸氣凌簪紳。", "聲名亹亹逼甫白，幽蘭直與梅爭春。", "誰知北面石霜老，服勤杖屨皆終身。", "二公所得當蓋世，英詞傑句風中塵。", "至今傳者以詩重，妙處反爲詩所湮。", "弄翰戲墨雖佛事，炊沙作糗成饑嗔。", "不欲詩工與字巧，緒餘能奪道之真。", "心宗一了萬法具，辯才飛轉陶家輪。", "君不見阿難多聞及辯慧，呪語要敵摩伽神。"]'),
('05c83ea6-d545-44fb-9626-8e0f632d9531','天育二老禪惠示經佛偈答以十詩  其一','鄭清之','宋','宋诗','song-poetry','','[]','二老毫端一滴曹，喚醒䆿語沒忉忉。',32,'全唐诗/poet.song.189000.json','["二老毫端一滴曹，喚醒䆿語沒忉忉。", "更無慧可安身處，作麽當時立得牢。"]'),
('9ca6486f-f060-4162-8ec8-4f868c290e94','天育二老禪惠示經佛偈答以十詩  其二','鄭清之','宋','宋诗','song-poetry','','[]','餘塵明極强分離，菩薩如來是阿誰。',32,'全唐诗/poet.song.189000.json','["餘塵明極强分離，菩薩如來是阿誰。", "既道本來無一物，將何芥子納須彌。"]'),
('15d2b617-50bb-4db1-a157-11213ac83f9d','天育二老禪惠示經佛偈答以十詩  其三','鄭清之','宋','宋诗','song-poetry','','[]','龍宮海藏自分明，搕{撟扷/韭}灘頭一任傾。',37,'全唐诗/poet.song.189000.json','["龍宮海藏自分明，搕{撟扷/韭}灘頭一任傾。", "因果若還終不昧，政須防作野狐鳴。"]'),
('3b757d02-4056-4e64-b3e4-d1b42c576eb5','天育二老禪惠示經佛偈答以十詩  其四','鄭清之','宋','宋诗','song-poetry','','[]','書經猶有遮箇在，畫佛何曾夢見來。',32,'全唐诗/poet.song.189000.json','["書經猶有遮箇在，畫佛何曾夢見來。", "玲石玉峰雷雨過，梅花昨夜一枝開。"]'),
('9cffa431-ed17-423f-a7ca-f5a91aa442a9','天育二老禪惠示經佛偈答以十詩  其五','鄭清之','宋','宋诗','song-poetry','','[]','三經已是太多羅，州去休休更問婆。',32,'全唐诗/poet.song.189000.json','["三經已是太多羅，州去休休更問婆。", "箇裏幸然無一事，何須終日把磚磨。"]'),
('c1ca321e-cf7c-478c-ad28-1910e03cce54','天育二老禪惠示經佛偈答以十詩  其六','鄭清之','宋','宋诗','song-poetry','','[]','四十劫來閑坐休，忽拋長舌閙籃頭。',32,'全唐诗/poet.song.189000.json','["四十劫來閑坐休，忽拋長舌閙籃頭。", "若言面壁爲心法，瞿老還輸第一籌。"]'),
('9f44924b-d129-4133-b3c1-569bc11f781a','天育二老禪惠示經佛偈答以十詩  其七','鄭清之','宋','宋诗','song-poetry','','[]','懵懂維摩不二門，畧無遺囑付兒孫。',32,'全唐诗/poet.song.189000.json','["懵懂維摩不二門，畧無遺囑付兒孫。", "普賢若匪剛饒舌，此事如何更吐吞。"]'),
('bf32b0c8-9675-4ff9-9801-195505c36ea2','天育二老禪惠示經佛偈答以十詩  其八','鄭清之','宋','宋诗','song-poetry','','[]','老胡無聖亦無言，驀指虛空喚作禪。',32,'全唐诗/poet.song.189000.json','["老胡無聖亦無言，驀指虛空喚作禪。", "掌血條痕無着處，教誰白地患青顛。"]'),
('44219118-ac67-483b-b40e-0a2e6e984b33','天育二老禪惠示經佛偈答以十詩  其九','鄭清之','宋','宋诗','song-poetry','','[]','般柴運水老龐禪，佛法無多在密邊。',32,'全唐诗/poet.song.189000.json','["般柴運水老龐禪，佛法無多在密邊。", "餠汝將來還與汝，因師交點更團圓。"]'),
('13d30097-93f8-4bdd-b7d6-f7a4b58a03dd','天育二老禪惠示經佛偈答以十詩  其一○','鄭清之','宋','宋诗','song-poetry','','[]','生老年來病已深，灸瘢着艾復難禁。',32,'全唐诗/poet.song.189000.json','["生老年來病已深，灸瘢着艾復難禁。", "六根四大元無有，何處求師下一鍼。"]'),
('0fb5c255-441b-434a-8197-5cb1b0f90979','鄭德言親睹洛伽觀音相遂依所見繪畫朝夕嚴奉且求贊語敬題其旁','鄭清之','宋','宋诗','song-poetry','','[]','具足圓通性，一念本昭徹。',132,'全唐诗/poet.song.189000.json','["具足圓通性，一念本昭徹。", "佛我與信心，是三無差別。", "凡人未見聖，如渴以河說。", "佛身忽現前，如水印秋月。", "心精自開遮，見根匪優劣。", "念中有大士，珠瓔百寶結。", "補陀洛伽相，在在猶日揭。", "是名爲正觀，倒想作奇絕。", "稽首圓通尊，茲念無起滅。", "非相亦非念，不盈復不闕。", "唯然觀自在，無眼耳鼻舌。"]'),
('00548412-4a9e-4a0f-9361-a55ef796b153','拙偈調偃谿上人','鄭清之','宋','宋诗','song-poetry','','[]','昌黎先生入山裏，大顛牢把數珠子。',64,'全唐诗/poet.song.189000.json','["昌黎先生入山裏，大顛牢把數珠子。", "松下經函着浄瓶，照管習之翻却水。", "丞郎滿檐江西禪，行行勘辯撩天鼻。", "偃溪爛嚼雪窗紙，換却舌頭別參起。"]'),
('84df3a28-59d3-43b0-9462-ab00c8ffec5d','雪窗董寺丞將指平讞安晚來訪因舉似偃溪爲下一則語','鄭清之','宋','宋诗','song-poetry','','[]','佛法方當惡劇時，偃溪笑裏袖鉗鎚。',32,'全唐诗/poet.song.189000.json','["佛法方當惡劇時，偃溪笑裏袖鉗鎚。", "不教管領千雲衲，打徹頭關更問誰。"]'),
('fdfea100-d6ee-4ed9-9dc0-7648ad5c27a6','簡雪窗董寺丞  其一','鄭清之','宋','宋诗','song-poetry','','[]','世路機心走兔迒，雪窗一縷不遮藏。',32,'全唐诗/poet.song.189000.json','["世路機心走兔迒，雪窗一縷不遮藏。", "籋雲梯月真游戯，茅舍何曾外玉堂。"]'),
('c1e43608-071a-46ca-bf69-c6bd43de2090','簡雪窗董寺丞  其二','鄭清之','宋','宋诗','song-poetry','','[]','聖賢事業在心槃，禹稷顔回豈異觀。',32,'全唐诗/poet.song.189000.json','["聖賢事業在心槃，禹稷顔回豈異觀。", "世故波瀾同起滅，姓名千古要清寒。"]'),
('02bd5229-4522-4da3-85a7-a5ca1e7fffff','山間大風雨晝夜不止聞松聲撼床戲成拙語謾錄呈葺芷參溪','鄭清之','宋','宋诗','song-poetry','','[]','顛風橫雨窮山秋，樵青弛檐車停輈。',240,'全唐诗/poet.song.189000.json','["顛風橫雨窮山秋，樵青弛檐車停輈。", "松聲撼空吼萬牛，轟豗勢欲傾不周。", "晨雞扼吭喑且愁，百鳥何敢相喧啾。", "恍疑趙壁環諸侯，呼聲動地鏘弓矛。", "又疑變化鵾鵬儔，垂天鼓翼南溟陬。", "或者挽翻河漢流，電飛霆擊龍蛟虬。", "不然火烈陸渾丘，天跳地踔啼熊猴。", "狂吞很吐山裂鳩，大音奔騰怒相投。", "夢中驚迴仙枕游，分明夜宿浙江頭。", "三更潮水掀柁樓，蒼茫起坐擁黄紬。", "觸屏喚作錢塘舟，此身端坐巖之幽。", "如何兩耳不自由，乃與喧寂爲湛浮。", "影蛇石虎以妄求，世間萬事浪喜憂。", "大學能定心逸休，疾雷破柱方夷猶。", "直須養浩師孟鄒，風止韵作商聲謳。"]'),
('1dc96efe-f5d2-445f-89da-887668252e53','和複岫庵賡酬之什  其一','鄭清之','宋','宋诗','song-poetry','','[]','勝地來休沐，山程懶忌前。',48,'全唐诗/poet.song.189000.json','["勝地來休沐，山程懶忌前。", "草堂新杜曲，詩格舊臨川。", "客乘千珠履，翁琴百澗泉。", "參尋幽路滑，空想石頭禪。"]'),
('0b5a1cbe-c150-45bc-9648-a6263e8a037a','和複岫庵賡酬之什  其二','鄭清之','宋','宋诗','song-poetry','','[]','大雅千巖秀，清標萬玉前。',48,'全唐诗/poet.song.189000.json','["大雅千巖秀，清標萬玉前。", "醉扶有宗武，屬和得師川。", "境勝堪鋤月，詩香可釀泉。", "竹林風度在，枯坐笑僧禪。"]'),
('3dae4ce9-156c-443c-93f2-5fcc266867e8','和趙從道賦菜畦春富貴  其一','鄭清之','宋','宋诗','song-poetry','','[]','多生菜氣粥魚僧，味菜還如好色登。',32,'全唐诗/poet.song.189000.json','["多生菜氣粥魚僧，味菜還如好色登。", "戲學挑根和露煮，正堪摘稻配香蒸。"]'),
('4bca636a-0adc-49b5-8c28-cd2012e5afbb','和趙從道賦菜畦春富貴  其二','鄭清之','宋','宋诗','song-poetry','','[]','芝田不減商山樂，蔬食誰言孔色矜。',32,'全唐诗/poet.song.189000.json','["芝田不減商山樂，蔬食誰言孔色矜。", "蒲筍祗應維蔌美，鏤鍚何必羨韓膺。"]'),
('266a4c19-3549-4368-a23d-0b483b0c56e2','送林教授行  其一','鄭清之','宋','宋诗','song-poetry','','[]','玉壺仙骨産蓬萊，客授京璜雋武開。',64,'全唐诗/poet.song.189000.json','["玉壺仙骨産蓬萊，客授京璜雋武開。", "曾向西山傳墨印，好遊東觀籋蘭臺。", "青雲直上輕餘子，黑髮誰量未易才。", "側耳韶簫充雅奏，願同觀樂詫州來。"]'),
('a83b5c17-9569-4288-ba5b-cc1d62bd1d07','送林教授行  其二','鄭清之','宋','宋诗','song-poetry','','[]','石鼎煎茶午夢醒，羊腸怕聽繞車聲。',64,'全唐诗/poet.song.189000.json','["石鼎煎茶午夢醒，羊腸怕聽繞車聲。", "剡舟忽至驚安道，漢使新招別子卿。", "交誼從君知絕俗，凋年如我最關情。", "鸞凰先路爲時瑞，肯卜筵篿訴獨清。"]'),
('14293718-b556-42fb-aec9-f9f608c62241','安晚園戲占','鄭清之','宋','宋诗','song-poetry','','[]','橫塘雨過水初平，浪影窺窗一孔明。',64,'全唐诗/poet.song.189000.json','["橫塘雨過水初平，浪影窺窗一孔明。", "籬下觸羝五鹿角，林間反舌百禽聲。", "柳公權可送行客，梅子真能寬渴兵。", "誰道夏園無所有，蓮花端可傲張卿。"]'),
('9b5b6370-55b3-4e7a-ac6c-a2ce331ac120','九日即事  其一','鄭清之','宋','宋诗','song-poetry','','[]','安晚閑身晚更安，蛩宵無夢落金鞍。',64,'全唐诗/poet.song.189000.json','["安晚閑身晚更安，蛩宵無夢落金鞍。", "通心白髮難爲染，對面青編儘耐看。", "多謝紫萸占老健，喜招黄菊伴秋寒。", "江城借黓生輕暖，忽有鳴蛙却爲官。"]'),
('f36ad2bb-8bbc-44c3-ae8e-acc09b896ab9','九日即事  其二','鄭清之','宋','宋诗','song-poetry','','[]','甕畦籬戶小園林，獨鶴相陪省一琴。',64,'全唐诗/poet.song.189000.json','["甕畦籬戶小園林，獨鶴相陪省一琴。", "老眡官年從實錄，貧依國息寄橫金。", "詩盈弓力猶能寸，客值騷醒且枉尋。", "楓葉似知酤令緩，漂摇醉臉出牆陰。"]'),
('69dfd66c-7e43-48a0-976c-d5763ac4fa31','九日即事  其三','鄭清之','宋','宋诗','song-poetry','','[]','童孫競爽祝雞翁，點勘凡將句讀中。',64,'全唐诗/poet.song.189000.json','["童孫競爽祝雞翁，點勘凡將句讀中。", "戲指丈兄誇少壯，嬾推庚甲問雌雄。", "窮秋對展三更月，迥夜傳呼萬竅風。", "逗曉東窗相管領，舉頭灧灧日車紅。"]'),
('c89644d3-5964-4769-8e06-1775ca8e7910','題偃溪聞長老堯民擊壤圖','鄭清之','宋','宋诗','song-poetry','','[]','炊煙萬井着僧居，人在康衢畫不如。',32,'全唐诗/poet.song.189000.json','["炊煙萬井着僧居，人在康衢畫不如。", "寄語偃溪崖淡墨，圖中添我一柴車。"]'),
('e4587d1f-3045-499c-b118-93c661ac4648','謝林治中訪別覺際庵','鄭清之','宋','宋诗','song-poetry','','[]','野服芒鞋踏蘚斑，千峰約飭整雲鬟。',64,'全唐诗/poet.song.189000.json','["野服芒鞋踏蘚斑，千峰約飭整雲鬟。", "山行陡覺精神健，老去惟貪耳目閑。", "步武來尋僧舍舊，話言應想夜窗閒。", "錢湖難買歸鞍駐，料得春衫憶素蠻。"]'),
('d81ac018-2bd8-4cbd-a1c9-467ef2784ed2','正月晦夕夢中作偈覺但記其首兩句遂於枕上足之錄呈慧上人','鄭清之','宋','宋诗','song-poetry','','[]','是身本虛妄，覓主了無得。',48,'全唐诗/poet.song.189000.json','["是身本虛妄，覓主了無得。", "誰知日用間，顛到由六賊。", "茫茫前後際，生滅在空色。", "賊去主人歸，渾家不相識。"]'),
('91946dde-62fb-4d00-a087-00185bcc5ec1','因筆記賊入空室頌','鄭清之','宋','宋诗','song-poetry','','[]','平生一片癡，妄意室中物。',48,'全唐诗/poet.song.189000.json','["平生一片癡，妄意室中物。", "自言富可待，到了貧徹骨。", "一宵入人家，百寶認髣髴。", "揀得真金身，明處是泥佛。"]'),
('2848fdee-129d-4c78-afa8-133072752f48','乙巳三月出湖口占  其一','鄭清之','宋','宋诗','song-poetry','','[]','幾朝花片落書奩，未信春光已屬厭。',32,'全唐诗/poet.song.189000.json','["幾朝花片落書奩，未信春光已屬厭。", "猛省清明今日是，家家青柳壓朱簷。"]'),
('7aab68e6-11a5-4bdd-800b-e0ef1687b6d4','乙巳三月出湖口占  其二','鄭清之','宋','宋诗','song-poetry','','[]','曉日慇懃爲着鞭，微風逐旋約輕煙。',64,'全唐诗/poet.song.189000.json','["曉日慇懃爲着鞭，微風逐旋約輕煙。", "東皇景勝渾如舊，西子妝濃許近前。", "檻外客山今對展，禊時朋酒占初筵。", "十年重訪蘇堤柳，總付春光入畫船。"]'),
('0fbf5d14-262b-49b3-b5a2-dbe035a318b0','到龍井寺  其一','鄭清之','宋','宋诗','song-poetry','','[]','竹門斜倚酒家帘，石路高低記水簾。',64,'全唐诗/poet.song.189000.json','["竹門斜倚酒家帘，石路高低記水簾。", "炙背老農驚傴僂，乘肩癡女笑窺覘。", "數羝人立攀籬落，一蝶兒嬉掠繖簷。", "款約朋從歸去路，馬頭應有月纖纖。"]'),
('252a67d0-dd3c-448d-9a3d-73c839ddbed9','到龍井寺  其二','鄭清之','宋','宋诗','song-poetry','','[]','山圍古寺綠周遭，一閣軒騰面勢高。',64,'全唐诗/poet.song.189000.json','["山圍古寺綠周遭，一閣軒騰面勢高。", "爐篆得薌抽露穟，石泉借茗作雲濤。", "風流二老歸靈鷲，筆墨千年續楚騷。", "拙語留題罥蛛壁，暗中摸索愧劉曹。"]'),
('d1840cec-1ef1-4d41-991b-e69d1ae292d2','到龍井寺  其三','鄭清之','宋','宋诗','song-poetry','','[]','底忙不肯訪禪林，山寺何曾避客深。',64,'全唐诗/poet.song.189000.json','["底忙不肯訪禪林，山寺何曾避客深。", "奇石韵高非令色，老松皮脫見真心。", "簷牙徇鐸關幽事，溪曲無絃出妙音。", "拂拭少游碑好在，姓名曾記落碑陰。"]'),
('e45dae19-e0ae-4813-a766-bc0c89fa7e70','到龍井寺  其四','鄭清之','宋','宋诗','song-poetry','','[]','十里輕軒憇佛廬，夢身差記蝶蘧蘧。',64,'全唐诗/poet.song.189000.json','["十里輕軒憇佛廬，夢身差記蝶蘧蘧。", "伊蒲巧作魚蝦樣，矮筍新鑱繭栗株。", "暫到欲陪僧夏靜，等閑生怕俗塵污。", "計然老去翻多事，空挽西施向五湖。"]'),
('c66438d0-e1a3-44bb-8fb1-af866eeea258','旌德觀  其一','鄭清之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','瀛丈移從弱水間，君恩泮奐得躋攀。',64,'全唐诗/poet.song.189000.json','["瀛丈移從弱水間，君恩泮奐得躋攀。", "茗香壺酒成三事，巾褐枝筇佔獨班。", "境勝亦能充道勝，官閑何似在家閑。", "玄都猶有桃花在，更向西湖訪好山。"]'),
('fc9743b0-196f-4d51-b07c-53d09e20b431','旌德觀  其二','鄭清之','宋','宋诗','song-poetry','','[]','綠蓑青笠慣菰蒲，錯認東湖處士居。',64,'全唐诗/poet.song.189000.json','["綠蓑青笠慣菰蒲，錯認東湖處士居。", "舟尾笑迎車後客，渡頭催買網中魚。", "水程趣戍半規日，山意論交千卷書。", "歸去重樓試凝望，恍曾雲氣矗凌虛。"]'),
('8a771703-d1fd-411b-a738-22a03c484fc0','旌德觀  其三','鄭清之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','半生東甬數間屋，一日西湖十首詩。',32,'全唐诗/poet.song.189000.json','["半生東甬數間屋，一日西湖十首詩。", "回首風光少年客，春山擁翠作蛾眉。"]'),
('eb2b4cdc-9a7e-44ff-890d-5649678f60b6','賜第登樓  其一','鄭清之','宋','宋诗','song-poetry','','[]','避俗懶成癖，登樓睡失魔。',48,'全唐诗/poet.song.189000.json','["避俗懶成癖，登樓睡失魔。", "忘機鷗自下，開檻蝶相過。", "高處景差勝，靜中春更多。", "君恩何以報，歸夢欲如何。"]'),
('db1a0784-ac8b-4f55-8ae6-cfdfc1005ea9','賜第登樓  其二','鄭清之','宋','宋诗','song-poetry','','[]','桃李漫山不是春，紛紛蜂蝶趁遊人。',32,'全唐诗/poet.song.189000.json','["桃李漫山不是春，紛紛蜂蝶趁遊人。", "梅花已带春歸了，分付垂楊浥露塵。"]'),
('d8f1cdfd-9006-429f-a1a7-3cc80880e490','賜第登樓  其三','鄭清之','宋','宋诗','song-poetry','','[]','病思歸心走兔迒，自嗤幻境未渠忘。',32,'全唐诗/poet.song.189000.json','["病思歸心走兔迒，自嗤幻境未渠忘。", "并州便作咸陽看，設若桑乾亦故鄉。"]'),
('3ebd36e4-7c3d-4cf4-b827-01a646f94d9b','觀王導傳作','鄭清之','宋','宋诗','song-poetry','','[]','江東老子惠之和，九錫牛車慍蔡婆。',32,'全唐诗/poet.song.189000.json','["江東老子惠之和，九錫牛車慍蔡婆。", "不殺伯仁君信否，澹然推分意如何。"]'),
('e311896b-93d0-4827-add9-c41595710f81','閑中偶成  其一','鄭清之','宋','宋诗','song-poetry','','[]','病覺身名小，閑知日月忙。',48,'全唐诗/poet.song.189000.json','["病覺身名小，閑知日月忙。", "篆香雲四合，盆篠竹千章。", "慧性乾成障，愁懷弱未張。", "何如莊宇定，虛室自天光。"]'),
('d2cf995e-d741-4368-8e61-cd47db27b34b','閑中偶成  其二','鄭清之','宋','宋诗','song-poetry','','[]','春過日初永，睡餘人未忺。',48,'全唐诗/poet.song.189000.json','["春過日初永，睡餘人未忺。", "露花心翼翼，風葉喜沾沾。", "殿後蜂尋穴，懷歸燕語簷。", "垂楊在何處，落絮點疎簾。"]'),
('b04308c2-b909-4f8f-8311-634daa797fe9','孟童子中異科而還來訪余於行都賜第輒贈以詩','鄭清之','宋','宋诗','song-poetry','','[]','在昔昌黎公，序贈張童子。',144,'全唐诗/poet.song.189000.json','["在昔昌黎公，序贈張童子。", "獨出超等夷，芳名駕青史。", "君門藹世勳，夐軼西平李。", "宗社方同休，彪炳見孩稚。", "天庭插犀角，星眸炯秋水。", "誦書如焦琴，高下涵角祉。", "朱門共駭聽，洗此箏笛耳。", "老翁欲笞兒，眼看拾青紫。", "一朝聞九關，賚予出周篚。", "我朝晏與楊，炳炳貴名起。", "願子志遠大，勤學踵前軌。", "家尊我相知，作詩贈歸騎。"]'),
('4ca8c68b-0173-412e-8871-0511ebe4ee7e','東湖送藕與葺芷','鄭清之','宋','宋诗','song-poetry','','[]','草木雖無知，葉落能糞本。',204,'全唐诗/poet.song.189000.json','["草木雖無知，葉落能糞本。", "榮枯遞乘除，苗實自穮蔉。", "東湖百頃蓮，夏日傲趙盾。", "州家浚河渠，獮薙甚耘墾。", "長身萬柄荷，髦梗付鍤畚。", "寒煙熨青鏡，時有白浪輥。", "水解毓仙骨，根着泉源混。", "外乾乃中腴，下益寧上損。", "淤泥胎玲瓏，多節竅渾沌。", "園丁亦善沒，擘波沸魴鱒。", "象株忽仰浮，登岸殊衮衮。", "誰知絳縣塗，可試平叔粉。", "名非玉井船，實過秋蘭畹。", "肴蔌雜燕豆，葅菜補中壼。", "交梨能養生，諼草亦忘忿。", "空言出好事，孰與津燥吻。", "贈君擬條冰，差勝羞藻蕰。"]'),
('9f5a8e66-b6e9-4fb1-b9f9-6343267164a9','送新薑與葺芷','鄭清之','宋','宋诗','song-poetry','','[]','仲尼胡不徹薑食，損智深譏藏戲劇。',240,'全唐诗/poet.song.189000.json','["仲尼胡不徹薑食，損智深譏藏戲劇。", "將以愚民豈其然，半山失喜爲動色。", "拗執誰解鎸此老，一時鑿說契胸臆。", "我疑諗之神農書，增壯胃腑良有力。", "呂令音商其味辛，調芼魚蔬蘗香稷。", "方冬沃土培其根，隴畦分封隨壤息。", "長鬚視苗廑獻新，先時斸取奮鉏棘。", "青株斯拔薤本重，紅萁半露蓤包側。", "駢指驚看産漆園，胝足疑爲導積石。", "欲搗芳辛入虀臼，爲憐膚理傲金狄。", "僕命薺荼涴詩雅，肩差梅桂班內則。", "笑加束縛代書鯉，持助饔庖鱠銀鯽。", "旱年宜薑諺有之，今歲雨多生意嗇。", "小摘酸寒類甲菜，大何嬰冒期膝席。", "公羊穀梁汝往哉，反音一笑當勿劾。"]'),
('d5fcf364-e3b6-421c-a8df-9e022b2ca868','山間錄拙作求教葺芷俚語將命笑擲幸甚','鄭清之','宋','宋诗','song-poetry','','[]','老我愧不學，無以祛六蔽。',288,'全唐诗/poet.song.189000.json','["老我愧不學，無以祛六蔽。", "短綆赴修汲，深淺忘厲揭。", "每逢撲凸篇，如對葛答謎。", "敵壘或致師，何以禦柴曳。", "書林倦回旋，筆徑宜睥睨。", "獨自搔背癢，誰與解襪繫。", "誤墨拙成蠅，飲醯癡聚蚋。", "器成多苦窳，草創類茅蕝。", "未善文心雕，曷助葵足衛。", "樂只正始音，盡發文冢瘞。", "古意窺九嶷，詞源决三澨。", "英風韵風雅，噩噩規誥誓。", "精剛拏健鶻，妥帖律狂猘。", "解注卑蟲魚，獻納笑蝦䱥。", "讀檄頭愈疾，聽語麋著箄。", "風高補釣臺，天朗摘蘭禊。", "合止按商角，刮磨出廉銳。", "妙指曲不傳，奪胎骨可蛻。", "神鍼如運斤，拆屋去眼翳。", "又如大醫王，刲胃滌淫滯。", "萬象困蒐討，瑶金拔昆麗。", "司文當執衡，却掃甘擁篲。", "空山闊游從，思君願言嚏。", "蕪詞薦藜藿，香芼待薑桂。"]'),
('732b618f-0d3e-4ca3-a0e8-45ca187e328a','書西湖雷峰雲講主草書','鄭清之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','雲師一生耽聖草，銀鐵蟠空覷天巧。',160,'全唐诗/poet.song.189000.json','["雲師一生耽聖草，銀鐵蟠空覷天巧。", "老來逸氣未全平，筆底鋒鋩猶獨掃。", "開關勇士爭赴敵，劍戟弓戈奮相繚。", "睡龍决起求頷珠，劃木抓巖紛怒爪。", "風雷喧豗撼坤軸，飛電交橫印清沼。", "忽然天宇變空澄，千丈孤峰立寒峭。", "張顛驚號智永泣，剝筋椎髓爲君飽。", "恨予不習草書訣，九轉枯腸祗自攪。", "雲師雲師汝誠能，春蚓秋蛇幾時了。", "何如認取主人翁，破衲蒙頭紙窗曉。"]'),
('d87a9e30-0a97-47b9-907c-594a884e0a46','送黄伯厚入廣','鄭清之','宋','宋诗','song-poetry','','[]','五行在天地，惟水明且清。',168,'全唐诗/poet.song.189000.json','["五行在天地，惟水明且清。", "如何南中泉，乃獨以貪名。", "水號黑與弱，淖汩稱濁涇。", "彼皆有其實，所以得此聲。", "山川日秀發，九疑羅翠屏。", "扶輿産清淑，丹砂銀石英。", "有泉出其間，泠然堪濯纓。", "政坐貪夫累，土炭涴玉冰。", "桓山以魋故，至今人羞稱。", "柳子愚其溪，百世相因仍。", "有如此白水，好貪豈其情。", "我欲招夷齊，稷之南山汀。", "一洗萬古貪，涌雪歸東溟。", "夫君素潔己，贈以貪泉銘。"]'),
('0e853465-4d4e-4c04-9411-476a744a9622','送繼一郭處士','鄭清之','宋','宋诗','song-poetry','','[]','聖君如堯舜，豈無巢與由。',240,'全唐诗/poet.song.189000.json','["聖君如堯舜，豈無巢與由。", "計然亦何慕，五湖一扁舟。", "之人久不作，側席思巖幽。", "嘗聞鹿何君，清芬徹凝旒。", "重華錫嘉號，見一光林丘。", "誰謂雅道息，競風日悠悠。", "脫冠掛神武，有士歸東州。", "笑將金閨籍，猛博處士裘。", "鈞天爲開顔，曰此夷逸儔。", "大書繼一字，虹光屬奎婁。", "宸章軼麟衮，正聲出天球。", "清名奬靜退，下視古素侯。", "睿謨廣先憲，姱節追前修。", "况今輯衆雋，丞弼登虞周。", "明時樂閒暇，出處自不侔。", "赤城宅仙子，登陸方蓬洲。", "君歸訪司馬，坐忘春與秋。", "方瞳照綠髮，戲轉黄河流。", "煙霧肅逋客，隠者應輟耰。", "欵乃輔行色，春風生柁樓。"]'),
('69cab477-29a1-406f-9000-f18adf5be6b6','妾薄命','鄭清之','宋','宋诗','song-poetry','','[]','妾有一片心，奚啻金與石。',84,'全唐诗/poet.song.189000.json','["妾有一片心，奚啻金與石。", "金石尚可磨，此心終不易。", "妾有金錯刀，不買珠與翠。", "一笑向尊前，願買郎心醉。", "娟娟桃李花，東風蕩柔枝。", "見郎郎弗顧，掩面啼春閨。", "不關郎意惡，自悲妾命薄。"]'),
('bf7668a1-af5a-4603-8b7c-96d9ce98737e','江漢亭百韵','鄭清之','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','山川自高深，開闢由邃古。',288,'全唐诗/poet.song.189000.json','["山川自高深，開闢由邃古。", "長江瀉岷峨，橫亙截區宇。", "東流爲沔津，疏鑿仗神禹。", "襟带成奧區，都會稱鄂渚。", "環城得修岡，雄勝著臺府。", "上有江漢亭，憑高欲鶱舉。", "雲譙護左方，南樓以爲輔。", "飛甍立嶕嶤，纔去天尺五。", "星辰近梯級，嵐霏日吞吐。", "橫陳極蒼茫，萬象互昂俯。", "晴光敞雙明，景物恣枚數。", "炊煙接空翠，下列十萬戶。", "榱棟出稜角，闤闠分脈縷。", "川塗競走集，水陸跨重阻。", "東南引湖湘，西北控淮楚。", "舟車所交屬，人物森萃聚。", "歌謠雜諧合，來往紛傴僂。", "溟濛塵蔽空，揮霍汗成雨。", "游蓋驚雲飄，聯轡識驂舞。", "驅馳溢阡陌，時節相媚嫵。", "裾袖翳朝日，光曜燭綃組。", "憧憧蟻遷穴，紜紜繭抽緒。", "亭亭肆遐睎，一一可細覩。", "至如城中邊，萬竈宅貔虎。"]'),
('2317bab9-91c1-4361-8913-b16638ae5ef7','惠墨','鄭清之','宋','宋诗','song-poetry','','[]','老龍卧蒼海，千年抱明珠。',204,'全唐诗/poet.song.189000.json','["老龍卧蒼海，千年抱明珠。", "神禹決淮泗，偃蹇不受驅。", "怒走崧岱頂，風雨撼八區。", "亭亭立天柱，化作青松株。", "蟠根蟄九地，融液如流酥。", "嶙峋脫支節，幽人拾肌膚。", "虹光夜穿屋，盎突明膏腴。", "芳薰漸凝漬，玄霜出冰壺。", "糅以丹鳳髓，摹以青龜趺。", "擣以明月兔，曝之暘谷烏。", "或潤似玉玦，或堅如金觚。", "六丁下取將，香藹流清都。", "絳闕注仙籍，白日飛凡夫。", "借問何神靈，黑質分龍軀。", "干將昨已至，莫耶復來趨。", "二龍適吻合，變化尤其殊。", "君看一滴水，雙雙躍天衢。"]'),
('44ee42a4-819b-4306-a9b1-ba2ef633f62d','贈已訥二老軒','鄭清之','宋','宋诗','song-poetry','','[]','吾聞墨者徒，設教本兼愛。',288,'全唐诗/poet.song.189000.json','["吾聞墨者徒，設教本兼愛。", "釋伽弘其源，方識宇宙大。", "河沙與寶塔，平等了無礙。", "夫何佛法衰，涉晉唐五代。", "祖師南北分，鼻孔爭譎怪。", "傳流各衣鉢，紛綸辨宗派。", "爾來三百年，涂轍日以隘。", "教律復異門，禪機亦殊解。", "訂以大小乘，森若立矛介。", "虎豹自猙獰，蛇龍相噬嘬。", "駕空樹金碧，爾汝別疆界。", "蒲盧學抱子，嗣續植根蔕。", "蝸爭競蠻觸，夷樂騁兜佅。", "裘屨無貳顔，楚越隔肝肺。", "天弢苦覊束，心穽堅莫壞。", "之人良可悲，賢愚固難概。", "誰知已訥公，粲粲發眉采。", "少年摻袂游，瓶錫遍湖海。", "是非不關耳，窮達付長嘅。", "晚歸耕石田，禾枯將種稗。", "唯有舊家山，青眼終不改。", "掛笠寄清樾，編茅客欠噫。", "目之維摩室，而無天女在。", "謂是龐公居，似欠孔明拜。"]'),
('5e67d07c-0a94-434b-9710-025c4d55b86d','東湖','鄭清之','宋','宋诗','song-poetry','','[]','誰將東湖光，歛作大圓鑑。',48,'全唐诗/poet.song.189000.json','["誰將東湖光，歛作大圓鑑。", "千峰就妝束，萬象互窺瞰。", "紅消日脚明，綠凈山影蘸。", "我來一登臨，扁舟聊可纜。"]'),
('759121f2-bf3c-46d3-bdc4-2e1cd78e71f9','次抱拙妾薄命','鄭清之','宋','宋诗','song-poetry','','[]','落花流水何紛紛，三分春色二分塵。',152,'全唐诗/poet.song.189000.json','["落花流水何紛紛，三分春色二分塵。", "黄鸝繞樹戀不得，蝶蜂浪作花都巡。", "昨日繁華今寂寞，飄零多屬風雨晨。", "金谷無人粉香死，錦踪繡跡俱成陳。", "世人重花不重葉，林園自此無精神。", "東君年少時，酷愛枝頭花。", "庸奴桃李妾姚魏，滿蹊未數黄娘家。", "一朝棄背春風老，懶踏長門階上草。", "芳菲特暫歡，顔色不長好。", "白頭事人那可期，不堪重賦章臺詩。"]'),
('c0f8e4ea-bfb7-465d-9ca1-a80758834b23','田家','鄭清之','宋','宋诗','song-poetry','','[]','老農喜說田家早，缺月疎星穿木杪。',64,'全唐诗/poet.song.189000.json','["老農喜說田家早，缺月疎星穿木杪。", "洗錚燎草作晨炊，麥飯嚥甘蟲食蓼。", "兒牽秧馬婦携笠，泥滑不嫌春雨少。", "平疇拍拍水連堤，姑惡數聲天欲曉。"]'),
('4c3fe8ad-aea9-464f-95b6-1fd29a2151de','水急船行頗遲','鄭清之','宋','宋诗','song-poetry','','[]','湖流湍駛欲下瀨，舟人挽牽如蹶張。',64,'全唐诗/poet.song.189000.json','["湖流湍駛欲下瀨，舟人挽牽如蹶張。", "空令百丈重牛首，如何萬斛浮龍驤。", "進寸退尺天未定，暮四朝三風作强。", "遲明檣烏幸西望，看取快箭激修房。"]'),
('7571d53b-4d50-4a3f-afd0-9e7f730b98dd','重賦章臺','鄭清之','宋','宋诗','song-poetry','','[]','楊花滿地飛蝴蝶，釵梁露濕羅衣怯。',72,'全唐诗/poet.song.189000.json','["楊花滿地飛蝴蝶，釵梁露濕羅衣怯。", "臉痕玉潤拂紅膏，顔色如花命如葉。", "鯉魚風起蒲葉香，鶑啼燕舞春日長，墮紅殘萼斷君腸。", "悞逐浮萍轉零落，自古佳人多命薄。"]'),
('22dd1feb-9d7e-4058-a047-d4daef5d2461','畫馬圖','鄭清之','宋','宋诗','song-poetry','','[]','房精夜隕渥洼水，中有天馬變如鬼。',112,'全唐诗/poet.song.189000.json','["房精夜隕渥洼水，中有天馬變如鬼。", "籋雲流赭登玉臺，清風謖謖生雙耳。", "無端遣入天子閑，足底百趼如關山。", "隔河唐將浴牝馬，哀鳴頓足將奔還。", "風毛雨鬣不自整，肯顧苑北雲錦斑。", "但有風稜餘瘦骨，竊銜不管霜蹄蹶。", "大星昨夜落旄頭，好載閼氏媒突厥。"]'),
('56224358-36eb-405e-a542-3339f2b4c732','碧扇行','鄭清之','宋','宋诗','song-poetry','','[]','冰蠶吐絲青唾茸，天孫轉機聲隆隆。',233,'全唐诗/poet.song.189000.json','["冰蠶吐絲青唾茸，天孫轉機聲隆隆。", "帝家初裁新樣月，蒼然正色摩寒宮。", "一朝飛隨烈士手，九關自此無剛風。", "乘鸞女與蒲葵翁，癡翁騃女誰爲容。", "吳剛斧頭紅玉篆，并州剪刀快如箭。", "化工持此天然巧，古璧團團照君面。", "長安四時生麴塵，馬頭摇曳春風轉。", "君不見醉李白，窮杜甫，當時西游乘蹇馿。", "太清獻賦動旒冕，脫靴笑視將軍奴。", "奇哉二子真坦率，朝暮貰酒黄公壚。", "游蓋飄雲手遮日，未省有扇如清夫。", "清夫扇子僅盈尺，買斷清風歸嘯廬。", "何物元規敢相污，醉中祗恐李杜呼。", "我當吮筆和墨喚起文與可，把君畫入李白杜甫圖。"]'),
('2609928f-b4e6-41c1-a2a1-4198a95b85bc','戲調長鳴鶴','鄭清之','宋','宋诗','song-poetry','','[]','瘦鶴雲霄志，相從伴獨清。',48,'全唐诗/poet.song.189000.json','["瘦鶴雲霄志，相從伴獨清。", "可堪三徑寂，頻作九臯鳴。", "博字輸鵝頸，橫空避雁聲。", "終辭華表去，汗漫逐騎鯨。"]'),
('f8d9adb0-a3b8-4ce9-8cb7-a492536677fc','覺際閒行','鄭清之','宋','宋诗','song-poetry','','[]','斜逕轉山腰，平疇露稚苗。',48,'全唐诗/poet.song.189000.json','["斜逕轉山腰，平疇露稚苗。", "雲低松挾長，雨足浪宣驕。", "宿鷺翔孤嶼，歸僧睨斷橋。", "倦餘成小立，新月掛青霄。"]'),
('69a03364-471b-4157-944e-338aa9d9bac6','三月末泛湖','鄭清之','宋','宋诗','song-poetry','','[]','半晴陰更重，乍煖冷猶爭。',48,'全唐诗/poet.song.189000.json','["半晴陰更重，乍煖冷猶爭。", "墜葉蒲芽綴，新蓴荇面生。", "鐘聲带雨澀，帆力貯風橫。", "客至雙飛鶴，歸歟茗可烹。"]'),
('c6066132-2812-4dcd-9d83-9100a408c6fa','菴前徐步','鄭清之','宋','宋诗','song-poetry','','[]','小橋銜石路，安步水之湄。',48,'全唐诗/poet.song.189000.json','["小橋銜石路，安步水之湄。", "浪蓋菰蒲伏，寒禁笋蕨癡。", "蜂房深戶牖，燕壘漸塗茨。", "過眼春餘幾，延緣歸思遲。"]'),
('ffe37eb0-5c97-4396-bc01-8ca94d6b129c','書齋獨坐','鄭清之','宋','宋诗','song-poetry','','[]','避事寧違俗，端居悟及身。',48,'全唐诗/poet.song.189000.json','["避事寧違俗，端居悟及身。", "穎泓供媵御，方冊替親賓。", "室闇月闌入，庭空花自陳。", "所安惟適耳，誰復辨秋春。"]'),
('ff376242-19fc-4e24-8eec-d9ef759592c1','東歸越上','鄭清之','宋','宋诗','song-poetry','','[]','急雨先聲入芰荷，傍船魚躍弄新波。',64,'全唐诗/poet.song.189000.json','["急雨先聲入芰荷，傍船魚躍弄新波。", "東西黑白投林鳥，高下青黄異畝禾。", "村豎相呼騎犢背，小舟斜艤問漁蓑。", "秋來物物供吟筆，不着黄秦可若何。"]'),
('f6b7bb03-301c-4983-b99e-fd7536a02cec','桂花','鄭清之','宋','宋诗','song-poetry','','[]','香粟飛從月姊邊，秋花無數總饒先。',64,'全唐诗/poet.song.189000.json','["香粟飛從月姊邊，秋花無數總饒先。", "清芬肯作椒蘭觀，雅韵羞陪粉黛妍。", "點就金丹篩雨露，染成玉骨跨神仙。", "餘芳更孕青青子，相伴寒梅到雪前。"]'),
('ace7f8e1-2257-442a-8b8e-ad73cb73dfaf','金峨途中','鄭清之','宋','宋诗','song-poetry','','[]','石路縈紆水繞村，酒帘深處見柴門。',64,'全唐诗/poet.song.189000.json','["石路縈紆水繞村，酒帘深處見柴門。", "橫塘樹密鳩携婦，老屋籬深犢有孫。", "麥莟菜花成錦繡，筍芽薤甲當雞豚。", "竹輿莫作追程去，半似桃源欲細論。"]'),
('7e2a0800-a1dc-4c04-9208-e80eca645e09','奉題蜀邸五雲西岷峨保障','鄭清之','宋','宋诗','song-poetry','','[]','西望岷峨天一方，誰教地險絕遐荒。',64,'全唐诗/poet.song.189000.json','["西望岷峨天一方，誰教地險絕遐荒。", "皇風已喜渾無外，國勢那須別有疆。", "黄鶴盤空飛不過，金牛拔地去何長。", "漢庭四海皆臣妾，一曲歌風未忍忘。"]'),
('d06c0544-8634-4e47-9efc-59ae6803e130','思鄉味戲成','鄭清之','宋','宋诗','song-poetry','','[]','隔籬野圈㹀眠犢，带雨村舂雞喚雛。',64,'全唐诗/poet.song.189000.json','["隔籬野圈㹀眠犢，带雨村舂雞喚雛。", "旋熟黄粱留客住，滿篘白酒倩人沽。", "未諳旅况三分在，早覺藜腸一半枯。", "寄語吾鄉譜鮮子，莫教辜負脆皮鱸。"]'),
('23329b79-e281-4677-8515-bba5d9ac0465','除夜求屠蘇','鄭清之','宋','宋诗','song-poetry','','[]','椒盤爲計定春前，客裏那知歲籥遷。',64,'全唐诗/poet.song.189000.json','["椒盤爲計定春前，客裏那知歲籥遷。", "行路間關穿履雪，薄官羞澀看囊錢。", "媿無黄帝屠蘇酒，試謁淵明種秫田。", "令尹可人應拍手，從教滿意作新年。"]'),
('087a967f-b0b5-49be-a2f1-21483a60d5d4','贈陳童子','鄭清之','宋','宋诗','song-poetry','','[]','前身端合是王充，收拾羣經貯腹中。',64,'全唐诗/poet.song.189000.json','["前身端合是王充，收拾羣經貯腹中。", "書吻可能如布穀，筆鋒應不事雕蟲。", "看來眉目真蘭茁，攬取詞章作繡筒。", "歸去莫誇童子技，好尋芳躅到蟾宮。"]'),
('ab321824-e46d-438b-8dfb-b1e815df7a69','山行','鄭清之','宋','宋诗','song-poetry','','[]','山行心迹已雙清，驟見清溪眼爲明。',64,'全唐诗/poet.song.189000.json','["山行心迹已雙清，驟見清溪眼爲明。", "鬼谷洞前符竹在，觀音巖下魶魚行。", "宗師宴坐空餘石，龍女分流不作聲。", "人影交橫到林薄，綠煙深處一猿驚。"]'),
('22a9c1f1-5aa0-456a-a2bc-4344cf516bb5','正月六日早行松山道','鄭清之','宋','宋诗','song-poetry','','[]','五更河鼓尚橫陳，小立晨光漸可人。',64,'全唐诗/poet.song.189000.json','["五更河鼓尚橫陳，小立晨光漸可人。", "日出野雞猶唱曉，雪晴山鳥競呼春。", "溪筠拂袖霜花落，石路支筇蘚迹新。", "慚愧明朝江國近，買魚沽酒祓征塵。"]'),
('c95b1796-b498-4559-a429-fc5099d19a58','送行詩  其一','鄭清之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','中年別意增懷抱，昨夜秋聲到客船。',64,'全唐诗/poet.song.189000.json','["中年別意增懷抱，昨夜秋聲到客船。", "流水孤村鴉好在，平沙遠景雁依然。", "惜無繡口供吟筆，只有蓴羹愧昔賢。", "付與西湖林處士，重陽健倒菊花前。"]'),
('c82dcc78-17a2-4342-8ad0-e1de79b20452','送行詩  其二','鄭清之','宋','宋诗','song-poetry','','[]','半生霜鬢飄萍迹，幾度風餐繫柳船。',64,'全唐诗/poet.song.189000.json','["半生霜鬢飄萍迹，幾度風餐繫柳船。", "舞詠未忘雩里在，去來翻似賈胡然。", "先生自是今和靖，林下端能友士賢。", "二畝孤山應更好，瘦梅疎影小春前。"]'),
('e1f5823a-a7cb-4400-9d9b-8335f5506750','山房秋日即事  其一','鄭清之','宋','宋诗','song-poetry','','[]','雨後鳴湍走碧溪，水聲秋意恰相宜。',64,'全唐诗/poet.song.189000.json','["雨後鳴湍走碧溪，水聲秋意恰相宜。", "窺蟬螳臂方衷甲，啄蚓雞羣競濟師。", "初月掛簷窗未覺，新涼入牖簟先知。", "西風早已催征棹，管領蓴鱸入夢思。"]'),
('bc1b3cb1-de44-4c35-852c-495e0e07c01e','山房秋日即事  其二','鄭清之','宋','宋诗','song-poetry','','[]','失驚牆外已飄黄，屈指秋來十日强。',64,'全唐诗/poet.song.189000.json','["失驚牆外已飄黄，屈指秋來十日强。", "暑寇負頑猶出沒，風師未壯且翺翔。", "橘包捧腹微藏葉，桂蕾呈身只欠香。", "掃盡暮天疑浴罷，半眉淡月畫新妝。"]'),
('dc688b65-c165-41eb-abd9-236a1afb6b30','山房秋日即事  其三','鄭清之','宋','宋诗','song-poetry','','[]','稻花經雨已脫白，楓葉未霜先借緋。',64,'全唐诗/poet.song.189000.json','["稻花經雨已脫白，楓葉未霜先借緋。", "入紵蚊牙千計巧，掛簷蛛腹十分肥。", "田翁看水携鋤去，山婦臨炊抱蔓歸。", "唯有詩腸無一事，隔溪數盡暮鴉飛。"]'),
('c4740575-973b-4e5b-980d-ffc9d7c66754','晨興散步  其一','鄭清之','宋','宋诗','song-poetry','','[]','軟紅銷盡利名韁，興到湖山取次行。',64,'全唐诗/poet.song.189000.json','["軟紅銷盡利名韁，興到湖山取次行。", "萬馬拍堤春浪起，一龜曝日曉峰橫。", "客中寢飯根塵寂，雪後松篁意氣生。", "身是定僧無欠賸，惟餘雙鶴報寒更。"]'),
('ba2237a4-2021-4b55-85ba-9cfc8fd11e03','晨興散步  其二','鄭清之','宋','宋诗','song-poetry','','[]','僧居西畔鶴居南，我向中邊住此菴。',64,'全唐诗/poet.song.189000.json','["僧居西畔鶴居南，我向中邊住此菴。", "歲晚結交松莫逆，老來知味菜分甘。", "禪心每日閑中得，世事新從夢裏諳。", "隠几空明香穗斷，凈揩雙目對晴嵐。"]'),
('7b425b74-3c01-4e50-a9d4-cd8031c12381','晨興散步  其三','鄭清之','宋','宋诗','song-poetry','','[]','晚歲知非蘧伯玉，前身作脫戒師兄。',64,'全唐诗/poet.song.189000.json','["晚歲知非蘧伯玉，前身作脫戒師兄。", "青山不灼利名火，白髮能銷忿欲兵。", "境對虛空全體現，眼無揀擇內心平。", "曉窗醒寂關何事，到枕清鐘一兩聲。"]'),
('538edb5a-9ba4-4351-8ca0-22f9f3191a58','食後閑步','鄭清之','宋','宋诗','song-poetry','','[]','乞得閑身入釣臺，柳眉舒盡見桃腮。',64,'全唐诗/poet.song.189000.json','["乞得閑身入釣臺，柳眉舒盡見桃腮。", "山中歷日花開落，物外交朋鶴去來。", "更展書窗延竹影，賸翻隙地長梅栽。", "春寒無頼欺霜履，健倒應愁破綠苔。"]'),
('c2e9fb43-453d-41e6-896a-dae1588d93e1','祈晴行西湖上呈館中一二同官  其一','鄭清之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','踏盡紅塵挹翠巒，江湖清夢入雕鞍。',64,'全唐诗/poet.song.189000.json','["踏盡紅塵挹翠巒，江湖清夢入雕鞍。", "濛濛薄霧渾疑雨，惻惻疎風不是寒。", "野菊頻催花事早，老楓初試葉聲乾。", "恰知病骨宜清景，恨不浮家學釣竿。"]'),
('95fb4ce3-89a0-41ab-9b6f-aca4fdbc7ae4','祈晴行西湖上呈館中一二同官  其二','鄭清之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','曉色窺林半淡濃，亂鴉飛去水漫空。',64,'全唐诗/poet.song.189000.json','["曉色窺林半淡濃，亂鴉飛去水漫空。", "山橫孤霧殘霞外，秋在微雲疎雨中。", "官事却能成勝賞，詩壇端可策新功。", "吳儂浪說西湖景，蓬觀今逢蘇長公。"]'),
('57f3b5d5-6ee7-4abf-a55d-036404d305d4','余識頔雲岑已三十年晚居覺際又八載矣近因山行疑接談麈偈語奉贈','鄭清之','宋','宋诗','song-poetry','','[]','嬾把無生話更參，月移梅影到枝南。',64,'全唐诗/poet.song.189000.json','["嬾把無生話更參，月移梅影到枝南。", "身心識破夢中蝶，頭角老來春後蠶。", "笑斸野泉畦露菊，巧尋煖地圃霜柑。", "蒲團睡足書遮眼，貝葉叢間會孔聃。"]'),
('1e0b4b04-ebfa-46ba-a6a3-e3de2a7d49ab','調雲岑','鄭清之','宋','宋诗','song-poetry','','[]','戲將鶡弁博緇衣，般若叢中賸作癡。',64,'全唐诗/poet.song.189000.json','["戲將鶡弁博緇衣，般若叢中賸作癡。", "鵝頸肯爲羅隠笑，鷄林能辨樂天詩。", "好從休處求安逸，莫向閒中覓住持。", "覺際湖山最佳趣，藕花洲渚菊東籬。"]'),
('e19fe4c6-7c84-48b3-9159-7e7931d57646','余自東山往金峨住山戒師迎於中塗到上方泉石幽勝有心匠助天巧者因成數語以贈','鄭清之','宋','宋诗','song-poetry','','[]','一奩鳴瀑寫天紳，怪石鯨奔欲化鱗。',64,'全唐诗/poet.song.189000.json','["一奩鳴瀑寫天紳，怪石鯨奔欲化鱗。", "靈隠飛來真相後，老坡重證戒師身。", "居山活計今成趣，造物工夫總待人。", "自喜愛閒逢勝絕，杖藜端不負殘春。"]'),
('6201974c-137b-4ae1-8ad7-930bcd58cd0a','三友','鄭清之','宋','宋诗','song-poetry','','[]','松號大夫交可絕，梅爲清客志相同。',64,'全唐诗/poet.song.189000.json','["松號大夫交可絕，梅爲清客志相同。", "英英鳳實卑餘子，楚楚龍孫過乃翁。", "晚際一弓櫜素月，署中千斛糶清風。", "小軒正欲供晨坐，付與遮攔曉日東。"]'),
('117b5c2f-76e9-4c11-958a-5f473b7b8aa6','遣興','鄭清之','宋','宋诗','song-poetry','','[]','舟車覆却萬變，人雷動靜兩忘。',28,'全唐诗/poet.song.189000.json','["舟車覆却萬變，人雷動靜兩忘。", "蟲臂聽渠得失，羊腸何異康莊。"]'),
('4de6cac6-a32c-4a5a-a5b6-b961c1c5fa4d','出市得鱖魚成六言','鄭清之','宋','宋诗','song-poetry','','[]','長鋏歸來有魚，狀似松江之鱸。',28,'全唐诗/poet.song.189000.json','["長鋏歸來有魚，狀似松江之鱸。", "爲向東坡傳語，醉卧黄公酒壚。"]'),
('bbf03a0c-b945-4e1e-8185-74a9c4c44163','觀史有感','鄭清之','宋','宋诗','song-poetry','','[]','家令身危侯國計，洛陽讒擯涕流書。',32,'全唐诗/poet.song.189000.json','["家令身危侯國計，洛陽讒擯涕流書。", "都門祖帳何功德，千古徽名說二疏。"]'),
('6c5c543a-44dd-437f-9165-29b0520f1184','晚晴','鄭清之','宋','宋诗','song-poetry','','[]','濯翠篩紅獻晚晴，爲渠日脚護歸程。',32,'全唐诗/poet.song.189000.json','["濯翠篩紅獻晚晴，爲渠日脚護歸程。", "碧雲四合如相妬，纔剩西邊一縷明。"]'),
('0d011aa2-3081-4257-a143-4cd9825cbe36','覺際偶成','鄭清之','宋','宋诗','song-poetry','','[]','自愧端平村宰相，今爲安晚野堂翁。',32,'全唐诗/poet.song.189000.json','["自愧端平村宰相，今爲安晚野堂翁。", "君恩全付閒身世，山水從容一笑中。"]'),
