('bcbeb97d-4278-4fa5-a589-7c8b2bfbe9d3','頔上人持瑩蘿月五詩見示因走筆和韵聊禦睡魔  其五','鄭清之','宋','宋诗','song-poetry','','[]','病著心華須佛治，老僧眼纈要經遮。',32,'全唐诗/poet.song.189000.json','["病著心華須佛治，老僧眼纈要經遮。", "勿逢蘿月五禪偈，絕勝盧仝七椀茶。"]'),
('edc82985-1c9c-4e50-b732-5ea5e046f1e7','登飛來峰','鄭清之','宋','宋诗','song-poetry','','[]','懸崖石路擘蒼苔，川竇巖扉處處開。',32,'全唐诗/poet.song.189000.json','["懸崖石路擘蒼苔，川竇巖扉處處開。", "信是拔山人有力，一峰搦碎總飛來。"]'),
('b93373e9-fdc7-4c83-9784-2b90973ba230','花間見蝶','鄭清之','宋','宋诗','song-poetry','','[]','粉翅縈花幾度忙，惜花長是爲春光。',32,'全唐诗/poet.song.189000.json','["粉翅縈花幾度忙，惜花長是爲春光。", "爭如箇箇蜂鬚上，到處分甘作乳房。"]'),
('027a9e48-791e-4f6b-92ee-34a3f98e3eef','上清宮  其一','鄭清之','宋','宋诗','song-poetry','','[]','雨餘日脚到天涯，十里平山戴晚霞。',32,'全唐诗/poet.song.189000.json','["雨餘日脚到天涯，十里平山戴晚霞。", "疑是千虹蟠絳闕，頻移光景入仙家。"]'),
('264ca6c8-e518-4737-b387-f02cbdd686f0','上清宮  其二','鄭清之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','上清山腹正便便，賸納風光似輞川。',64,'全唐诗/poet.song.189000.json','["上清山腹正便便，賸納風光似輞川。", "曉雨洗開新綠岸，晚霞蘸出嫩紅天。", "鞭浮野竹數莖筍，葉俯秋荷幾柄蓮。", "不是西湖最佳景，更於何處著癯仙。"]'),
('4da30850-48c5-4f9c-8148-210259fa4584','浄明院','鄭清之','宋','宋诗','song-poetry','','[]','齋宿虛閒只浄明，俗氛暫洗覺身輕。',64,'全唐诗/poet.song.189000.json','["齋宿虛閒只浄明，俗氛暫洗覺身輕。", "半山雲脚炊煙溼，一枕松聲澗水鳴。", "對語老禪真法器，譯經新諦出僧檠。", "歸翻貝葉蓮花頌，猶带招提月影清。"]'),
('85279f88-f768-485f-aaf4-59256462e368','雙井','鄭清之','宋','宋诗','song-poetry','','[]','水神何時生六翮，飛出雙泉江練白。',176,'全唐诗/poet.song.189000.json','["水神何時生六翮，飛出雙泉江練白。", "平湖浸月渺無邊，一笑對之成揖客。", "轆轤初動曉星橫，夜捲寒瓊聲湱湱。", "千年佛殿礎花乾，十畝空庭蔭修柏。", "問泉何事逞奇觀，故向庭前作真澤。", "昔年何塞今何通，泉豈有心猶揀擇。", "若云泉自井中來，枯甃沿山有龜拆。", "如信地中泉自見，是年何須穿土脈。", "幡風胥動兩無憑，細詮此證歸禪伯。", "我方饒舌爲作記，了不相干勞刻畫。", "寄詩更欲結茶緣，付與宗風自鎚拍。"]'),
('0fd869fa-3f21-4f57-9618-8dc55c2072d1','贈雲洲老師','鄭清之','宋','宋诗','song-poetry','','[]','嘉定丙子斗插申，秋灰出管纔半旬。',288,'全唐诗/poet.song.189000.json','["嘉定丙子斗插申，秋灰出管纔半旬。", "我來適值蒸暑節，燭龍吐燄扶桑濱。", "炎官流汗走躑躅，金烏啄火焚空旻。", "溼雲擁岫呼不出，火雲糊天挂赫日。", "腦脂蓋眼壯士眠，誰挽天河洗蒸鬰。", "友人萬君家龍丘，追涼共作招提游。", "入門指點到丈室，中有石壁清且幽。", "半月泓澄鎖寒綠，氣象淒切涵清秋。", "凜然便覺肌骨爽，恍疑石罅蟠蛟虬。", "老師宴坐圓覺場，一笑對客雙胡牀。", "雀芽新試蠏眼湯，未到舌本先生涼。", "懸河倒流揮玉麈，果然驚出蛟龍舞。", "須臾霧裹浮圖尖，地墨天昏作風雨。", "吻端造化轉寒燠，約束商羊上天去。", "雲開月明衆峰出，指向巖前石應語。", "歸來爲乏瓊瑶報，清夢安排幾番到。", "池角土花生碧草，逗曉簷前乾鵲噪。", "我承佛敕爲行詞，可拜雲洲老師號。"]'),
('d0bfe608-e0f6-4aae-a398-4515c1f3b9d7','贅禪宗無門關後第四十九則語','鄭清之','宋','宋诗','song-poetry','','[]','語火是燈，掉頭弗應。',20,'全唐诗/poet.song.189000.json','["語火是燈，掉頭弗應。", "惟賊識賊，一問即承。"]'),
('2b4595a3-f4cc-4b20-a9b3-da59f0d401a5','荷花','鄭清之','宋','宋诗','song-poetry','','[]','一樣娉婷絕代無，水宮魚貫出瓊鋪。',32,'全唐诗/poet.song.189000.json','["一樣娉婷絕代無，水宮魚貫出瓊鋪。", "緣何買得凌波女，爲有荷盤萬斛珠。"]'),
('f27b2333-ffe8-4d74-b31d-75ea348e2abd','瑞香花','鄭清之','宋','宋诗','song-poetry','','[]','粉面芳心碧玉裳，持來宛作故山香。',32,'全唐诗/poet.song.189000.json','["粉面芳心碧玉裳，持來宛作故山香。", "征途不覺春如許，更問蘭芽幾寸長。"]'),
('878e056c-b0d3-42ff-8697-8d4f9b8b2c1b','茶','鄭清之','宋','宋诗','song-poetry','','[]','書如香色倦猶愛，茶似苦言終有情。',32,'全唐诗/poet.song.189000.json','["書如香色倦猶愛，茶似苦言終有情。", "慎勿教渠紈袴識，珠槽碎釜浪相輕。"]'),
('b661f65f-9e61-4a55-adf4-927cc3636e3f','題雪竇山妙高峰','鄭清之','宋','宋诗','song-poetry','','[]','陸地芳洲擁翠翹，巨靈穿石滾雲濤。',64,'全唐诗/poet.song.189000.json','["陸地芳洲擁翠翹，巨靈穿石滾雲濤。", "摶空蒼鳳欲飛舞，奔海玉龍爭怒號。", "萬象橫陳坤軸富，一亭平挹月輪高。", "獨醒未覺孤清景，笑酌寒泉讀楚騷。"]'),
('b0a62a90-918f-4837-926c-79a605a569ce','可齋陳大卿政成之暇蒐討河渠爲鄉國長久慮開萬世利非君侯其誰屬因效一得以廣盛心焉','鄭清之','宋','宋诗','song-poetry','','[]','四明瀛海壖，大田沃多稼。',192,'全唐诗/poet.song.189000.json','["四明瀛海壖，大田沃多稼。", "三江納行潦，九穀偏畏夏。", "治水宜講行，時哉及閒暇。", "方當暑如惔，孰謂晴可乍。", "十雨非所憂，一暴良已怕。", "東有錢湖浸，寒玉渺無價。", "西有它山源，盈科通晝夜。", "維此兩支邑，厥田俱下下。", "問之何因爾，水道無所舍。", "河伯空望洋，旱魃巧乘罅。", "緬思井田規，畎澮分溆汊。", "培浚儻高深，怒潮敢雄跨。", "官但督賦輿，誰肯趨田駕。", "六輔能即功，百泉豈難壩。", "願言均此施，利澤侔造化。", "盡復淮南陂，端可儕杜亞。"]'),
('18b9f309-b2fd-49ed-8ec0-c283f3ef9fe8','再用韵','鄭清之','宋','宋诗','song-poetry','','[]','孔明本躬耕，樊遲請學稼。',192,'全唐诗/poet.song.189000.json','["孔明本躬耕，樊遲請學稼。", "力田乃有秋，暑雨敢咨夏。", "聖賢每憂民，孔墨不遑暇。", "因思比歲饑，可謂越俗乍。", "豈惟農夫驚，亦使達官怕。", "倉無矯制發，米湧在東價。", "居然望豐年，譬彼求時夜。", "畫壤來福星，上熟壓中下。", "二麥賸割雲，五菜紛繞舍。", "苗根舒薤本，黍莟拆榴罅。", "龍鱗原鏤塍，燕尾水分汊。", "毨獸將西成，秧馬豈虛跨。", "劭農收奇勳，省斂不更駕。", "豫爲鄞鄉謀，復廣它山壩。", "功比昔賢倍，政隨時雨化。", "願刻可齋詩，端與雅頌亞。"]'),
('21ed81d8-62e6-4e56-9108-5172b43370f7','頔上人索春間詩軸以臂疼未能錄去姑以偈語展限','鄭清之','宋','宋诗','song-poetry','','[]','轉盼湖山忽半年，春鶑啼處起秋蟬。',64,'全唐诗/poet.song.189000.json','["轉盼湖山忽半年，春鶑啼處起秋蟬。", "詩囊未倒真成債，道眼相看總是禪。", "壯士不甘弓掛壁，病翁猶有筆如椽。", "少須定賦茅齋約，恐掉頭吟聒夜眠。"]'),
('33389b1c-6559-447b-99eb-2e00981ff937','還雲岑魯直詩','鄭清之','宋','宋诗','song-poetry','','[]','蟠空健筆虎蛟騰，九折羊腸萬馬登。',64,'全唐诗/poet.song.189000.json','["蟠空健筆虎蛟騰，九折羊腸萬馬登。", "裁剸燠寒真見聖，牢籠泉石肯輸僧。", "命意得了兔走穴，放字未安狐聽冰。", "句法當頭飛棒喝，就渠言下辨三乘。"]'),
('a33c1b57-601b-4247-be4d-f60c75e15cb0','讀魯直詩','鄭清之','宋','宋诗','song-poetry','','[]','晚唐詩似晚春景，姿媚有餘風骨輕。',32,'全唐诗/poet.song.189000.json','["晚唐詩似晚春景，姿媚有餘風骨輕。", "千歲俄逢古罍洗，摩挲篆籀眼增明。"]'),
('0d5909f2-10a8-413e-b2d3-8c576e4ddc8f','口占','鄭清之','宋','宋诗','song-poetry','','[]','誰道寒官俸給稀，齎裝滿路得追隨。',32,'全唐诗/poet.song.189000.json','["誰道寒官俸給稀，齎裝滿路得追隨。", "秋光不與詩腸算，無限江山信筆支。"]'),
('145d8b40-b66b-4590-94ff-bf90f671cc0e','西湖  其一','鄭清之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','黑雲妬日故要遮，剩得輕紅一縷霞。',32,'全唐诗/poet.song.189000.json','["黑雲妬日故要遮，剩得輕紅一縷霞。", "小雨挾風針水面，滿奩皺縠起團花。"]'),
('3a10683c-e808-4aa1-a03d-9f9fc2b7d020','西湖  其二','鄭清之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','官程未了是敲推，課督無人只自催。',32,'全唐诗/poet.song.189000.json','["官程未了是敲推，課督無人只自催。", "不到西湖無半句，西湖端合號詩媒。"]'),
('681f12e3-215b-4e7b-90eb-3deedf90d9db','病目自嘲','鄭清之','宋','宋诗','song-poetry','','[]','兼旬病目成鴆媒，竟日掩書風爲開。',64,'全唐诗/poet.song.189000.json','["兼旬病目成鴆媒，竟日掩書風爲開。", "端如猩猩畏機穽，愛酒着屐須一來。", "信手翻書未終葉，春風已覺生牙頰。", "笑同黄卷且尋醫，免使鷦鷯翳蚊睫。"]'),
('07fe1ccd-db89-4c29-a746-a69d6dca997f','目眚忌食戲成','鄭清之','宋','宋诗','song-poetry','','[]','生平未省讀食經，蟛蜞何事干荀卿。',224,'全唐诗/poet.song.189000.json','["生平未省讀食經，蟛蜞何事干荀卿。", "霜螯带糟老饕賦，素鱗斫鱠晶盤行。", "政欲蓴鱸飽歸興，肯嫌蛙蛤譏南烹。", "誰言厚味多腊毒，坐疑匕箸生戎兵。", "緇塵浪欲滓銀海，所頼烱烱留元精。", "飛蛾擾燈室光暗，很蟆食月天公驚。", "我今所患在目睫，口非得罪曹緘銘。", "一身百體兼所養，六鑿未可分重輕。", "詎容貴目乃賤口，無端腸胃甘檗冰。", "就令辟穀即仙去，何異餒鼠乘飛翎。", "我聞養生先實腹，幸乏明珠買娉婷。", "稻魚粗可足生理，饑夢不到侯門鯖。", "更畦菘薤自鋤灌，肯與雞鶩爭餘贏。", "笑揩雙目保亡恙，况無傳筆如丘明。"]'),
('3888ddd5-9bd7-474b-bfb9-62d5f746f235','壽留守','鄭清之','宋','宋诗','song-poetry','','[]','皇朝誕節號乾明，此日親賢間世生。',64,'全唐诗/poet.song.189000.json','["皇朝誕節號乾明，此日親賢間世生。", "處貴從來如白屋，愛閑真定壓專城。", "但知篤孝終身樂，不慕紆朱萬事輕。", "黄閣功名知未晚，飛鴻心事亦冥冥。"]'),
('c5b7187f-7b5d-48d3-acb1-280bdb38c857','梵王宮','鄭清之','宋','宋诗','song-poetry','','[]','圓嶠移來東海東，梵王宮在最高峰。',32,'全唐诗/poet.song.189000.json','["圓嶠移來東海東，梵王宮在最高峰。", "試將法雨周沙界，千丈巖頭挂玉虹。"]'),
('332f21aa-7356-4417-888e-50fff4431656','咏六和塔','鄭清之','宋','宋诗','song-poetry','','[]','經行塔下幾春秋，每恨無因到上頭。',32,'全唐诗/poet.song.189000.json','["經行塔下幾春秋，每恨無因到上頭。", "今日始知高處險，不如歸卧舊林丘。"]'),
('cbeb3162-3512-4d21-a3a2-3aae3ba52d4f','句  其一','鄭清之','宋','宋诗','song-poetry','','[]','客裏不知春早晚，失驚紅雨到牆陰。',16,'全唐诗/poet.song.189000.json','["客裏不知春早晚，失驚紅雨到牆陰。"]'),
('02fb02dd-d634-4f11-a60b-4e240e19f678','句  其二','鄭清之','宋','宋诗','song-poetry','','[]','玉昆相倚带仙風，壁立春前萬卉空。',16,'全唐诗/poet.song.189000.json','["玉昆相倚带仙風，壁立春前萬卉空。"]'),
('31e6e86c-66e6-44b6-ae45-8f13d00df7bb','句  其三','鄭清之','宋','宋诗','song-poetry','','[]','國香不欲論家譜，合姓孫枝作鄭花。',16,'全唐诗/poet.song.189000.json','["國香不欲論家譜，合姓孫枝作鄭花。"]'),
('53261d0d-b0fe-451c-88ef-edf139c7092a','句  其四','鄭清之','宋','宋诗','song-poetry','','[]','玉質欲藏如許脆，鐵芒何苦太尖生。',16,'全唐诗/poet.song.189000.json','["玉質欲藏如許脆，鐵芒何苦太尖生。"]'),
('235fc964-4e1d-49ac-815c-0590559d658d','句  其五','鄭清之','宋','宋诗','song-poetry','','[]','他年蒙渥澤，方玉带圍赬。',12,'全唐诗/poet.song.189000.json','["他年蒙渥澤，方玉带圍赬。"]'),
('c13d42c7-5f6e-4691-91c0-0d71705ff35d','水天月歌','汪莘','宋','宋诗','song-poetry','','[]','朝立寒溪東，暮立寒溪西。',182,'全唐诗/poet.song.189000.json','["朝立寒溪東，暮立寒溪西。", "一到神頓領，熟視眼更迷。", "水光不見水，但見青天無表裏。", "天光不見天，但見一片清烟涵無邊。", "水中有天天不濕，天中有水水不入。", "天耶水耶墮渺茫，只是天光與水光。", "月來水天中，水天裹月如不裹。", "月去水天中，水天鎖月如不鎖。", "明月不來不去時，琉璃泡中珠一顆。", "先自水天莫分別，更添月色更親切。", "水色天色月色擘不開，水光天光月光拈不來。", "夢中酒渴不可忍，一口吸下驪龍腮。"]'),
('7073c6a4-5deb-4541-83b0-872c5f8b0fc1','日月蓮花歌','汪莘','宋','宋诗','song-poetry','','[]','偉哉天地間，誰家兩枝蓮。',329,'全唐诗/poet.song.189000.json','["偉哉天地間，誰家兩枝蓮。", "紅蓮一枝瑰子鮮，白蓮一枝雪樣妍。", "兩花徑面各千里，壓盡衆草無朱鉛。", "不見賣花翁，不知阿誰擔南躔又北躔。", "不見賣花蜂，但見烏蟾兩點追過天津橋那邊。", "有時雙暈更整整，有時五彩尤戔戔。", "有時露下花頭濕，有時風起花頭偏。", "五鳳銜入淵中淵，六龍插上天中天。", "一入一上知何年，至今絡繹如梭穿。", "花歛作昏舒作晝，世間未識春前後。", "神農教民亂耕耨，唐侯指出兩花定節候。", "唐侯司花方少年，朝朝暮暮長與花周旋。", "苟非其人子莫傳，爲花揀得花中仙。", "姚家愛花故不俗，花前自鼓薰風曲。", "綵旗幻出芙蓉面，晚來旗脚薰風轉。", "此花不費一錢買，付與後來司花作模楷。", "青春飛過秋飛迴，紅白芙蕖花自開。", "曾觀堯舜山河去，也見漢唐池舘來。", "看花人逐年年改，疇昔看花幾人在。", "惟有阿兄日珠姊月珠，坐乘兩花撫四海。"]'),
('bbb11c71-66a5-4d75-b307-9b573bce5413','潘別駕寄牡丹歌次韵','汪莘','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','別駕寄我新詩章，賞花須賞花中王。',338,'全唐诗/poet.song.189000.json','["別駕寄我新詩章，賞花須賞花中王。", "我誦此詩欲大叫，山川靈氣未始亡。", "憶昔少年健如虎，兩脚不住尋奇芳。", "何曾著眼看桃李，天台洞口呼劉郎。", "癡兒騃女意自得，不肯隨我超凡常。", "嵩山洛浦忽入夢，秦人漢士俱堂堂。", "仰天大笑不復道，朱宮紫府森開張。", "是時青春二三月，姚家一樹真黄裳。", "其餘牛家魏家種，千紅萬碧羅新妝。", "論花固是花中傑，論人亦是人中祥。", "不覺我醉花亦醉，不覺花香人亦香。", "氣高已壓玉笥綴，骨硬肯羨金釵行。", "授我以元君之雲篆，沃我以王母之霞觴。", "當時跳出生死窟，自此踏倒名利場。", "懷洞庭兮悲瀟湘，吟清風兮詠滄浪。", "仙人擊節相屬和，賤子起舞尤顛狂。", "歷聘二十八列宿，遍謁三千六上皇。", "東風未斷薰風起，江北吹落江南藏。", "天葩何年到此土，形貌雖減神猶昌。", "濂溪先生誇富貴，東坡老子憐忠良。", "不如煎酥煮麵喫，大勝三椀搜枯腸。"]'),
('cf80136a-ea04-4537-936d-8dbf4544da33','瑞粟歌','汪莘','宋','宋诗','song-poetry','','[]','君不見濟陰九穗禾，又不見河南六岐麥。',287,'全唐诗/poet.song.189000.json','["君不見濟陰九穗禾，又不見河南六岐麥。", "何似新安海陽縣，瑞粟一枝超簡冊。", "嘉定四載六月中，採來疑自東極東。", "龍枝鳳冠雲蕖叢，令人多力善走顔色紅。", "六岐九穗豈足道，徑欲一醉敲金鐘。", "趙君不敢留，馳以告宰公。", "宰公不敢留，馳以告太守意甚忠。", "嘉定聖人坐法宮，聲色不邇心在農。", "嘉定聖人與天通，故産瑞粟昭年豐。", "新安太守見此喜，謂匪奇花異卉同，銷金黄羅手自封。", "再拜獻天門，進入開天容。", "吾聞粟有神，其姓曰慶天。", "吾聞粟字制，其西曰金堅。", "吾聞粟字釋，蓋取陽精相續如百川。", "請君占所聞，可以知開先。", "我歌賀宰公，宰公歸太守。", "我歌賀太守，太守歸我皇極天子大父母，願見太平萬古萬萬古。", "惟有貧儒都不知，但願食粟長無饑。"]'),
('1795a56d-a08e-4de3-9296-d92574084c32','擊鼓行','汪莘','宋','宋诗','song-poetry','','[]','柳塘有狂士，酒闌好擊鼓。',232,'全唐诗/poet.song.189000.json','["柳塘有狂士，酒闌好擊鼓。", "殷出黄金骨裏淚，摻出白玉心中苦。", "此苦知爲何人家，寒宵心事亂如麻。", "岑牟肯戴紅槿帽，蹀足不數漁陽檛。", "翻手作春杏開早，覆手秋風葉如掃。", "開元天子是天工，那知塵起長安道。", "我今擊鼓一聲高徹天，擊鼓二聲深徹泉。", "天上拂開白日路，地鎖掣斷如飛烟。", "豺狼聞之腦門裂，狐鼠粉碎臭滿穴。", "惟有蒼鱗火鬣雙虬龍，籋雲揈雷雨騷屑。", "青天洗出古時青，日月洗出古時明。", "百穀草木催發生，鸞鳳亦作簫韶鳴。", "走上半空望五嶽，插天截海蟠金城。", "我皇無爲人自寧，此時方表鼓中聲，寫作柳塘擊鼓行。"]'),
('5d19ea10-7026-40ad-989b-372626d0a72b','放歌行','汪莘','宋','宋诗','song-poetry','','[]','口中吐佛子，腰間出神仙。',373,'全唐诗/poet.song.189000.json','["口中吐佛子，腰間出神仙。", "眉心紅日大如錢，腦宮誦經聲泠然。", "瞿曇黄老去我久，可使舉世終無傳。", "天亦若忌我，我自夢裏知其天。", "團團清光中，本來面目常現前。", "分明是真不是想，水中月影鏡中像。", "自從別後見君稀，一朝邂逅成歡賞。", "見亦不可擬，得亦不可强。", "知音相逢只彈指，甃命遮寒且涵養。", "芙蓉芰荷顛倒披，九天風露流肝脾。", "俯觀人世不忍棄，世人棄我良非癡。", "有時憤悶須痛飲，長安市上相追隨。", "左挾田先生，右拍樊於期。", "狗屠在前舞陽後，擊筑叱起高漸離。", "揚雄但能識奇字，未識以道御之無不宜。", "一舞神鬼哭，再舞雷電飛。", "三舞乾坤悉清凈，却視萬物生光輝。", "我衰不能作伊川，手把犂鋤墾蚯蚓。", "亦復不能作呂望，垂絲磻溪上。", "但願漢家宗社牢，化權何必吾人操。", "但願紫微宮南太微北，中間七箇能甄陶。", "君不見張三裹青衫，李四著紫袍，黄金轉多官轉高。", "孔丘盜跖那復辨，長蛇封豕爭雄豪。", "我欲告天天肯否，旁人竊笑婦摇手。"]'),
('527e29b1-2909-4307-9180-24dd277b29ff','中原行懷古','汪莘','宋','宋诗','song-poetry','','[]','漢家中原一百州，故老南望空悠悠。',184,'全唐诗/poet.song.189000.json','["漢家中原一百州，故老南望空悠悠。", "問君北賊何足道，坐守畫地如窮愁。", "不共戴天是此仇，生不殺賊死不休。", "諸公但能安身計，更無一點英雄氣。", "遂令多士皆沉醉，絕口不復言時事。", "恭惟主上天勇智，皦日平生復仇志。", "秋色平場千萬騎，望裏亭亭黄屋至。", "六軍拜手呼萬歲，報恩便欲無生意。", "西風蕭瑟天無雲，引領蟠冢愁黄曛。", "白衣不得見天子，道人何得愁朱門，可憐涇渭胸中分。", "願起沔陽死諸葛，作我大宋飛將軍。"]'),
('86a6a75e-3adf-4546-abcc-1da203973fb0','觀雪行','汪莘','宋','宋诗','song-poetry','','[]','仙人剪水銀河邊，仙風吹散花聯翩。',96,'全唐诗/poet.song.189000.json','["仙人剪水銀河邊，仙風吹散花聯翩。", "明星撩亂入我眼，風緊一陣隨天旋。", "如今誰卧剡溪雪，如今誰訪山陰船。", "古人氣韵不可見，曉來對此空悠然。", "檐前未覺眼界豁，臨眺忽憶樓居仙。", "若爲留得數玉樹，六月繞屋生清妍。"]'),
('4b451348-aad4-438d-a5b3-baab674db57f','別真直院西山','汪莘','宋','宋诗','song-poetry','','[]','去年來見公，畧以書自陳。',168,'全唐诗/poet.song.189000.json','["去年來見公，畧以書自陳。", "今年來見公，知公意已親。", "一見爲我喜，再見爲我顰。", "溫存到風雨，檢點及米薪。", "會我群玉堂，坐上皆偉人。", "欲引野鶴姿，軒昂出京塵。", "公自哀其窮，我豈有足珍。", "但願公富貴，何憂我賤貧。", "過從兩三月，意味十萬春。", "將非前世緣，更結來生因。", "所恨難久留，歸理青溪緡。", "公亦厭承明，請牧江海濱。", "嗟我老于行，東西足悲辛。", "那宜種橘柚，幸使守松筠。"]'),
('b5fbc5d1-9f2c-4401-9184-a764f5f549f3','訪孟守','汪莘','宋','宋诗','song-poetry','','[]','紫陽佳山水，帝室雄垣藩。',288,'全唐诗/poet.song.189000.json','["紫陽佳山水，帝室雄垣藩。", "桑柘若雲屯，梨棗如星環。", "邇來十四載，有失漢詔寬。", "坐令隴畝上，面作百摺酸。", "侯來自江西，與物破險囏。", "處處春風村，家家秋月灣。", "矧侯老儒術，淵源起波瀾。", "文盟後韓孟，詩社前張樊。", "賤子昔好學，何理不仰鑽。", "風雷繞腸胃，日月懸肺肝。", "宇宙在掌握，鬼神露毫端。", "身由疾惡病，家以論事殫。", "天門守九虎，歸卧牛衣間。", "誓欲滅此賊，使天回正觀。", "豫子欲趨趙，聶生方入韓。", "匕首忽電掣，鐵椎已雷鑽。", "世無伯牙手，鍾子每長嘆。", "世無子期耳，伯牙淚空彈。", "人生樂相知，相知良亦難。", "不知起胡越，相知同歲寒。", "自侯之來矣，願言識孔鸞。", "秋風動心氣，朔雲資瘧姦。", "及此春日舒，扶病猶蹣跚。", "怪僕來胡遲，爲僕留城關。"]'),
('8410e444-c837-413f-94f6-f43c53d83702','訪湯倅','汪莘','宋','宋诗','song-poetry','','[]','文者道之器，詩者文之精。',240,'全唐诗/poet.song.189000.json','["文者道之器，詩者文之精。", "世儒失本原，謂以一枝鳴。", "僕昔頗好學，不與時俗并。", "始求爲己事，中有濟物情。", "靜與古月俱，動與秋陽行。", "先聖此從容，風流被後生。", "身世兩相違，淹留竟何成。", "一丘聊自適，萬化爭逢迎。", "天地露根柢，動植陳性情。", "日月顯處妙，鬼神隠中明。", "老佛既恍惚，諸子亦縱橫。", "興衰雜今古，憂豫難悉平。", "時買白玉板，寫此朱絲聲。", "似被天公嗔，魑魅出見驚。", "秋霜下黄葉，春風自抽萌。", "蘭花待春風，深林含芳馨。", "屬聞賢別駕，古學兼韶韺。", "仍聞吐佳句，氣挾蘇州清。", "今朝別柴扉，匪敢投公卿。", "臭味畧相似，長松與茯苓。"]'),
('73dcf5b3-ba23-4998-9ee0-273e43f5fa11','對月與念六弟談化作','汪莘','宋','宋诗','song-poetry','','[]','新月長眉清，娟娟照茅舍。',240,'全唐诗/poet.song.189000.json','["新月長眉清，娟娟照茅舍。", "坐有我弟俱，因得窮造化。", "初嘆此箇月，涵浙復涵灞。", "終憶此箇月，古夜復今夜。", "日月天中行，地下亦雙明。", "天地在太虛，一點如流萍。", "水輪載以浮，風輪吹不停。", "地譬雞子黄，天乃雞子清。", "天半繞地下，天半出地上。", "星辰附天旋，晝夜成俯仰。", "吾嘗揮雷鞭，騎龍日宮前。", "整頓朝東皇，拜手金烏傍。", "日宮月宮留不住，翻身透過天頂去。", "雙手撥轉赤精毬，山河萬象在裏頭。", "此時見天不見地，憶嘗閲盡世間事。", "幾度穿入月之內，幾度穿出天之外。", "幾度天地劫火來，只有太虛元不壞。", "我自太虛觀世間，釋迦老子皆等閑。"]'),
('809cabfd-f472-4488-81b0-c0b90a439704','春懷  其一','汪莘','宋','宋诗','song-poetry','','[]','太皡涵帝德，勾芒播皇仁。',96,'全唐诗/poet.song.189000.json','["太皡涵帝德，勾芒播皇仁。", "群龍服蒼駕，靈雨冒南岑。", "淵魚自暖躍，谷鳥相和吟。", "桃花既夾道，麥苗亦成林。", "竹籬带夕陽，茅舍含清陰。", "白蘋空騁望，青楓第傷心。", "况值聖明代，聊以陶吾真。", "寄言同懷子，芳醪期共斟。"]'),
('84accfa2-e0ec-452f-b2c8-d9c93cd20e90','春懷  其二','汪莘','宋','宋诗','song-poetry','','[]','黄鸝占高枝，蝴蝶戀芳草。',96,'全唐诗/poet.song.189000.json','["黄鸝占高枝，蝴蝶戀芳草。", "達人能岸春，兒女被春惱。", "和風吹衣裳，白日照懷抱。", "天地爲我園，衆目一何小。", "東皇行仲月，南極現朱鳥。", "虞帝被袗衣，周王在靈沼。", "于飛既覽德，於牣亦知道。", "感此彌恨長，冉冉以空老。"]'),
('e61b6468-5dea-4b9b-a98c-f20ffd10efa0','春懷  其三','汪莘','宋','宋诗','song-poetry','','[]','綠水繞北戶，白日挂南榮。',96,'全唐诗/poet.song.189000.json','["綠水繞北戶，白日挂南榮。", "岑樓高中天，引領望咸京。", "咸京望不見，遠山與雲橫。", "鸞鳳邈何許，燕雀巢朱甍。", "谷風起將夕，偃月哉生明。", "童子焚妙香，稚女彈神箏。", "似非今世曲，無乃古人情。", "爲言且勿彈，吾疾方未平。"]'),
('8460511a-f75b-42af-aec3-21fa2d5ac604','春懷  其四','汪莘','宋','宋诗','song-poetry','','[]','神游何邊方，夢到迷處所。',96,'全唐诗/poet.song.189000.json','["神游何邊方，夢到迷處所。", "論世非秦漢，辨地豈吳楚。", "碧桃翳陽林，翠霞蔭清渚。", "鵾雞鳴花間，鸞鶴將儔侶。", "中有古玉堂，日月光相貯。", "似是重瞳君，左右列二女。", "我時再拜興，帝復相爾汝。", "蘧然形已開，不得竟所語。"]'),
('999458cb-ec39-46f8-b68a-0247aec77b8e','春懷  其五','汪莘','宋','宋诗','song-poetry','','[]','青天夫何長，白日又何促。',96,'全唐诗/poet.song.189000.json','["青天夫何長，白日又何促。", "吹却幾株花，成此一村綠。", "不嫌春已晚，春晚愛不足。", "誰能描晚春，隠然在心曲。", "我心如明鏡，萬象相映燭。", "我心如虛空，萬物自磨觸。", "斜陽紅欲滴，遠水光可掬。", "中有太古人，歌聲出金玉。"]'),
('d37783ea-9ec8-4057-93b6-2a8fbcc1cd61','春懷  其六','汪莘','宋','宋诗','song-poetry','','[]','夕陽下西崦，明月出東方。',96,'全唐诗/poet.song.189000.json','["夕陽下西崦，明月出東方。", "清波如有神，喬木何蒼蒼。", "簪玉待魏文，趿履從思王。", "奎壁不在天，西園爛成章。", "祥飈繞飛蓋，鴛鴦宿春塘。", "絲竹壯高會，賓主無留觴。", "憂生惜日短，玩物貪夜長。", "歲寒不易得，此道亦足藏。"]'),
('9e9daffa-2b9a-4806-9293-2b9f1953a34a','春懷  其七','汪莘','宋','宋诗','song-poetry','','[]','夾鍾應和氣，和氣到天中。',96,'全唐诗/poet.song.189000.json','["夾鍾應和氣，和氣到天中。", "半爲枝間綠，半作水上紅。", "杖策南野際，鸛鶴摩蒼穹。", "君子有本性，不受外物攻。", "那能學攀桂，俯首嫦娥宮。", "竦身攝倒景，與子凌剛風。", "參旗一以展，欃搶避其鋒。", "舉瓢酌雲將，歌詩謝鴻濛。"]'),
('06ee296d-cf03-46ba-8ecd-0a6ad6b6e19f','春懷  其八','汪莘','宋','宋诗','song-poetry','','[]','魚鼈好在川，鳥獸好在山。',96,'全唐诗/poet.song.189000.json','["魚鼈好在川，鳥獸好在山。", "人皆好山水，所好非一端。", "君子抱仁智，寓意山水間。", "矧乃陽春月，富貴相追攀。", "靚裝散香風，纖指發清彈。", "道旁起深羨，有識獨長嘆。", "我亦共春游，所遇得正觀。", "可與達者悟，難與昧者談。"]'),
('f5127d73-dee9-44d9-868d-fb8f2ca74772','春懷  其九','汪莘','宋','宋诗','song-poetry','','[]','日釀天正綠，風酣麥方秋。',96,'全唐诗/poet.song.189000.json','["日釀天正綠，風酣麥方秋。", "閑携稚子輩，眷言共春游。", "芒鞋過澗壑，竹杖穿林丘。", "東西隨所適，語嘿頗自由。", "亦有一樽酒，父子相獻酬。", "山花既含笑，野草亦忘憂。", "一輪漸隠隠，半規尚悠悠。", "歸路何所嘆，古人可與謀。"]'),
('9f507ffa-7569-4175-b9cf-e17638c66bf8','春懷  其一○','汪莘','宋','宋诗','song-poetry','','[]','曳杖登春臺，萬物含光輝。',96,'全唐诗/poet.song.189000.json','["曳杖登春臺，萬物含光輝。", "天地豈不大，孤雲獨無依。", "我友在東海，古屋弦湘妃。", "昔醉芙蓉浦，今掩桃李扉。", "不見已三年，何由會王畿。", "贈子青玉案，報我紫金鞿。", "日暗牛羊下，月明烏鵲飛。", "有生共如此，擾擾徒增欷。"]'),
('6f63a404-cf0f-42ef-84d8-728e1bf31503','春曉','汪莘','宋','宋诗','song-poetry','','[]','曉來雨初晴，天宇凈如拭。',48,'全唐诗/poet.song.189000.json','["曉來雨初晴，天宇凈如拭。", "隔籬見花柳，春氣亂五色。", "東君渾不管，但爲閑者得。", "我方獵鵾鵬，溟南復溟北。"]'),
('80b50668-f11b-4b9f-9985-603f6f44c97c','陋居五詠 景風院','汪莘','宋','宋诗','song-poetry','','[]','昔年浮丘人，池舘藏一丘。',72,'全唐诗/poet.song.189000.json','["昔年浮丘人，池舘藏一丘。", "天門騎鹿仙，浩氣壓女牛。", "朅來木正落，歌動林塘幽。", "至今五月花，憔悴因郎羞。", "底處牽白犢，超然對清流。", "景風故隨車，爲我迴凉秋。"]'),
('b56f2466-b22d-4d11-bd4f-146f7a55c34c','陋居五詠 池館','汪莘','宋','宋诗','song-poetry','','[]','丈室明松窗，水竹相因依。',60,'全唐诗/poet.song.189000.json','["丈室明松窗，水竹相因依。", "盧橘冬已花，日出黄蜂飛。", "愛此禪房幽，不踏市朝機。", "時觀彼蒼意，常與人願違。", "彼蒼不可會，青山又斜暉。"]'),
('d410e686-adfc-4e8e-a5c4-0ee52df9a86c','陋居五詠 竹澗','汪莘','宋','宋诗','song-poetry','','["\u897f\u6e56"]','散髮篁竹中，濯足寒澗流。',84,'全唐诗/poet.song.189000.json','["散髮篁竹中，濯足寒澗流。", "太陽正徘徊，心與爽氣遊。", "活活走龍鱗，鏘鏘韵天球。", "於焉種荷花，遥剪西湖秋。", "亦思百頃綠，薰風木蘭舟。", "青鳥去還來，白魚沉更浮。", "竹澗魚鳥家，益覺吾廬幽。"]'),
('6ef8f4a6-9f5a-41b8-980e-b2295fd6ace7','陋居五詠 蔣徑','汪莘','宋','宋诗','song-poetry','','[]','穿渠带幽徑，列竹依清流。',72,'全唐诗/poet.song.189000.json','["穿渠带幽徑，列竹依清流。", "中有好鳥鳴，暮鎖星辰稠。", "北風攪雪花，更覺龍鳳遒。", "東皇憐歲寒，丹白如飛浮。", "細履或得得，長歌亦悠悠。", "顧我非蔣卿，何以致羊裘。"]'),
('766bf65d-af90-4abb-98de-bc1d15968ce1','陋居五詠 月臺','汪莘','宋','宋诗','song-poetry','','[]','呼匠琢山骨，臨水起月臺。',72,'全唐诗/poet.song.189000.json','["呼匠琢山骨，臨水起月臺。", "一槃古月色，竹影凉毰毸。", "竹影如掃月，月色掃不開。", "居然廣寒宮，桂枝苦低回。", "便欲招謫仙，娥眉送瓊杯。", "娥眉見梅花，思君弄青梅。"]'),
('e80b9f57-006f-40ce-8c90-1afd9ac8fbf0','竹洲見寄次韵','汪莘','宋','宋诗','song-poetry','','[]','朱宮瓦缶鳴，汙澤黄鍾屏。',144,'全唐诗/poet.song.189000.json','["朱宮瓦缶鳴，汙澤黄鍾屏。", "古來會通籍，作者能籤整。", "翁如食橄欖，但願回味永。", "只今竹洲上，伏臘仰公廩。", "玩彼易外象，付此卦中影。", "遥知疏桐下，缺月見深省。", "我來如征鴻，愛此沙洲冷。", "他年直紫薇，夢斷青絲綆。", "舊游倘入念，折簡肯相命。", "新詩蒙剪拂，爲憐伍噲等。", "駕言載雙榼，卜日問三徑。", "預約清樽月，雲頭開金餠。"]'),
('2fbac2d7-6a7f-45b7-91ab-22134d9cb926','又敘謝','汪莘','宋','宋诗','song-poetry','','[]','竹翁惡俗客，屢舉却塵翁。',168,'全唐诗/poet.song.189000.json','["竹翁惡俗客，屢舉却塵翁。", "云何一見我，捉手形深睠。", "坐呼蘭溪酒，即取太白勸。", "階前抱關卒，爲我顔色變。", "解榻經兩眠，天寒恐冰霰。", "主意厚且真，惜別如挽牽。", "握手紫竹杖，眩轉含飛電。", "端作臨水送，沙溪清練練。", "還家甫席暖，書到驚一縣。", "特遣贈行詩，水剪梨花片。", "且約二三子，同煮竹洲麵。", "豈意古人事，乃復今日見。", "理髮敘心曲，所屬加餐飯。", "無事覺晝長，明窗試筆硯。"]'),
('5e8e758c-6e18-4f4a-b274-3ef6456fdf6f','群玉堂即事','汪莘','宋','宋诗','song-poetry','','[]','蓬萊道山到者稀，忽隨飈駕同來歸。',354,'全唐诗/poet.song.189000.json','["蓬萊道山到者稀，忽隨飈駕同來歸。", "天橫閬野望不盡，地絕瀛海如無依。", "初得松門入蕭瑟，漸繞苔徑穿芳菲。", "奇花異卉不可識，但覺春是人間非。", "高檐長廊白日靜，朱簾綠幕清風微。", "仰觀群玉三大字，始憶上帝書所儲。", "赤圖綠牒文字古，空桑孤竹音調希。", "飲中八仙各灑落，瓊林風月相光輝。", "坐而投壺妙貫耳，立而對奕工解圖。", "吟詩誦賦清且永，何事顧我頻歔欷。", "君不見咸平景德時，太平都在楊劉詩。", "又不見慶曆元祐際，後來誰與歐蘇繼。", "只今延閣多才賢，如玉在山珠在淵。", "楊劉歐蘇未爲老，秦皇鼂張俱少年。", "有客野於孟東野，更宜盧仝作詩社。", "碧牋小紙辱佳命，青林紫筆令揮寫。", "君山天酒澆枯腸，吸盡一架酴醿香。", "贈君千歲白鹿健，報我三尺金魚光。", "羽陵蠹簡非我處，老上龍庭欲飛去。", "鳳臺南軒又招手，第一內宅由來住。", "東西南北身已老，安得丹液還元腦。", "碧桃洞口花亂飛，留待歸來不須掃。"]'),
('6dc75b79-5ce6-4a72-938d-3be6e51e5ddc','黄山高','汪莘','宋','宋诗','song-poetry','','[]','黄山高哉，巋然爲江東之巨鎮兮，壁立於兩浙之上游。',483,'全唐诗/poet.song.189000.json','["黄山高哉，巋然爲江東之巨鎮兮，壁立於兩浙之上游。", "摩天戛日以直上，陽枝陰派盤數州。", "四海不知兩根本，行人但覺雲飛浮。", "嘗試芒鞋竹枝迨乎其間兮，一溪桃杏紅爛熳，萬壑松柏寒颼颼。", "懸崖絕磴可望不可到兮，古木倒挂險更遒。", "上有靈泉瀑布千萬道，如銀河自天爭瀉而競注兮，砅雷濺雪隠現穿林幽。", "中有青鸞黄鶴千萬對，雄倡雌和迭舞而交鳴兮，深林自適復有雪白數點之猿猴。", "山中自昔無曆日，花開葉落成春秋。", "殘英脫葉不知其所從來兮，但見夫澗谷之間桃花如扇，松花如纛，竹葉如笠，蓮葉如舟。", "菖蒲九節餵白鹿，靈芝三秀眠青牛。", "人間三月春已暮，洞中花卉春長留。", "奇香異氣逐風去，散落塵世誰能酬。", "黄山高哉，雲際一峰尚可畫，雲外一峰畫不得，霜繒鋪了掉首休。", "丹砂一峰燭天爭日月，九龍一峰拔地張旂旒。", "天都一峰傑出於三十六峰兮，星斗森羅挂珠殿，日月對展瓊瑶樓。", "中有一人兮龍冠而鳳裘，左容成兮右浮丘。", "我時收却釣竿樵具作一束，投諸曹阮溪中流。", "浴余身兮湯泉，風余袂兮帝所。", "夔鼓隠隠兮管啾啾，水精盤兮碧玉甌。", "帝酌我兮勞我，左右爲余兮凝眸。", "指余以南峰石壁記，授余以紅鉛黑汞大丹頭。", "黄山高哉，余將覽秀巢雲鍊其下，坐令萬物不生疵癘黍盈疇。"]'),
('642a7594-1157-4b7b-8a60-dea9ddb18fd5','訪建康留守','汪莘','宋','宋诗','song-poetry','','[]','敬公太古明月服，愛公九天寒露漿。',192,'全唐诗/poet.song.189000.json','["敬公太古明月服，愛公九天寒露漿。", "畏公龍泉太阿劍，喜公班虎花蛇囊。", "月中含月作懷抱，露表滴露生清凉。", "風塵澒洞要英傑，太平潤色須文章。", "公昔荷橐侍紫皇，公今握符坐建康。", "綸巾羽扇夏日靜，鳴鳩乳燕南風長。", "青天有月來堂堂，白鷺分水鳴湯湯。", "城頭獨立是誰子，身長七尺鬚眉蒼。", "袖藏古劍咸陽市，淚逐東風灑桃李。", "一心只望金陵飛，未到三更已千里。", "北斗錯落垂寒光，願公提起掃八荒。", "刺人如影那見血，激天孤竹和空桑。"]'),
('94b9f951-eb11-4e63-ac94-a449be8b7419','訪曾侍郎','汪莘','宋','宋诗','song-poetry','','[]','青天蕩蕩摩青銅，紫微將相環西東。',156,'全唐诗/poet.song.189000.json','["青天蕩蕩摩青銅，紫微將相環西東。", "大鵬一擊九萬里，兩翼不鼓乘長風。", "大鵬飛到天門下，天門無不聳觀者。", "列星退步失光彩，九虎低頭若凡馬。", "有鳥决起搶榆枋，望而不見空斷腸。", "青天愈高鵬愈遠，豈不有意招八荒。", "我捨新安來，狂歌錢塘市。", "上有無情之吳山，下有傷心之江水。", "春已暮，人未歸，平生不問鱖魚肥。", "若教買得青山住，飽食笋蕨歌春暉。"]'),
('402eb3f1-c041-4c2d-99d2-fec90b4ca3e1','訪吳安撫竹洲','汪莘','宋','宋诗','song-poetry','','[]','憶昔見公十載前，知公即日圖凌烟。',96,'全唐诗/poet.song.189000.json','["憶昔見公十載前，知公即日圖凌烟。", "而今見公十載後，豈意翻爲竹洲叟。", "黄金照日天門開，夜叉安得生風雷。", "龍文虎脊君當取，有才不用當誰哉。", "中原寢廟無消息，塞上無人能殺賊。", "君王此志二十秋，四海看君閑不得。"]'),
('2ab66ad2-06a2-4e24-b476-0afd57202de5','題新安郡圃駐屐亭','汪莘','宋','宋诗','song-poetry','','[]','先王昔牧紫陽城，池邊駐屐荷花生。',96,'全唐诗/poet.song.189000.json','["先王昔牧紫陽城，池邊駐屐荷花生。", "先王今居帝青閣，歲歲荷花自開落。", "華榜高垂四十年，銀鈎鐵畫蛟龍纏。", "公來對之不忍去，如見先王在眼前。", "願公子孫滿仙籍，相繼此邦森畫戟。", "願君與國爲柱石，長使邦人歌駐屐。"]'),
('17adb55f-e2ef-4af0-9920-8030f687c477','雞雛','汪莘','宋','宋诗','song-poetry','','[]','負清抱黄圓如彈，昆侖磅礴幽未判。',261,'全唐诗/poet.song.189000.json','["負清抱黄圓如彈，昆侖磅礴幽未判。", "母雞春日宿雞棲，躬抱乾坤入烹煆。", "翼之腹之氣自蒸，有時踏轉令交貫。", "朦朦如困當晝中，惺惺無眠過夜半。", "食時莫怪喚不應，凝然有在應難喚。", "君不見陰陽氣足有超越，恍惚惚恍生神觀。", "數聲隔㲉聞淳音，一點懸胎脫幽贊。", "母雞慣事徐啄開，可憐毛羽良毰毸。", "却思裏許若爲活，跧伏性命能低回。", "啄粟飲水孰教之，天機自動曾何疑。", "三三兩兩旋母脚，出入南北相追隨。", "纍然多寡乍磊落，倏然後先無定著。", "乘閒疾數數不得，往來旁午依前錯。", "聞道輪迴少安泊，謫仙那能被法縛。", "秋山歸來酒新熟，呼童烹雞色自若。", "殺與不殺莫忖度，請君注目寒江倚山閣。"]'),
('b3ebeed0-d980-47bf-b21b-358693b8300e','贈祁門不老山高法師','汪莘','宋','宋诗','song-poetry','','[]','鼇山萬仞峙璇霄，上有高真道寂寥。',320,'全唐诗/poet.song.189000.json','["鼇山萬仞峙璇霄，上有高真道寂寥。", "拔足壯能軒物表，洗心清不渾塵囂。", "洞天別有風光異，人世那知宇宙遥。", "雲覆醮壇閑悄悄，烟凝仙室靜蕭蕭。", "步虛韵穩聽晨禮，環珮聲遲識晚朝。", "飯啗青精顔色好，詞歌白鶴利名消。", "囊空阿堵緣辭寵，匣蓄干將爲斬妖。", "折角巾多裁氎布，隠居衣盡屏鮫綃。", "神游汗漫趨蓬島，禹步迴旋指斗杓。", "九轉丹砂盈日月，三千功行繼松喬。", "密渠細石通泉竇，斜插疏籬護藥苗。", "甕裏香醪斟琥珀，壁間修扇閣芭蕉。", "蟠桃欲熟人爭竊，野菜初生手自挑。", "花卉得時舒錦繡，瓶湯娛客奏笙簫。", "長松夭矯龍千尺，嫩竹琳琅玉萬條。", "鳳翅亂峰森洞口，羊腸微徑繞山腰。", "床眠癭木肱常曲，兀坐文藤足屢翹。", "衮衮騫河傾俊辯，溫溫和璞琢孤標。", "我慚未躍三春浪，君去行看八月潮。", "好把陰功拯存沒，西歸宜早買吳舠。"]'),
('65fb753f-654b-48b6-ab0b-66ad0fa6299c','題汪侍郎仲宗北山道院','汪莘','宋','宋诗','song-poetry','','[]','北山之宅可忘歸，北山之山天下稀。',206,'全唐诗/poet.song.189000.json','["北山之宅可忘歸，北山之山天下稀。", "自非君身有仙骨，安得蓬壺閬苑相因依。", "長松巨柏氣象古，紅鸞白鳳交橫飛。", "朔風萬里促冬日，金橘千樹爭光輝。", "樞密曾孫侍御子，天資酷與前人似。", "只今四十未爲老，不選娥眉壓閭里。", "道院夜長霜月白，豪氣猶餘好賓客。", "早晚春歸花亂發，蝶舞鶑啼亦傷魄。", "此言聊戲爾，時事端可惜。", "大兒只求上上考，次兒只用平平策。", "胡運已衰當謝絕，西戎方彊又須索。", "北山主人那得閑，袖中三尺青蛇斑。", "有客不知其所往，歲暮江頭雪三尺。"]'),
('33e8a28c-cb68-4ef4-8e2a-41c791111a5f','訪吳安撫命賦詩竹洲中有靜香亭長堤靜觀齋舞雩亭','汪莘','宋','宋诗','song-poetry','','[]','鳳麟敢謂皇家無，如公自合應時須。',288,'全唐诗/poet.song.189000.json','["鳳麟敢謂皇家無，如公自合應時須。", "胡爲返駕竹洲隠，只與高堂素壁成畫圖。", "一麾淮海重拜敕，老人在南子在北。", "稱家菽水歡有餘，每日乃得見顔色。", "大兒三十心力到，租稅免教官吏逼。", "小兒十五天資敏，火耕水耨云未克。", "竹林茅屋謾讀書，我正不蒙稽古力。", "請言竹洲勝，蕖篠相因依。", "紅蕖未妨晚色靜，翠篠解過凉陰稀。", "漁童樵青足驅使，夜深醉和風雨歸。", "夢中突兀長堤橫，忽覺單騎遊邊城。", "擒胡已决千里外，邯鄲一枕空崢嶸。", "閑來靜觀宛殊昨，却憐蒲團坐日落。", "偶見始畫天地心，從此鳶飛共魚躍。", "向來天地本來閑，獵夫見鹿不見山。", "不然堤下寒流自太古，何人曾作沂水看。", "前日從公洲上語，茯苓期我能同煮。", "未容只作竹洲翁，屬聞漢詔求伊呂。"]'),
('eed02cb6-01dc-4821-ac79-66734c3a1140','梧竹亭','汪莘','宋','宋诗','song-poetry','','[]','人家有園種花柳，君家有園種梧竹。',198,'全唐诗/poet.song.189000.json','["人家有園種花柳，君家有園種梧竹。", "花柳只引蜂蝶來，梧竹能招鸞鳳宿。", "昨君飲我池上亭，亭邊梧竹深冥冥。", "鎪風鏤月已足玩，滴雨灑雪尤堪聽。", "君不見梧君昔在岐山上，開花與鳳作屏障。", "又不見竹君昔在渭水陽，結實與鳳充糇糧。", "岐山渭水地差遠，頗覺老鳳勞往返。", "成周已去漢唐空，梧亦無根竹無本。", "君家甲第連朱扉，碧梧翠竹相因依。", "千年老鳳嘆何在，一旦下集增光輝。", "梧君竹君喜相遇，鳳兮鳳兮君且住。", "老鳳回頭謝二君，吾方高舉青天去。"]'),
('84daca3f-8ce5-45eb-bd6b-6368788af405','淳熙壬寅仲夏大雨寫望','汪莘','宋','宋诗','song-poetry','','[]','一朵烏雲起天末，倏忽長驅半天闊。',128,'全唐诗/poet.song.189000.json','["一朵烏雲起天末，倏忽長驅半天闊。", "雲頭到處急雨來，雨脚錯落飛河魁。", "吹以南箕更豪橫，打窗噴壁催吟詠。", "恰驚瓦上碎珠跳，已快檐前銀竹映。", "平生不識南箕狀，且看平疇翻翠浪。", "恍然立我三湘間，欲著扁舟相跌宕。", "風迴雨霽天地新，良苗斗覺添精神。", "天意更看七八月，明年無處可打蕨。"]'),
('ee21bb00-8e7b-4ebf-828e-14c3a7ec07f9','野趣亭','汪莘','宋','宋诗','song-poetry','','[]','晚唐多處士，林亭足娛嬉。',346,'全唐诗/poet.song.189000.json','["晚唐多處士，林亭足娛嬉。", "吾鄉盛儒冠，何園可棲遲。", "貧者有不能，富者有不爲。", "我窮不出門，出門復坐馳。", "此事我所嘆，無地容蛟螭。", "聞君築小亭，幽懷正在茲。", "况復扁野趣，未見已伸眉。", "示我野趣詩一軸，邀我共賦野趣詩。", "我思其義浸宏闊，操筆引紙頻嗟咨。", "古今何人得野趣，野趣不許凡人窺。", "見君所賦我已會，賦我所見君勿嗤。", "請從大庭栗陸葛天起，一片野趣無高卑。", "居不懸金石，出不建旄旗。", "衣不繪龍鳳，食不羅鼎彜。", "人家忘貧亦忘富，鄰里何盛仍何衰。", "蒼顔白髮各自足，山圍水繞忘所之。", "堯舜禮樂民始慕，湯武干戈民始疑。", "窮奢極侈到秦漢，沉酣骨髓終陳隋。", "遂令舉世不復野，村夫俚婦爭夸毗。", "我觀宇宙間，野趣元不移。", "散殊零落遍處處，收拾聚集當時時。", "多年如客棄不采，一朝有主來如期。", "君看上下數千載，不多古跡存餘基。", "乃知作者豈俗士，後有繼者須英奇。"]'),
('44176417-f98a-41df-b89a-fcb232bad6d3','方壺自詠  其一','汪莘','宋','宋诗','song-poetry','','[]','性靜無一物，心生有萬端。',48,'全唐诗/poet.song.189000.json','["性靜無一物，心生有萬端。", "曾將魂魄鍊，不被鬼神瞞。", "縱步地雖窄，仰頭天自寬。", "裁詩偏得偶，遇卦只成單。"]'),
('b9d02428-5d63-4098-9204-3202284cc479','方壺自詠  其二','汪莘','宋','宋诗','song-poetry','','[]','三萬六千刻，四千三百時。',48,'全唐诗/poet.song.189000.json','["三萬六千刻，四千三百時。", "不思人事汩，只怪歲華馳。", "拚命嘗因道，忘家亦爲詩。", "幽懷聊自遣，俗子莫令知。"]'),
('15d964a2-c2ca-4dfe-8062-300555c2c84f','方壺自詠  其三','汪莘','宋','宋诗','song-poetry','','[]','生死何時了，盈虛祇足傷。',48,'全唐诗/poet.song.189000.json','["生死何時了，盈虛祇足傷。", "誰能一刻靜，大勝百年忙。", "反己求中帝，逢時說外王。", "紛紛徒藉藉，踽踽亦凉凉。"]'),
('10289e64-8f79-4668-a340-413bb8b34bf2','方壺自詠  其四','汪莘','宋','宋诗','song-poetry','','[]','事體向晚境，情懷非少年。',48,'全唐诗/poet.song.189000.json','["事體向晚境，情懷非少年。", "平生不得地，至死亦由天。", "坐背暑彌勝，行膺寒愈堅。", "願言過去苦，莫與後來賢。"]'),
('9b505775-a7d0-406f-aa7c-548e8aeea67f','方壺自詠  其五','汪莘','宋','宋诗','song-poetry','','[]','白晝常陪俗，清宵得養魂。',48,'全唐诗/poet.song.189000.json','["白晝常陪俗，清宵得養魂。", "幾時成草屋，終日掩柴門。", "事迫文方出，身閑道始尊。", "世方懷祖逖，吾已吊劉琨。"]'),
('88e6fe1d-52ae-48f7-921f-756aa63f970d','方壺自詠  其六','汪莘','宋','宋诗','song-poetry','','[]','無象始無假，有形斯有邪。',48,'全唐诗/poet.song.189000.json','["無象始無假，有形斯有邪。", "盈虛憐日月，聚散笑烟霞。", "一性亦無我，五行何况他。", "誰能離火宅，吾與上牛車。"]'),
('66ea15fa-961a-4cdc-a803-5211389931b8','方壺自詠  其七','汪莘','宋','宋诗','song-poetry','','[]','殘臘天垂老，新春日始孩。',48,'全唐诗/poet.song.189000.json','["殘臘天垂老，新春日始孩。", "玄君歸渾沌，青帝出肧胎。", "樓上獨倚處，海邊相見來。", "閑思栽五柳，怒欲拔三槐。"]'),
('f2ba1dfc-8259-490a-8cde-4cc362537c5b','方壺自詠  其八','汪莘','宋','宋诗','song-poetry','','[]','百歲已過半，隻身誰與偕。',48,'全唐诗/poet.song.189000.json','["百歲已過半，隻身誰與偕。", "得因徵悟道，失在太開懷。", "且託山花宿，時從水竹齋。", "神回天上活，骨付月中埋。"]'),
('a18e6150-3d50-4822-9a01-8c1bf01ac20d','方壺自詠  其九','汪莘','宋','宋诗','song-poetry','','[]','興發花開處，情生葉落邊。',48,'全唐诗/poet.song.189000.json','["興發花開處，情生葉落邊。", "既爲欣厭惑，未脫死生纏。", "鑿破心中月，衝開頂上天。", "俗儒應大笑，古佛不曾傳。"]'),
('15005f9d-419d-43b1-ac50-5147aa309932','方壺自詠  其一○','汪莘','宋','宋诗','song-poetry','','[]','誰和陽春曲，仍操白雪音。',48,'全唐诗/poet.song.189000.json','["誰和陽春曲，仍操白雪音。", "郊寒猶有骨，島瘦未無心。", "雲到散時看，月當虧處尋。", "可憐持玉尺，終不度金針。"]'),
('e85804f7-b904-43b6-b649-78ee5e309054','方壺自詠  其一一','汪莘','宋','宋诗','song-poetry','','[]','直寫胸中事，誰拈紙上塵。',48,'全唐诗/poet.song.189000.json','["直寫胸中事，誰拈紙上塵。", "興來那暇懶，得處不容廑。", "行有鬼神覷，詩防天地嗔。", "歐蘇尋後輩，郊島是前身。"]'),
('826ddc2c-4efd-4c24-b693-fcc66e8f871e','開禧元年四月自中都挈家還鄉寓居城南十二月遷居柳溪上其夜大雪初一日蓋宰來訪約過縣齋爲一日款深夜而歸賦此  其一','汪莘','宋','宋诗','song-poetry','','[]','出郭已超俗，住溪尤近真。',48,'全唐诗/poet.song.189000.json','["出郭已超俗，住溪尤近真。", "青天素知我，白雪便隨人。", "守道何妨賤，藏書不盡貧。", "長懷社中友，共發甕頭春。"]'),
('b51202c1-aeb7-44de-9fa3-e99027dbb566','開禧元年四月自中都挈家還鄉寓居城南十二月遷居柳溪上其夜大雪初一日蓋宰來訪約過縣齋爲一日款深夜而歸賦此  其二','汪莘','宋','宋诗','song-poetry','','[]','世事偏宜假，吾生只認真。',48,'全唐诗/poet.song.189000.json','["世事偏宜假，吾生只認真。", "少知行路惡，老愛在家貧。", "寧接古時鬼，怕逢今世人。", "澗松方卧雪，野草亦爭春。"]'),
('ec119f7e-7bbd-49c3-ae91-73229f3a06bf','開禧元年四月自中都挈家還鄉寓居城南十二月遷居柳溪上其夜大雪初一日蓋宰來訪約過縣齋爲一日款深夜而歸賦此  其三','汪莘','宋','宋诗','song-poetry','','[]','群處那相合，單棲正自如。',48,'全唐诗/poet.song.189000.json','["群處那相合，單棲正自如。", "好言天外事，懶讀世間書。", "指直筆難把，唇濡硯屢噓。", "傾壺有餘瀝，窺甕得殘菹。"]'),
('a1ee59e2-b98c-46a7-a8dd-2002f7d3ee8c','開禧元年四月自中都挈家還鄉寓居城南十二月遷居柳溪上其夜大雪初一日蓋宰來訪約過縣齋爲一日款深夜而歸賦此  其四','汪莘','宋','宋诗','song-poetry','','[]','每恨投南鵲，尤憐向北枝。',48,'全唐诗/poet.song.189000.json','["每恨投南鵲，尤憐向北枝。", "雖蒙今士笑，恐有後人思。", "運火解朝凍，嚥津充夜饑。", "不來溪上住，那得雪中詩。"]'),
('c6b3d722-2cbf-4db2-a886-e3346b833c7d','開禧元年四月自中都挈家還鄉寓居城南十二月遷居柳溪上其夜大雪初一日蓋宰來訪約過縣齋爲一日款深夜而歸賦此  其五','汪莘','宋','宋诗','song-poetry','','[]','徹骨寒誰覺，回骸暖自醒。',48,'全唐诗/poet.song.189000.json','["徹骨寒誰覺，回骸暖自醒。", "直須人悄悄，方得物亭亭。", "性伏涵三極，心開燭萬靈。", "有僧肥臃腫，怪我瘦竛竮。"]'),
('656086da-c094-4221-b4a1-b49b688239a5','開禧元年四月自中都挈家還鄉寓居城南十二月遷居柳溪上其夜大雪初一日蓋宰來訪約過縣齋爲一日款深夜而歸賦此  其六','汪莘','宋','宋诗','song-poetry','','[]','脫命市朝隘，側身桑梓深。',48,'全唐诗/poet.song.189000.json','["脫命市朝隘，側身桑梓深。", "山含首陽色，水带汨羅音。", "中夜不能寐，萬端都上心。", "鄰鷄猶未動，沙鳥已相尋。"]'),
('59aa1113-22e7-4451-b24a-1ae32c375d69','開禧元年四月自中都挈家還鄉寓居城南十二月遷居柳溪上其夜大雪初一日蓋宰來訪約過縣齋爲一日款深夜而歸賦此  其七','汪莘','宋','宋诗','song-poetry','','[]','茅屋凍將壓，柴扉寒不開。',48,'全唐诗/poet.song.189000.json','["茅屋凍將壓，柴扉寒不開。", "交朋幾竿竹，兄弟數枝梅。", "渡口月初出，沙頭人正迴。", "客居殊自在，歲事亦相催。"]'),
('95bbb183-846c-46b3-becf-680195c8f327','開禧元年四月自中都挈家還鄉寓居城南十二月遷居柳溪上其夜大雪初一日蓋宰來訪約過縣齋爲一日款深夜而歸賦此  其八','汪莘','宋','宋诗','song-poetry','','[]','朱減顔逾皺，霜添鬢却新。',48,'全唐诗/poet.song.189000.json','["朱減顔逾皺，霜添鬢却新。", "文章應捨我，富貴不如人。", "照破生前物，思窮死後神。", "謂宜休仕漢，何必只逃秦。"]'),
('1a27ff38-9094-4daa-8996-8c3c4745c5ec','開禧元年四月自中都挈家還鄉寓居城南十二月遷居柳溪上其夜大雪初一日蓋宰來訪約過縣齋爲一日款深夜而歸賦此  其九','汪莘','宋','宋诗','song-poetry','','[]','積雪滴還凍，斜陽陰復明。',48,'全唐诗/poet.song.189000.json','["積雪滴還凍，斜陽陰復明。", "千峰濃淡碧，一水淺深清。", "醫卜猶真祿，樵漁亦美名。", "人皆云有命，我獨得無生。"]'),
('c72362d7-caff-4748-93a6-29b633362341','開禧元年四月自中都挈家還鄉寓居城南十二月遷居柳溪上其夜大雪初一日蓋宰來訪約過縣齋爲一日款深夜而歸賦此  其一○','汪莘','宋','宋诗','song-poetry','','[]','築室深山裏，開門古澗邊。',48,'全唐诗/poet.song.189000.json','["築室深山裏，開門古澗邊。", "月高猿子叫，日晏虎兒眠。", "带雪挑黄菜，敲冰取碧泉。", "不知居士樂，空受俗人憐。"]'),
('8c25ef7f-bc4a-4275-a676-6a4f28ef4cf8','懷朱晦菴先生','汪莘','宋','宋诗','song-poetry','','[]','道在羲皇孰斷金，至人出處合天心。',64,'全唐诗/poet.song.189000.json','["道在羲皇孰斷金，至人出處合天心。", "青山白雲有生路，流水落花無足音。", "世外太古日色靜，洞中一片春風深。", "自憐晚輩服膺久，亦許杖屨來相尋。"]'),
('95d4a126-69e5-4876-9ca1-022b439a8a6d','壽高內翰  其一','汪莘','宋','宋诗','song-poetry','','[]','胸次包天燭九垓，正須博大濟時材。',64,'全唐诗/poet.song.189000.json','["胸次包天燭九垓，正須博大濟時材。", "朝從碧落摶風角，暮泛靈槎出斗魁。", "別墅已將修竹隠，朱門仍向鏡湖開。", "如今且爲蒼生起，一取前賢氣燄回。"]'),
('267e9494-5588-4918-a9b5-349eba48f5b5','壽高內翰  其二','汪莘','宋','宋诗','song-poetry','','["\u897f\u6e56"]','璞玉渾金表裏同，心知言動有陰功。',64,'全唐诗/poet.song.189000.json','["璞玉渾金表裏同，心知言動有陰功。", "一門人傑成龍種，三世科名各繼宮。", "華蓋共瞻天座北，勾陳長扈帝垣中。", "野人只待秋風起，去向西湖作釣翁。"]'),
('dc7a9d0b-5740-4c7a-995b-cdbb865d8e3b','壽高內翰  其三','汪莘','宋','宋诗','song-poetry','','[]','鶴立青松老令威，佳辰山水倍清輝。',64,'全唐诗/poet.song.189000.json','["鶴立青松老令威，佳辰山水倍清輝。", "曾扶東壁排雲出，幾跨蒼龍带雨飛。", "竹簟水風須得意，玉堂春日即催歸。", "願公與國爲梁棟，千載煌煌照太微。"]'),
('e6199f3b-de69-46fa-9ef4-75a79b33f657','壽高秘書','汪莘','宋','宋诗','song-poetry','','[]','萬壑千巖映翠霞，越王城下競傳誇。',64,'全唐诗/poet.song.189000.json','["萬壑千巖映翠霞，越王城下競傳誇。", "青天白日秘書舫，乳燕鳴鳩內相家。", "高浪趣潮滄海直，大鵬橫擊五雲斜。", "自吹玉笛相爲壽，昨夜菖蒲吐紫花。"]'),
('a2056711-0a29-4a6f-91cc-92e8c8618ea3','壽何尚書','汪莘','宋','宋诗','song-poetry','','[]','雪艇風帆去玉京，故家猿鶴相歡迎。',64,'全唐诗/poet.song.189000.json','["雪艇風帆去玉京，故家猿鶴相歡迎。", "九天氣母壺中足，十月嬰兒頂上行。", "曾問何修能至此，但云無欲自然成。", "夜來夢向山莊立，一炷清香徹太清。"]'),
('5b358ada-155d-473a-81db-a52db74e25c1','寄商察院','汪莘','宋','宋诗','song-poetry','','["\u897f\u6e56"]','竊伏西湖雪鬢催，長歌聲斷鬼神哀。',64,'全唐诗/poet.song.189000.json','["竊伏西湖雪鬢催，長歌聲斷鬼神哀。", "青天有月無人看，白帝行秋待我來。", "近水遠山俱冷淡，敗荷孤葦尚低回。", "今朝欲向青門道，出到疏籬意已灰。"]'),
('2fdc42ce-3ddc-4396-944c-bd05848fad34','玉堂中賡任宮講希夷惠詩韵','汪莘','宋','宋诗','song-poetry','','[]','宮講先生句子香，晦菴衣鉢有餘芳。',64,'全唐诗/poet.song.189000.json','["宮講先生句子香，晦菴衣鉢有餘芳。", "松篁性本參天直，楊柳情仍庇地長。", "自恨此身真逆旅，不知何日更傳觴。", "山人初向山中出，還欲歸來水一方。"]'),
('fff5c9bf-5f54-4bc3-a9ef-12e4a3d84deb','訪楊湖州  其一','汪莘','宋','宋诗','song-poetry','','[]','一道西江隔水雲，夜瞻牛斗共天文。',64,'全唐诗/poet.song.189000.json','["一道西江隔水雲，夜瞻牛斗共天文。", "聖之清必先夫子，仁者勇須今使君。", "天下山川居一半，湖州風月占三分。", "錦囊幸許傳抄去，預取蘭香手自薰。"]'),
('5d0d9585-7e1b-44bb-8537-f8016add45d0','訪楊湖州  其二','汪莘','宋','宋诗','song-poetry','','[]','苕溪霅溪風景好，浙西浙東皆弗如。',64,'全唐诗/poet.song.189000.json','["苕溪霅溪風景好，浙西浙東皆弗如。", "處處堤邊種楊柳，家家門外有芙蕖。", "使君遠繼東坡事，處士端宜耘老居。", "聞道香名來一訪，白鬚照水久躊躇。"]'),
('104471d3-2776-4e32-8e8b-0cc93997f517','寄潘倅','汪莘','宋','宋诗','song-poetry','','[]','夢魂何事練溪濱，起自新春向晚春。',64,'全唐诗/poet.song.189000.json','["夢魂何事練溪濱，起自新春向晚春。", "紅杏園林催百舌，綠楊洲渚薦重唇。", "一年好處是寒食，三月水邊多麗人。", "遥想使君行樂處，牡丹如障草如茵。"]'),
('8dd02252-0ab9-4fb1-9c1c-aa7d8939201a','中秋月  其一','汪莘','宋','宋诗','song-poetry','','[]','今宵何處愜清遊，震澤波心太華頭。',64,'全唐诗/poet.song.189000.json','["今宵何處愜清遊，震澤波心太華頭。", "初出海張紅錦扇，到中天挂水晶毬。", "兔蟾迸作雙輪現，金火鎔成一鑑秋。", "惟有飛仙知表裏，入他宮殿又焉廋。"]'),
('94fb44eb-ffca-45a4-a916-bb9936349f38','中秋月  其二','汪莘','宋','宋诗','song-poetry','','[]','對月題詩過幾人，不知何句與渠親。',64,'全唐诗/poet.song.189000.json','["對月題詩過幾人，不知何句與渠親。", "精神尤向水中活，形狀直須天上真。", "紫磨一輪開作屋，桂花千朵斫爲薪。", "寒儒老矣心猶在，誠念唐虞有野臣。"]'),
('dd366f0f-8864-40c8-a194-d2e16e47afe7','中秋月  其三','汪莘','宋','宋诗','song-poetry','','[]','萬派寒芒一道飛，陰精盛處遠成圍。',64,'全唐诗/poet.song.189000.json','["萬派寒芒一道飛，陰精盛處遠成圍。", "抱回紅日浴東井，橫截碧天朝太微。", "惟有中秋金正王，復當子夜水生肥。", "溶溶滿掬乾坤髓，說向傍人是泄機。"]'),
('fb682a38-f072-4a6f-8d24-27e2d0f8b3ff','中秋月  其四','汪莘','宋','宋诗','song-poetry','','[]','吟詩競盡月精微，自昔誰明造化機。',64,'全唐诗/poet.song.189000.json','["吟詩競盡月精微，自昔誰明造化機。", "近作金波千道去，遠成玉鑑一團飛。", "陽魂滿處因乾父，陰魄虧時自巽妃。", "笠澤漁舟都不問，醉中倒着綠蓑衣。"]'),
('b5bcf175-f245-47ce-8605-d62c6ac7c870','中秋月  其五','汪莘','宋','宋诗','song-poetry','','[]','詩人長以月爲心，對月題詩隨淺深。',64,'全唐诗/poet.song.189000.json','["詩人長以月爲心，對月題詩隨淺深。", "缺此作鈎圓作鑑，白將如玉紫如金。", "鍊丹道士綿綿守，見性禪師了了吟。", "今夜誰家殺風景，聒天鼓吹到橫參。"]'),
('9882e67d-8b30-4b95-ad6c-d662f743f3e3','佛書載兜率天有內院道書有赤城朱窗乃帝一內宅因述所聞','汪莘','宋','宋诗','song-poetry','','[]','結髮師心內院行，紫雲門闕碧霞城。',64,'全唐诗/poet.song.189000.json','["結髮師心內院行，紫雲門闕碧霞城。", "一聲霹靂衝天響，萬點星辰匝地明。", "鼎裏金丹能虎變，牀頭鐵杖带龍腥。", "極知富貴非吾事，玉簡珠繒有姓名。"]'),
('f2bcf254-c933-4b26-8b1d-a5ca49a150f1','游甘露寺','汪莘','宋','宋诗','song-poetry','','[]','扁舟京口意躊躇，北固峰頭淚滿裾。',64,'全唐诗/poet.song.189000.json','["扁舟京口意躊躇，北固峰頭淚滿裾。", "聞道昔時兵可用，未知今日事何如。", "傷心南渡英雄盡，屈指中原歲月疏。", "待見太平心始足，不妨歸去老樵漁。"]'),
('30c9de6e-d46b-4779-ac93-105f7e6183c1','夜興','汪莘','宋','宋诗','song-poetry','','[]','倚天長劍爲誰收，欲獻君王鎮九州。',64,'全唐诗/poet.song.189000.json','["倚天長劍爲誰收，欲獻君王鎮九州。", "世事漫隨紅日下，壯心空逐碧江流。", "雁橫西塞偏愁客，菊綻東籬始當秋。", "抖擻向來塵土夢，便提蓑笠上漁舟。"]'),
('ef123b65-19c6-4b7a-81ed-1aae80e6f3f6','秋懷  其一','汪莘','宋','宋诗','song-poetry','','[]','形骸欹仄面皮黄，破屋三間號柳塘。',32,'全唐诗/poet.song.189000.json','["形骸欹仄面皮黄，破屋三間號柳塘。", "自大暑來真畏暑，到微凉處便知凉。"]'),
('d82a219d-fe54-4d9a-ba93-e615137828a8','秋懷  其二','汪莘','宋','宋诗','song-poetry','','[]','四野秋風交敝廬，時平不用藺相如。',32,'全唐诗/poet.song.189000.json','["四野秋風交敝廬，時平不用藺相如。", "有人來問生涯事，指點蓑衣學釣魚。"]'),
('a4efbac6-681f-4a62-ac99-c7a9de4705cb','秋懷  其三','汪莘','宋','宋诗','song-poetry','','[]','秋雲無復似春濃，天地何人到此窮。',32,'全唐诗/poet.song.189000.json','["秋雲無復似春濃，天地何人到此窮。", "斜日淡烟今古恨，如何都付與孤鴻。"]'),
('081a69a2-e043-4d9f-b2ce-403fded4d930','秋懷  其四','汪莘','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','北渚風生禾葉秋，洞庭波起夕陽收。',32,'全唐诗/poet.song.189000.json','["北渚風生禾葉秋，洞庭波起夕陽收。", "楚人臨水爲誰立，帝子隔烟相對愁。"]'),
('2daafd2e-c75e-46cf-a9d0-65e593f44ce3','秋懷  其五','汪莘','宋','宋诗','song-poetry','','[]','自分爲人類魯臯，幾將心事泛吳舠。',32,'全唐诗/poet.song.189000.json','["自分爲人類魯臯，幾將心事泛吳舠。", "手摶日月供宸筆，揀盡金雞玉兔毫。"]'),
('c3851cdf-952c-4cc2-8f08-256235d56e2c','秋懷  其六','汪莘','宋','宋诗','song-poetry','','[]','曾向瀟湘遇水仙，倏來如月去如烟。',32,'全唐诗/poet.song.189000.json','["曾向瀟湘遇水仙，倏來如月去如烟。", "深林一笑聞山鬼，余處幽篁不見天。"]'),
('a71f2ff2-02e2-4178-be65-78fd676f4da1','秋懷  其七','汪莘','宋','宋诗','song-poetry','','[]','傷春未了又悲秋，無復歡悰到酒舟。',32,'全唐诗/poet.song.189000.json','["傷春未了又悲秋，無復歡悰到酒舟。", "茅屋半欹籬半倒，伏羲一卷在牀頭。"]'),
('e46c8aef-c31f-4bde-8cf3-6ca00ec9a024','秋懷  其八','汪莘','宋','宋诗','song-poetry','','[]','玉露金風刮夜天，疏桐缺月耿窗前。',32,'全唐诗/poet.song.189000.json','["玉露金風刮夜天，疏桐缺月耿窗前。", "十詩未盡窮愁志，說與家僮汝自眠。"]'),
('ce4828f5-9435-44f0-964a-0d16be59ec2d','秋懷  其九','汪莘','宋','宋诗','song-poetry','','[]','一带青巒失舊青，荻花楓葉夕陽明。',32,'全唐诗/poet.song.189000.json','["一带青巒失舊青，荻花楓葉夕陽明。", "閑思天上多官府，自是幽人道未成。"]'),
('c2c0e6d0-a6e2-465b-baf9-579f5aa633ff','秋懷  其一○','汪莘','宋','宋诗','song-poetry','','[]','虞帝周王不復生，幾多豪傑應離明。',32,'全唐诗/poet.song.189000.json','["虞帝周王不復生，幾多豪傑應離明。", "鳳凰覽遍真難合，直至而今欠一聲。"]'),
('dcc45512-a237-4ab6-ac09-3925b0cc2758','次潘別駕韵','汪莘','宋','宋诗','song-poetry','','[]','野店溪橋柳色新，千愁萬恨爲何人。',32,'全唐诗/poet.song.189000.json','["野店溪橋柳色新，千愁萬恨爲何人。", "殷勤織就黄金縷，带雨籠烟過一春。"]'),
('1661b0bc-3a18-41a0-bf85-e2e8a77e07c4','潘別駕自祁門回','汪莘','宋','宋诗','song-poetry','','[]','白馬嘶風入紫陽，使君一笑列壺觴。',32,'全唐诗/poet.song.189000.json','["白馬嘶風入紫陽，使君一笑列壺觴。", "秋原是處堪圖畫，豆子花紅稻半黄。"]'),
('0fd98026-28ea-4ae8-b677-41be26141dd3','九月十六日出郡登舟如錢塘十七日舟中雜興  其一','汪莘','宋','宋诗','song-poetry','','[]','落日扁舟萬古心，半山明耀半溪陰。',32,'全唐诗/poet.song.189000.json','["落日扁舟萬古心，半山明耀半溪陰。", "漁鹽商賈都來往，縱有客星何處尋。"]'),
('417504a6-3ca1-4aea-a598-a60909333bbe','九月十六日出郡登舟如錢塘十七日舟中雜興  其二','汪莘','宋','宋诗','song-poetry','','[]','一簇沙鷗占碧波，手摇雙槳叫吳歌。',32,'全唐诗/poet.song.189000.json','["一簇沙鷗占碧波，手摇雙槳叫吳歌。", "大羅只許詩人賦，不許詩人上大羅。"]'),
('0c604181-0bf7-48d0-ac10-c2af3733cd75','九月十六日出郡登舟如錢塘十七日舟中雜興  其三','汪莘','宋','宋诗','song-poetry','','[]','天地窮時事不窮，最傷心處是凉風。',32,'全唐诗/poet.song.189000.json','["天地窮時事不窮，最傷心處是凉風。", "少年每下悲秋淚，投老情知淚亦空。"]'),
('9aed3bc8-5baa-4617-9906-d73aff255b34','九月十六日出郡登舟如錢塘十七日舟中雜興  其四','汪莘','宋','宋诗','song-poetry','','[]','兩夜江心對泬寥，恍兮惚裏有逍遥。',32,'全唐诗/poet.song.189000.json','["兩夜江心對泬寥，恍兮惚裏有逍遥。", "堂堂皓月排空出，自覺精神湧碧霄。"]'),
('c24019a7-03ce-4966-9285-b4c9682ab656','九月十六日出郡登舟如錢塘十七日舟中雜興  其五','汪莘','宋','宋诗','song-poetry','','[]','碧天似水元非水，碧水如天不是天。',32,'全唐诗/poet.song.189000.json','["碧天似水元非水，碧水如天不是天。", "人現非天非水處，君來何處覓神仙。"]'),
('15231c13-0762-4cc8-929e-1b0b2fd201ad','九月十六日出郡登舟如錢塘十七日舟中雜興  其六','汪莘','宋','宋诗','song-poetry','','[]','白雲晚向山中出，白霧朝從水上生。',32,'全唐诗/poet.song.189000.json','["白雲晚向山中出，白霧朝從水上生。", "三百里灘轟笛過，鬼神驚倒怒龍聲。"]'),
('f56e2dd5-60a3-479c-98fd-1e65ac92fb72','九月十六日出郡登舟如錢塘十七日舟中雜興  其七','汪莘','宋','宋诗','song-poetry','','[]','莘野磻溪亦偶然，每逢耕釣憶前賢。',32,'全唐诗/poet.song.189000.json','["莘野磻溪亦偶然，每逢耕釣憶前賢。", "春風秋月閑來往，只付時人一醉眠。"]'),
('9e82c516-22dc-4943-9b9c-390590f9070e','九月十六日出郡登舟如錢塘十七日舟中雜興  其八','汪莘','宋','宋诗','song-poetry','','[]','橫石灘頭古釣磯，綠波擊破雪花飛。',32,'全唐诗/poet.song.189000.json','["橫石灘頭古釣磯，綠波擊破雪花飛。", "老翁識得魚爭處，手把綸竿滿意歸。"]'),
('f82f1ea1-6fdc-41f2-af61-75e3eb40d1bb','九月十六日出郡登舟如錢塘十七日舟中雜興  其九','汪莘','宋','宋诗','song-poetry','','[]','日暮滄江駐客舟，眼前境界起詩愁。',32,'全唐诗/poet.song.189000.json','["日暮滄江駐客舟，眼前境界起詩愁。", "沿山幾處人烟僻，摘粟收麻到白頭。"]'),
('ba05db1d-8b3c-4a5d-8dd4-9eba075d0663','九月十六日出郡登舟如錢塘十七日舟中雜興  其一○','汪莘','宋','宋诗','song-poetry','','[]','巍然釣石壓江濱，烟水茫茫斷四鄰。',32,'全唐诗/poet.song.189000.json','["巍然釣石壓江濱，烟水茫茫斷四鄰。", "天帝座邊元是客，劉郎何得欲相臣。"]'),
('18020347-7973-4961-813b-eb0b9910a8db','遊南山','汪莘','宋','宋诗','song-poetry','','[]','山蹊黄葉從過滿，石案蒼苔不用除。',32,'全唐诗/poet.song.189000.json','["山蹊黄葉從過滿，石案蒼苔不用除。", "壇上古松巖畔竹，切須留伴老僧居。"]'),
('e2f0d478-1c51-4a84-a0cf-842f46544d21','送趙君十絕  其一','汪莘','宋','宋诗','song-poetry','','[]','皂蓋朱轓練水濱，春生秋殺總精神。',32,'全唐诗/poet.song.189000.json','["皂蓋朱轓練水濱，春生秋殺總精神。", "須知愛士何曾泛，屈指應無第二人。"]'),
('e3060ad2-2752-4e30-a0c1-958cd47787bc','送趙君十絕  其二','汪莘','宋','宋诗','song-poetry','','[]','醉把金鞭度綠楊，軍民夾道笛聲長。',32,'全唐诗/poet.song.189000.json','["醉把金鞭度綠楊，軍民夾道笛聲長。", "紅旗千面詩千首，半雜風雲入建章。"]'),
('c036128f-531b-4725-991c-70b5af6e418e','送趙君十絕  其三','汪莘','宋','宋诗','song-poetry','','[]','荷葉高高荷蘂低，夕陽初落畫橋西。',32,'全唐诗/poet.song.189000.json','["荷葉高高荷蘂低，夕陽初落畫橋西。", "湖州士女來相接，爭擁蘭舟入霅溪。"]'),
('8b155452-6706-4480-bff8-8d731bb7e57d','送趙君十絕  其四','汪莘','宋','宋诗','song-poetry','','[]','歸去苕溪理釣蓬，風清月白水精宮。',32,'全唐诗/poet.song.189000.json','["歸去苕溪理釣蓬，風清月白水精宮。", "青蓮居士爭閑得，時答天書一兩通。"]'),
('d7ce3bb9-694b-4083-a806-0c14af1eaf41','送趙君十絕  其五','汪莘','宋','宋诗','song-poetry','','[]','風雨黄昏自掩扉，燈前時復一歔欷。',32,'全唐诗/poet.song.189000.json','["風雨黄昏自掩扉，燈前時復一歔欷。", "兒曹相問緣何事，爲道君侯早晚歸。"]'),
('d14d79c9-6e2c-4f12-9d49-3564aacdeff5','送趙君十絕  其六','汪莘','宋','宋诗','song-poetry','','[]','一榼村醪插別筵，清風急雨送歸船。',32,'全唐诗/poet.song.189000.json','["一榼村醪插別筵，清風急雨送歸船。", "望中未是湖州境，便有吳歌唱採蓮。"]'),
('7ba35c9e-0822-4cf4-a02a-0083f0ec1c35','送趙君十絕  其七','汪莘','宋','宋诗','song-poetry','','[]','練水至清無淺深，使君何日再登臨。',32,'全唐诗/poet.song.189000.json','["練水至清無淺深，使君何日再登臨。", "請看江上千株柳，盡是君民離別心。"]'),
('02baa39a-fe7e-49f4-82d0-901240e8bdd8','送趙君十絕  其八','汪莘','宋','宋诗','song-poetry','','[]','有客胸藏太息書，蕭蕭白髮不堪梳。',32,'全唐诗/poet.song.189000.json','["有客胸藏太息書，蕭蕭白髮不堪梳。", "君王若問江東士，莫只相憐誦子虛。"]'),
('f940c188-e7ca-4cd6-b967-0638bea23b8d','秋興  其一','汪莘','宋','宋诗','song-poetry','','[]','閑步水南因水北，仍從山後復山前。',32,'全唐诗/poet.song.189000.json','["閑步水南因水北，仍從山後復山前。", "日歸海底龍方覺，月到天心虎正眠。"]');
